-- exercises_ficha.sql — GENERADO por scripts/build-ficha-seed.js (no editar a mano)
-- Contenido de fichas de ejercicio (pasos/errores/pro_tip/terciarios) ES+EN.
-- content_verified queda en false: requiere validación de entrenador antes de prod.
-- Fuente: supabase/seed/ficha/*.json
BEGIN;
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con los pies al ancho de la cadera y agarrá la barra en supinación con las manos separadas al ancho de los hombros.","Mantené los codos pegados a los costados del torso durante todo el recorrido.","Espirá y flexioná los codos subiendo la barra en arco hacia los hombros hasta una flexión máxima.","Pausá un instante en la contracción y bajá de forma controlada inspirando.","No extiendas completamente el codo al fondo para mantener tensión continua en los flexores."]'::jsonb,
  execution_steps_en = '["Stand with feet hip-width apart and grip the bar with a supinated grip, hands shoulder-width apart.","Keep your elbows pinned to your sides throughout the movement.","Exhale and flex the elbows, curling the bar in an arc toward your shoulders to peak contraction.","Pause briefly at the top and lower the bar in a controlled manner while inhaling.","Avoid fully locking out the elbow at the bottom to maintain continuous tension on the flexors."]'::jsonb,
  common_errors_es = '["Usar el balance del torso para ayudar a subir la barra, reduciendo el trabajo del bíceps.","Dejar caer los codos hacia adelante al subir, lo que quita tensión en el punto de máxima contracción.","Extender completamente el codo al fondo con carga, lo que sobrecarga el tendón distal del bíceps.","Agarrar la barra con las muñecas dobladas hacia atrás, generando tensión innecesaria."]'::jsonb,
  common_errors_en = '["Using torso momentum to help raise the bar, reducing bicep engagement.","Allowing the elbows to drift forward on the way up, reducing tension at peak contraction.","Fully extending the elbow at the bottom under load, stressing the distal bicep tendon.","Gripping the bar with hyperextended wrists, creating unnecessary joint tension."]'::jsonb,
  pro_tip_es = 'Para la barra EZ, el agarre semisupinado reduce el estrés en la muñeca y aumenta levemente la participación del braquiorradial; es una alternativa válida si tenés molestias en la muñeca con barra recta.',
  pro_tip_en = 'With an EZ bar, the semi-supinated grip reduces wrist stress and slightly increases brachioradialis involvement; it''s a valid alternative if you experience discomfort with a straight bar.',
  tertiary_muscles = ARRAY['Pronator Teres','Flexor Carpi Radialis','Core']::text[]
WHERE slug = 'barbell-bicep-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá la barra sobre la parte superior del trapecio (sentadilla alta) o en los deltoides posteriores (sentadilla baja).","Abrí los pies al ancho de los hombros o un poco más con los dedos levemente hacia afuera.","Inspirá, braceá el core y bajá controlado flexionando caderas y rodillas simultáneamente.","Descendé hasta que los muslos queden paralelos al suelo o más abajo si tu movilidad lo permite.","Espirá y empujá el suelo para subir manteniendo el torso erguido y las rodillas en línea con los dedos del pie."]'::jsonb,
  execution_steps_en = '["Position the bar across the upper traps (high bar) or rear delts (low bar).","Set your feet shoulder-width or slightly wider with toes turned out slightly.","Inhale, brace your core, and descend in a controlled manner by flexing hips and knees simultaneously.","Lower until thighs are parallel to the floor or deeper if mobility allows.","Exhale and drive through the floor to stand, keeping your torso upright and knees tracking over your toes."]'::jsonb,
  common_errors_es = '["Dejar caer las rodillas hacia adentro (valgo) al subir bajo carga.","Inclinar el torso excesivamente hacia adelante por falta de movilidad de tobillo.","Levantar los talones del suelo durante el descenso.","No activar el core antes de iniciar el movimiento, exponiendo la espalda baja."]'::jsonb,
  common_errors_en = '["Allowing the knees to cave inward (valgus) when driving up under load.","Excessive forward lean due to limited ankle mobility.","Raising the heels off the floor during the descent.","Not bracing the core before initiating the movement, exposing the lower back."]'::jsonb,
  pro_tip_es = 'Aunque está catalogado en Arms por el equipamiento de la base de datos, la sentadilla con barra es fundamentalmente un ejercicio de tren inferior; priorizá la profundidad dentro del rango que tu movilidad permita sin perder la posición de la espalda.',
  pro_tip_en = 'Although listed under Arms in the database by equipment, the barbell squat is fundamentally a lower-body exercise; prioritize depth within the range your mobility allows without losing back position.',
  tertiary_muscles = ARRAY['Core','Erector Spinae','Tibialis Anterior']::text[]
WHERE slug = 'barbell-squat';
UPDATE public.exercise_library SET
  execution_steps_es = '["Regulá el asiento para que los codos queden alineados con el eje de rotación de la máquina al apoyar los brazos.","Agarrá las manijas en supinación con los codos bien apoyados en el acolchado.","Espirá y flexioná los codos llevando las manijas hacia los hombros en el arco que dicta la máquina.","Pausá un instante en la contracción máxima y bajá inspirando de forma controlada.","No dejes que el peso caiga solo; controlá todo el recorrido excéntrico."]'::jsonb,
  execution_steps_en = '["Adjust the seat so your elbows align with the machine''s rotation axis when arms rest on the pad.","Grip the handles with a supinated grip, elbows firmly on the pad.","Exhale and flex the elbows, curling the handles toward your shoulders along the machine''s arc.","Pause briefly at peak contraction and lower while inhaling in a controlled manner.","Do not let the weight drop; control the entire eccentric portion."]'::jsonb,
  common_errors_es = '["Desalinear los codos del eje de la máquina, lo que altera la curva de resistencia.","Levantar los hombros durante la flexión para compensar con el deltoides anterior.","Soltar el peso bruscamente en el descenso, perdiendo el trabajo excéntrico.","Usar un peso que no permite llegar a la extensión completa al inicio."]'::jsonb,
  common_errors_en = '["Misaligning the elbows from the machine axis, altering the resistance curve.","Shrugging the shoulders during the curl to compensate with the anterior deltoid.","Dropping the weight abruptly on the way down, losing eccentric work.","Using a weight that prevents full extension at the start of the rep."]'::jsonb,
  pro_tip_es = 'Si la máquina tiene agarres neutralos (palmas enfrentadas), usarlos distribuye más trabajo al braquiorradial y a la cabeza larga del bíceps; alterna los agarre según el objetivo de la sesión.',
  pro_tip_en = 'If the machine offers neutral handles (palms facing each other), using them shifts more work to the brachioradialis and long head of the bicep; alternate grips based on your session goal.',
  tertiary_muscles = ARRAY['Pronator Teres','Flexor Carpi Radialis','Anterior Deltoid']::text[]
WHERE slug = 'bicep-curl-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá la polea en la posición baja y elegí el accesorio (barra recta, EZ, cuerda o manija simple).","Paráte con los pies al ancho de la cadera, codos pegados a los costados y agarrá el accesorio en supinación.","Espirá y flexioná los codos llevando el accesorio hacia los hombros; la tensión del cable es constante desde el inicio.","Pausá en la contracción y bajá inspirando sin dejar que el peso jale los hombros hacia adelante.","Mantené el torso quieto; toda la acción está en los antebrazos moviéndose sobre los codos fijos."]'::jsonb,
  execution_steps_en = '["Set the pulley to the low position and choose your attachment (straight bar, EZ bar, rope, or single handle).","Stand hip-width apart with elbows pinned to your sides and grip the attachment with a supinated grip.","Exhale and flex the elbows, curling toward your shoulders; cable tension is constant from the start.","Pause at the top and lower while inhaling, not allowing the weight to pull your shoulders forward.","Keep your torso still; all action is the forearms moving on fixed elbows."]'::jsonb,
  common_errors_es = '["Permitir que los hombros se adelanten bajo la tensión del cable, incorporando el deltoides.","Llevar los codos hacia adelante al subir para ganar rango, perdiendo la fijación del codo.","No aprovechar la tensión constante del cable controlando el excéntrico.","Usar demasiado peso que impide un rango de movimiento completo."]'::jsonb,
  common_errors_en = '["Allowing the shoulders to drift forward under cable tension, involving the deltoid.","Driving the elbows forward on the way up to gain range, losing elbow fixation.","Not taking advantage of the cable''s constant tension by neglecting the eccentric.","Using too much weight that prevents a full range of motion."]'::jsonb,
  pro_tip_es = 'La polea en supinación ofrece tensión máxima tanto en la contracción como en la extensión, a diferencia de las mancuernas. Usá este ejercicio para terminar la sesión de bíceps con un quemado de alto volumen.',
  pro_tip_en = 'The cable with supinated grip offers peak tension at both contraction and extension, unlike dumbbells. Use this exercise to finish your bicep session with a high-volume burn.',
  tertiary_muscles = ARRAY['Pronator Teres','Flexor Carpi Radialis','Core']::text[]
WHERE slug = 'cable-bicep-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá la barra EZ a la polea baja y posicionáte a una distancia de un paso del cable.","Agarrá la barra en los ángulos semisupinados internos con los codos a los costados del torso.","Espirá y flexioná los codos subiendo la barra hacia los hombros con tensión constante del cable.","Pausá en la contracción y bajá de forma controlada inspirando.","No dejes que los codos se abran o adelanten durante el movimiento."]'::jsonb,
  execution_steps_en = '["Attach the EZ bar to the low pulley and stand one step away from the cable.","Grip the bar at the inner angled sections with a semi-supinated grip, elbows at your sides.","Exhale and flex the elbows, curling the bar toward your shoulders with constant cable tension.","Pause at peak contraction and lower in a controlled manner while inhaling.","Do not allow your elbows to flare or drift forward during the movement."]'::jsonb,
  common_errors_es = '["Usar los ángulos externos de la barra EZ, lo que reduce la supinación y la activación del bíceps.","Oscilar el torso hacia atrás para ayudar a subir el peso.","No mantener los codos fijos como pivote durante todo el recorrido.","Extender el codo por completo bajo carga en cada repetición."]'::jsonb,
  common_errors_en = '["Gripping the outer EZ bar angles, which reduces supination and bicep activation.","Swinging the torso backward to assist in lifting the weight.","Not keeping the elbows fixed as a pivot throughout the movement.","Fully extending the elbow under load at the bottom of each rep."]'::jsonb,
  pro_tip_es = 'La barra EZ en polea combina el beneficio ergonómico del agarre angular con la tensión constante del cable; es una excelente opción para personas con molestias en las muñecas al usar barra recta.',
  pro_tip_en = 'The EZ bar on cable combines the ergonomic benefit of the angled grip with constant cable tension; it''s an excellent choice for those who experience wrist discomfort with a straight bar.',
  tertiary_muscles = ARRAY['Brachioradialis','Flexor Carpi Radialis','Core']::text[]
WHERE slug = 'cable-bicep-curl-ez-bar';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá la barra recta a la polea baja y agarrala en supinación completa con las manos al ancho de los hombros.","Paráte erguido con los codos pegados a los flancos del cuerpo.","Espirá y curlá la barra hacia el pecho manteniendo los codos como punto fijo.","Pausá en el punto de máxima contracción y descendé controlado inspirando.","Aprovechá la tensión constante del cable también en la fase excéntrica."]'::jsonb,
  execution_steps_en = '["Attach the straight bar to the low pulley and grip it with full supination, hands shoulder-width apart.","Stand upright with elbows pinned to the sides of your body.","Exhale and curl the bar toward your chest while keeping your elbows as the fixed pivot.","Pause at peak contraction and lower under control while inhaling.","Take advantage of the cable''s constant tension in the eccentric phase as well."]'::jsonb,
  common_errors_es = '["Doblar las muñecas hacia atrás bajo la barra, generando tensión en la articulación.","Permitir que el cable jale los hombros hacia adelante al bajar.","Subir los codos al final del movimiento para ganar recorrido falso.","Usar un agarre demasiado ancho que distribuye el trabajo innecesariamente."]'::jsonb,
  common_errors_en = '["Bending the wrists backward under the bar, creating joint tension.","Allowing the cable to pull the shoulders forward on the way down.","Raising the elbows at the end of the movement to gain false range.","Using too wide a grip that unnecessarily distributes the workload."]'::jsonb,
  pro_tip_es = 'La barra recta en polea baja no tiene ''zona muerta'' como las mancuernas: el bíceps trabaja bajo tensión en todo el arco, lo que la convierte en una opción superior para hipertrofia a igualdad de esfuerzo percibido.',
  pro_tip_en = 'The straight bar on a low pulley has no ''dead zone'' like dumbbells: the bicep works under tension throughout the full arc, making it a superior hypertrophy option at equal perceived effort.',
  tertiary_muscles = ARRAY['Brachialis','Pronator Teres','Core']::text[]
WHERE slug = 'cable-bicep-curl-straight-bar';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá la cuerda o una manija neutra a la polea baja y agarrá con las palmas enfrentadas.","Paráte erguido con los codos pegados a los costados.","Espirá y flexioná los codos subiendo las manos hacia los hombros sin rotar las palmas.","Pausá en la contracción y bajá inspirando de forma controlada.","Mantené las palmas enfrentadas durante todo el movimiento para trabajar el braquiorradial y braquial."]'::jsonb,
  execution_steps_en = '["Attach a rope or neutral handle to the low pulley and grip with palms facing each other.","Stand upright with elbows pinned to your sides.","Exhale and flex the elbows, raising your hands toward your shoulders without rotating the palms.","Pause at the top and lower while inhaling in a controlled manner.","Keep palms facing each other throughout to target the brachioradialis and brachialis."]'::jsonb,
  common_errors_es = '["Supinar las palmas durante el ascenso, convirtiendo el ejercicio en un curl clásico.","Separar los codos del torso para generar impulso.","Usar el hombro para iniciar el movimiento en vez del codo.","No controlar el excéntrico, perdiendo el estímulo de elongación bajo carga."]'::jsonb,
  common_errors_en = '["Supinating the palms during the ascent, turning it into a classic curl.","Flaring the elbows away from the torso to generate momentum.","Using the shoulder to initiate the movement instead of the elbow.","Not controlling the eccentric, losing the stimulus of lengthening under load."]'::jsonb,
  pro_tip_es = 'El agarre neutro en polea permite trabajar el braquial anterior y el braquiorradial con tensión constante; incluilo como complemento para añadir grosor al brazo más allá del bíceps.',
  pro_tip_en = 'The neutral grip on cable allows you to target the brachialis and brachioradialis under constant tension; add it as a complement to build arm thickness beyond the bicep.',
  tertiary_muscles = ARRAY['Biceps Brachii','Flexor Carpi Radialis','Core']::text[]
WHERE slug = 'cable-hammer-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Regulá ambas poleas a la altura de la cabeza y agarrá una manija con cada mano en supinación.","Paráte en el centro con los brazos extendidos horizontalmente como en una pose de doble bíceps.","Inspirá, y espirá flexionando los codos llevando las manos hacia la cabeza sin mover los brazos de la horizontal.","Pausá en la contracción y extendé controlado volviendo a la posición inicial.","Sentí el estiramiento máximo de la cabeza larga del bíceps en la posición inicial."]'::jsonb,
  execution_steps_en = '["Set both pulleys to head height and grip a handle in each hand with a supinated grip.","Stand in the center with arms extended horizontally like a double bicep pose.","Inhale, then exhale and flex the elbows, bringing your hands toward your head without dropping your upper arms from horizontal.","Pause at peak contraction and extend back under control to the start position.","Feel the maximum stretch in the long head of the bicep at the start position."]'::jsonb,
  common_errors_es = '["Dejar caer los brazos de la posición horizontal, eliminando el estiramiento de la cabeza larga.","Usar impulso del torso flexionándolo hacia adelante al curlar.","No mantener los codos al mismo nivel que los hombros durante el movimiento.","Extender completamente los codos al fondo sin control bajo la tensión del cable."]'::jsonb,
  common_errors_en = '["Dropping the upper arms from the horizontal position, eliminating the long head stretch.","Using torso momentum by leaning forward during the curl.","Not keeping the elbows level with the shoulders throughout the movement.","Fully extending the elbows at the bottom without control under cable tension."]'::jsonb,
  pro_tip_es = 'Este ejercicio maximiza el estiramiento de la cabeza larga del bíceps al iniciar desde una posición con el hombro en abducción; es especialmente útil si buscás desarrollar el pico del bíceps.',
  pro_tip_en = 'This exercise maximizes the long head bicep stretch by starting with the shoulder in abduction; it''s especially useful if you''re aiming to develop the bicep peak.',
  tertiary_muscles = ARRAY['Brachialis','Anterior Deltoid','Core']::text[]
WHERE slug = 'cable-overhead-bicep-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá la cuerda a la polea baja y posicionáte de espaldas a ella con un pie adelantado.","Tomá la cuerda por encima de la cabeza con los codos cerca de las orejas y flexionados.","Inspirá y espirá extendiendo los codos hacia arriba y al frente hasta que los brazos queden casi rectos.","Pausá en la extensión y bajá controlado inspirando, permitiendo que los codos se flexionen completamente.","Mantené la parte superior del brazo estacionaria; solo se mueven los antebrazos."]'::jsonb,
  execution_steps_en = '["Attach the rope to the low pulley and stand with your back to it, one foot forward.","Hold the rope overhead with elbows close to your ears and bent.","Inhale, then exhale and extend the elbows upward and forward until arms are nearly straight.","Pause at full extension and lower under control while inhaling, allowing full elbow flexion.","Keep the upper arm stationary; only the forearms move."]'::jsonb,
  common_errors_es = '["Abrir los codos hacia los lados durante la extensión, perdiendo el trabajo de la cabeza larga.","Mover la parte superior del brazo en vez de fijarla como pivote.","Hiperflejar la espalda lumbar al inclinarse hacia adelante bajo la carga del cable.","No permitir la flexión completa del codo al bajar, reduciendo el rango efectivo."]'::jsonb,
  common_errors_en = '["Allowing the elbows to flare outward during the extension, reducing long head involvement.","Moving the upper arm instead of keeping it as a fixed pivot.","Hyperextending the lower back by leaning forward under cable load.","Not allowing full elbow flexion on the way down, reducing effective range."]'::jsonb,
  pro_tip_es = 'La posición overhead maximiza el estiramiento de la cabeza larga del tríceps, que cruza la articulación del hombro; este ejercicio es el más efectivo para el desarrollo volumétrico del tríceps.',
  pro_tip_en = 'The overhead position maximizes the stretch of the tricep''s long head, which crosses the shoulder joint; this exercise is the most effective for volumetric tricep development.',
  tertiary_muscles = ARRAY['Anconeus','Core','Posterior Deltoid']::text[]
WHERE slug = 'cable-overhead-tricep-extension';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá la polea en la posición baja y agarrá la manija con una mano en agarre neutro.","Incliná el torso hacia adelante unos 45-60° y llevá el codo hacia atrás hasta que el brazo quede paralelo al suelo.","Espirá y extendé el antebrazo hacia atrás hasta que el brazo quede recto, contrayendo el tríceps.","Pausá en la extensión y volvé controlado a la posición inicial inspirando.","Mantené el codo alto y fijo; no lo dejes caer durante el movimiento."]'::jsonb,
  execution_steps_en = '["Set the pulley to the low position and grip the handle with one hand in a neutral grip.","Hinge the torso forward 45-60° and pull the elbow back until the upper arm is parallel to the floor.","Exhale and extend the forearm backward until the arm is straight, contracting the tricep.","Pause at extension and return under control to the start position while inhaling.","Keep the elbow high and fixed; do not let it drop during the movement."]'::jsonb,
  common_errors_es = '["Mover el codo hacia arriba y abajo en vez de fijarlo como palanca del movimiento.","No llegar a la extensión completa del codo en el punto de máxima contracción.","Usar el hombro para generar impulso al inicio del movimiento.","Inclinar el torso en exceso o rotar para compensar la falta de fuerza."]'::jsonb,
  common_errors_en = '["Moving the elbow up and down instead of fixing it as the movement''s pivot.","Not reaching full elbow extension at the point of peak contraction.","Using the shoulder to generate momentum at the start of the movement.","Leaning the torso excessively or rotating to compensate for lack of strength."]'::jsonb,
  pro_tip_es = 'El kickback en polea mantiene tensión en la contracción (a diferencia de la mancuerna, que pierde tensión al final); usalo para maximizar el estímulo de contracción en la cabeza lateral del tríceps.',
  pro_tip_en = 'The cable kickback maintains tension at full contraction (unlike the dumbbell version, which loses it at the end); use it to maximize contraction stimulus in the lateral head of the tricep.',
  tertiary_muscles = ARRAY['Triceps Medial Head','Posterior Deltoid','Anconeus']::text[]
WHERE slug = 'cable-tricep-kickback';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá la barra (recta o EZ) a la polea alta y agarrala en pronación con las manos al ancho de los hombros.","Paráte erguido o levemente inclinado hacia adelante con los codos pegados a los flancos.","Espirá y empujá la barra hacia abajo hasta extender completamente los codos.","Pausá en la contracción y subí controlado inspirando hasta que los antebrazos queden paralelos al suelo.","No muevas los codos de su posición; son el único pivote del movimiento."]'::jsonb,
  execution_steps_en = '["Attach the bar (straight or EZ) to the high pulley and grip it pronated, hands shoulder-width apart.","Stand upright or slightly leaning forward with elbows pinned to your sides.","Exhale and push the bar down until elbows are fully extended.","Pause at contraction and raise under control while inhaling until forearms are parallel to the floor.","Do not move your elbows from their position; they are the sole pivot of the movement."]'::jsonb,
  common_errors_es = '["Abrir los codos al bajar, incorporando los hombros y el pectoral al movimiento.","Inclinar el torso hacia adelante para usar el peso corporal como palanca.","No llegar a la extensión completa del codo en cada repetición.","Subir los antebrazos más allá de la posición paralela al suelo, perdiendo tensión en el tríceps."]'::jsonb,
  common_errors_en = '["Flaring the elbows on the way down, recruiting the shoulders and chest.","Leaning the torso forward to use bodyweight as leverage.","Not reaching full elbow extension on each repetition.","Raising the forearms beyond parallel to the floor, losing tension on the tricep."]'::jsonb,
  pro_tip_es = 'La polea en supinación (palmas hacia arriba) se afirma que aumenta la cabeza lateral, aunque la diferencia es pequeña; lo más relevante es la supinación final que facilita la extensión completa con menos molestia en la muñeca.',
  pro_tip_en = 'A supinated grip (palms up) is claimed to increase lateral head recruitment, though the difference is small; the most relevant benefit is the final supination that allows full extension with less wrist discomfort.',
  tertiary_muscles = ARRAY['Anconeus','Flexor Carpi Radialis','Core']::text[]
WHERE slug = 'cable-tricep-pushdown-bar';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá la cuerda a la polea alta y agarrá los extremos con las palmas enfrentadas.","Paráte con los codos pegados a los costados y el torso levemente inclinado.","Espirá y empujá la cuerda hacia abajo; al llegar al final, separás los extremos hacia afuera para maximizar la contracción.","Pausá con los brazos extendidos y subí controlado inspirando hasta que los codos estén a 90°.","Las tres cabezas del tríceps trabajan; la separación final de la cuerda potencia la contracción de la cabeza lateral."]'::jsonb,
  execution_steps_en = '["Attach the rope to the high pulley and grip the ends with palms facing each other.","Stand with elbows pinned to your sides and a slight forward lean.","Exhale and push the rope downward; at the bottom, separate the ends outward to maximize contraction.","Pause with arms extended and raise under control while inhaling until elbows are at 90°.","All three tricep heads work; the final rope separation enhances lateral head contraction."]'::jsonb,
  common_errors_es = '["No separar los extremos de la cuerda al final, perdiendo la contracción adicional.","Abrir los codos al bajar, incorporando el hombro y el pectoral.","Subir demasiado alto y perder la tensión del cable sobre el tríceps.","Usar el torso para generar impulso en vez de aislar el codo."]'::jsonb,
  common_errors_en = '["Not separating the rope ends at the bottom, losing the additional contraction.","Flaring the elbows on the way down, involving the shoulder and chest.","Raising too high and losing cable tension on the tricep.","Using the torso for momentum instead of isolating the elbow."]'::jsonb,
  pro_tip_es = 'La cuerda permite un agarre neutro y la separación final que activan las tres cabezas; es uno de los accesorios más versátiles para el tríceps en polea.',
  pro_tip_en = 'The rope allows a neutral grip and final separation that recruits all three heads; it is one of the most versatile cable tricep attachments.',
  tertiary_muscles = ARRAY['Anconeus','Posterior Deltoid','Core']::text[]
WHERE slug = 'cable-tricep-pushdown-rope';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte de espaldas a la polea alta con la cuerda tomada por encima de la cabeza y los codos cerca de las orejas.","Con un pie adelantado para mayor estabilidad, tensá el core antes de iniciar.","Espirá y extendé los codos hacia abajo y al frente hasta que los brazos queden casi rectos.","Pausá en la extensión y volvé controlado a la posición inicial inspirando.","Una variante es realizar el movimiento con una sola mano para mayor rango de trabajo unilateral."]'::jsonb,
  execution_steps_en = '["Stand facing away from the high pulley holding the rope overhead with elbows near your ears.","Place one foot forward for stability and brace your core before starting.","Exhale and extend the elbows downward and forward until arms are nearly straight.","Pause at full extension and return under control while inhaling.","A variation is to perform the movement single-arm for greater unilateral range."]'::jsonb,
  common_errors_es = '["Dejar que los codos se abran lateralmente durante la extensión.","No fijar la parte superior del brazo, usando el hombro como motor.","Hiperflejar la espalda lumbar al inclinarse bajo el tirón del cable.","No alcanzar la extensión completa del codo en cada repetición."]'::jsonb,
  common_errors_en = '["Letting the elbows flare out to the sides during extension.","Not fixing the upper arm, using the shoulder as the motor.","Hyperextending the lower back while leaning against cable pull.","Not reaching full elbow extension on each repetition."]'::jsonb,
  pro_tip_es = 'Esta variante desde la posición overhead desafía la cabeza larga del tríceps en elongación máxima; combinalá con el pushdown clásico en la misma sesión para abarcar todo el espectro de longitudes musculares.',
  pro_tip_en = 'This overhead variation challenges the long head of the tricep at maximum elongation; pair it with classic pushdowns in the same session to cover the full spectrum of muscle lengths.',
  tertiary_muscles = ARRAY['Anconeus','Core','Serratus Anterior']::text[]
WHERE slug = 'cable-tricep-pushdown-rope-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá la barra recta a la polea alta y agarrala en pronación con las manos algo más juntas que el ancho de hombros.","Paráte erguido con los codos fijos a los costados del torso.","Espirá y empujá la barra hacia abajo hasta la extensión completa de los codos a nivel de las caderas.","Pausá en la contracción y subí controlado inspirando hasta que los antebrazos queden paralelos al suelo.","La barra recta permite más pronación y es la variante clásica para ganar masa en el tríceps."]'::jsonb,
  execution_steps_en = '["Attach the straight bar to the high pulley and grip it pronated, hands slightly closer than shoulder width.","Stand upright with elbows fixed to the sides of your torso.","Exhale and push the bar downward to full elbow extension at hip level.","Pause at contraction and raise under control while inhaling until forearms are parallel to the floor.","The straight bar allows maximum pronation and is the classic variation for tricep mass building."]'::jsonb,
  common_errors_es = '["Doblar las muñecas hacia abajo al final del empuje, sobrecargando la articulación.","Abrir los codos del cuerpo para usar más peso del adecuado.","No bajar lo suficiente y no alcanzar la extensión completa del codo.","Arquear la espalda hacia atrás para generar impulso en el movimiento."]'::jsonb,
  common_errors_en = '["Bending the wrists downward at the bottom of the push, overloading the joint.","Flaring the elbows away from the body to handle more weight than appropriate.","Not pushing down enough to reach full elbow extension.","Arching the back to generate momentum during the movement."]'::jsonb,
  pro_tip_es = 'El pushdown con barra recta permite manejar más carga que la cuerda; úsalo al principio de la sesión de tríceps cuando el músculo está fresco para maximizar la ganancia de fuerza.',
  pro_tip_en = 'The straight bar pushdown lets you handle more load than the rope; use it at the start of your tricep session when the muscle is fresh to maximize strength gains.',
  tertiary_muscles = ARRAY['Anconeus','Flexor Carpi Radialis','Core']::text[]
WHERE slug = 'cable-tricep-pushdown-straight-bar';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco plano y agarrá la barra con un agarre cerrado (manos a unos 20-30 cm entre sí, dentro del ancho de los hombros).","Bajá la barra controlado hasta el pecho medio manteniedo los codos cerca del torso (~45° o menos de apertura).","Tocá levemente el pecho sin rebotar y empujá hacia arriba espirando hasta la extensión de los brazos.","Inspirá al bajar; mantené los pies apoyados y el core activo durante toda la serie.","El agarre cerrado reduce la participación del pectoral y transfiere más trabajo al tríceps."]'::jsonb,
  execution_steps_en = '["Lie on a flat bench and grip the bar close (hands ~20-30 cm apart, inside shoulder width).","Lower the bar in a controlled manner to the mid-chest, keeping elbows close to the torso (~45° or less flare).","Lightly touch the chest without bouncing and press upward while exhaling until arms are extended.","Inhale on the way down; keep feet flat and core engaged throughout the set.","The close grip reduces pectoral involvement and transfers more work to the triceps."]'::jsonb,
  common_errors_es = '["Agarrar la barra demasiado junto (manos casi tocándose), lo que genera molestia en la muñeca.","Abrir los codos en exceso hacia los lados, convirtiéndolo en un press de pecho convencional.","Rebotar la barra en el pecho para aprovechar el impulso.","No mantener las muñecas neutras bajo la barra, doblándolas hacia atrás."]'::jsonb,
  common_errors_en = '["Gripping too close (hands nearly touching), causing wrist discomfort.","Flaring the elbows excessively, turning it into a conventional chest press.","Bouncing the bar off the chest for momentum.","Not keeping the wrists neutral under the bar, bending them backward."]'::jsonb,
  pro_tip_es = 'El agarre cerrado ideal en el press de banca no significa manos juntas: encontrá la anchura que mantiene las muñecas neutras y los codos cerca del cuerpo sin generar molestia.',
  pro_tip_en = 'The ideal close grip in the bench press does not mean hands touching: find the width that keeps wrists neutral and elbows close to the body without discomfort.',
  tertiary_muscles = ARRAY['Coracobrachialis','Serratus Anterior','Core']::text[]
WHERE slug = 'close-grip-bench-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en un banco con los pies bien apoyados y agarrá la mancuerna con una mano.","Apoyá la parte posterior del brazo en la cara interna del muslo del mismo lado, con el brazo extendido hacia abajo.","Espirá y flexioná el codo de forma estricta llevando la mancuerna hacia el hombro contrario.","Pausá en la contracción máxima un instante y bajá controlado inspirando.","No muevas el torso ni el brazo de apoyo; toda la acción es del antebrazo sobre el codo fijo."]'::jsonb,
  execution_steps_en = '["Sit on a bench with feet flat and grip a dumbbell in one hand.","Brace the back of your arm against the inner thigh of the same side, arm hanging down.","Exhale and strictly flex the elbow, curling the dumbbell toward the opposite shoulder.","Pause at peak contraction for a moment and lower under control while inhaling.","Do not move the torso or the bracing arm; all action is the forearm pivoting on the fixed elbow."]'::jsonb,
  common_errors_es = '["Mover el codo fuera del muslo durante la subida para ganar rango de movimiento.","Usar el torso para oscilar y ayudar a subir el peso.","No llegar a la extensión controlada al bajar, haciendo el movimiento demasiado corto.","Sujetar la mancuerna con el pulgar en el mismo lado que los demás dedos (sin agarre de pulgar opuesto)."]'::jsonb,
  common_errors_en = '["Moving the elbow off the thigh during the lift to gain range of motion.","Using the torso to swing and assist in lifting the weight.","Not reaching a controlled extension on the way down, making the movement too short.","Gripping the dumbbell without a proper thumb-wrapped grip."]'::jsonb,
  pro_tip_es = 'El apoyo del brazo en el muslo fuerza un trabajo estricto del bíceps; es uno de los mejores ejercicios para aislar el pico del bíceps (cabeza corta) eliminando cualquier inercia.',
  pro_tip_en = 'Bracing the arm against the thigh forces strict bicep work; it''s one of the best exercises for isolating the bicep peak (short head) while eliminating any momentum.',
  tertiary_muscles = ARRAY['Pronator Teres','Flexor Carpi Radialis','Brachialis']::text[]
WHERE slug = 'concentration-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Apoyá las manos en el borde de un banco con los dedos hacia adelante y las piernas extendidas con los talones apoyados al frente.","Manteniendo la espalda cerca del banco, bajá el cuerpo en vertical flexionando los codos hacia atrás.","Descendé hasta que los codos lleguen aproximadamente a 90° o donde tu movilidad lo permita.","Espirá y empujá con el tríceps extendiendo los codos para volver a la posición inicial.","Para reducir la dificultad, apoyá los pies más cerca del banco en lugar de extender las piernas."]'::jsonb,
  execution_steps_en = '["Place your hands on the edge of a bench with fingers facing forward and legs extended, heels resting forward.","Keeping your back close to the bench, lower your body vertically by bending your elbows backward.","Descend until elbows reach approximately 90° or within your available mobility.","Exhale and push through your triceps by extending the elbows back to the start position.","To reduce difficulty, place your feet closer to the bench instead of extending the legs."]'::jsonb,
  common_errors_es = '["Alejar el cuerpo del banco al bajar, aumentando el estrés sobre el hombro anterior.","Bajar más allá de los 90° de flexión de codo sin suficiente control, sobrecargando el hombro.","No extender completamente los codos al subir, acortando el rango efectivo.","Levantar los hombros hacia las orejas durante el movimiento."]'::jsonb,
  common_errors_en = '["Letting the body drift away from the bench on the way down, increasing stress on the anterior shoulder.","Descending beyond 90° elbow flexion without sufficient control, overloading the shoulder.","Not fully extending the elbows at the top, shortening the effective range.","Shrugging the shoulders toward the ears during the movement."]'::jsonb,
  pro_tip_es = 'Mantené el torso vertical y la espalda rozando el banco durante todo el movimiento; si el cuerpo se aleja, el foco pasa del tríceps al pectoral inferior y el hombro trabaja en posición desventajosa.',
  pro_tip_en = 'Keep the torso vertical and back grazing the bench throughout; if the body drifts forward, focus shifts from the tricep to the lower pec and the shoulder works at a disadvantaged angle.',
  tertiary_muscles = ARRAY['Serratus Anterior','Coracobrachialis','Core']::text[]
WHERE slug = 'dips-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte o sentáte con una mancuerna en cada mano con las palmas hacia adentro (posición neutra) al inicio.","Al comenzar la flexión, supinás gradualmente la palma para que quede mirando hacia arriba en el punto más alto.","Espirá durante la flexión; inspirá al bajar de forma controlada.","Podés realizar el movimiento de forma alterna (un brazo por vez) o simultánea.","Mantené los codos fijos a los costados del torso durante todo el recorrido."]'::jsonb,
  execution_steps_en = '["Stand or sit holding a dumbbell in each hand with palms facing inward (neutral) at the start.","As you begin the curl, gradually supinate the palm so it faces upward at the top.","Exhale during the curl; inhale as you lower under control.","You can alternate arms (one at a time) or curl simultaneously.","Keep elbows fixed to the sides of your torso throughout."]'::jsonb,
  common_errors_es = '["Oscilar el torso hacia atrás para ayudar a levantar el peso, reduciendo el trabajo del bíceps.","No supinar completamente la palma durante la subida, perdiendo la activación máxima del bíceps.","Extender completamente el codo bajo carga en cada repetición, estresando el tendón distal.","Dejar caer la mancuerna sin control en la bajada, perdiendo el trabajo excéntrico."]'::jsonb,
  common_errors_en = '["Swinging the torso backward to help lift the weight, reducing bicep engagement.","Not fully supinating the palm during the ascent, missing maximum bicep activation.","Fully extending the elbow under load each rep, stressing the distal tendon.","Dropping the dumbbell without control on the way down, losing eccentric work."]'::jsonb,
  pro_tip_es = 'La supinación progresiva durante el curl con mancuerna activa el bíceps en todo su rango funcional; priorizá ese giro de muñeca en cada repetición para aprovechar la ventaja mecánica que la mancuerna ofrece sobre la barra.',
  pro_tip_en = 'The progressive supination during a dumbbell curl activates the bicep through its full functional range; prioritize that wrist rotation on each rep to take advantage of the mechanical benefit dumbbells offer over a bar.',
  tertiary_muscles = ARRAY['Pronator Teres','Brachialis','Core']::text[]
WHERE slug = 'dumbbell-bicep-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco plano y sostenélas mancuernas en agarre neutro (palmas enfrentadas) por encima del pecho.","Juntá las mancuernas o mantenélas muy próximas, con los codos pegados al torso.","Inspirá y bajá las mancuernas controlado hasta la altura del pecho con los codos apuntando hacia los pies.","Espirá y empujá hacia arriba extendiendo los codos, manteniendo las mancuernas juntas.","No permitás que los codos se abran durante el movimiento; el trabajo principal es del tríceps."]'::jsonb,
  execution_steps_en = '["Lie on a flat bench holding dumbbells in a neutral grip (palms facing each other) above your chest.","Press the dumbbells together or keep them very close, elbows pinned to the torso.","Inhale and lower the dumbbells in a controlled manner to chest height, elbows pointing toward your feet.","Exhale and press upward extending the elbows, keeping the dumbbells together.","Do not allow your elbows to flare during the movement; the primary work is on the triceps."]'::jsonb,
  common_errors_es = '["Dejar que los codos se abran hacia los lados, convirtiendo el ejercicio en un press de pecho.","Separar las mancuernas durante el movimiento, perdiendo la tensión interna.","No bajar lo suficiente para obtener un rango de movimiento completo.","Arquear excesivamente la espalda baja durante el empuje."]'::jsonb,
  common_errors_en = '["Allowing the elbows to flare outward, turning it into a chest press.","Separating the dumbbells during the movement, losing internal tension.","Not lowering enough to achieve a full range of motion.","Excessively arching the lower back during the press."]'::jsonb,
  pro_tip_es = 'Presionar las mancuernas entre sí durante todo el movimiento aumenta la activación del pectoral esternal y mantiene los tríceps bajo mayor tensión; es una técnica de intensificación efectiva.',
  pro_tip_en = 'Pressing the dumbbells together throughout the movement increases sternal pectoral activation and keeps the triceps under greater tension; it''s an effective intensification technique.',
  tertiary_muscles = ARRAY['Pectoralis Major','Anterior Deltoid','Serratus Anterior']::text[]
WHERE slug = 'dumbbell-close-grip-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en el borde del banco con los pies bien apoyados y las piernas abiertas.","Apoyá la parte posterior del brazo en la cara interna del muslo del mismo lado, mancuerna colgando.","Espirá y flexioná el codo de forma estricta hasta la contracción máxima del bíceps.","Pausá un instante en la contracción y bajá controlado inspirando sin perder el contacto del brazo con el muslo.","Completá todas las repeticiones de un lado antes de pasar al otro."]'::jsonb,
  execution_steps_en = '["Sit on the edge of the bench with feet flat and legs spread.","Brace the back of your arm against the inner thigh of the same side, dumbbell hanging.","Exhale and strictly flex the elbow to peak bicep contraction.","Pause briefly at the top and lower under control while inhaling without losing arm-thigh contact.","Complete all reps on one side before switching."]'::jsonb,
  common_errors_es = '["Sacar el codo del muslo para aumentar el rango, perdiendo el aislamiento.","Usar el torso oscilante para generar impulso.","No controlar el descenso, perdiendo el trabajo excéntrico del bíceps.","Inclinar el torso lateralmente sobre el brazo de trabajo."]'::jsonb,
  common_errors_en = '["Lifting the elbow off the thigh to increase range, losing the isolation.","Using a swinging torso to generate momentum.","Not controlling the descent, losing eccentric bicep work.","Tilting the torso laterally over the working arm."]'::jsonb,
  pro_tip_es = 'Este ejercicio aísla la cabeza corta del bíceps (el pico) mejor que casi cualquier otro; hacélo al final de la sesión como finalizador con series largas de 12-15 repeticiones.',
  pro_tip_en = 'This exercise isolates the short head of the bicep (the peak) better than almost anything else; perform it at the end of your session as a finisher with longer sets of 12-15 reps.',
  tertiary_muscles = ARRAY['Brachialis','Pronator Teres','Flexor Carpi Radialis']::text[]
WHERE slug = 'dumbbell-concentration-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con una mancuerna en cada mano con las palmas enfrentadas (agarre neutro) y los brazos extendidos.","Mantené los codos pegados a los costados del torso durante todo el movimiento.","Espirá y flexioná los codos subiendo las mancuernas hacia los hombros sin rotar las palmas.","Pausá un instante en la contracción y bajá controlado inspirando.","Podés realizar el movimiento de forma alterna o simultánea según el objetivo."]'::jsonb,
  execution_steps_en = '["Stand holding a dumbbell in each hand with palms facing each other (neutral grip) and arms extended.","Keep your elbows pinned to your sides throughout the movement.","Exhale and flex your elbows, raising the dumbbells toward your shoulders without rotating your palms.","Pause briefly at the top and lower under control while inhaling.","You can alternate arms or curl simultaneously depending on the goal."]'::jsonb,
  common_errors_es = '["Supinar las palmas durante el ascenso, perdiendo el foco en el braquiorradial.","Separar los codos del torso y usarlos como palanca.","Oscilar el torso hacia atrás para ayudar a levantar el peso.","No bajar hasta la extensión controlada del codo."]'::jsonb,
  common_errors_en = '["Supinating the palms during the ascent, losing focus on the brachioradialis.","Flaring the elbows away from the torso and using them as levers.","Swinging the torso backward to help lift the weight.","Not lowering to controlled elbow extension."]'::jsonb,
  pro_tip_es = 'El curl martillo añade grosor al brazo trabajando el braquial y el braquiorradial, que son los responsables del volumen lateral del brazo; incluilo en todas las sesiones de bíceps como complemento del curl en supinación.',
  pro_tip_en = 'The hammer curl adds arm thickness by working the brachialis and brachioradialis, which are responsible for lateral arm volume; include it in every bicep session alongside supinated curls.',
  tertiary_muscles = ARRAY['Biceps Brachii','Flexor Carpi Radialis','Core']::text[]
WHERE slug = 'dumbbell-hammer-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Regulá el banco a 45-60° y recostáte con los brazos colgando hacia abajo a los costados.","Agarrá las mancuernas en supinación con los brazos completamente extendidos, sintiendo el estiramiento de la cabeza larga.","Espirá y flexioná los codos llevando las mancuernas hacia los hombros desde esa posición elongada.","Pausá en la contracción y bajá controlado inspirando hasta la extensión completa.","No muevas la parte superior del brazo hacia adelante; mantená el hombro en posición neutra."]'::jsonb,
  execution_steps_en = '["Set the bench to 45-60° and lie back with arms hanging down at the sides.","Grip the dumbbells with a supinated grip and fully extended arms, feeling the long head stretch.","Exhale and flex the elbows, curling the dumbbells toward your shoulders from that elongated position.","Pause at contraction and lower under control while inhaling to full extension.","Do not bring the upper arm forward; keep the shoulder in a neutral position."]'::jsonb,
  common_errors_es = '["Adelantar la parte superior del brazo para reducir el estiramiento del bíceps al bajar.","Usar un ángulo de banco demasiado vertical, lo que reduce el estiramiento de la cabeza larga.","Rebotar en el punto de máxima extensión para aprovechar el impulso elástico.","Agarrar la mancuerna sin el pulgar en agarre cerrado (seguro)."]'::jsonb,
  common_errors_en = '["Moving the upper arm forward to reduce the bicep stretch on the way down.","Using too vertical a bench angle, which reduces the long head stretch.","Bouncing at the point of maximum extension to use elastic momentum.","Gripping the dumbbell with an open thumb (thumbless grip)."]'::jsonb,
  pro_tip_es = 'La posición inclinada estira la cabeza larga del bíceps al inicio, lo que maximiza el reclutamiento y el pico de tensión mecánica; es una de las variantes más efectivas para el desarrollo de la cabeza larga.',
  pro_tip_en = 'The incline position stretches the long head of the bicep at the start, maximizing recruitment and peak mechanical tension; it''s one of the most effective variations for long head development.',
  tertiary_muscles = ARRAY['Brachialis','Brachioradialis','Posterior Deltoid']::text[]
WHERE slug = 'dumbbell-incline-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en un banco con respaldo o paráte, y sostenéla mancuerna con ambas manos por encima de la cabeza.","Agarrá la paleta superior de la mancuerna con ambas palmas (agarre diamante) con los codos cerca de las orejas.","Inspirá y bajá la mancuerna por detrás de la cabeza flexionando solo los codos hasta donde tu movilidad lo permita.","Espirá y extendé los codos hacia arriba hasta la posición inicial sin mover la parte superior de los brazos.","La posición overhead maximiza el estiramiento y el trabajo de la cabeza larga del tríceps."]'::jsonb,
  execution_steps_en = '["Sit on a bench with back support or stand, holding one dumbbell with both hands overhead.","Grip the top plate of the dumbbell with both palms (diamond grip), elbows close to your ears.","Inhale and lower the dumbbell behind your head by bending only the elbows to the extent your mobility allows.","Exhale and extend the elbows upward back to the start without moving the upper arms.","The overhead position maximizes stretch and work of the tricep''s long head."]'::jsonb,
  common_errors_es = '["Abrir los codos hacia los lados durante la bajada, reduciendo el trabajo de la cabeza larga.","Mover la parte superior del brazo junto con el antebrazo, perdiendo el aislamiento del tríceps.","Descender demasiado rápido sin controlar el punto de máximo estiramiento.","Hiperflejar la espalda lumbar al llevar el peso hacia atrás."]'::jsonb,
  common_errors_en = '["Flaring the elbows outward on the way down, reducing long head involvement.","Moving the upper arm along with the forearm, losing tricep isolation.","Lowering too fast without controlling the point of maximum stretch.","Hyperextending the lower back when bringing the weight backward."]'::jsonb,
  pro_tip_es = 'Para máximo desarrollo de la cabeza larga del tríceps, priorizá este ejercicio: es el único donde el músculo trabaja desde su longitud máxima. Controlá especialmente el excéntrico.',
  pro_tip_en = 'For maximum long head tricep development, prioritize this exercise: it is the only one where the muscle works from its maximum length. Pay special attention to the eccentric.',
  tertiary_muscles = ARRAY['Anconeus','Core','Posterior Deltoid']::text[]
WHERE slug = 'dumbbell-overhead-tricep-extension';
UPDATE public.exercise_library SET
  execution_steps_es = '["Apoyá el brazo en el acolchado del banco predicador con el codo alienado con el eje, la mancuerna colgando.","Agarrá la mancuerna en supinación completa con el codo bien apoyado en el acolchado.","Espirá y flexioná el codo de forma estricta llevando la mancuerna hacia el hombro.","Pausá en la contracción y bajá controlado inspirando hasta casi la extensión completa.","Completá todas las repeticiones de un lado antes de cambiar de brazo."]'::jsonb,
  execution_steps_en = '["Rest your arm on the preacher bench pad with the elbow aligned with the axis, dumbbell hanging.","Grip the dumbbell with full supination, elbow well supported on the pad.","Exhale and strictly flex the elbow, curling the dumbbell toward your shoulder.","Pause at the top and lower under control while inhaling to near full extension.","Complete all reps on one side before switching arms."]'::jsonb,
  common_errors_es = '["Levantar el codo del acolchado durante la subida para ganar recorrido.","Bajar la mancuerna con un golpe en la extensión, sobrecargando el tendón distal del bíceps.","No supinar completamente la palma, perdiendo la activación máxima del bíceps.","Usar un peso excesivo que impide el rango completo de movimiento."]'::jsonb,
  common_errors_en = '["Lifting the elbow off the pad on the way up to gain range.","Dropping the dumbbell suddenly at extension, overloading the distal bicep tendon.","Not fully supinating the palm, missing maximum bicep activation.","Using excessive weight that prevents a full range of motion."]'::jsonb,
  pro_tip_es = 'El banco predicador evita el trampeo eliminando la inercia del torso; es ideal para trabajar la cabeza corta del bíceps con alta tensión en todo el rango. Controlá especialmente el excéntrico.',
  pro_tip_en = 'The preacher bench prevents cheating by eliminating torso momentum; it''s ideal for working the short head of the bicep with high tension throughout the range. Pay special attention to the eccentric.',
  tertiary_muscles = ARRAY['Brachialis','Pronator Teres','Flexor Carpi Radialis']::text[]
WHERE slug = 'dumbbell-preacher-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco plano con las mancuernas sobre el pecho, brazos extendidos verticalmente.","Con los codos apuntando al techo y fijos en esa posición, bajá las mancuernas hacia las sienes flexionando solo los codos.","Descendé de forma controlada hasta que los antebrazos queden paralelos al suelo o levemente más.","Espirá y extendé los codos volviendo a la posición inicial sin mover la parte superior del brazo.","Mantené las mancuernas paralelas entre sí durante todo el movimiento para mayor estabilidad."]'::jsonb,
  execution_steps_en = '["Lie on a flat bench with dumbbells above your chest and arms fully extended vertically.","With elbows pointing toward the ceiling and fixed, lower the dumbbells toward your temples by bending only the elbows.","Descend under control until forearms are parallel to the floor or slightly beyond.","Exhale and extend the elbows back to the start without moving the upper arm.","Keep the dumbbells parallel to each other throughout for greater stability."]'::jsonb,
  common_errors_es = '["Mover la parte superior del brazo junto con el antebrazo, perdiendo el aislamiento del tríceps.","Bajar las mancuernas demasiado rápido sin controlar el punto de máximo estiramiento.","Abrir los codos hacia afuera, reduciendo la eficiencia del movimiento.","Usar un peso que no permite controlar el descenso de forma segura."]'::jsonb,
  common_errors_en = '["Moving the upper arm along with the forearm, losing tricep isolation.","Lowering the dumbbells too fast without controlling the point of maximum stretch.","Flaring the elbows outward, reducing movement efficiency.","Using a weight that does not allow safe control on the way down."]'::jsonb,
  pro_tip_es = 'Las mancuernas permiten mayor rango de movimiento que la barra en este ejercicio al no haber barra que limite el descenso; aprovechá ese rango extra para maximizar el estiramiento del tríceps.',
  pro_tip_en = 'Dumbbells allow a greater range of motion than a barbell in this exercise since there is no bar limiting the descent; use that extra range to maximize the tricep stretch.',
  tertiary_muscles = ARRAY['Anconeus','Anterior Deltoid','Core']::text[]
WHERE slug = 'dumbbell-skull-crusher';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con una mancuerna en cada mano en posición neutra (palmas hacia adentro), brazos extendidos.","Iniciá la flexión de un brazo desde la posición neutra y realizá la supinación gradual de la palma durante el ascenso.","En el punto más alto la palma mira hacia arriba; pausá en la contracción.","Bajá controlado volviendo a la posición neutra mientras extendés el codo inspirando.","Alternás los brazos: mientras uno baja, el otro sube."]'::jsonb,
  execution_steps_en = '["Stand holding a dumbbell in each hand in a neutral position (palms inward), arms extended.","Begin curling one arm from the neutral position and progressively supinate the palm during the ascent.","At the top, the palm faces upward; pause at the contraction.","Lower under control while returning to the neutral position as you extend the elbow and inhale.","Alternate arms: while one lowers, the other rises."]'::jsonb,
  common_errors_es = '["Supinar demasiado temprano (al inicio del movimiento) en vez de hacerlo progresivamente.","No supinar completamente al llegar al punto más alto del movimiento.","No extender del todo el codo al bajar, acortando el rango funcional.","Oscilar el torso para ayudar a completar el movimiento de un lado."]'::jsonb,
  common_errors_en = '["Supinating too early (at the start of the movement) instead of progressively.","Not fully supinating at the top of the movement.","Not fully extending the elbow on the way down, shortening the functional range.","Swinging the torso to assist completing the movement on one side."]'::jsonb,
  pro_tip_es = 'El giro de supinación progresivo durante el curl activa el bíceps en su función de supinador del antebrazo además de la flexión del codo; es la variante más completa para el trabajo del bíceps con mancuernas.',
  pro_tip_en = 'The progressive supination during the curl activates the bicep in its role as forearm supinator in addition to elbow flexion; it''s the most complete dumbbell bicep variation.',
  tertiary_muscles = ARRAY['Brachialis','Brachioradialis','Pronator Teres']::text[]
WHERE slug = 'dumbbell-supination-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Incliná el torso hacia adelante unos 45-60° apoyando la mano libre en un banco para estabilizarte.","Llevá el codo del brazo de trabajo hacia atrás hasta que el brazo quede paralelo al suelo.","Espirá y extendé el antebrazo hacia atrás hasta la extensión completa del codo, contrayendo el tríceps.","Pausá en la extensión y volvé controlado a la posición inicial con el codo fijo.","Completá todas las repeticiones de un lado antes de cambiar."]'::jsonb,
  execution_steps_en = '["Hinge your torso forward 45-60°, resting your free hand on a bench for stability.","Bring the working arm''s elbow back until the upper arm is parallel to the floor.","Exhale and extend the forearm backward to full elbow extension, contracting the tricep.","Pause at extension and return under control to the start with the elbow fixed.","Complete all reps on one side before switching."]'::jsonb,
  common_errors_es = '["No llevar el brazo totalmente paralelo al suelo antes de extender, reduciendo el rango efectivo.","Mover el codo arriba y abajo en vez de fijarlo como pivote.","Usar el hombro o el torso para ayudar a generar el movimiento.","Elegir un peso demasiado alto que impide la extensión completa del codo."]'::jsonb,
  common_errors_en = '["Not bringing the upper arm fully parallel to the floor before extending, reducing effective range.","Moving the elbow up and down instead of fixing it as a pivot.","Using the shoulder or torso to assist in generating the movement.","Choosing too heavy a weight that prevents full elbow extension."]'::jsonb,
  pro_tip_es = 'El kickback trabaja al tríceps en su longitud más corta (máxima contracción); es un ejercicio de acabado más que de masa. Para mayor tensión en la contracción, hacelo en polea en vez de con mancuerna.',
  pro_tip_en = 'The kickback trains the tricep at its shortest length (peak contraction); it''s more of a finishing exercise than a mass builder. For greater tension at contraction, do it on a cable instead.',
  tertiary_muscles = ARRAY['Posterior Deltoid','Anconeus','Core']::text[]
WHERE slug = 'dumbbell-tricep-kickback';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con una mancuerna en cada mano en supinación (palmas hacia arriba) con los brazos extendidos.","Espirá y flexioná los codos curlando las mancuernas hacia los hombros como en un curl clásico.","En el punto más alto rotá las muñecas a pronación (palmas hacia abajo).","Bajá las mancuernas de forma controlada en pronación inspirando hasta la extensión.","Rotá de vuelta a supinación al inicio de la siguiente repetición."]'::jsonb,
  execution_steps_en = '["Stand holding a dumbbell in each hand supinated (palms up), arms extended.","Exhale and flex the elbows, curling the dumbbells toward your shoulders as in a classic curl.","At the top, rotate your wrists to pronation (palms facing down).","Lower the dumbbells under control in the pronated position while inhaling to full extension.","Rotate back to supination at the start of the next rep."]'::jsonb,
  common_errors_es = '["No rotar completamente las muñecas en la parte alta, perdiendo el trabajo de la bajada en pronación.","Bajar en pronación demasiado rápido, sin controlar el trabajo del braquiorradial.","Oscilar el torso para ayudar a subir el peso.","Realizar la rotación de muñeca antes de llegar al punto alto del movimiento."]'::jsonb,
  common_errors_en = '["Not fully rotating the wrists at the top, losing the pronated lowering work.","Lowering too fast in pronation, without controlling the brachioradialis work.","Swinging the torso to help raise the weight.","Rotating the wrist before reaching the top of the movement."]'::jsonb,
  pro_tip_es = 'El curl Zottman es una de las pocas variantes que entrena el bíceps en supinación (subida) y el braquiorradial en pronación (bajada) en el mismo movimiento; es eficiente para el trabajo integral del antebrazo y el brazo.',
  pro_tip_en = 'The Zottman curl is one of the few variations that trains the bicep in supination (going up) and the brachioradialis in pronation (going down) in the same movement; it''s efficient for comprehensive forearm and arm work.',
  tertiary_muscles = ARRAY['Brachialis','Extensor Carpi Radialis','Pronator Teres']::text[]
WHERE slug = 'dumbbell-zottman-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Agarrá la barra EZ en los ángulos internos (semisupinación) con las manos al ancho de los hombros.","Paráte erguido con los codos pegados a los costados del torso.","Espirá y flexioná los codos llevando la barra EZ hacia los hombros en el arco de movimiento.","Pausá en la contracción y bajá controlado inspirando sin llegar a la extensión total bajo carga.","Mantené el torso quieto durante todo el movimiento."]'::jsonb,
  execution_steps_en = '["Grip the EZ bar at the inner angles (semi-supinated) with hands shoulder-width apart.","Stand upright with elbows pinned to your sides.","Exhale and flex the elbows, curling the EZ bar toward your shoulders through the range of motion.","Pause at contraction and lower under control while inhaling, without reaching full extension under load.","Keep the torso still throughout the movement."]'::jsonb,
  common_errors_es = '["Agarrar los ángulos externos de la barra EZ, que reduce la supinación efectiva.","Oscilar el torso hacia atrás para generar impulso.","Extender completamente el codo bajo carga en cada repetición.","Abrir los codos durante el ascenso, perdiendo el pivote fijo."]'::jsonb,
  common_errors_en = '["Gripping the outer EZ bar angles, which reduces effective supination.","Swinging the torso backward to generate momentum.","Fully extending the elbow under load each rep.","Allowing the elbows to flare during the ascent, losing the fixed pivot."]'::jsonb,
  pro_tip_es = 'La barra EZ reduce el estrés en la muñeca respecto a la barra recta y es más cómoda para series largas; es una alternativa válida para quien tenga molestias en la muñeca con barra recta sin sacrificar la activación del bíceps.',
  pro_tip_en = 'The EZ bar reduces wrist stress compared to a straight bar and is more comfortable for longer sets; it''s a valid alternative for those with wrist discomfort without sacrificing bicep activation.',
  tertiary_muscles = ARRAY['Brachioradialis','Brachialis','Pronator Teres']::text[]
WHERE slug = 'ez-bar-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco plano con la barra EZ o recta sostenida verticalmente sobre el pecho con los brazos extendidos.","Inspirá y bajá la barra flexionando solo los codos hacia la frente o la parte superior de la cabeza.","Descendé de forma controlada hasta que los antebrazos queden paralelos al suelo o levemente más abajo.","Espirá y extendé los codos hacia arriba hasta la posición inicial sin mover la parte superior del brazo.","La barra EZ es preferible a la recta por el menor estrés en la muñeca que genera el agarre semisupinado."]'::jsonb,
  execution_steps_en = '["Lie on a flat bench holding the EZ or straight bar vertically above your chest with arms extended.","Inhale and lower the bar by bending only the elbows toward your forehead or upper head.","Descend under control until forearms are parallel to the floor or slightly past.","Exhale and extend the elbows upward back to the start without moving the upper arm.","The EZ bar is preferred over straight bar due to lower wrist stress from the semi-supinated grip."]'::jsonb,
  common_errors_es = '["Mover la parte superior del brazo en vez de fijarla verticalmente.","Bajar la barra demasiado hacia la nariz o la barbilla en vez de hacia la frente/cabeza.","No controlar el excéntrico, dejando caer la barra rápidamente.","Abrir los codos hacia afuera durante el movimiento, reduciendo la eficiencia."]'::jsonb,
  common_errors_en = '["Moving the upper arm instead of keeping it fixed vertically.","Lowering the bar toward the nose or chin instead of the forehead/upper head.","Not controlling the eccentric, allowing the bar to drop quickly.","Flaring the elbows outward during the movement, reducing efficiency."]'::jsonb,
  pro_tip_es = 'En el press francés, los codos tienden a abrirse con el aumento de peso; usá un espejo lateral o pedí a alguien que supervise para mantener los codos paralelos durante toda la serie.',
  pro_tip_en = 'In the French press, elbows tend to flare as weight increases; use a side mirror or ask someone to check that your elbows stay parallel throughout the set.',
  tertiary_muscles = ARRAY['Anconeus','Anterior Deltoid','Core']::text[]
WHERE slug = 'french-press-skull-crusher-bar';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco plano y sostenéla mancuerna con una mano en pronación sobre el pecho, el otro brazo fija el bíceps del brazo de trabajo.","Inspirá y bajá la mancuerna flexionando el codo hacia el hombro contrario (diagonal).","Descendé de forma controlada sintiendo el estiramiento del tríceps.","Espirá y extendé el codo hasta la posición inicial sin mover la parte superior del brazo.","Completá todas las repeticiones de un lado antes de cambiar."]'::jsonb,
  execution_steps_en = '["Lie on a flat bench holding a dumbbell in one hand pronated above your chest, the other hand stabilizing the working arm''s bicep.","Inhale and lower the dumbbell by bending the elbow diagonally toward the opposite shoulder.","Descend under control feeling the tricep stretch.","Exhale and extend the elbow back to the start without moving the upper arm.","Complete all reps on one side before switching."]'::jsonb,
  common_errors_es = '["No estabilizar el brazo de trabajo con la mano libre, perdiendo el control del movimiento.","Bajar la mancuerna hacia el lado en vez de hacia el hombro contrario.","Mover la parte superior del brazo junto con el antebrazo.","Usar un peso excesivo que no permite controlar el descenso."]'::jsonb,
  common_errors_en = '["Not stabilizing the working arm with the free hand, losing movement control.","Lowering the dumbbell to the side instead of toward the opposite shoulder.","Moving the upper arm along with the forearm.","Using excessive weight that does not allow controlled descent."]'::jsonb,
  pro_tip_es = 'La variante unilateral con mancuerna permite mayor rango de movimiento y corrección de asimetrías entre brazos; es especialmente recomendada para aislar la cabeza externa del tríceps.',
  pro_tip_en = 'The unilateral dumbbell variation allows a greater range of motion and correction of arm asymmetries; it is especially recommended for isolating the lateral head of the tricep.',
  tertiary_muscles = ARRAY['Anconeus','Posterior Deltoid','Core']::text[]
WHERE slug = 'french-press-skull-crusher-dumbbell';
UPDATE public.exercise_library SET
  execution_steps_es = '["Regulá la polea a la altura de la cabeza o levemente por encima y agarrá la manija con una mano en supinación.","Paráte lateral o de frente a la polea con el brazo extendido horizontalmente hacia el cable.","Espirá y flexioná el codo llevando la mano hacia la cabeza sin mover la parte superior del brazo.","Pausá en la contracción y extendé controlado inspirando volviendo al punto inicial.","Realizá todas las repeticiones de un lado antes de cambiar."]'::jsonb,
  execution_steps_en = '["Set the pulley to head height or slightly above and grip the handle with one hand in supination.","Stand lateral or facing the pulley with the arm extended horizontally toward the cable.","Exhale and flex the elbow, bringing your hand toward your head without moving the upper arm.","Pause at contraction and extend under control while inhaling back to the start.","Complete all reps on one side before switching."]'::jsonb,
  common_errors_es = '["Dejar caer la parte superior del brazo de la posición horizontal al flexionar.","Usar el hombro para generar impulso al iniciar la flexión.","No controlar el excéntrico, dejando que el cable lleve el brazo a la extensión rápidamente.","Rotar el torso para compensar la falta de fuerza al final de la serie."]'::jsonb,
  common_errors_en = '["Dropping the upper arm from horizontal as you flex.","Using the shoulder to generate momentum at the start of the curl.","Not controlling the eccentric, letting the cable pull the arm to extension rapidly.","Rotating the torso to compensate for lack of strength at the end of the set."]'::jsonb,
  pro_tip_es = 'Esta variante unilateral en polea alta permite mayor rango de concentración y control por brazo; es ideal como finalizador de la sesión de bíceps para corregir asimetrías entre brazos.',
  pro_tip_en = 'This single-arm high cable variation allows greater focus and control per arm; it''s ideal as a bicep session finisher to correct asymmetries between arms.',
  tertiary_muscles = ARRAY['Brachialis','Anterior Deltoid','Core']::text[]
WHERE slug = 'high-cable-curl-single-arm';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco a 45-60° y recostáte con los brazos colgando a los costados con las mancuernas en posición neutra.","Iniciá la flexión de un brazo desde la posición neutra y supinás la palma durante el ascenso.","Subí la mancuerna pegada al abdomen mientras rotás; abrí el giro y bajá con ligera rotación externa.","Alternás los brazos: mientras uno sube, el otro baja en posición neutra.","Inspirá al bajar, espirá al subir; no pierdas el contacto del respaldo con el banco."]'::jsonb,
  execution_steps_en = '["Adjust the bench to 45-60° and lie back with arms hanging at your sides, dumbbells in neutral position.","Begin curling one arm from neutral and supinate the palm during the ascent.","Raise the dumbbell close to the abdomen while rotating; open the turn and lower with slight external rotation.","Alternate arms: as one rises, the other lowers in neutral.","Inhale on the way down, exhale on the way up; do not lose contact between your back and the bench."]'::jsonb,
  common_errors_es = '["Adelantar los hombros para reducir el estiramiento al bajar.","No supinar completamente durante el ascenso.","Usar un ángulo de banco demasiado vertical que reduce el beneficio del estiramiento.","Rebotar la mancuerna en el punto de máxima extensión."]'::jsonb,
  common_errors_en = '["Rolling the shoulders forward to reduce the stretch on the way down.","Not fully supinating during the ascent.","Using too steep a bench angle that reduces the stretch benefit.","Bouncing the dumbbell at the point of maximum extension."]'::jsonb,
  pro_tip_es = 'El curl inclinado con mancuerna combina el estiramiento de la cabeza larga y la supinación progresiva; es ideal para una sesión en la que buscás trabajo integral del bíceps con una sola variante.',
  pro_tip_en = 'The incline dumbbell curl combines long head stretch with progressive supination; it''s ideal for a session where you want comprehensive bicep work from a single variation.',
  tertiary_muscles = ARRAY['Brachialis','Brachioradialis','Posterior Deltoid']::text[]
WHERE slug = 'incline-dumbbell-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Posicionáte de espaldas a la polea alta y sujetá el agarre (cuerda o barra) con ambas manos detrás del torso.","Con los pies ligeramente abiertos y paralelos, bloqueá el torso activando el core.","Espirá y extendé los codos hacia abajo y por detrás del cuerpo hasta la extensión completa.","Pausá en la extensión y subí controlado inspirando hasta volver a la posición inicial con codos a 90°.","Mantené la parte superior del brazo fija durante todo el movimiento."]'::jsonb,
  execution_steps_en = '["Position yourself facing away from the high pulley and grip the attachment (rope or bar) with both hands behind your torso.","With feet slightly open and parallel, brace your torso by engaging the core.","Exhale and extend the elbows downward and behind your body to full extension.","Pause at extension and raise under control while inhaling back to the start with elbows at 90°.","Keep the upper arm fixed throughout the entire movement."]'::jsonb,
  common_errors_es = '["Abrir los codos al extender, perdiendo el foco en el tríceps.","Mover la parte superior del brazo en la dirección del movimiento.","Hiperflejar la espalda lumbar al inclinarse bajo el tirón del cable.","No llegar a la extensión completa del codo en cada repetición."]'::jsonb,
  common_errors_en = '["Flaring the elbows during extension, losing tricep focus.","Moving the upper arm in the direction of the movement.","Hyperextending the lower back while leaning under cable pull.","Not reaching full elbow extension on each rep."]'::jsonb,
  pro_tip_es = 'Esta variante en polea alta de espaldas trabaja el tríceps en una posición funcional de extensión; aseguráte de que el agarre esté cómodo para tus muñecas antes de aumentar la carga.',
  pro_tip_en = 'This rear-facing high cable variation trains the tricep in a functional extension position; make sure the grip is comfortable for your wrists before increasing load.',
  tertiary_muscles = ARRAY['Anconeus','Posterior Deltoid','Core']::text[]
WHERE slug = 'overhead-cable-tricep-extension';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte o sentáte con una mancuerna sostenida con ambas manos por encima de la cabeza en agarre diamante.","Con los codos cerca de las orejas, inspirá y bajá la mancuerna por detrás de la cabeza flexionando solo los codos.","Descendé de forma controlada hasta donde tu movilidad lo permita sin forzar los hombros.","Espirá y extendé los codos hacia arriba hasta la posición inicial sin mover la parte superior de los brazos.","Mantené los codos paralelos entre sí durante todo el recorrido."]'::jsonb,
  execution_steps_en = '["Stand or sit holding one dumbbell with both hands overhead in a diamond grip.","With elbows close to your ears, inhale and lower the dumbbell behind your head by bending only the elbows.","Descend under control to the extent your mobility allows without forcing the shoulders.","Exhale and extend the elbows upward to the start position without moving the upper arms.","Keep the elbows parallel throughout the entire movement."]'::jsonb,
  common_errors_es = '["Abrir los codos hacia los lados al bajar, reduciendo el trabajo de la cabeza larga.","Mover la parte superior del brazo junto al antebrazo, perdiendo el aislamiento.","Descender más allá del rango disponible de movilidad del hombro, generando molestia.","Hiperflejar la espalda lumbar en la posición sentada."]'::jsonb,
  common_errors_en = '["Flaring the elbows outward on the way down, reducing long head involvement.","Moving the upper arm along with the forearm, losing isolation.","Descending past available shoulder mobility range, causing discomfort.","Hyperextending the lower back in the seated position."]'::jsonb,
  pro_tip_es = 'La extensión overhead con mancuerna a dos manos es más estable que la variante unilateral; comenzá con esta variante si estás aprendiendo el patrón de movimiento antes de progresar a versiones más desafiantes.',
  pro_tip_en = 'The two-handed overhead dumbbell extension is more stable than the unilateral version; start with this variation when learning the movement pattern before progressing to more challenging versions.',
  tertiary_muscles = ARRAY['Anconeus','Core','Serratus Anterior']::text[]
WHERE slug = 'overhead-tricep-extension-dumbbell';
UPDATE public.exercise_library SET
  execution_steps_es = '["Regulá el asiento para que los codos queden alineados con el eje de rotación de la máquina.","Apoyá los brazos en el acolchado y agarrá las manijas en supinación.","Espirá y flexioná los codos llevando las manijas hacia los hombros de forma estricta.","Pausá en la contracción y bajá controlado inspirando hasta casi la extensión completa.","La máquina elimina la posibilidad de trampa y permite concentrarse en la contracción del bíceps."]'::jsonb,
  execution_steps_en = '["Adjust the seat so your elbows align with the machine''s rotation axis.","Rest your arms on the pad and grip the handles with a supinated grip.","Exhale and flex the elbows, bringing the handles toward your shoulders in a strict fashion.","Pause at contraction and lower under control while inhaling to near full extension.","The machine eliminates cheating and allows focus on the bicep contraction."]'::jsonb,
  common_errors_es = '["Levantar los codos del acolchado para ganar rango de movimiento.","Usar el impulso para iniciar el movimiento en vez de activar el bíceps desde el inicio.","Bajar el peso bruscamente sin controlar el excéntrico.","No ajustar el asiento correctamente, desalineando el codo con el eje de la máquina."]'::jsonb,
  common_errors_en = '["Lifting the elbows off the pad to gain range of motion.","Using momentum to initiate the movement instead of activating the bicep from the start.","Dropping the weight abruptly without controlling the eccentric.","Not adjusting the seat correctly, misaligning the elbow with the machine axis."]'::jsonb,
  pro_tip_es = 'La máquina predicador es ideal para principiantes porque enseña el patrón de movimiento correcto del curl sin posibilidad de trampa; también es útil para trabajo de alta repetición al final de la sesión.',
  pro_tip_en = 'The preacher machine is ideal for beginners because it teaches the correct curl movement pattern with no cheating possible; it''s also useful for high-rep work at the end of a session.',
  tertiary_muscles = ARRAY['Brachialis','Pronator Teres','Flexor Carpi Radialis']::text[]
WHERE slug = 'preacher-curl-machine-bicep-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Apoyá los brazos en el acolchado del banco Scott con los codos al ancho de los hombros y las manos más allá del borde.","Agarrá la barra (recta o EZ) en supinación con los brazos casi extendidos.","Espirá y flexioná los codos de forma estricta llevando la barra hacia los hombros.","Pausá en la contracción y bajá controlado inspirando hasta casi la extensión completa.","La variante unilateral con mancuerna permite corregir asimetrías entre brazos."]'::jsonb,
  execution_steps_en = '["Rest your arms on the Scott bench pad with elbows shoulder-width apart and hands beyond the edge.","Grip the bar (straight or EZ) supinated with arms nearly extended.","Exhale and strictly flex the elbows, curling the bar toward your shoulders.","Pause at contraction and lower under control while inhaling to near full extension.","The unilateral dumbbell variation allows correction of arm asymmetries."]'::jsonb,
  common_errors_es = '["Levantar los codos del acolchado durante la subida, perdiendo el beneficio del banco predicador.","Dejar caer la barra bruscamente al bajar, sobrecargando el tendón distal del bíceps.","Usar un agarre demasiado ancho que reduce la supinación y la activación del bíceps.","Arquear el torso hacia adelante para ayudar al final de la serie."]'::jsonb,
  common_errors_en = '["Lifting the elbows off the pad on the way up, losing the preacher bench benefit.","Dropping the bar abruptly on the way down, stressing the distal bicep tendon.","Using too wide a grip that reduces supination and bicep activation.","Arching the torso forward to assist at the end of the set."]'::jsonb,
  pro_tip_es = 'El banco Scott fuerza el trabajo del bíceps en elongación (al inicio) con el brazo delante del eje del cuerpo; es especialmente efectivo para la cabeza corta del bíceps y para eliminar el trampeo.',
  pro_tip_en = 'The Scott bench forces bicep work in elongation (at the start) with the arm in front of the body''s axis; it''s especially effective for the short head of the bicep and for eliminating cheating.',
  tertiary_muscles = ARRAY['Brachialis','Pronator Teres','Flexor Carpi Radialis']::text[]
WHERE slug = 'preacher-curl-scott-bench';
UPDATE public.exercise_library SET
  execution_steps_es = '["Apoyá las manos en el suelo a la anchura de los hombros con los dedos hacia adelante y las piernas extendidas.","Mantenéun cuerpo rígido como una tabla desde los talones hasta la cabeza activando el core.","Inspirá y bajá el pecho hacia el suelo flexionando los codos hacia atrás (cerca del torso).","Descendé hasta que el pecho quede a pocos centímetros del suelo y empujá de vuelta espirando.","Para mayor trabajo de tríceps, juntá las manos para que los pulgares casi se toquen en el centro."]'::jsonb,
  execution_steps_en = '["Place your hands on the floor shoulder-width apart with fingers forward and legs extended.","Maintain a rigid plank-like body from heels to head by engaging the core.","Inhale and lower your chest toward the floor by bending the elbows backward (close to the torso).","Descend until your chest is a few centimeters from the floor, then push back up while exhaling.","For greater tricep work, bring your hands together so thumbs nearly touch in the center."]'::jsonb,
  common_errors_es = '["Dejar caer las caderas hacia el suelo, perdiendo la posición de tabla.","Abrir los codos en exceso hacia los lados, transfiriendo el trabajo al pectoral.","No bajar lo suficiente para obtener el rango completo de movimiento.","Empujar desde el cuello adelantando la cabeza en vez de mover el pecho."]'::jsonb,
  common_errors_en = '["Dropping the hips toward the floor, losing the plank position.","Flaring the elbows too far to the sides, transferring work to the pectoral.","Not lowering enough to achieve the full range of motion.","Pushing from the neck by jutting the head forward instead of moving the chest."]'::jsonb,
  pro_tip_es = 'La variante con manos juntas (pulgares casi tocándose) aumenta significativamente el trabajo del tríceps respecto a la flexión estándar; es una alternativa efectiva sin necesidad de equipamiento.',
  pro_tip_en = 'The close-hands variation (thumbs nearly touching) significantly increases tricep work compared to standard push-ups; it''s an effective equipment-free alternative.',
  tertiary_muscles = ARRAY['Serratus Anterior','Core','Coracobrachialis']::text[]
WHERE slug = 'push-ups-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Agarrá la barra en pronación (palmas hacia abajo) con las manos al ancho de los hombros.","Paráte erguido con los codos pegados a los costados del torso.","Espirá y flexioná los codos llevando la barra hacia los hombros manteniendo la pronación.","Pausá en la contracción y bajá controlado inspirando.","El movimiento es el mismo que el curl clásico pero con el dorso de la mano mirando hacia arriba."]'::jsonb,
  execution_steps_en = '["Grip the bar with a pronated grip (palms facing down), hands shoulder-width apart.","Stand upright with elbows pinned to your sides.","Exhale and flex the elbows, curling the bar toward your shoulders while maintaining pronation.","Pause at contraction and lower under control while inhaling.","The movement mirrors the classic curl but with the back of the hand facing upward."]'::jsonb,
  common_errors_es = '["Supinar las muñecas durante el ascenso, perdiendo el enfoque en el braquial y braquiorradial.","Oscilar el torso para ayudar a levantar la barra.","Doblar las muñecas hacia abajo bajo la barra al llegar al punto alto.","Usar un peso excesivo para este patrón, que permite menos carga que el curl en supinación."]'::jsonb,
  common_errors_en = '["Supinating the wrists during the ascent, losing focus on the brachialis and brachioradialis.","Swinging the torso to help lift the bar.","Bending the wrists downward under the bar at the top.","Using excessive weight for this pattern, which tolerates less load than supinated curls."]'::jsonb,
  pro_tip_es = 'El curl en pronación (reverse curl) es fundamentalmente un ejercicio de antebrazo y braquial más que de bíceps; incluilo como complemento para desarrollar el grosor del brazo desde ángulos menos trabajados.',
  pro_tip_en = 'The reverse curl is fundamentally a forearm and brachialis exercise more than a bicep exercise; include it as a complement to develop arm thickness from less-trained angles.',
  tertiary_muscles = ARRAY['Biceps Brachii','Extensor Carpi Radialis','Extensor Digitorum']::text[]
WHERE slug = 'reverse-curl-pronated';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en un banco con los antebrazos apoyados en los muslos y las muñecas más allá del borde de las rodillas, palmas hacia abajo.","Agarrá las mancuernas en pronación con un agarre firme.","Dejá caer las manos hacia abajo (flexión palmar) de forma controlada.","Espirá y extendé las muñecas hacia arriba (extensión dorsal) hasta el rango disponible.","Bajá controlado inspirando; el movimiento es de poca amplitud pero de alta especificidad."]'::jsonb,
  execution_steps_en = '["Sit on a bench with forearms resting on your thighs and wrists beyond the knee edge, palms facing down.","Grip the dumbbells pronated with a firm hold.","Allow the hands to drop downward (palmar flexion) in a controlled manner.","Exhale and extend the wrists upward (dorsal extension) to the available range.","Lower under control while inhaling; the movement has a small amplitude but high specificity."]'::jsonb,
  common_errors_es = '["Mover el antebrazo en vez de solo la muñeca.","Usar un peso demasiado alto que limite el rango de extensión.","No controlar el descenso, dejando caer la mancuerna sin resistencia.","Realizar el movimiento con las muñecas dentro del borde de la rodilla, eliminando el rango."]'::jsonb,
  common_errors_en = '["Moving the forearm instead of only the wrist.","Using a weight too heavy that limits extension range.","Not controlling the descent, dropping the dumbbell without resistance.","Performing the movement with wrists inside the knee edge, eliminating range."]'::jsonb,
  pro_tip_es = 'La extensión de muñeca en pronación trabaja los extensores del carpo, que son los músculos del antebrazo opuestos a los que trabajan en el wrist curl clásico; incluí ambas variantes para un desarrollo equilibrado del antebrazo.',
  pro_tip_en = 'The pronated wrist extension works the carpal extensors, the forearm muscles opposite to those worked in the classic wrist curl; include both variations for balanced forearm development.',
  tertiary_muscles = ARRAY['Extensor Carpi Ulnaris','Extensor Digitorum','Anconeus']::text[]
WHERE slug = 'reverse-wrist-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sujetá el palo del enrollador con ambas manos en pronación, brazos extendidos al frente a la altura de los hombros.","Enrollá la cuerda girando alternativamente las muñecas hacia adelante (extensión dorsal) para subir el peso.","Una vez el peso llegue al tope, desenrollá con control girando en sentido contrario.","Mantené los brazos extendidos al frente durante todo el ejercicio sin doblarlos.","Realizá el movimiento de forma lenta y controlada, sin acelerones."]'::jsonb,
  execution_steps_en = '["Hold the roller bar with both hands pronated, arms extended forward at shoulder height.","Roll the rope by alternately extending the wrists forward (dorsal extension) to raise the weight.","Once the weight reaches the top, unroll under control by rotating in the opposite direction.","Keep the arms extended in front throughout without bending them.","Perform the movement slowly and controlled, without sudden bursts."]'::jsonb,
  common_errors_es = '["Doblar los codos durante el ejercicio, reduciendo el trabajo de los antebrazos.","Bajar los brazos de la posición horizontal para descansar.","Realizar el movimiento demasiado rápido sin controlar la fase de bajada.","No llegar hasta el punto máximo de enrollado antes de bajar el peso."]'::jsonb,
  common_errors_en = '["Bending the elbows during the exercise, reducing forearm work.","Dropping the arms from the horizontal position to rest.","Performing the movement too fast without controlling the lowering phase.","Not reaching full roll before lowering the weight."]'::jsonb,
  pro_tip_es = 'El enrollamiento de cuerda es uno de los ejercicios más efectivos para el desarrollo funcional del antebrazo; variá la dirección del giro (palmar para subir y dorsal para subir) en diferentes series para trabajar tanto flexores como extensores.',
  pro_tip_en = 'Rope wrist rolling is one of the most effective exercises for functional forearm development; vary the rolling direction (palmar up or dorsal up) across different sets to work both flexors and extensors.',
  tertiary_muscles = ARRAY['Extensor Carpi Radialis','Flexor Digitorum','Brachioradialis']::text[]
WHERE slug = 'rope-wrist-roll';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte delante de un escalón o banco estable de altura adecuada.","Apoyá un pie completo sobre el escalón y empujá con ese talón para subir el cuerpo.","Traé el otro pie arriba hasta pararte completamente erguido sobre el escalón.","Bajá controlado con el mismo pie que subiste primero y volvé a la posición inicial.","Completá todas las repeticiones de un lado antes de cambiar o alternás de forma continua."]'::jsonb,
  execution_steps_en = '["Stand in front of a stable step or bench of appropriate height.","Place one full foot on the step and drive through that heel to raise your body.","Bring the other foot up until you are standing fully upright on the step.","Lower under control with the same foot that led the ascent back to the start.","Complete all reps on one side before switching, or alternate continuously."]'::jsonb,
  common_errors_es = '["Empujar con el pie del suelo en vez de trabajar con la pierna sobre el escalón.","Inclinarte hacia adelante en exceso, poniendo más carga sobre la espalda baja.","Usar un escalón demasiado alto para tu nivel actual de fuerza y movilidad.","No apoyar el pie completo sobre el escalón, reduciendo la base de apoyo."]'::jsonb,
  common_errors_en = '["Pushing off the floor foot instead of working with the leg on the step.","Leaning forward excessively, placing more load on the lower back.","Using a step too tall for your current strength and mobility level.","Not placing the full foot on the step, reducing the base of support."]'::jsonb,
  pro_tip_es = 'Aunque catalogado en Arms por el equipamiento, el step-up es primariamente un ejercicio de piernas; enfocáte en presionar el talón del pie elevado para maximizar el trabajo del glúteo y cuádriceps.',
  pro_tip_en = 'Although listed under Arms by equipment, the step-up is primarily a lower-body exercise; focus on pressing through the heel of the elevated foot to maximize glute and quad engagement.',
  tertiary_muscles = ARRAY['Core','Erector Spinae','Tibialis Anterior']::text[]
WHERE slug = 'step-up';
UPDATE public.exercise_library SET
  execution_steps_es = '["Regulá el asiento para que los codos queden alineados con el eje de la máquina al apoyar los brazos.","Agarrá las manijas en agarre neutro con los codos bien apoyados en el acolchado.","Espirá y extendé los codos empujando hacia abajo (o hacia adelante según la máquina) hasta casi la extensión completa.","Pausá en la contracción y volvé controlado inspirando a la posición inicial.","No bloquees los codos en la extensión; dejá un leve ángulo de seguridad."]'::jsonb,
  execution_steps_en = '["Adjust the seat so your elbows align with the machine axis when arms rest on the pad.","Grip the handles in a neutral grip with elbows well supported on the pad.","Exhale and extend the elbows by pushing downward (or forward depending on the machine) to near full extension.","Pause at contraction and return under control while inhaling to the start position.","Do not fully lock the elbows at extension; keep a slight safety angle."]'::jsonb,
  common_errors_es = '["Desalinear los codos del eje de la máquina, alterando la curva de resistencia.","Levantar los hombros durante la extensión, usando el deltoides anterior.","Bloquear los codos en extensión completa con carga, sobrecargando la articulación.","No ajustar el asiento a la altura correcta antes de cargar el peso."]'::jsonb,
  common_errors_en = '["Misaligning the elbows from the machine axis, altering the resistance curve.","Shrugging the shoulders during extension, recruiting the anterior deltoid.","Locking the elbows at full extension under load, overloading the joint.","Not adjusting the seat to the correct height before loading weight."]'::jsonb,
  pro_tip_es = 'La máquina de extensión de tríceps es ideal para principiantes porque guía el movimiento y elimina la necesidad de estabilización; usala al principio del aprendizaje antes de progresar a versiones libres.',
  pro_tip_en = 'The tricep extension machine is ideal for beginners because it guides the movement and eliminates the need for stabilization; use it early in learning before progressing to free-weight versions.',
  tertiary_muscles = ARRAY['Anconeus','Flexor Carpi Radialis','Core']::text[]
WHERE slug = 'tricep-extension-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina similar a un banco Scott para tríceps y apoyá los brazos en el acolchado con los codos más allá del borde.","Agarrá las manijas en agarre neutro con los codos alineados con el eje de la máquina.","Espirá y extendé los codos hasta casi la extensión completa siguiendo el arco de la máquina.","Pausá en la contracción y volvé controlado inspirando hasta la posición inicial.","El diseño de la máquina guía el movimiento y elimina la posibilidad de compensar con otros músculos."]'::jsonb,
  execution_steps_en = '["Sit in the Scott-style tricep machine and rest your arms on the pad with elbows beyond the edge.","Grip the handles in a neutral grip with elbows aligned with the machine axis.","Exhale and extend the elbows to near full extension following the machine''s arc.","Pause at contraction and return under control while inhaling to the start.","The machine''s design guides the movement and eliminates the ability to compensate with other muscles."]'::jsonb,
  common_errors_es = '["Levantar los codos del acolchado durante la extensión.","No alinear correctamente los codos con el eje de rotación de la máquina.","Usar los hombros para ayudar a completar el movimiento al final de la serie.","No controlar el retorno del peso, dejando que el tríceps se relaje abruptamente."]'::jsonb,
  common_errors_en = '["Lifting the elbows off the pad during the extension.","Not correctly aligning the elbows with the machine''s rotation axis.","Using the shoulders to help complete the movement at the end of the set.","Not controlling the weight return, allowing the tricep to relax abruptly."]'::jsonb,
  pro_tip_es = 'Esta variante guiada es especialmente útil al final de la sesión cuando el tríceps está fatigado; la guía mecánica permite seguir reclutando fibras de forma segura con técnica comprometida.',
  pro_tip_en = 'This guided variation is especially useful at the end of a session when the tricep is fatigued; the mechanical guide allows continued safe fiber recruitment even with compromised technique.',
  tertiary_muscles = ARRAY['Anconeus','Posterior Deltoid','Core']::text[]
WHERE slug = 'tricep-extension-machine-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Incliná el torso hacia adelante unos 45-60° apoyando la mano libre en un banco.","Llevá el codo del brazo de trabajo hacia atrás hasta que el brazo quede paralelo al suelo.","Espirá y extendé el antebrazo hacia atrás hasta la extensión completa del codo.","Pausá en la extensión y volvé controlado a la posición inicial inspirando.","Podés variar el agarre entre neutro y pronación según el objetivo; en pronación se afirma mayor cabeza interna."]'::jsonb,
  execution_steps_en = '["Hinge your torso forward 45-60°, resting your free hand on a bench.","Bring the working arm''s elbow back until the upper arm is parallel to the floor.","Exhale and extend the forearm backward to full elbow extension.","Pause at extension and return under control to the start while inhaling.","You can vary grip between neutral and pronated; pronated grip is claimed to increase medial head work."]'::jsonb,
  common_errors_es = '["No llevar el brazo totalmente paralelo al suelo antes de extender.","Mover el codo como palanca en vez de fijarlo como pivote.","Usar un peso que no permite la extensión completa del codo.","Rotar el torso para compensar la falta de fuerza al final de la serie."]'::jsonb,
  common_errors_en = '["Not bringing the upper arm fully parallel to the floor before extending.","Moving the elbow as a lever instead of fixing it as a pivot.","Using a weight that prevents full elbow extension.","Rotating the torso to compensate for lack of strength at the end of the set."]'::jsonb,
  pro_tip_es = 'El kickback tiene mayor eficiencia mecánica al final del movimiento (extensión completa); hacélo despacio en el excéntrico para maximizar el tiempo bajo tensión en el rango de máxima contracción.',
  pro_tip_en = 'The kickback has greater mechanical efficiency at the end of the movement (full extension); do the eccentric slowly to maximize time under tension in the peak contraction range.',
  tertiary_muscles = ARRAY['Anconeus','Posterior Deltoid','Core']::text[]
WHERE slug = 'tricep-kickback';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina de press horizontal y regulá el asiento para que las manijas queden a la altura del pecho.","Agarrá en agarre cerrado con los codos pegados al cuerpo y los pulgares hacia arriba.","Inspirá, tensá el core, y espirá mientras empujás las manijas hacia adelante extendiendo los codos.","Detené el movimiento antes del bloqueo completo de los codos y volvé controlado a la posición inicial.","Mantené los codos cerca del torso durante todo el movimiento para maximizar el trabajo del tríceps."]'::jsonb,
  execution_steps_en = '["Sit in the horizontal press machine and adjust the seat so the handles are at chest height.","Grip close with elbows near the body and thumbs facing up.","Inhale, brace the core, and exhale while pressing the handles forward by extending the elbows.","Stop before full elbow lockout and return under control to the start position.","Keep the elbows close to your torso throughout to maximize tricep involvement."]'::jsonb,
  common_errors_es = '["Abrir los codos durante el press, incorporando el pectoral y el deltoides anterior.","Bloquear los codos completamente en la extensión bajo carga.","Usar el cuerpo para generar impulso inicial en vez de activar el tríceps desde el inicio.","No regular el asiento correctamente, afectando la alineación de los codos."]'::jsonb,
  common_errors_en = '["Flaring the elbows during the press, involving the pectoral and anterior deltoid.","Fully locking the elbows at extension under load.","Using body momentum to initiate instead of activating the tricep from the start.","Not adjusting the seat correctly, affecting elbow alignment."]'::jsonb,
  pro_tip_es = 'El press de tríceps en máquina es más seguro que el press libre con agarre cerrado porque guía el movimiento; úsalo como complemento cuando busques volumen en el tríceps sin el riesgo de balanceo de la barra.',
  pro_tip_en = 'The machine tricep press is safer than a free close-grip press because it guides the movement; use it as a complement when targeting tricep volume without the bar stability risk.',
  tertiary_muscles = ARRAY['Pectoralis Major','Anterior Deltoid','Serratus Anterior']::text[]
WHERE slug = 'tricep-press-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en un banco con los antebrazos apoyados en los muslos y las muñecas en el borde de las rodillas, palmas hacia arriba.","Agarrá la barra en supinación; dejá que la barra ruede hasta la punta de los dedos abriendo levemente la mano.","Espirá y flexioná primero los dedos cerrando la mano y luego las muñecas hacia arriba hasta el rango máximo.","Bajá controlado inspirando volviendo a la posición de extensión sobre los dedos.","Usá un peso que permita un rango completo de movimiento; el ejercicio tiene poca amplitud."]'::jsonb,
  execution_steps_en = '["Sit on a bench with forearms resting on your thighs and wrists at the knee edge, palms facing up.","Grip the bar supinated; let it roll to the fingertips by slightly opening the hand.","Exhale and first flex the fingers to close the hand, then flex the wrists upward to full range.","Lower under control while inhaling back to the fingertip extension position.","Use a weight that allows full range; the exercise has a small amplitude."]'::jsonb,
  common_errors_es = '["Mover el antebrazo en vez de solo la muñeca y los dedos.","Usar un peso tan alto que impide el rango completo de flexión de muñeca.","No controlar el descenso, dejando caer la barra sin resistencia.","Realizar el movimiento con las muñecas dentro del borde de la rodilla, eliminando el rango."]'::jsonb,
  common_errors_en = '["Moving the forearm instead of only the wrist and fingers.","Using a weight so heavy it prevents full wrist flexion range.","Not controlling the descent, dropping the bar without resistance.","Performing with wrists inside the knee edge, eliminating range."]'::jsonb,
  pro_tip_es = 'Incluir la extensión hasta la punta de los dedos y el cierre de la mano al inicio añade trabajo a los flexores de los dedos además del carpo; usá esa variante completa para un desarrollo integral del antebrazo.',
  pro_tip_en = 'Including the extension to fingertips and hand closing at the start adds work to the finger flexors in addition to the wrist; use that full variation for comprehensive forearm development.',
  tertiary_muscles = ARRAY['Flexor Digitorum Profundus','Flexor Pollicis Longus','Palmaris Longus']::text[]
WHERE slug = 'wrist-curl-barbell';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte o paráte sosteniendo una mancuerna liviana con el pulgar apuntando hacia arriba (agarre neutro).","Con el antebrazo apoyado o sujeto, dejá caer la mano hacia el lado cubital (hacia el meñique) de forma controlada.","Espirá y elevá la mano hacia el lado radial (hacia el pulgar) hasta el rango máximo disponible.","Bajá controlado inspirando; el movimiento es de poca amplitud y requiere peso liviano.","La variante en decúbito permite mayor rango al trabajar contra la gravedad en otra dirección."]'::jsonb,
  execution_steps_en = '["Sit or stand holding a light dumbbell with the thumb pointing upward (neutral grip).","With the forearm supported or held, allow the hand to drop toward the ulnar side (pinky side) in a controlled manner.","Exhale and raise the hand toward the radial side (thumb side) to the available maximum range.","Lower under control while inhaling; the movement has small amplitude and requires light weight.","The lying variation allows greater range by working against gravity from a different angle."]'::jsonb,
  common_errors_es = '["Mover el antebrazo o el codo en vez de solo la muñeca.","Usar un peso excesivo para este movimiento de poca amplitud.","No controlar el descenso hacia el lado cubital.","Realizar el movimiento demasiado rápido, perdiendo el trabajo de los músculos pequeños del antebrazo."]'::jsonb,
  common_errors_en = '["Moving the forearm or elbow instead of only the wrist.","Using excessive weight for this small-range movement.","Not controlling the descent toward the ulnar side.","Performing the movement too fast, losing the small forearm muscle work."]'::jsonb,
  pro_tip_es = 'La flexión radial de muñeca trabaja músculos pequeños del antebrazo (extensor largo radial y separador largo del pulgar) que raramente se trabajan en los ejercicios compuestos; incluílo como trabajo preventivo y complementario.',
  pro_tip_en = 'Wrist radial flexion works small forearm muscles (extensor carpi radialis longus and abductor pollicis longus) rarely challenged in compound exercises; include it as preventive and supplementary work.',
  tertiary_muscles = ARRAY['Extensor Pollicis Longus','Flexor Carpi Radialis','Brachioradialis']::text[]
WHERE slug = 'wrist-radial-flexion';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el peso de asistencia en la máquina: cuanto más alto, menor resistencia de tu propio cuerpo.","Arrodilláte o subí a la plataforma asistida y agarrá la barra con un agarre pronado (palmas al frente) al ancho de hombros.","Inspirá, apretá el core y tirá los codos hacia abajo y atrás para subir el cuerpo hasta que el mentón supere la barra.","Pausá brevemente arriba y espirá mientras bajás de forma controlada hasta la extensión completa de brazos.","Mantené el pecho levemente elevado en todo el recorrido; evitá balancear el torso."]'::jsonb,
  execution_steps_en = '["Set the assistance weight: the higher the weight, the lower the resistance from your own body.","Kneel or stand on the assisted platform and grip the bar with a pronated (palms-forward) shoulder-width grip.","Inhale, brace your core, and drive your elbows down and back to pull your body up until your chin clears the bar.","Pause briefly at the top, then exhale as you lower in a controlled manner to full arm extension.","Keep your chest slightly elevated throughout; avoid swinging the torso."]'::jsonb,
  common_errors_es = '["Usar demasiada asistencia y no progresar hacia la dominada libre.","Dejar que los hombros suban hacia las orejas en lugar de deprimirlos al inicio del tirón.","Bajar demasiado rápido sin controlar la fase excéntrica.","Balancear las rodillas para generar impulso."]'::jsonb,
  common_errors_en = '["Using too much assistance and failing to progress toward unassisted pull-ups.","Letting the shoulders shrug toward the ears instead of depressing them at the start of the pull.","Lowering too quickly without controlling the eccentric phase.","Swinging the knees to generate momentum."]'::jsonb,
  pro_tip_es = 'Deprimí los omóplatos (bajálos) antes de doblar los codos: eso activa el dorsal desde el inicio y protege el hombro.',
  pro_tip_en = 'Depress your shoulder blades (pull them down) before bending your elbows: this activates the lats from the start and protects the shoulder.',
  tertiary_muscles = ARRAY['Rhomboids','Infraspinatus','Serratus Anterior']::text[]
WHERE slug = 'assisted-pull-up-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Seleccioná el agarre neutro (palmas enfrentadas) o supinado si la máquina lo permite, con manos separadas al ancho de hombros.","Ajustá la asistencia y ubicáte en la plataforma con el cuerpo erguido.","Inspirá, deprimí los omóplatos y tirá los codos hacia las caderas para subir el cuerpo.","Subí hasta que el mentón quede a la altura de las manos; pausá un instante.","Espirá y bajá lentamente hasta la extensión completa de los brazos."]'::jsonb,
  execution_steps_en = '["Select a neutral (palms facing each other) or supinated grip if the machine allows, hands shoulder-width apart.","Set the assistance and stand or kneel on the platform with an upright posture.","Inhale, depress your shoulder blades, and pull your elbows toward your hips to raise your body.","Rise until your chin is level with your hands; pause briefly.","Exhale and lower slowly to full arm extension."]'::jsonb,
  common_errors_es = '["Cambiar el ángulo del codo durante el movimiento en lugar de mantenerlo constante.","No alcanzar la extensión completa en la fase de bajada, limitando el rango de recorrido.","Usar un peso de asistencia tan alto que elimina toda demanda muscular real.","Encorvar la espalda alta en lugar de mantener el pecho abierto."]'::jsonb,
  common_errors_en = '["Changing elbow angle mid-movement instead of keeping it consistent.","Not reaching full extension on the way down, limiting range of motion.","Using so much assistance that real muscular demand is eliminated.","Rounding the upper back instead of keeping the chest open."]'::jsonb,
  pro_tip_es = 'El agarre neutro suele sentirse más natural en el hombro y permite mayor recorrido; usálo como puente entre las dominadas en pronación y las en supinación.',
  pro_tip_en = 'A neutral grip often feels more natural on the shoulder and allows greater range of motion; use it as a bridge between pronated and supinated pull-ups.',
  tertiary_muscles = ARRAY['Infraspinatus','Teres Minor','Core']::text[]
WHERE slug = 'assisted-pull-up-machine-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el pad de la máquina para que quede a nivel de las caderas, con los tobillos bien fijados.","Inspirá y dejá caer el torso hacia adelante de manera controlada hasta que el tronco quede perpendicular al suelo.","Espirá y extendé la espalda hacia arriba hasta que el cuerpo quede horizontal; no hiperextendas la columna.","Apretá los glúteos al llegar a la posición horizontal y mantené un segundo.","Repetí el movimiento de forma fluida, sin rebotar en ninguno de los extremos."]'::jsonb,
  execution_steps_en = '["Adjust the machine pad to hip level with your ankles firmly secured.","Inhale and lower your torso forward in a controlled manner until your trunk is perpendicular to the floor.","Exhale and extend your back upward until your body is horizontal; do not hyperextend the spine.","Squeeze your glutes at the horizontal position and hold for one second.","Repeat the movement fluidly without bouncing at either end of the range."]'::jsonb,
  common_errors_es = '["Hiperextender la columna más allá de la horizontal, sobrecargando los discos lumbares.","Hacer el movimiento con velocidad en lugar de controlar la bajada.","No fijar bien los tobillos, perdiendo estabilidad en la fase de extensión.","Flexionar las rodillas durante el recorrido."]'::jsonb,
  common_errors_en = '["Hyperextending the spine past horizontal, overloading lumbar discs.","Performing the movement quickly instead of controlling the descent.","Not securing the ankles properly, losing stability during the extension phase.","Bending the knees during the movement."]'::jsonb,
  pro_tip_es = 'Si querés mayor activación de glúteos, apretálos activamente antes de iniciar la extensión y mantenélos contraídos hasta el punto más alto.',
  pro_tip_en = 'For greater glute activation, actively squeeze them before starting the extension and keep them contracted to the top position.',
  tertiary_muscles = ARRAY['Multifidus','Adductor Magnus','Core']::text[]
WHERE slug = 'back-extension-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con los pies al ancho de cadera, agarrá la barra en pronación con las manos algo más anchas que los hombros.","Inclinante hacia adelante desde las caderas (no la cintura) hasta que el torso quede casi paralelo al suelo, rodillas levemente flexionadas.","Inspirá, apretá el core y tirá la barra hacia el abdomen bajo llevando los codos atrás y pegados al torso.","Espirá, apretá los omóplatos en la contracción máxima y bajá la barra de manera controlada.","Mantené la columna neutra en todo momento; no curvés la espalda alta."]'::jsonb,
  execution_steps_en = '["Stand with feet hip-width apart, grip the bar with a pronated grip slightly wider than shoulders.","Hinge forward at the hips (not the waist) until the torso is nearly parallel to the floor, knees slightly bent.","Inhale, brace your core, and row the bar toward your lower abdomen driving elbows back close to your torso.","Exhale, squeeze your shoulder blades at peak contraction, then lower the bar in a controlled manner.","Keep your spine neutral throughout; do not round the upper back."]'::jsonb,
  common_errors_es = '["Redondear la espalda alta al tirar, aumentando el estrés sobre los discos.","Usar el impulso del torso (balancear el cuerpo) para mover el peso.","Tirar la barra hacia el pecho en lugar del abdomen, cambiando el enfoque muscular.","No llevar la barra a la extensión completa al bajar, acortando el recorrido."]'::jsonb,
  common_errors_en = '["Rounding the upper back while pulling, increasing disc stress.","Using torso momentum (body swinging) to move the weight.","Rowing the bar toward the chest instead of the abdomen, shifting muscle focus.","Not lowering the bar to full extension, shortening the range of motion."]'::jsonb,
  pro_tip_es = 'Pensá en ''llevar los codos al bolsillo trasero'' en lugar de ''tirar la barra'': esto orienta el movimiento al dorsal y reduce la compensación del bíceps.',
  pro_tip_en = 'Think of ''driving your elbows to your back pocket'' rather than ''pulling the bar'': this directs the movement to the lats and reduces bicep compensation.',
  tertiary_muscles = ARRAY['Infraspinatus','Subscapularis','Erector Spinae']::text[]
WHERE slug = 'barbell-bent-over-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá un par de manijas a las poleas bajas y paráte en el medio con una manija en cada mano, brazos extendidos a los costados.","Mantené los brazos rectos y elevá los hombros directamente hacia las orejas sin rotar el cuello.","Mantené la contracción máxima durante uno o dos segundos.","Bajá los hombros de manera controlada hasta la posición inicial.","Espirá al subir, inspirá al bajar; mantenéingás el torso estable en todo momento."]'::jsonb,
  execution_steps_en = '["Attach handles to the low pulleys and stand in the middle with a handle in each hand, arms extended at your sides.","Keep arms straight and elevate your shoulders directly toward your ears without rotating your neck.","Hold the peak contraction for one to two seconds.","Lower your shoulders in a controlled manner to the starting position.","Exhale on the rise, inhale on the descent; keep your torso stable throughout."]'::jsonb,
  common_errors_es = '["Rotar los hombros en círculo en lugar de elevarlos en línea recta.","Doblar los codos durante el movimiento, perdiendo el aislamiento del trapecio.","Hacer movimientos bruscos en lugar de controlados.","Inclinar el cuello o mover la cabeza al elevar los hombros."]'::jsonb,
  common_errors_en = '["Rolling the shoulders in a circle instead of elevating them in a straight line.","Bending the elbows during the movement, losing trapezius isolation.","Performing jerky movements instead of controlled ones.","Tilting the neck or moving the head when elevating the shoulders."]'::jsonb,
  pro_tip_es = 'La polea mantiene tensión constante en todo el recorrido a diferencia de las mancuernas; aprovechá eso exagerando la contracción arriba.',
  pro_tip_en = 'The cable maintains constant tension throughout the range unlike dumbbells; take advantage of this by maximizing the contraction at the top.',
  tertiary_muscles = ARRAY['Sternocleidomastoid','Rhomboids','Supraspinatus']::text[]
WHERE slug = 'cable-shrug';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte frente a la polea alta y agarrá la barra recta o cuerda con los brazos extendidos a la altura de los hombros.","Mantenéingás los codos extendidos (sin bloquearlos) durante todo el movimiento.","Inspirá y tirá la barra en arco hacia abajo hasta que toque tus muslos.","Espirá al llegar abajo, apretando el dorsal en la contracción máxima.","Volvé a la posición inicial de forma lenta y controlada, sintiendo el estiramiento del dorsal."]'::jsonb,
  execution_steps_en = '["Stand facing the high pulley and grip the straight bar or rope with arms extended at shoulder height.","Keep your elbows extended (without locking them) throughout the entire movement.","Inhale and pull the bar in a downward arc until it touches your thighs.","Exhale at the bottom, squeezing the lat at peak contraction.","Return to the starting position slowly and controlled, feeling the lat stretch."]'::jsonb,
  common_errors_es = '["Doblar los codos, convirtiendo el ejercicio en un jalón de bíceps.","Inclinarte hacia adelante en lugar de mantener el torso erguido.","No extender completamente los brazos al volver, perdiendo el estiramiento del dorsal.","Usar impulso del torso para mover el peso en lugar del dorsal."]'::jsonb,
  common_errors_en = '["Bending the elbows, turning it into a biceps pulldown.","Leaning forward instead of keeping the torso upright.","Not fully extending the arms on the return, missing the lat stretch.","Using torso momentum to move the weight instead of the lat."]'::jsonb,
  pro_tip_es = 'Este ejercicio aísla el dorsal sin involucrar el bíceps; es ideal para pre-fatigar el músculo antes de remos o para finalizadores de espalda.',
  pro_tip_en = 'This exercise isolates the lat without involving the biceps; it is ideal for pre-fatiguing the muscle before rows or as a back finisher.',
  tertiary_muscles = ARRAY['Posterior Deltoid','Pectoralis Major (Lower)','Core']::text[]
WHERE slug = 'cable-straight-arm-pulldown';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá la cuerda a la polea alta y paráte con los pies al ancho de cadera.","Agarrá la cuerda con agarre neutro (palmas enfrentadas) o en ligera pronación.","Inspirá y bajá los brazos extendidos en arco hasta las caderas, separando los extremos de la cuerda al final.","Espirá y apretá el dorsal en la contracción; la cuerda permite mayor rango que la barra.","Volvé a la posición inicial de forma controlada, sin soltar la tensión muscular."]'::jsonb,
  execution_steps_en = '["Attach the rope to the high pulley and stand with feet hip-width apart.","Grip the rope with a neutral (palms facing) or slightly pronated grip.","Inhale and pull your extended arms in a downward arc to your hips, spreading the rope ends at the bottom.","Exhale and squeeze the lat at contraction; the rope allows greater range than a bar.","Return to the starting position in a controlled manner without releasing muscle tension."]'::jsonb,
  common_errors_es = '["Doblar los codos durante el descenso en lugar de mantenerlos extendidos.","No separar los extremos de la cuerda al final, perdiendo el pico de contracción.","Inclinar excesivamente el torso hacia adelante para compensar el peso.","Soltar el control en la fase concéntrica y dejar que la polea tire los brazos hacia arriba."]'::jsonb,
  common_errors_en = '["Bending the elbows during the descent instead of keeping them extended.","Not spreading the rope ends at the bottom, missing the peak contraction.","Excessively leaning the torso forward to compensate for the weight.","Losing control in the concentric phase and letting the cable pull the arms up."]'::jsonb,
  pro_tip_es = 'La cuerda te permite llevar el movimiento más allá de las caderas y mayor énfasis en el deltoides posterior; separalas activamente al final del recorrido.',
  pro_tip_en = 'The rope lets you extend the movement past your hips and gives more emphasis to the rear delt; actively spread them at the end of the range.',
  tertiary_muscles = ARRAY['Rhomboids','Serratus Anterior','Posterior Deltoid']::text[]
WHERE slug = 'cable-straight-arm-pulldown-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá la cuerda o el triángulo a la polea baja y paráte a unos pasos de distancia.","Inclinante hacia adelante desde las caderas hasta que el torso quede a unos 45° del suelo, rodillas levemente flexionadas.","Inspirá y tirá el agarre hacia el abdomen bajo, llevando los codos atrás y pegados al torso.","Espirá y apretá los omóplatos en la posición de máxima contracción.","Extendé los brazos de manera controlada hasta la posición de partida sin desenganchar el core."]'::jsonb,
  execution_steps_en = '["Attach the rope or triangle handle to the low cable and stand a few steps away.","Hinge forward at the hips until your torso is at roughly 45° to the floor, knees slightly bent.","Inhale and row the handle toward your lower abdomen, driving elbows back close to your torso.","Exhale and squeeze your shoulder blades at the peak contraction.","Extend your arms in a controlled manner back to the start without disengaging the core."]'::jsonb,
  common_errors_es = '["Redondear la espalda baja al tirar con peso elevado.","Usar el impulso del torso para completar la repetición.","Tirar el agarre hacia el pecho en lugar del abdomen.","No extender los brazos completamente en la bajada."]'::jsonb,
  common_errors_en = '["Rounding the lower back when pulling with heavy weight.","Using torso momentum to complete the repetition.","Pulling the handle toward the chest instead of the abdomen.","Not fully extending the arms on the way down."]'::jsonb,
  pro_tip_es = 'La polea mantiene tensión constante a diferencia del remo en T con barra libre; aprovechá ese estiramiento en la posición extendida para maximizar el trabajo del dorsal.',
  pro_tip_en = 'The cable maintains constant tension unlike a free-weight T-bar row; take advantage of that stretch in the extended position to maximize lat work.',
  tertiary_muscles = ARRAY['Infraspinatus','Subscapularis','Posterior Deltoid']::text[]
WHERE slug = 'cable-t-bar-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con los pies al ancho de cadera, la barra sobre el mediopié, y agachate para agarrarla con agarre pronado al ancho de hombros.","Bajá las caderas, sacá pecho y mantené la columna neutra desde la cabeza hasta la cola.","Inspirá profundo, apretá el core y empujá el suelo hacia abajo con los pies para iniciar el movimiento.","Extendé caderas y rodillas simultáneamente hasta quedar de pie; no hiperextendas la columna arriba.","Espirá y volvé la barra al suelo de forma controlada siguiendo la misma trayectoria."]'::jsonb,
  execution_steps_en = '["Stand with feet hip-width apart, bar over mid-foot, and hinge down to grip it with a pronated grip at shoulder width.","Lower your hips, chest up, and maintain a neutral spine from head to tailbone.","Take a deep breath, brace your core, and push the floor away with your feet to initiate the lift.","Extend hips and knees simultaneously until fully upright; do not hyperextend the spine at the top.","Exhale and return the bar to the floor in a controlled manner following the same path."]'::jsonb,
  common_errors_es = '["Redondear la espalda baja al iniciar el tirón, sobrecargando los discos lumbares.","Dejar que la barra se aleje del cuerpo durante el ascenso.","Tirar con los brazos en lugar de empujar el suelo con las piernas.","Hiperextender la columna lumbar al llegar a la posición final erguida."]'::jsonb,
  common_errors_en = '["Rounding the lower back at the start of the pull, overloading lumbar discs.","Letting the bar drift away from the body during the ascent.","Pulling with the arms instead of pushing the floor with the legs.","Hyperextending the lumbar spine at the lockout position."]'::jsonb,
  pro_tip_es = 'Antes de arrancar, ''apretá la naranja en la axila'': eso crea una tensión en el dorsal que estabiliza la columna y mantiene la barra pegada al cuerpo.',
  pro_tip_en = 'Before lifting, ''squeeze an orange in your armpit'': this creates lat tension that stabilizes the spine and keeps the bar close to your body.',
  tertiary_muscles = ARRAY['Adductor Magnus','Quadriceps','Core']::text[]
WHERE slug = 'deadlift';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con los pies al ancho de cadera y una mancuerna en cada mano; inclinante desde las caderas hasta que el torso quede a unos 45°.","Inspirá y tirá ambas mancuernas hacia las caderas simultáneamente, llevando los codos atrás.","Espirá y apretá los omóplatos en la contracción máxima.","Bajá las mancuernas de forma controlada hasta la extensión completa de los brazos.","Mantené la columna neutra durante toda la serie; no curvés la espalda alta."]'::jsonb,
  execution_steps_en = '["Stand with feet hip-width apart and a dumbbell in each hand; hinge at the hips until the torso is at roughly 45°.","Inhale and row both dumbbells toward your hips simultaneously, driving elbows back.","Exhale and squeeze your shoulder blades at peak contraction.","Lower the dumbbells in a controlled manner to full arm extension.","Keep your spine neutral throughout the set; do not round your upper back."]'::jsonb,
  common_errors_es = '["Balancear el torso para generar impulso y mover el peso.","Elevar los hombros hacia las orejas en lugar de deprimirlos.","No llevar los codos atrás del torso, limitando la activación de romboides.","Redondear la columna torácica al fatigarse."]'::jsonb,
  common_errors_en = '["Swinging the torso to generate momentum and move the weight.","Elevating the shoulders toward the ears instead of depressing them.","Not driving elbows behind the torso, limiting rhomboid activation.","Rounding the thoracic spine as fatigue sets in."]'::jsonb,
  pro_tip_es = 'Las mancuernas permiten un agarre neutro y mayor recorrido que la barra; usá ese rango extra en la bajada para maximizar el estiramiento del dorsal.',
  pro_tip_en = 'Dumbbells allow a neutral grip and greater range of motion than a barbell; use that extra range on the way down to maximize lat stretch.',
  tertiary_muscles = ARRAY['Infraspinatus','Subscapularis','Erector Spinae']::text[]
WHERE slug = 'dumbbell-bent-over-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con los pies al ancho de cadera y una mancuerna en cada mano frente a los muslos.","Inclinante hacia adelante desde las caderas manteniendo la columna neutra y la mirada al frente.","Bajá las mancuernas cerca de las piernas hasta que sientas el estiramiento en los isquiotibiales.","Inspirá antes de bajar; espirá y extendé las caderas y rodillas para volver a la posición erguida.","Apretá los glúteos al llegar arriba sin hiperextender la columna lumbar."]'::jsonb,
  execution_steps_en = '["Stand with feet hip-width apart and a dumbbell in each hand in front of your thighs.","Hinge forward at the hips keeping your spine neutral and gaze forward.","Lower the dumbbells close to your legs until you feel a stretch in your hamstrings.","Inhale before lowering; exhale and extend your hips and knees to return to the upright position.","Squeeze your glutes at the top without hyperextending your lumbar spine."]'::jsonb,
  common_errors_es = '["Redondear la espalda baja al bajar las mancuernas.","Alejar las mancuernas del cuerpo en lugar de deslizarlas cerca de las piernas.","Doblar las rodillas en exceso, convirtiendo el ejercicio en una sentadilla.","No apoyar los pies de forma pareja y perder el equilibrio."]'::jsonb,
  common_errors_en = '["Rounding the lower back when lowering the dumbbells.","Moving the dumbbells away from the body instead of sliding them close to the legs.","Bending the knees excessively, turning it into a squat.","Not planting both feet evenly and losing balance."]'::jsonb,
  pro_tip_es = 'Imaginá que estás ''empujando el suelo hacia abajo'' en lugar de ''subir la mancuerna'': eso activa la cadena posterior de forma más efectiva.',
  pro_tip_en = 'Imagine ''pushing the floor away'' rather than ''lifting the dumbbell'': this activates the posterior chain more effectively.',
  tertiary_muscles = ARRAY['Adductor Magnus','Quadriceps','Core']::text[]
WHERE slug = 'dumbbell-deadlift';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte transversalmente en el banco con los hombros apoyados y las caderas colgando levemente hacia abajo.","Sostené las mancuernas sobre el pecho con los codos levemente flexionados.","Inspirá y bajá las mancuernas lentamente por encima de la cabeza en arco hasta sentir el estiramiento del dorsal y el pectoral.","Espirá y volvé las mancuernas a la vertical del pecho contrayendo el dorsal.","Mantené la flexión de codo fija durante todo el arco; no cambies el ángulo."]'::jsonb,
  execution_steps_en = '["Lie across the bench with your shoulders supported and your hips hanging slightly lower.","Hold the dumbbells over your chest with elbows slightly bent.","Inhale and lower the dumbbells slowly overhead in an arc until you feel a stretch in the lats and chest.","Exhale and return the dumbbells to chest vertical by contracting the lats.","Keep elbow bend fixed throughout the arc; do not change the angle."]'::jsonb,
  common_errors_es = '["Cambiar el ángulo del codo durante el arco, convirtiendo el movimiento en un press.","Bajar el peso tan profundamente que la articulación del hombro se ve comprometida.","No estabilizar las caderas, lo que hace que el torso rote.","Usar peso excesivo que impide el control en el punto de mayor estiramiento."]'::jsonb,
  common_errors_en = '["Changing elbow angle during the arc, turning the movement into a press.","Lowering the weight so deep that the shoulder joint is compromised.","Not stabilizing the hips, causing torso rotation.","Using excessive weight that prevents control at the point of greatest stretch."]'::jsonb,
  pro_tip_es = 'La variante con dos mancuernas permite mayor individualización de cada lado; priorizá la forma sobre la carga, ya que es un ejercicio de estiramiento y contracción, no de fuerza máxima.',
  pro_tip_en = 'The two-dumbbell variation allows greater individualization per side; prioritize form over load, as this is a stretch-and-contract exercise, not a max-strength one.',
  tertiary_muscles = ARRAY['Serratus Anterior','Rhomboids','Subscapularis']::text[]
WHERE slug = 'dumbbell-pullover-3';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco plano con los hombros apoyados y una mancuerna sujeta con ambas manos sobre el pecho.","Extendé los brazos casi completamente (codos apenas flexionados) para maximizar la participación del dorsal.","Inspirá y bajá la mancuerna lentamente por encima de la cabeza en arco amplio, enfocándote en el estiramiento del dorsal.","Espirá y tirá la mancuerna de vuelta hacia el pecho pensando en ''bajar los codos hacia las caderas''.","Controlá la fase excéntrica; no dejes caer el peso."]'::jsonb,
  execution_steps_en = '["Lie on a flat bench with shoulders supported and a dumbbell held with both hands over your chest.","Extend your arms almost fully (elbows barely bent) to maximize lat involvement.","Inhale and slowly lower the dumbbell overhead in a wide arc, focusing on the lat stretch.","Exhale and pull the dumbbell back toward your chest thinking of ''driving elbows toward your hips''.","Control the eccentric phase; do not drop the weight."]'::jsonb,
  common_errors_es = '["Doblar demasiado los codos, trasladando el trabajo al pectoral y al tríceps.","Bajar el peso sin controlar el tempo, poniendo en riesgo el hombro.","No enfocarse en el dorsal en la fase concéntrica, perdiendo el beneficio del ejercicio.","Levantar las caderas del banco al volver el peso hacia el pecho."]'::jsonb,
  common_errors_en = '["Bending the elbows too much, shifting work to the pectoral and triceps.","Lowering the weight without controlling tempo, risking the shoulder.","Not focusing on the lat during the concentric phase, losing the benefit of the exercise.","Lifting the hips off the bench when returning the weight to chest."]'::jsonb,
  pro_tip_es = 'Para énfasis en el dorsal, mantené los brazos más extendidos que en la variante para pectoral; el codo casi recto cambia drásticamente qué músculo trabaja más.',
  pro_tip_en = 'For lat emphasis, keep your arms more extended than in the chest variation; the nearly straight elbow dramatically changes which muscle does more work.',
  tertiary_muscles = ARRAY['Serratus Anterior','Posterior Deltoid','Core']::text[]
WHERE slug = 'dumbbell-pullover-back-focus';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte en posición de plancha alta con las manos sobre las mancuernas en el suelo, ligeramente más anchas que los hombros.","Aseguráte de que el cuerpo esté rígido de cabeza a talones: core apretado, glúteos activos.","Inspirá y tirá una mancuerna hacia la cadera del mismo lado llevando el codo hacia el techo.","Espirá y bajá la mancuerna de vuelta al suelo de forma controlada; repetí del otro lado.","Evitá rotar el torso: el objetivo es que las caderas queden paralelas al suelo en todo momento."]'::jsonb,
  execution_steps_en = '["Get into a high plank position with hands on dumbbells on the floor, slightly wider than shoulders.","Ensure your body is rigid from head to heels: core braced, glutes active.","Inhale and row one dumbbell toward your hip on the same side, driving the elbow toward the ceiling.","Exhale and lower the dumbbell back to the floor in a controlled manner; repeat on the other side.","Avoid rotating the torso: the goal is to keep your hips parallel to the floor throughout."]'::jsonb,
  common_errors_es = '["Rotar las caderas al tirar, perdiendo el componente anti-rotación del ejercicio.","No mantener el cuerpo rígido, dejando que las caderas caigan o suban.","Abrir los pies demasiado para compensar la inestabilidad en lugar de trabajar el core.","Tirar la mancuerna hacia el hombro en lugar de la cadera."]'::jsonb,
  common_errors_en = '["Rotating the hips when rowing, losing the anti-rotation component of the exercise.","Not keeping the body rigid, letting the hips sag or rise.","Spreading the feet too wide to compensate for instability instead of working the core.","Rowing the dumbbell toward the shoulder instead of the hip."]'::jsonb,
  pro_tip_es = 'Separás un poco más los pies da más base de sustentación; si recién empezás, hacélo así hasta dominar la posición de plancha bajo carga.',
  pro_tip_en = 'Spreading your feet slightly wider gives a larger base of support; if you are just starting, do it this way until you master the plank position under load.',
  tertiary_muscles = ARRAY['Obliques','Subscapularis','Anterior Deltoid']::text[]
WHERE slug = 'dumbbell-renegade-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con los pies al ancho de cadera y una mancuerna en cada mano, colgando a los costados del cuerpo.","Mantené los brazos completamente rectos durante todo el movimiento.","Elevá los hombros directamente hacia las orejas de forma explosiva controlada.","Mantené la contracción en el punto más alto durante uno o dos segundos.","Bajá los hombros lentamente hasta la posición de partida; no los dejes caer."]'::jsonb,
  execution_steps_en = '["Stand with feet hip-width apart and a dumbbell in each hand hanging at your sides.","Keep your arms completely straight throughout the entire movement.","Elevate your shoulders directly toward your ears with controlled explosiveness.","Hold the contraction at the top for one to two seconds.","Lower your shoulders slowly to the starting position; do not let them drop."]'::jsonb,
  common_errors_es = '["Rotar los hombros hacia adelante o atrás en lugar de elevarlos en línea recta.","Doblar los codos durante la elevación.","Usar el impulso del cuerpo para mover el peso.","No alcanzar la contracción máxima al llegar arriba."]'::jsonb,
  common_errors_en = '["Rolling the shoulders forward or backward instead of elevating them straight up.","Bending the elbows during the elevation.","Using body momentum to move the weight.","Not reaching peak contraction at the top."]'::jsonb,
  pro_tip_es = 'Imaginá que intentás tocar las orejas con los hombros; eso asegura el recorrido completo y máxima contracción del trapecio superior.',
  pro_tip_en = 'Imagine trying to touch your ears with your shoulders; this ensures full range and maximum upper trapezius contraction.',
  tertiary_muscles = ARRAY['Levator Scapulae','Sternocleidomastoid','Rhomboids']::text[]
WHERE slug = 'dumbbell-shrug';
UPDATE public.exercise_library SET
  execution_steps_es = '["Apoyá una rodilla y la mano del mismo lado en el banco; el pie contrario en el suelo y la mancuerna en la mano libre.","Mantenéingás el torso paralelo al suelo y la columna neutra.","Inspirá y tirá la mancuerna hacia la cadera, llevando el codo hacia el techo.","Espirá y apretá el dorsal en la contracción máxima, luego bajá de forma controlada.","No rotés el torso para generar impulso; el movimiento es solo del brazo y el omóplato."]'::jsonb,
  execution_steps_en = '["Place one knee and the same-side hand on the bench; opposite foot on the floor and dumbbell in the free hand.","Keep your torso parallel to the floor and spine neutral.","Inhale and row the dumbbell toward your hip, driving your elbow toward the ceiling.","Exhale and squeeze the lat at peak contraction, then lower in a controlled manner.","Do not rotate your torso to generate momentum; the movement is only from the arm and shoulder blade."]'::jsonb,
  common_errors_es = '["Rotar el torso para ganar impulso, reduciendo el trabajo del dorsal.","Tirar la mancuerna hacia el hombro en lugar de la cadera.","No alcanzar la extensión completa al bajar, limitando el rango.","Encorvar la espalda alta durante el tirón."]'::jsonb,
  common_errors_en = '["Rotating the torso to gain momentum, reducing lat work.","Rowing the dumbbell toward the shoulder instead of the hip.","Not reaching full extension on the way down, limiting range.","Rounding the upper back during the pull."]'::jsonb,
  pro_tip_es = 'Pensá en el brazo como un gancho: el codo arrastra el peso, no la mano. Eso desactiva el bíceps y pone el trabajo en el dorsal.',
  pro_tip_en = 'Think of your arm as a hook: your elbow pulls the weight, not your hand. This deactivates the biceps and puts the work on the lat.',
  tertiary_muscles = ARRAY['Infraspinatus','Teres Minor','Core']::text[]
WHERE slug = 'dumbbell-single-arm-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte con el torso en posición oblicua (no horizontal), apoyando solo la mano en el banco a menor altura que en la variante básica.","Agarrá la mancuerna y mantenéingás el codo algo más separado del torso que en el remo unilateral estándar.","Inspirá y tirá la mancuerna hacia la zona media-alta del torso, con el codo abierto hacia afuera.","Espirá y apretá el trapecio y los romboides en la contracción; bajá de forma controlada.","Mantené la columna neutra en todo momento; el torso oblicuo ya de por sí recarga la zona alta."]'::jsonb,
  execution_steps_en = '["Position your torso at an oblique angle (not horizontal), resting only your hand on the bench at a lower point than in the standard variation.","Grip the dumbbell and keep your elbow slightly more flared away from your torso than in the standard unilateral row.","Inhale and row the dumbbell toward the mid-upper torso with the elbow angled outward.","Exhale and squeeze the trapezius and rhomboids at contraction; lower in a controlled manner.","Keep your spine neutral throughout; the oblique torso position already loads the upper back."]'::jsonb,
  common_errors_es = '["Volver a la posición horizontal del remo estándar, perdiendo el énfasis en la zona alta.","Tirar el codo demasiado abierto, lo que sobrecarga el hombro.","Usar impulso del torso en lugar de activar los romboides y trapecio.","No controlar el peso en la fase excéntrica."]'::jsonb,
  common_errors_en = '["Reverting to the horizontal position of the standard row, losing the upper back emphasis.","Flaring the elbow too wide, which overloads the shoulder.","Using torso momentum instead of activating rhomboids and trapezius.","Not controlling the weight in the eccentric phase."]'::jsonb,
  pro_tip_es = 'Esta variante es ideal para completar la espalda alta después de los remos estándar; usala al final de la sesión con menor carga y mayor concentración en la contracción.',
  pro_tip_en = 'This variation is ideal for completing the upper back after standard rows; use it at the end of the session with less weight and more focus on the contraction.',
  tertiary_muscles = ARRAY['Infraspinatus','Posterior Deltoid','Erector Spinae']::text[]
WHERE slug = 'dumbbell-single-arm-row-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte de costado a la barra vertical o horizontal con los pies cerca de ella y agarráte con una mano.","Dejá caer el cuerpo lateralmente de forma rígida hasta que el brazo quede casi extendido.","Inspirá y tirá del brazo para acercar el cuerpo a la barra, llevando el codo hacia el costado.","Espirá al alcanzar la contracción máxima y volvé de forma controlada a la posición extendida.","Mantené el cuerpo rígido de cabeza a pies; no flexiones las rodillas ni muevas las caderas."]'::jsonb,
  execution_steps_en = '["Stand sideways to a firm vertical or horizontal bar with feet close to it, gripping it with one hand.","Drop your body laterally in a rigid position until your arm is almost fully extended.","Inhale and pull your arm to bring your body toward the bar, driving the elbow toward your side.","Exhale at peak contraction and return in a controlled manner to the extended position.","Keep your body rigid from head to feet; do not bend knees or shift hips."]'::jsonb,
  common_errors_es = '["Flexionar las rodillas o mover los pies para compensar la falta de fuerza.","No mantener el cuerpo rígido, dejando que las caderas caigan durante el descenso.","Usar el impulso del balanceo en lugar del dorsal para subir.","No llegar a la extensión completa del brazo al bajar."]'::jsonb,
  common_errors_en = '["Bending the knees or moving the feet to compensate for lack of strength.","Not keeping the body rigid, letting the hips drop during the descent.","Using swinging momentum instead of the lat to pull up.","Not reaching full arm extension on the way down."]'::jsonb,
  pro_tip_es = 'Este ejercicio exige coordinación y fuerza de core; si no podés mantener el cuerpo rígido, fortalecé la plancha lateral antes de intentarlo con carga.',
  pro_tip_en = 'This exercise demands coordination and core strength; if you cannot keep your body rigid, strengthen the side plank before attempting it under load.',
  tertiary_muscles = ARRAY['Core','Pectoralis Major','Triceps Long Head']::text[]
WHERE slug = 'inverted-t-bar-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina, ajustá el pad de rodillas y agarrá la barra con agarre pronado al ancho indicado.","Inclinante levemente hacia atrás (~15°), sacá pecho e inspirá.","Tirá la barra hacia el pecho alto llevando los codos hacia abajo y atrás.","Tocá el pecho alto con la barra y apretá los omóplatos; pausá un instante.","Espirá y devolvéla de manera controlada hasta la extensión completa de los brazos."]'::jsonb,
  execution_steps_en = '["Sit at the machine, adjust the knee pad, and grip the bar with a pronated grip at the indicated width.","Lean back slightly (~15°), chest up, and inhale.","Pull the bar toward your upper chest, driving elbows down and back.","Touch the bar to your upper chest and squeeze your shoulder blades; pause briefly.","Exhale and return it in a controlled manner to full arm extension."]'::jsonb,
  common_errors_es = '["Bajar la barra detrás de la nuca, aumentando el estrés en el cuello y el hombro.","Inclinar el torso hacia atrás en exceso, convirtiendo el jalón en un remo.","Usar el peso corporal como impulso para bajar la barra.","No extender los brazos completamente arriba, perdiendo el estiramiento del dorsal."]'::jsonb,
  common_errors_en = '["Pulling the bar behind the neck, increasing stress on the neck and shoulder.","Leaning the torso too far back, turning the pulldown into a row.","Using body weight as momentum to pull the bar down.","Not fully extending the arms at the top, missing the lat stretch."]'::jsonb,
  pro_tip_es = 'Antes de doblar los codos, iniciá el movimiento deprimiendo los omóplatos: eso asegura que el dorsal lidera el tirón desde el principio.',
  pro_tip_en = 'Before bending your elbows, initiate the movement by depressing your shoulder blades: this ensures the lats lead the pull from the start.',
  tertiary_muscles = ARRAY['Infraspinatus','Subscapularis','Serratus Anterior']::text[]
WHERE slug = 'lat-pulldown';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el asiento y el pad de rodillas de la máquina de jalón selectorizada.","Agarrá las manijas o la barra con agarre pronado al ancho de hombros.","Inspirá, inclináte levemente hacia atrás y deprimí los omóplatos antes de doblar los codos.","Tirá las manijas hacia el pecho alto, llevando los codos hacia abajo.","Espirá al llegar a la contracción y volvé de forma controlada hasta la extensión completa."]'::jsonb,
  execution_steps_en = '["Adjust the seat and knee pad of the selectorized pulldown machine.","Grip the handles or bar with a pronated shoulder-width grip.","Inhale, lean back slightly, and depress your shoulder blades before bending your elbows.","Pull the handles toward your upper chest, driving elbows downward.","Exhale at the contraction and return in a controlled manner to full extension."]'::jsonb,
  common_errors_es = '["No ajustar el pad de rodillas, permitiendo que el cuerpo se eleve al tirar.","Iniciar el movimiento con los brazos en lugar del omóplato.","Inclinar el torso en exceso hacia atrás para usar el peso del cuerpo.","Soltar la tensión al volver a la posición inicial."]'::jsonb,
  common_errors_en = '["Not adjusting the knee pad, allowing the body to rise while pulling.","Starting the movement with the arms instead of the shoulder blade.","Leaning the torso too far back to use body weight.","Releasing tension when returning to the start position."]'::jsonb,
  pro_tip_es = 'La máquina selectorizada es ideal para principiantes porque la trayectoria guiada reduce la demanda de coordinación; usala para aprender el patrón antes de pasar a la polea libre.',
  pro_tip_en = 'The selectorized machine is ideal for beginners because the guided path reduces coordination demands; use it to learn the pattern before moving to the free cable.',
  tertiary_muscles = ARRAY['Infraspinatus','Posterior Deltoid','Core']::text[]
WHERE slug = 'lat-pulldown-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá el accesorio en V o las manijas neutras a la polea de jalón.","Sentáte, ajustá el pad y agarrá las manijas con palmas enfrentadas.","Inspirá, inclináte levemente y deprimí los omóplatos.","Tirá los codos hacia abajo y hacia los costados del torso hasta que las manijas lleguen al pecho.","Espirá en la contracción y volvé a la extensión completa de forma controlada."]'::jsonb,
  execution_steps_en = '["Attach a V-bar or neutral handles to the pulldown pulley.","Sit, adjust the pad, and grip the handles with palms facing each other.","Inhale, lean back slightly, and depress your shoulder blades.","Pull your elbows downward and toward the sides of your torso until the handles reach your chest.","Exhale at the contraction and return to full extension in a controlled manner."]'::jsonb,
  common_errors_es = '["No mantener las palmas enfrentadas durante todo el recorrido, rotando el antebrazo.","Llevar los codos hacia afuera en lugar de hacia abajo y los costados del torso.","No alcanzar la extensión completa de los brazos al volver.","Inclinar el torso en exceso hacia atrás."]'::jsonb,
  common_errors_en = '["Not keeping palms facing each other throughout the range, rotating the forearm.","Driving elbows outward instead of downward and toward the torso sides.","Not reaching full arm extension on the return.","Leaning the torso excessively backward."]'::jsonb,
  pro_tip_es = 'El agarre neutro estrecho permite mayor recorrido articular y más participación del bíceps; es una excelente variante para sesiones en las que también entrenás bíceps.',
  pro_tip_en = 'The narrow neutral grip allows greater joint range and more biceps involvement; it is an excellent variation for sessions where you also train biceps.',
  tertiary_muscles = ARRAY['Teres Minor','Subscapularis','Serratus Anterior']::text[]
WHERE slug = 'lat-pulldown-narrowneutral-grip';
UPDATE public.exercise_library SET
  execution_steps_es = '["Agarrá la barra de jalón con agarre supinado (palmas hacia vos), manos separadas al ancho de hombros.","Sentáte, ajustá el pad de rodillas y mantené el pecho elevado.","Inspirá, deprimí los omóplatos e iniciá el tirón llevando los codos hacia abajo y hacia atrás.","Tirá la barra hasta el pecho alto o el mentón; sentís mayor trabajo del bíceps en esta variante.","Espirá y volvé de forma controlada a la extensión completa de los brazos."]'::jsonb,
  execution_steps_en = '["Grip the pulldown bar with a supinated (palms toward you) grip, hands shoulder-width apart.","Sit, adjust the knee pad, and keep your chest elevated.","Inhale, depress your shoulder blades, and initiate the pull by driving elbows down and back.","Pull the bar to your upper chest or chin; you will feel greater biceps work in this variation.","Exhale and return in a controlled manner to full arm extension."]'::jsonb,
  common_errors_es = '["Inclinar el torso hacia atrás para usar el peso del cuerpo.","No mantener las muñecas neutras, doblándolas hacia atrás bajo la carga.","Tirar la barra detrás de la nuca, lo que no corresponde a este agarre.","No alcanzar la extensión completa al volver, acortando el rango del dorsal."]'::jsonb,
  common_errors_en = '["Leaning the torso back to use body weight.","Not keeping wrists neutral, bending them backward under load.","Pulling the bar behind the neck, which does not apply to this grip.","Not reaching full extension on the return, shortening the lat range."]'::jsonb,
  pro_tip_es = 'El agarre supinado cambia la orientación del codo y permite más trabajo conjunto del bíceps y el dorsal; útil si el jalón en pronación genera molestias en los codos.',
  pro_tip_en = 'The supinated grip changes elbow orientation and allows greater combined work of the biceps and lat; useful if the pronated pulldown causes elbow discomfort.',
  tertiary_muscles = ARRAY['Teres Minor','Posterior Deltoid','Serratus Anterior']::text[]
WHERE slug = 'lat-pulldown-reverseunderhand-grip';
UPDATE public.exercise_library SET
  execution_steps_es = '["Agarrá la barra de jalón con agarre pronado y manos claramente más anchas que los hombros.","Sentáte, ajustá el pad y mantené el pecho elevado con una leve inclinación hacia atrás.","Inspirá, deprimí los omóplatos y tirá la barra hacia el pecho alto.","Llevá los codos hacia abajo y levemente hacia afuera; tocá el pecho con la barra.","Espirá y volvé de forma controlada a la extensión completa de los brazos."]'::jsonb,
  execution_steps_en = '["Grip the pulldown bar with a pronated grip and hands clearly wider than your shoulders.","Sit, adjust the pad, and keep your chest elevated with a slight backward lean.","Inhale, depress your shoulder blades, and pull the bar toward your upper chest.","Drive elbows down and slightly outward; touch the bar to your chest.","Exhale and return in a controlled manner to full arm extension."]'::jsonb,
  common_errors_es = '["Bajar la barra detrás de la nuca, aumentando el estrés cervical y del hombro.","Inclinar el torso demasiado hacia atrás usando el peso corporal.","No extender completamente los brazos arriba, perdiendo el estiramiento del dorsal.","Tirar con los brazos antes de deprimir los omóplatos."]'::jsonb,
  common_errors_en = '["Pulling the bar behind the neck, increasing cervical and shoulder stress.","Leaning the torso too far back using body weight.","Not fully extending the arms at the top, missing the lat stretch.","Pulling with the arms before depressing the shoulder blades."]'::jsonb,
  pro_tip_es = 'El agarre ancho enfatiza el ancho del dorsal; combinalo con un agarre estrecho o neutro en la misma sesión para trabajar el dorsal en su totalidad.',
  pro_tip_en = 'A wide grip emphasizes lat width; pair it with a narrow or neutral grip in the same session to work the lat completely.',
  tertiary_muscles = ARRAY['Infraspinatus','Teres Minor','Serratus Anterior']::text[]
WHERE slug = 'lat-pulldown-wide-grip';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el asiento de la máquina de remo para que las manijas queden a la altura del abdomen.","Sentáte con el pecho apoyado en el pad (si existe) y agarrá las manijas con el agarre correspondiente.","Inspirá y tirá las manijas hacia el abdomen o el pecho, llevando los codos hacia atrás.","Espirá, apretá los omóplatos y pausá un instante en la contracción máxima.","Volvé a la posición inicial de forma controlada hasta la extensión completa de los brazos."]'::jsonb,
  execution_steps_en = '["Adjust the machine seat so that the handles are at abdomen height.","Sit with your chest against the pad (if present) and grip the handles with the appropriate grip.","Inhale and row the handles toward your abdomen or chest, driving elbows back.","Exhale, squeeze your shoulder blades, and pause briefly at peak contraction.","Return to the starting position in a controlled manner to full arm extension."]'::jsonb,
  common_errors_es = '["Inclinar el torso hacia atrás para usar el impulso del cuerpo.","No llevar los codos hasta detrás del plano del torso, limitando la activación del dorsal.","Usar solo la fuerza de los brazos sin involucrar el omóplato.","Liberar el peso de forma brusca en la fase excéntrica."]'::jsonb,
  common_errors_en = '["Leaning the torso backward to use body momentum.","Not driving the elbows past the plane of the torso, limiting lat activation.","Using only arm strength without involving the shoulder blade.","Releasing the weight abruptly in the eccentric phase."]'::jsonb,
  pro_tip_es = 'En las máquinas con agarre ancho en pronación, enfocáte en llevar los codos hacia atrás y separados del torso para reclutar deltoides posterior y romboides.',
  pro_tip_en = 'On machines with a wide pronated grip, focus on driving elbows back and away from the torso to recruit the rear delt and rhomboids.',
  tertiary_muscles = ARRAY['Posterior Deltoid','Subscapularis','Core']::text[]
WHERE slug = 'machine-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina de jalón, ajustá el pad de rodillas y agarrá las palancas o manijas.","Inspirá, elevá levemente el pecho y deprimí los omóplatos antes de iniciar el tirón.","Tirá las palancas hacia abajo y hacia los costados del torso hasta alcanzar la contracción máxima.","Espirá y apretá el dorsal; mantené la posición un instante antes de volver.","Volvé a la posición inicial de forma lenta y controlada hasta la extensión completa de los brazos."]'::jsonb,
  execution_steps_en = '["Sit at the lat pulldown machine, adjust the knee pad, and grip the levers or handles.","Inhale, slightly elevate your chest, and depress your shoulder blades before starting the pull.","Pull the levers downward and toward the sides of your torso until you reach peak contraction.","Exhale and squeeze the lat; hold the position briefly before returning.","Return to the starting position slowly and controlled to full arm extension."]'::jsonb,
  common_errors_es = '["No ajustar el asiento a la altura correcta, limitando el rango de movimiento.","Iniciar el movimiento con el codo en lugar del omóplato.","Inclinar el torso excesivamente hacia atrás.","Volver a la posición inicial de forma rápida sin controlar la tensión."]'::jsonb,
  common_errors_en = '["Not adjusting the seat to the correct height, limiting range of motion.","Initiating the movement with the elbow instead of the shoulder blade.","Leaning the torso excessively backward.","Returning to the starting position quickly without controlling tension."]'::jsonb,
  pro_tip_es = 'Si la máquina tiene palancas independientes, podés hacerlo a una mano manteniendo la otra en isométrico; eso obliga al core a estabilizar y mejora la concentración muscular.',
  pro_tip_en = 'If the machine has independent levers, you can perform it one arm at a time while keeping the other in isometric hold; this forces the core to stabilize and improves muscle focus.',
  tertiary_muscles = ARRAY['Infraspinatus','Serratus Anterior','Core']::text[]
WHERE slug = 'máquina-de-dorsal-jalón-en-máquina';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte entre las dos poleas laterales con las piernas semiflexionadas y el core apretado.","Agarrá los cables con los codos semiflexionados y los brazos en cruz.","Inspirá y, sin variar la flexión del codo, tirá los brazos hacia atrás y abajo juntando los codos detrás del torso.","Espirá en la contracción máxima, donde los codos quedan detrás del plano del cuerpo.","Volvé los brazos a la posición en cruz de forma controlada, sintiendo el estiramiento del dorsal."]'::jsonb,
  execution_steps_en = '["Stand between two lateral pulleys with legs slightly bent and core braced.","Grip the cables with elbows slightly bent and arms extended out to the sides.","Inhale and, without changing the elbow angle, pull your arms back and downward, bringing elbows behind your torso.","Exhale at peak contraction, where elbows are behind the plane of your body.","Return your arms to the outstretched position in a controlled manner, feeling the lat stretch."]'::jsonb,
  common_errors_es = '["Cambiar la flexión del codo durante el movimiento, convirtiendo el ejercicio en un jalón.","Inclinar el torso hacia adelante en lugar de mantenerlo erguido.","No llevar los codos detrás del torso, reduciendo la aducción del dorsal.","Usar peso excesivo que impide el rango completo."]'::jsonb,
  common_errors_en = '["Changing elbow flexion during the movement, turning it into a pulldown.","Leaning the torso forward instead of keeping it upright.","Not driving elbows behind the torso, reducing lat adduction.","Using excessive weight that prevents full range."]'::jsonb,
  pro_tip_es = 'Este ejercicio es muy similar al cruce de poleas para pectoral pero en dirección contraria; si ya dominás ese movimiento, el patrón motor te resultará familiar.',
  pro_tip_en = 'This exercise is very similar to the cable crossover for chest but in the opposite direction; if you already master that movement, the motor pattern will feel familiar.',
  tertiary_muscles = ARRAY['Posterior Deltoid','Teres Major','Core']::text[]
WHERE slug = 'neutral-grip-lat-pulldown';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colgáte de la barra con agarre pronado (dominadas) o supinado (chin-ups) al ancho de hombros.","Deprimí los omóplatos antes de doblar los codos para activar el dorsal desde el inicio.","Inspirá y tirá los codos hacia abajo y atrás hasta que el mentón supere la barra.","Espirá en la contracción, apretando el dorsal y los omóplatos al llegar arriba.","Bajá de forma lenta y controlada hasta la extensión completa de los brazos."]'::jsonb,
  execution_steps_en = '["Hang from the bar with a pronated (pull-up) or supinated (chin-up) grip at shoulder width.","Depress your shoulder blades before bending your elbows to activate the lats from the start.","Inhale and drive your elbows down and back until your chin clears the bar.","Exhale at the contraction, squeezing lats and shoulder blades at the top.","Lower slowly and in a controlled manner to full arm extension."]'::jsonb,
  common_errors_es = '["Balancear el cuerpo para generar impulso y subir con inercia.","No bajar hasta la extensión completa de los brazos, limitando el rango.","Encoger los hombros en lugar de deprimirlos al iniciar el tirón.","Usar solo la fuerza del brazo sin activar el dorsal."]'::jsonb,
  common_errors_en = '["Swinging the body to generate momentum and rise with inertia.","Not lowering to full arm extension, limiting the range.","Shrugging the shoulders instead of depressing them when starting the pull.","Using only arm strength without activating the lat."]'::jsonb,
  pro_tip_es = 'La fase excéntrica (bajar lento) es tan importante como la concéntrica; controlá la bajada al menos 3 segundos para maximizar las ganancias de fuerza.',
  pro_tip_en = 'The eccentric phase (slow lowering) is as important as the concentric; control the descent for at least 3 seconds to maximize strength gains.',
  tertiary_muscles = ARRAY['Infraspinatus','Subscapularis','Serratus Anterior']::text[]
WHERE slug = 'pull-ups-chin-ups';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte frente a la polea baja y agarrá la barra o las manijas con agarre pronado o neutro.","Inclinante levemente hacia atrás, manteniendo la columna neutra.","Inspirá y tirá el agarre hacia el abdomen, llevando los codos atrás y pegados al torso.","Espirá y apretá el dorsal y los romboides en la contracción máxima.","Volvé a la posición inicial de forma controlada hasta la extensión completa de los brazos."]'::jsonb,
  execution_steps_en = '["Sit facing the low pulley and grip the bar or handles with a pronated or neutral grip.","Lean back slightly, keeping your spine neutral.","Inhale and row the handle toward your abdomen, driving elbows back close to your torso.","Exhale and squeeze the lat and rhomboids at peak contraction.","Return to the starting position in a controlled manner to full arm extension."]'::jsonb,
  common_errors_es = '["Inclinar el torso demasiado hacia atrás, convirtiendo el remo en un tirón de espalda baja.","Tirar el agarre hacia el pecho en lugar del abdomen.","No llevar los codos detrás del plano del torso.","Liberar la tensión de forma brusca en la fase excéntrica."]'::jsonb,
  common_errors_en = '["Leaning the torso too far back, turning the row into a lower back pull.","Rowing the handle toward the chest instead of the abdomen.","Not driving elbows behind the plane of the torso.","Releasing tension abruptly in the eccentric phase."]'::jsonb,
  pro_tip_es = 'Si el remo en Gironda se realiza desde la polea alta, el torso debe quedar más erguido; eso reduce la carga lumbar pero también el peso posible.',
  pro_tip_en = 'If the Gironda row is performed from the high pulley, the torso should be more upright; this reduces lumbar load but also the possible weight.',
  tertiary_muscles = ARRAY['Posterior Deltoid','Subscapularis','Erector Spinae']::text[]
WHERE slug = 'remo-en-polea-gironda';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco romano para que el pad quede a nivel de las caderas y los pies estén bien anclados.","Cruzá los brazos sobre el pecho o posicionalos detrás de la cabeza.","Inspirá y dejá caer el torso hacia abajo de forma controlada hasta que el cuerpo forme un ángulo de 90°.","Espirá y extendé la espalda hasta que el cuerpo quede horizontal; no hiperextendas.","Apretá los glúteos al llegar arriba y repetí sin usar impulso."]'::jsonb,
  execution_steps_en = '["Adjust the Roman chair so the pad is at hip level with your feet firmly anchored.","Cross your arms over your chest or position them behind your head.","Inhale and lower your torso in a controlled manner until your body forms a 90° angle.","Exhale and extend your back until your body is horizontal; do not hyperextend.","Squeeze your glutes at the top and repeat without using momentum."]'::jsonb,
  common_errors_es = '["Hiperextender la columna más allá de la horizontal, comprimiendo los discos lumbares.","Realizar el movimiento con velocidad en lugar de controlar el tempo.","No anclar bien los pies, perdiendo estabilidad.","Poner las manos detrás de la cabeza y jalarse el cuello hacia adelante."]'::jsonb,
  common_errors_en = '["Hyperextending the spine past horizontal, compressing lumbar discs.","Performing the movement quickly instead of controlling the tempo.","Not securing the feet properly, losing stability.","Placing hands behind the head and pulling the neck forward."]'::jsonb,
  pro_tip_es = 'Podés agregar una leve rotación al llegar arriba para trabajar el cuadrado lumbar de forma unilateral; hacélo sin peso adicional hasta dominar el movimiento básico.',
  pro_tip_en = 'You can add a slight rotation at the top to work the quadratus lumborum unilaterally; do it without added weight until you master the basic movement.',
  tertiary_muscles = ARRAY['Multifidus','Quadratus Lumborum','Adductor Magnus']::text[]
WHERE slug = 'roman-chair-back-extension';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en el banco de remo en polea y apoyá los pies en los soportes con las rodillas levemente flexionadas.","Agarrá el triángulo o las manijas y mantené el torso erguido.","Inspirá y tirá el agarre hacia el abdomen, llevando los codos atrás y pegados al torso.","Espirá, apretá los omóplatos y pausá un instante en la contracción máxima.","Extendé los brazos de forma controlada hasta la posición inicial sin redondear la espalda."]'::jsonb,
  execution_steps_en = '["Sit on the cable row bench and place your feet on the supports with knees slightly bent.","Grip the triangle or handles and keep your torso upright.","Inhale and row the handle toward your abdomen, driving elbows back close to your torso.","Exhale, squeeze your shoulder blades, and pause briefly at peak contraction.","Extend your arms in a controlled manner to the starting position without rounding your back."]'::jsonb,
  common_errors_es = '["Inclinar el torso hacia atrás en exceso para usar el impulso del cuerpo.","Redondear la espalda baja al extender los brazos en la fase excéntrica.","No llegar a la extensión completa de los brazos al volver.","Tirar el agarre hacia el pecho en lugar del abdomen."]'::jsonb,
  common_errors_en = '["Leaning the torso back excessively to use body momentum.","Rounding the lower back when extending the arms in the eccentric phase.","Not reaching full arm extension on the return.","Rowing the handle toward the chest instead of the abdomen."]'::jsonb,
  pro_tip_es = 'Mantené el torso perfectamente vertical durante toda la serie; si necesitás inclinar el cuerpo para mover el peso, reducí la carga.',
  pro_tip_en = 'Keep your torso perfectly vertical throughout the entire set; if you need to lean your body to move the weight, reduce the load.',
  tertiary_muscles = ARRAY['Erector Spinae','Posterior Deltoid','Core']::text[]
WHERE slug = 'seated-cable-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el asiento para que las manijas queden a la altura del abdomen y el pecho esté apoyado si el diseño lo permite.","Agarrá las manijas con el agarre indicado y mantenéingás el torso erguido.","Inspirá y tirá las manijas hacia el torso, llevando los codos atrás.","Espirá, apretá los omóplatos y pausá en la contracción máxima.","Volvé a la posición inicial de forma controlada hasta la extensión completa de los brazos."]'::jsonb,
  execution_steps_en = '["Adjust the seat so the handles are at abdomen height and your chest is supported if the design allows.","Grip the handles with the indicated grip and keep your torso upright.","Inhale and row the handles toward your torso, driving elbows back.","Exhale, squeeze your shoulder blades, and pause at peak contraction.","Return to the starting position in a controlled manner to full arm extension."]'::jsonb,
  common_errors_es = '["Inclinar el torso hacia atrás usando el impulso del cuerpo.","No ajustar el asiento a la altura correcta, alterando el ángulo del movimiento.","Liberar el peso de forma brusca en la fase excéntrica.","No alcanzar la extensión completa de los brazos, reduciendo el rango."]'::jsonb,
  common_errors_en = '["Leaning the torso backward using body momentum.","Not adjusting the seat to the correct height, altering the movement angle.","Releasing the weight abruptly in the eccentric phase.","Not reaching full arm extension, reducing range."]'::jsonb,
  pro_tip_es = 'La máquina de remo sentado reduce el estrés lumbar comparado con el remo libre; es una opción segura para quienes tienen molestias en la espalda baja.',
  pro_tip_en = 'The seated row machine reduces lumbar stress compared to free-weight rows; it is a safe option for those with lower back discomfort.',
  tertiary_muscles = ARRAY['Posterior Deltoid','Subscapularis','Core']::text[]
WHERE slug = 'seated-row-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá una manija a la polea alta y sentáte en el suelo o arrodilláte frente a la máquina.","Agarrá la manija con una mano y extendé el brazo completamente hacia arriba.","Inspirá, deprimí el omóplato del lado que trabaja y tirá el codo hacia abajo y hacia la cadera.","Espirá en la contracción máxima, donde el codo queda junto al torso.","Volvé a la extensión completa de forma controlada; completá la serie y cambiá de lado."]'::jsonb,
  execution_steps_en = '["Attach a handle to the high pulley and sit on the floor or kneel in front of the machine.","Grip the handle with one hand and extend your arm fully upward.","Inhale, depress the shoulder blade on the working side, and pull your elbow down toward your hip.","Exhale at peak contraction, where your elbow is close to your torso.","Return to full extension in a controlled manner; complete the set and switch sides."]'::jsonb,
  common_errors_es = '["Doblar el codo en exceso, convirtiendo el ejercicio en un curl de bíceps.","No deprimir el omóplato antes de tirar, perdiendo la activación del dorsal.","Inclinar el torso hacia el lado contrario al trabajar, en lugar de mantenerse erguido.","Usar el impulso del cuerpo para completar la repetición."]'::jsonb,
  common_errors_en = '["Bending the elbow too much, turning it into a biceps curl.","Not depressing the shoulder blade before pulling, losing lat activation.","Leaning the torso to the opposite side when working, instead of staying upright.","Using body momentum to complete the repetition."]'::jsonb,
  pro_tip_es = 'Sentáte en el suelo o arrodilláte para eliminar el balanceo del cuerpo y aislar mejor el dorsal de cada lado de forma independiente.',
  pro_tip_en = 'Sit on the floor or kneel to eliminate body sway and better isolate each lat independently.',
  tertiary_muscles = ARRAY['Posterior Deltoid','Teres Minor','Core']::text[]
WHERE slug = 'single-arm-cable-pulldown';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá la barra del Smith a la altura adecuada y posiciónate debajo de ella con agarre pronado.","Inclinante hacia adelante desde las caderas hasta que el torso quede casi paralelo al suelo.","Inspirá, desbloquéa la barra y tirala hacia el abdomen bajo llevando los codos atrás.","Espirá, apretá los omóplatos en la contracción y volvé a la posición inicial de forma controlada.","La trayectoria guiada del Smith mantiene la barra en la misma línea vertical en todo el recorrido."]'::jsonb,
  execution_steps_en = '["Set the Smith machine bar to the appropriate height and position yourself underneath with a pronated grip.","Hinge forward at the hips until your torso is nearly parallel to the floor.","Inhale, unrack the bar, and row it toward your lower abdomen driving elbows back.","Exhale, squeeze your shoulder blades at the contraction, and return in a controlled manner.","The Smith machine''s guided path keeps the bar on the same vertical line throughout the movement."]'::jsonb,
  common_errors_es = '["Redondear la espalda baja al tirar la barra.","Usar el impulso del torso para mover el peso.","No llevar los codos detrás del plano del torso en la contracción.","Bloquear la barra en la fase excéntrica en lugar de controlar el descenso."]'::jsonb,
  common_errors_en = '["Rounding the lower back when rowing the bar.","Using torso momentum to move the weight.","Not driving elbows behind the plane of the torso at the contraction.","Locking the bar in the eccentric phase instead of controlling the descent."]'::jsonb,
  pro_tip_es = 'La trayectoria fija del Smith reduce la demanda de coordinación; es ideal para aprender el patrón del remo inclinado antes de pasar a la barra libre.',
  pro_tip_en = 'The fixed Smith path reduces coordination demands; it is ideal for learning the bent-over row pattern before moving to a free barbell.',
  tertiary_muscles = ARRAY['Infraspinatus','Erector Spinae','Core']::text[]
WHERE slug = 'smith-machine-bent-over-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá la barra del Smith a la altura de la cadera y posiciónate con los pies al ancho de cadera.","Agarrá la barra con agarre pronado al ancho de hombros y desbloquéala.","Inclinante hacia adelante desde las caderas, deslizando la barra cerca de los muslos, con la espalda recta.","Inspirá antes de bajar; bajá hasta sentir el estiramiento en los isquiotibiales (a la altura de la rodilla o por debajo si la movilidad lo permite).","Espirá y extendé las caderas para volver a la posición erguida; apretá los glúteos al llegar arriba."]'::jsonb,
  execution_steps_en = '["Set the Smith bar at hip height and position yourself with feet hip-width apart.","Grip the bar with a pronated shoulder-width grip and unrack it.","Hinge forward at the hips, sliding the bar close to your thighs, with a straight back.","Inhale before lowering; descend until you feel a hamstring stretch (knee level or below if mobility allows).","Exhale and extend your hips to return to the upright position; squeeze your glutes at the top."]'::jsonb,
  common_errors_es = '["Redondear la espalda baja durante el descenso.","Doblar las rodillas en exceso, convirtiendo el movimiento en una sentadilla.","Alejar la barra del cuerpo en lugar de deslizarla cerca de los muslos.","Hiperextender la columna lumbar al llegar a la posición erguida."]'::jsonb,
  common_errors_en = '["Rounding the lower back during the descent.","Bending the knees excessively, turning it into a squat.","Moving the bar away from the body instead of sliding it close to the thighs.","Hyperextending the lumbar spine at the upright position."]'::jsonb,
  pro_tip_es = 'La guía del Smith elimina el componente de equilibrio; usálo para aprender el patrón de bisagra de cadera con cargas moderadas antes de pasar al peso libre.',
  pro_tip_en = 'The Smith guide eliminates the balance component; use it to learn the hip hinge pattern with moderate loads before transitioning to free weight.',
  tertiary_muscles = ARRAY['Adductor Magnus','Quadriceps','Core']::text[]
WHERE slug = 'smith-machine-romanian-deadlift';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá la barra del Smith a la altura adecuada e inclinante hacia adelante con el torso casi paralelo al suelo.","Agarrá la barra en pronación con las manos algo más anchas que los hombros y desbloquéala.","Inspirá y tirá la barra hacia el abdomen, con los codos abiertos y paralelos al suelo.","Espirá, apretá los omóplatos en la contracción máxima y volvé a la posición inicial.","Mantené la columna neutra en todo momento; no redondeés la espalda alta."]'::jsonb,
  execution_steps_en = '["Set the Smith bar to the appropriate height and hinge forward with torso nearly parallel to the floor.","Grip the bar with a pronated grip slightly wider than shoulders and unrack it.","Inhale and row the bar toward your abdomen with elbows flared and parallel to the floor.","Exhale, squeeze your shoulder blades at peak contraction, and return to the starting position.","Keep your spine neutral throughout; do not round your upper back."]'::jsonb,
  common_errors_es = '["Inclinar el torso demasiado erguido, perdiendo el estímulo del remo.","Tirar la barra hacia el pecho en lugar del abdomen.","Usar el impulso del torso para completar la repetición.","Redondear la espalda alta al fatigarse."]'::jsonb,
  common_errors_en = '["Keeping the torso too upright, losing the rowing stimulus.","Rowing the bar toward the chest instead of the abdomen.","Using torso momentum to complete the repetition.","Rounding the upper back as fatigue sets in."]'::jsonb,
  pro_tip_es = 'El remo en Smith permite cargar más que en barra libre porque la trayectoria está guiada; aseguráte de compensar eso con mayor enfoque en la contracción muscular.',
  pro_tip_en = 'The Smith row allows more load than free barbell because the path is guided; make sure to compensate by focusing more on muscle contraction.',
  tertiary_muscles = ARRAY['Infraspinatus','Erector Spinae','Posterior Deltoid']::text[]
WHERE slug = 'smith-machine-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá las manijas a la polea baja y paráte a unos pasos de distancia con los pies al ancho de cadera.","Inclinante levemente hacia adelante desde las caderas (torso a unos 30-45° del suelo) y agarrá las manijas.","Inspirá y tirá las manijas hacia el abdomen, llevando los codos atrás y pegados al torso.","Espirá y apretá los omóplatos en la contracción; pausá un instante.","Extendé los brazos de forma controlada hasta la posición de partida."]'::jsonb,
  execution_steps_en = '["Attach handles to the low pulley and stand a few steps away with feet hip-width apart.","Hinge slightly forward at the hips (torso at about 30-45° to the floor) and grip the handles.","Inhale and row the handles toward your abdomen, driving elbows back close to your torso.","Exhale and squeeze your shoulder blades at the contraction; pause briefly.","Extend your arms in a controlled manner back to the starting position."]'::jsonb,
  common_errors_es = '["Inclinar el torso demasiado erguido, convirtiéndolo en un jalón de espalda.","Tirar con los brazos usando impulso en lugar de activar el dorsal.","No mantener el core activo, dejando que la espalda baja absorba el estrés.","Usar peso excesivo que obliga a desequilibrar el cuerpo hacia atrás."]'::jsonb,
  common_errors_en = '["Keeping the torso too upright, turning it into a back pulldown.","Pulling with arm momentum instead of activating the lat.","Not keeping the core active, letting the lower back absorb the stress.","Using excessive weight that forces the body to lean backward."]'::jsonb,
  pro_tip_es = 'Este ejercicio está a mitad de camino entre el remo y el jalón; usálo en superserie con el pullover en polea alta para un finalizador completo de dorsal.',
  pro_tip_en = 'This exercise is halfway between a row and a pulldown; use it in a superset with the high-pulley pullover for a complete lat finisher.',
  tertiary_muscles = ARRAY['Posterior Deltoid','Rhomboids','Core']::text[]
WHERE slug = 'standing-low-cable-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte sobre la plataforma del remo en punta con los pies al ancho de cadera y agarrá las manijas.","Inclinante hacia adelante desde las caderas hasta que el torso quede casi paralelo al suelo.","Inspirá y tirá las manijas hacia el pecho, llevando los codos hacia arriba y afuera.","Espirá, apretá los omóplatos en la contracción y pausá un instante.","Volvé a la posición inicial de forma controlada hasta la extensión completa de los brazos."]'::jsonb,
  execution_steps_en = '["Stand on the T-bar row platform with feet hip-width apart and grip the handles.","Hinge forward at the hips until your torso is nearly parallel to the floor.","Inhale and row the handles toward your chest, driving elbows up and outward.","Exhale, squeeze your shoulder blades at the contraction, and pause briefly.","Return to the starting position in a controlled manner to full arm extension."]'::jsonb,
  common_errors_es = '["Usar el impulso del torso para mover el peso en lugar del dorsal y los romboides.","No llevar los codos más allá del plano del torso en la contracción.","Redondear la espalda alta al fatigarse.","No llegar a la extensión completa de los brazos al bajar."]'::jsonb,
  common_errors_en = '["Using torso momentum to move the weight instead of the lats and rhomboids.","Not driving elbows past the plane of the torso at the contraction.","Rounding the upper back as fatigue sets in.","Not lowering to full arm extension."]'::jsonb,
  pro_tip_es = 'El agarre ancho en T desplaza el trabajo hacia la zona alta de la espalda (deltoides posterior y romboides); combinalo con el remo en punta de agarre estrecho para cobertura completa.',
  pro_tip_en = 'The wide T-bar grip shifts work to the upper back (rear delt and rhomboids); pair it with a narrow-grip T-bar row for complete coverage.',
  tertiary_muscles = ARRAY['Posterior Deltoid','Infraspinatus','Erector Spinae']::text[]
WHERE slug = 't-bar-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Subí a la plataforma de la máquina de remo en T, colocá los pies en los soportes y agarrá las manijas.","Inclinante hacia adelante hasta que el pecho quede cerca del soporte o el torso casi paralelo al suelo.","Inspirá y tirá las manijas hacia el pecho llevando los codos hacia arriba.","Espirá, apretá los omóplatos y pausá brevemente en la contracción máxima.","Volvé a la posición inicial de forma lenta y controlada."]'::jsonb,
  execution_steps_en = '["Step on the T-bar row machine platform, place your feet on the supports, and grip the handles.","Hinge forward until your chest is near the support or your torso is nearly parallel to the floor.","Inhale and row the handles toward your chest, driving elbows upward.","Exhale, squeeze your shoulder blades, and pause briefly at peak contraction.","Return to the starting position slowly and in a controlled manner."]'::jsonb,
  common_errors_es = '["Usar el impulso del torso para iniciar el tirón.","No mantener el torso en el ángulo correcto durante toda la serie.","No llegar a la contracción máxima, quedándose a mitad del recorrido.","Dejar caer el peso de forma brusca en la fase excéntrica."]'::jsonb,
  common_errors_en = '["Using torso momentum to initiate the pull.","Not maintaining the correct torso angle throughout the set.","Not reaching peak contraction, stopping halfway through the range.","Dropping the weight abruptly in the eccentric phase."]'::jsonb,
  pro_tip_es = 'La máquina de remo en T con plataforma estabiliza el torso y permite cargas más altas que la versión libre; es una buena opción para periodizar volumen de espalda.',
  pro_tip_en = 'The T-bar row machine with a platform stabilizes the torso and allows higher loads than the free-weight version; it is a good option for periodizing back volume.',
  tertiary_muscles = ARRAY['Posterior Deltoid','Infraspinatus','Core']::text[]
WHERE slug = 't-bar-row-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco con la cabeza en el borde y sujetá las asas de la polea baja con los codos semiflexionados.","Inspirá profundo y bajá lentamente el peso por encima de tu cabeza sin cambiar el ángulo de los codos.","Sentí el estiramiento en el pectoral al llegar al punto más bajo del arco.","Espirá y volvé el peso a la vertical de los ojos contrayendo el pectoral.","Controlá el movimiento en todo momento; no soltés la tensión al final del recorrido."]'::jsonb,
  execution_steps_en = '["Lie on the bench with your head at the edge and grip the low pulley handles with elbows slightly bent.","Take a deep breath and slowly lower the weight overhead in an arc without changing elbow angle.","Feel the chest stretch at the bottom of the arc.","Exhale and return the weight to eye level by contracting the pectorals.","Maintain controlled movement throughout; do not release tension at the end of the range."]'::jsonb,
  common_errors_es = '["Doblar los codos durante el movimiento, convirtiendo el ejercicio en un jalón de tríceps.","Bajar el peso demasiado rápido y perder el control en el estiramiento.","Levantar las caderas del banco al generar momentum.","Usar un peso excesivo que impide el rango completo de movimiento."]'::jsonb,
  common_errors_en = '["Bending the elbows during movement, turning it into a triceps pulldown.","Lowering the weight too fast and losing control during the stretch.","Lifting the hips off the bench to generate momentum.","Using excessive weight that limits the full range of motion."]'::jsonb,
  pro_tip_es = 'Mantené una leve flexión fija en los codos durante todo el arco; esto protege la articulación del hombro y mantiene el trabajo en el pectoral.',
  pro_tip_en = 'Keep a slight fixed bend in your elbows throughout the entire arc; this protects the shoulder joint and keeps the work on the pectoral.',
  tertiary_muscles = ARRAY['Subscapularis','Rhomboids','Core']::text[]
WHERE slug = 'assisted-dips-cable';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco plano y agarrá la barra con las manos separadas al ancho de los hombros (agarre cerrado, ~20 cm entre manos).","Bajá la barra de forma controlada hasta el pecho medio-bajo, manteniendo los codos a unos 45° del torso.","Tocá levemente el pecho sin rebotar y empujá la barra hacia arriba hasta extender los brazos.","Espirá durante el empuje; inspirá durante la bajada.","Mantené los pies apoyados en el suelo y la espalda baja con arco natural durante toda la serie."]'::jsonb,
  execution_steps_en = '["Lie on a flat bench and grip the bar with hands shoulder-width apart (close grip, ~20 cm between hands).","Lower the bar in a controlled manner to the mid-lower chest, keeping elbows at roughly 45° from the torso.","Lightly touch the chest without bouncing and press the bar back up until arms are extended.","Exhale during the press; inhale during the descent.","Keep feet flat on the floor and maintain a natural lower back arch throughout the set."]'::jsonb,
  common_errors_es = '["Rebotar la barra sobre el pecho para aprovechar el impulso.","Abrir los codos en exceso, aumentando la carga sobre el hombro.","Levantar los glúteos del banco durante el empuje.","Usar muñecas débiles o dobladas hacia atrás bajo la barra."]'::jsonb,
  common_errors_en = '["Bouncing the bar off the chest to use momentum.","Flaring the elbows excessively, increasing shoulder stress.","Lifting the glutes off the bench during the press.","Using weak or hyperextended wrists under the bar."]'::jsonb,
  pro_tip_es = 'Al agarre cerrado, el tríceps trabaja más que en el press ancho; priorizá este ejercicio si querés desarrollar la fuerza del tríceps en paralelo con el pectoral.',
  pro_tip_en = 'With a close grip, the triceps contribute more than in a wide-grip press; prioritize this exercise if you want to develop triceps strength alongside the pectorals.',
  tertiary_muscles = ARRAY['Core','Subscapularis','Serratus Anterior']::text[]
WHERE slug = 'bench-press-barbell';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá las poleas en la posición baja y agarrá una manija en cada mano con los brazos extendidos hacia abajo.","Inclinándote levemente hacia adelante, subí los brazos en arco hacia arriba y al centro hasta que las manos se encuentren frente al pecho.","Mantené una leve flexión en los codos durante todo el recorrido.","Bajá las manos de vuelta controlando la tensión; no dejes caer el peso.","Espirá al cerrar, inspirá al abrir."]'::jsonb,
  execution_steps_en = '["Set pulleys to the low position and grip a handle in each hand with arms extended downward.","Leaning slightly forward, raise your arms in an upward arc toward center until hands meet at chest level.","Keep a slight bend in the elbows throughout the movement.","Lower hands back while controlling the tension; do not drop the weight.","Exhale on the close, inhale on the open."]'::jsonb,
  common_errors_es = '["Estirar los codos completamente, convirtiendo el movimiento en un press.","No mantener la inclinación del torso, reduciendo la activación del pectoral superior.","Usar demasiado peso y perder el arco fluido del movimiento.","Dejar que los hombros se eleven al subir las manos."]'::jsonb,
  common_errors_en = '["Fully straightening the elbows, turning the movement into a press.","Not maintaining the forward torso lean, reducing upper pectoral activation.","Using too much weight and losing the smooth arc of movement.","Allowing the shoulders to shrug as the hands rise."]'::jsonb,
  pro_tip_es = 'La polea baja dirige la tensión hacia la zona clavicular del pectoral; al llegar al punto de cierre apretá el pecho por un segundo antes de volver.',
  pro_tip_en = 'The low pulley directs tension toward the clavicular head of the pectoral; at the closed position squeeze the chest for one second before returning.',
  tertiary_muscles = ARRAY['Coracobrachialis','Core']::text[]
WHERE slug = 'cable-chest-fly-low-pulley';
UPDATE public.exercise_library SET
  execution_steps_es = '["Posicionáte de pie entre las estaciones de poleas o de espaldas a ellas, con las poleas a la altura del pecho.","Agarrá las manijas con los codos doblados y los brazos abiertos.","Empujá las manijas hacia adelante hasta extender los brazos frente al pecho.","Volvé de forma controlada sintiendo el estiramiento en el pectoral.","Mantené el core activo y el torso estable durante todo el movimiento."]'::jsonb,
  execution_steps_en = '["Stand between cable stations or with your back to them, with pulleys at chest height.","Grip the handles with elbows bent and arms open.","Press the handles forward until arms are extended in front of your chest.","Return in a controlled manner, feeling the stretch in the pectoral.","Keep the core engaged and the torso stable throughout the movement."]'::jsonb,
  common_errors_es = '["Inclinarse excesivamente hacia adelante, convirtiendo el ejercicio en una versión inclinada.","No controlar el retorno, dejando que la polea tire bruscamente del brazo.","Permitir que los codos bajen por debajo de la línea del pecho.","Usar el momentum del torso para completar las repeticiones."]'::jsonb,
  common_errors_en = '["Leaning excessively forward, turning it into an incline variation.","Not controlling the return, letting the cable pull the arm back abruptly.","Allowing the elbows to drop below chest level.","Using torso momentum to complete reps."]'::jsonb,
  pro_tip_es = 'A diferencia de la barra, la polea mantiene tensión constante en todo el recorrido; aprovechá eso haciendo el movimiento de forma lenta y deliberada.',
  pro_tip_en = 'Unlike the barbell, the cable maintains constant tension throughout the range; take advantage of that by performing the movement slowly and deliberately.',
  tertiary_muscles = ARRAY['Core','Serratus Anterior']::text[]
WHERE slug = 'cable-chest-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Posicionáte en el centro entre dos poleas a la altura del pecho o ligeramente más arriba, con un pie adelantado para estabilizarte.","Agarrá las manijas con los codos semiflexionados y los brazos abiertos a los costados.","Traé las manos hacia el frente y abajo en un arco, juntándolas al frente del cuerpo.","Doblá levemente los codos al abrir y extendélos suavemente al cerrar.","Volvé de forma controlada; no dejes que los hombros se adelanten al abrir."]'::jsonb,
  execution_steps_en = '["Stand in the center between two pulleys set at chest height or slightly above, with one foot forward for stability.","Grip the handles with elbows slightly bent and arms open to the sides.","Bring your hands forward and slightly downward in an arc, meeting them in front of the body.","Slightly bend the elbows on the open phase and gently extend them on the close.","Return in a controlled manner; do not let the shoulders roll forward on the open phase."]'::jsonb,
  common_errors_es = '["Cruzar las manos más allá de la línea media de forma brusca, generando tensión excesiva en el hombro.","Inclinar el torso hacia adelante y usar el peso del cuerpo para mover la carga.","Doblar los codos en exceso, convirtiendo el movimiento en un press.","No estabilizar el torso, permitiendo que el cuerpo se balancee entre repeticiones."]'::jsonb,
  common_errors_en = '["Crossing the hands well past the midline abruptly, creating excessive shoulder tension.","Leaning the torso forward and using body weight to move the load.","Bending the elbows too much, turning the movement into a press.","Not stabilizing the torso, allowing the body to sway between reps."]'::jsonb,
  pro_tip_es = 'En el punto de cierre, cruzá una mano sobre la otra de forma alternada para maximizar la contracción del pectoral en cada repetición.',
  pro_tip_en = 'At the closed position, alternate crossing one hand over the other to maximize pectoral contraction on each rep.',
  tertiary_muscles = ARRAY['Coracobrachialis','Subscapularis','Core']::text[]
WHERE slug = 'cable-crossover';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá las poleas en la posición alta y posicionáte en el centro con un pie adelantado.","Agarrá las manijas con los brazos extendidos hacia arriba y afuera.","Bajá los brazos en arco hacia abajo y al centro, hasta que las manos se encuentren frente a la cadera.","Mantené los codos ligeramente flexionados y el pecho elevado durante todo el movimiento.","Volvé de forma controlada resistiendo la tensión de las poleas."]'::jsonb,
  execution_steps_en = '["Set pulleys to the high position and stand in the center with one foot forward.","Grip the handles with arms extended upward and outward.","Bring your arms in a downward arc toward center until hands meet at hip level.","Keep elbows slightly bent and chest tall throughout.","Return in a controlled manner, resisting the pulley tension."]'::jsonb,
  common_errors_es = '["Dejar que los hombros se eleven y se adelanten durante el movimiento.","Bajar el peso bruscamente sin controlar la tensión.","Extender completamente los codos, quitando trabajo al pectoral.","No mantener la estabilidad del torso entre repeticiones."]'::jsonb,
  common_errors_en = '["Allowing the shoulders to rise and roll forward during the movement.","Dropping the weight abruptly without controlling the tension.","Fully extending the elbows, removing work from the pectoral.","Not maintaining torso stability between reps."]'::jsonb,
  pro_tip_es = 'Este cruce de polea alta-a-baja aísla la zona inferior y esternal del pectoral; incluilo al final del entrenamiento cuando la musculatura ya está fatigada para maximizar la congestión.',
  pro_tip_en = 'This high-to-low crossover isolates the lower and sternal pectoral; include it at the end of training when the muscle is already fatigued to maximize the pump.',
  tertiary_muscles = ARRAY['Biceps Brachii','Core','Coracobrachialis']::text[]
WHERE slug = 'cable-crossover-high-to-low';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá la polea a la posición baja y posicionáte inclinado hacia adelante o usá un banco inclinado frente a la polea.","Agarrá la manija con las manos a la altura del pecho y los codos doblados.","Empujá la manija hacia arriba y al frente en ángulo inclinado hasta extender el brazo.","Bajá de forma controlada sintiendo el estiramiento en la zona clavicular del pectoral.","Mantené el core activo y evitá arquear la espalda en exceso."]'::jsonb,
  execution_steps_en = '["Set the cable to the low position and position yourself leaning forward or use an incline bench facing the cable.","Grip the handle with hands at chest level and elbows bent.","Press the handle upward and forward at an incline angle until the arm is extended.","Lower in a controlled manner, feeling the stretch in the clavicular pectoral.","Keep the core engaged and avoid excessive back arch."]'::jsonb,
  common_errors_es = '["No mantener el ángulo inclinado del empuje, perdiendo el foco en el pectoral superior.","Dejar que el codo baje por debajo de la línea del pecho.","Extender bruscamente el brazo al final del movimiento.","Usar el hombro en vez del pectoral para completar el movimiento."]'::jsonb,
  common_errors_en = '["Not maintaining the incline angle of the press, losing focus on the upper pectoral.","Allowing the elbow to drop below chest level.","Abruptly extending the arm at the end of the movement.","Using the shoulder instead of the pectoral to complete the movement."]'::jsonb,
  pro_tip_es = 'La polea mantiene tensión constante en el recorrido completo, a diferencia del banco inclinado libre; usá un peso moderado y concentrate en la contracción en la parte superior del movimiento.',
  pro_tip_en = 'The cable maintains constant tension throughout the full range, unlike the free-weight incline bench; use moderate weight and focus on contraction at the top of the movement.',
  tertiary_muscles = ARRAY['Serratus Anterior','Core']::text[]
WHERE slug = 'cable-incline-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el asiento para que las manijas queden a la altura del pecho.","Sentáte con la espalda completamente apoyada en el respaldo y los pies en el suelo.","Agarrá las manijas con los codos a 45°-75° del torso.","Empujá las manijas hacia adelante hasta extender los brazos completamente.","Volvé de forma controlada sin dejar que los pesos se apoyen entre repeticiones."]'::jsonb,
  execution_steps_en = '["Adjust the seat so the handles are at chest height.","Sit with your back fully supported against the pad and feet flat on the floor.","Grip the handles with elbows at 45-75° from the torso.","Push the handles forward until arms are fully extended.","Return in a controlled manner without letting the weight stack rest between reps."]'::jsonb,
  common_errors_es = '["Abrir los codos a 90° del torso, aumentando el estrés en el hombro.","No ajustar correctamente el asiento, lo que desplaza el trabajo hacia los hombros.","Apostar las pesas entre repeticiones, perdiendo la tensión muscular.","Empujar con los brazos asimétricamente."]'::jsonb,
  common_errors_en = '["Flaring elbows to 90° from the torso, increasing shoulder stress.","Not adjusting the seat correctly, shifting work to the shoulders.","Letting the weight stack rest between reps, losing muscular tension.","Pushing asymmetrically with both arms."]'::jsonb,
  pro_tip_es = 'La máquina guiada es ideal para aprender el patrón de movimiento del press; una vez dominado, incorporá las variantes con peso libre para mayor activación muscular.',
  pro_tip_en = 'The guided machine is ideal for learning the press movement pattern; once mastered, incorporate free-weight variations for greater muscle activation.',
  tertiary_muscles = ARRAY['Core','Subscapularis']::text[]
WHERE slug = 'chest-press-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco plano y agarrá la barra con las manos separadas aproximadamente al ancho de los hombros o levemente más juntas.","Bajá la barra de forma controlada hacia la parte baja del pecho con los codos cerca del cuerpo.","Tocá levemente el pecho sin rebotar y empujá hacia arriba extendiendo los codos.","Espirá durante el empuje; inspirá durante la bajada.","Mantené las muñecas en posición neutra y el core apretado durante toda la serie."]'::jsonb,
  execution_steps_en = '["Lie on a flat bench and grip the bar with hands roughly shoulder-width apart or slightly closer.","Lower the bar in a controlled manner to the lower chest, keeping elbows close to the body.","Lightly touch the chest without bouncing and press upward by extending the elbows.","Exhale during the press; inhale during the descent.","Keep wrists in a neutral position and core braced throughout the set."]'::jsonb,
  common_errors_es = '["Poner las manos demasiado juntas, aumentando el estrés en las muñecas.","Abrir los codos al subir, quitando trabajo al tríceps.","Rebotar la barra en el pecho para ganar impulso.","No mantener la barra sobre la muñeca, doblándola hacia atrás."]'::jsonb,
  common_errors_en = '["Placing hands too close together, increasing wrist stress.","Flaring the elbows outward on the press, removing work from the triceps.","Bouncing the bar off the chest for momentum.","Not keeping the bar over the wrist, causing it to hyperextend."]'::jsonb,
  pro_tip_es = 'Mantené los codos cerca del torso durante toda la bajada; así el tríceps trabaja a su máximo potencial y reducís el riesgo en el hombro.',
  pro_tip_en = 'Keep your elbows tucked close to the torso throughout the descent; this maximizes triceps contribution and reduces shoulder risk.',
  tertiary_muscles = ARRAY['Coracobrachialis','Serratus Anterior','Core']::text[]
WHERE slug = 'close-grip-barbell-bench-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco entre -15° y -30° y aseguráte de tener los pies bien sujetos.","Recibí las mancuernas de un compañero o subílas desde las rodillas al recostarte.","Bajá las mancuernas de forma controlada hacia la parte inferior del pecho con los codos a unos 45°-60° del torso.","Empujá hacia arriba y ligeramente hacia el centro hasta extender los brazos.","Espirá al empujar; pedí ayuda para bajar las mancuernas al terminar la serie."]'::jsonb,
  execution_steps_en = '["Set the bench between -15° and -30° and make sure your feet are securely anchored.","Receive the dumbbells from a partner or lift them from your knees as you lie back.","Lower the dumbbells in a controlled manner toward the lower chest with elbows at 45-60° from the torso.","Press upward and slightly toward center until arms are extended.","Exhale on the press; ask for help to bring the dumbbells down at the end of the set."]'::jsonb,
  common_errors_es = '["No asegurar los pies correctamente antes de comenzar la serie.","Intentar series pesadas sin asistencia en posición declinada.","Bajar los codos por debajo de la línea del banco aumentando el estrés en el hombro.","No controlar el peso al finalizar la serie, lo que puede causar lesión."]'::jsonb,
  common_errors_en = '["Not properly securing the feet before starting the set.","Attempting heavy sets without assistance in the decline position.","Dropping elbows below bench level, increasing shoulder stress.","Not controlling the weight at the end of the set, which can cause injury."]'::jsonb,
  pro_tip_es = 'El press declinado activa las fibras inferiores del pectoral; dado el riesgo postural de la posición, priorizá la técnica correcta sobre el peso usado.',
  pro_tip_en = 'The decline press activates the lower pectoral fibers; given the postural risk of the position, prioritize correct technique over the weight used.',
  tertiary_muscles = ARRAY['Subscapularis','Serratus Anterior','Core']::text[]
WHERE slug = 'decline-bench-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Posicionáte sobre las paralelas con los brazos extendidos y el torso ligeramente inclinado hacia adelante.","Bajá el cuerpo doblando los codos hasta que los hombros estén aproximadamente al nivel de los codos.","Mantené el torso inclinado hacia adelante durante toda la bajada para enfatizar el pectoral inferior.","Empujá hacia arriba extendiendo los codos hasta volver a la posición inicial.","Espirá al subir; inspirá al bajar."]'::jsonb,
  execution_steps_en = '["Position yourself on the parallel bars with arms extended and torso slightly leaning forward.","Lower your body by bending the elbows until the shoulders are roughly level with the elbows.","Keep the torso leaning forward throughout the descent to emphasize the lower pectoral.","Press upward by extending the elbows until you return to the starting position.","Exhale on the way up; inhale on the way down."]'::jsonb,
  common_errors_es = '["Mantener el torso muy vertical, desviando el trabajo hacia los tríceps y quitándoselo al pectoral.","Bajar más allá del rango seguro, generando estrés excesivo en el hombro.","Usar demasiado peso adicional antes de dominar la técnica con el peso corporal.","Rebotar en el punto más bajo del movimiento."]'::jsonb,
  common_errors_en = '["Keeping the torso too upright, shifting work to the triceps away from the pectorals.","Descending beyond a safe range, generating excessive shoulder stress.","Adding too much extra weight before mastering technique with bodyweight.","Bouncing at the bottom of the movement."]'::jsonb,
  pro_tip_es = 'La inclinación del torso es la clave: a mayor inclinación, mayor activación del pectoral inferior; si el objetivo es tríceps, mantené el torso recto.',
  pro_tip_en = 'The torso lean is the key: the greater the forward lean, the more the lower pectoral is activated; if targeting triceps, keep the torso upright.',
  tertiary_muscles = ARRAY['Coracobrachialis','Subscapularis','Core']::text[]
WHERE slug = 'dips';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco entre -15° y -30° y aseguráte de tener los pies fijados.","Subí las mancuernas desde las rodillas o recibilas de un compañero al recostarte.","Bajá las mancuernas hacia la parte inferior del pecho con los codos a 45°-60° del torso.","Empujá hacia arriba y levemente al centro hasta extender los brazos.","Volvé de forma controlada y pedí asistencia para soltar las mancuernas al terminar."]'::jsonb,
  execution_steps_en = '["Set the bench to -15 to -30° and secure your feet.","Lift the dumbbells from your knees or receive them from a partner as you lie back.","Lower the dumbbells toward the lower chest with elbows at 45-60° from the torso.","Press upward and slightly inward until arms are extended.","Return in a controlled manner and ask for assistance when dropping the dumbbells at the end."]'::jsonb,
  common_errors_es = '["No fijar los pies correctamente, generando riesgo de caída.","Abrir los codos a 90°, aumentando la carga sobre el hombro anterior.","Usar un rango de movimiento incompleto por exceso de peso.","Soltar las mancuernas bruscamente al finalizar."]'::jsonb,
  common_errors_en = '["Not securing the feet properly, creating a fall risk.","Flaring the elbows to 90°, increasing stress on the anterior shoulder.","Using incomplete range of motion due to excessive weight.","Dropping the dumbbells abruptly at the end."]'::jsonb,
  pro_tip_es = 'Las mancuernas en banco declinado permiten mayor rango de movimiento que la barra; aprovechá eso bajando las mancuernas ligeramente más allá del nivel del pecho.',
  pro_tip_en = 'Dumbbells on a decline bench allow a greater range of motion than the barbell; use that by lowering the dumbbells slightly below chest level.',
  tertiary_muscles = ARRAY['Subscapularis','Serratus Anterior','Core']::text[]
WHERE slug = 'dumbbell-decline-bench-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco entre -15° y -30°, aseguráte de tener los pies fijados y subí las mancuernas.","Posicionáte con los brazos extendidos sobre el pecho inferior y las palmas enfrentadas.","Abrí los brazos en arco hacia los costados manteniendo una leve flexión en los codos.","Bajá hasta sentir un estiramiento cómodo en el pectoral inferior sin forzar el hombro.","Volvé al centro espirando y contrayendo el pectoral en la parte superior del movimiento."]'::jsonb,
  execution_steps_en = '["Set the bench to -15 to -30°, secure your feet, and lift the dumbbells.","Position yourself with arms extended over the lower chest and palms facing each other.","Open your arms in an arc to the sides maintaining a slight bend in the elbows.","Lower until you feel a comfortable stretch in the lower pectoral without stressing the shoulder.","Return to center, exhaling and contracting the pectoral at the top of the movement."]'::jsonb,
  common_errors_es = '["Estirar completamente los codos durante el arco, aumentando el estrés articular.","Bajar las mancuernas demasiado, forzando el hombro en rango extremo.","Usar demasiado peso para una apertura, convirtiendo el ejercicio en un press.","No controlar la bajada, dejando caer los brazos por la gravedad."]'::jsonb,
  common_errors_en = '["Fully straightening the elbows during the arc, increasing joint stress.","Lowering the dumbbells too far, forcing the shoulder into an extreme range.","Using too much weight for a fly, turning it into a press.","Not controlling the descent, letting the arms fall due to gravity."]'::jsonb,
  pro_tip_es = 'Imaginá que estás abrazando un barril al cerrar los brazos; eso te ayuda a mantener la trayectoria en arco y el trabajo en el pectoral.',
  pro_tip_en = 'Imagine you are hugging a barrel as you close your arms; this helps you maintain the arc trajectory and keep the work on the pectoral.',
  tertiary_muscles = ARRAY['Coracobrachialis','Core']::text[]
WHERE slug = 'dumbbell-decline-fly';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco plano con las mancuernas apoyadas sobre los muslos; usá el impulso de las rodillas para subirlas al pecho.","Colocá las mancuernas a la altura del pecho con los codos a unos 45°-75° del torso y las palmas mirando hacia los pies.","Empujá las mancuernas hacia arriba y levemente al centro hasta que los brazos estén casi extendidos.","Bajá de forma controlada más allá del nivel del banco para obtener un mayor estiramiento del pectoral.","Espirá al empujar; inspirá al bajar."]'::jsonb,
  execution_steps_en = '["Lie on a flat bench with dumbbells resting on your thighs; use your knees to help kick them to chest level.","Position the dumbbells at chest height with elbows at 45-75° from the torso and palms facing your feet.","Press the dumbbells upward and slightly inward until arms are nearly extended.","Lower in a controlled manner slightly below bench level for a greater pectoral stretch.","Exhale on the press; inhale on the descent."]'::jsonb,
  common_errors_es = '["Abrir los codos a 90°, poniendo el hombro en una posición vulnerable.","No bajar las mancuernas lo suficiente, acortando el rango de movimiento.","Chocar las mancuernas en la parte superior, perdiendo tensión muscular.","Arquear la espalda baja en exceso para levantar más peso."]'::jsonb,
  common_errors_en = '["Flaring elbows to 90°, putting the shoulder in a vulnerable position.","Not lowering the dumbbells enough, shortening the range of motion.","Clashing the dumbbells at the top, losing muscular tension.","Excessively arching the lower back to lift more weight."]'::jsonb,
  pro_tip_es = 'Las mancuernas permiten mayor rango de movimiento y corrección de desequilibrios lado a lado que la barra; prestá atención a si un lado trabaja más que el otro.',
  pro_tip_en = 'Dumbbells allow a greater range of motion and correction of side-to-side imbalances than the barbell; pay attention to whether one side is doing more work than the other.',
  tertiary_muscles = ARRAY['Subscapularis','Serratus Anterior','Core']::text[]
WHERE slug = 'dumbbell-flat-bench-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco plano con las mancuernas sobre el pecho, palmas enfrentadas y codos ligeramente flexionados.","Abrí los brazos en arco hacia los costados manteniendo esa leve flexión en los codos fija durante todo el movimiento.","Bajá hasta sentir un estiramiento suave en el pectoral sin sobrepasar el nivel del banco.","Cerrá los brazos de vuelta hacia el centro espirando y apretando el pectoral.","No bloqueés los codos en ningún momento del movimiento."]'::jsonb,
  execution_steps_en = '["Lie flat on the bench with dumbbells over the chest, palms facing each other and elbows slightly bent.","Open your arms in an arc to the sides while keeping that slight elbow bend fixed throughout the movement.","Lower until you feel a gentle pectoral stretch without going past bench level.","Close your arms back to center, exhaling and squeezing the pectoral.","Do not lock the elbows at any point during the movement."]'::jsonb,
  common_errors_es = '["Doblar los codos durante el movimiento, convirtiendo la apertura en un press.","Bajar las mancuernas demasiado, sobreestirando el manguito rotador.","Usar demasiado peso para una apertura correcta.","No apretar el pectoral en la parte superior del movimiento."]'::jsonb,
  common_errors_en = '["Bending the elbows during the movement, turning the fly into a press.","Lowering the dumbbells too far, overstretching the rotator cuff.","Using too much weight for a proper fly.","Not squeezing the pectoral at the top of the movement."]'::jsonb,
  pro_tip_es = 'Usá un peso más ligero de lo que creés necesario; las aperturas planas son difíciles de ejecutar correctamente con carga excesiva y el riesgo de lesión en el hombro es real.',
  pro_tip_en = 'Use lighter weight than you think you need; flat dumbbell flys are hard to execute correctly with excessive load and the risk of shoulder injury is real.',
  tertiary_muscles = ARRAY['Coracobrachialis','Core']::text[]
WHERE slug = 'dumbbell-flat-fly';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco entre 30° y 45° e inclinás las mancuernas sobre el pecho superior con las palmas enfrentadas.","Abrí los brazos en arco hacia los costados manteniendo una leve flexión fija en los codos.","Bajá hasta sentir el estiramiento en las fibras superiores del pectoral.","Cerrá los brazos de vuelta hacia el centro espirando y apretando el pectoral.","Mantenés el torso apoyado en el banco sin levantar los glúteos."]'::jsonb,
  execution_steps_en = '["Set the bench to 30-45° and position the dumbbells over the upper chest with palms facing each other.","Open your arms in an arc to the sides maintaining a slight fixed bend in the elbows.","Lower until you feel the stretch in the upper pectoral fibers.","Close your arms back to center, exhaling and squeezing the pectoral.","Keep the torso supported on the bench without lifting the glutes."]'::jsonb,
  common_errors_es = '["Doblar los codos durante el movimiento y convertir la apertura en un press.","Bajar las mancuernas más allá de un rango cómodo, sobreestirando el hombro.","Levantar los glúteos del banco para generar impulso.","Usar cargas excesivas que impiden el control del movimiento."]'::jsonb,
  common_errors_en = '["Bending the elbows during movement, converting the fly into a press.","Lowering the dumbbells past a comfortable range, overstretching the shoulder.","Lifting the glutes off the bench to generate momentum.","Using excessive loads that prevent controlled movement."]'::jsonb,
  pro_tip_es = 'La apertura inclinada aísla mejor la zona clavicular que el press inclinado; usala al final del entrenamiento para congestión específica del pectoral superior.',
  pro_tip_en = 'The incline fly isolates the clavicular area better than the incline press; use it at the end of training for specific upper pectoral pump.',
  tertiary_muscles = ARRAY['Coracobrachialis','Subscapularis','Biceps Brachii']::text[]
WHERE slug = 'dumbbell-fly';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco entre 30° y 45° y sentáte con las mancuernas apoyadas en los muslos.","Usá el impulso de las rodillas para subir las mancuernas al pecho al recostarte.","Bajá las mancuernas hacia la parte superior del pecho con los codos a unos 45°-60° del torso.","Empujá hacia arriba hasta extender los brazos sin chocar las mancuernas en la parte superior.","Espirá al empujar; inspirá al bajar."]'::jsonb,
  execution_steps_en = '["Set the bench to 30-45° and sit with the dumbbells resting on your thighs.","Use your knees to help kick the dumbbells to chest level as you lie back.","Lower the dumbbells toward the upper chest with elbows at 45-60° from the torso.","Press upward until arms are extended without clashing the dumbbells at the top.","Exhale on the press; inhale on the descent."]'::jsonb,
  common_errors_es = '["Inclinar el banco más de 45°, desplazando el trabajo hacia los deltoides anteriores.","Abrir los codos a 90°, generando estrés excesivo en el hombro.","Arqueár la espalda baja para ayudar en el empuje.","Dejar que las mancuernas se inclinen o rueden durante el movimiento."]'::jsonb,
  common_errors_en = '["Setting the bench above 45°, shifting work to the anterior deltoids.","Flaring the elbows to 90°, generating excessive shoulder stress.","Arching the lower back to assist in the press.","Allowing the dumbbells to tilt or roll during the movement."]'::jsonb,
  pro_tip_es = 'Un ángulo de 30° activa el pectoral superior con menor participación del deltoides que 45°; si tu objetivo es pectoral, mantené el banco en el rango bajo.',
  pro_tip_en = 'A 30° angle activates the upper pectoral with less deltoid involvement than 45°; if your goal is chest, keep the bench in the lower range.',
  tertiary_muscles = ARRAY['Subscapularis','Serratus Anterior','Core']::text[]
WHERE slug = 'dumbbell-incline-bench-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco entre 30° y 45° y posicionáte con las mancuernas sobre el pecho superior, palmas enfrentadas.","Abrí los brazos en arco hacia los costados manteniendo una leve flexión fija en los codos.","Bajá hasta sentir el estiramiento en la zona clavicular del pectoral sin sobrepasar el plano del banco.","Cerrá los brazos de vuelta al centro espirando y apretando el pectoral superior.","Controlá el ritmo en todo momento; evitá movimientos bruscos."]'::jsonb,
  execution_steps_en = '["Set the bench to 30-45° and position yourself with dumbbells over the upper chest, palms facing each other.","Open your arms in an arc to the sides maintaining a slight fixed bend in the elbows.","Lower until you feel the stretch in the clavicular pectoral without going past the bench plane.","Close your arms back to center, exhaling and squeezing the upper pectoral.","Control the tempo throughout; avoid sudden movements."]'::jsonb,
  common_errors_es = '["Doblar los codos durante el movimiento y convertir la apertura en un press.","Bajar las mancuernas demasiado, forzando el hombro en un rango extremo.","Usar cargas que impiden la correcta trayectoria en arco.","No apretar el pectoral al cerrar los brazos."]'::jsonb,
  common_errors_en = '["Bending the elbows during movement, turning the fly into a press.","Lowering the dumbbells too far, forcing the shoulder into an extreme range.","Using loads that prevent correct arc trajectory.","Not squeezing the pectoral when closing the arms."]'::jsonb,
  pro_tip_es = 'Combiná el press inclinado con mancuernas con esta apertura inclinada en el mismo entrenamiento para cubrir tanto la zona de fuerza como la de congestión del pectoral superior.',
  pro_tip_en = 'Combine the dumbbell incline press with this incline fly in the same session to cover both the strength and pump zones of the upper pectoral.',
  tertiary_muscles = ARRAY['Coracobrachialis','Core']::text[]
WHERE slug = 'dumbbell-incline-fly';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco plano con las mancuernas a la altura del pecho y las palmas mirando hacia los pies.","Empujá las mancuernas hacia arriba extendiendo los brazos; al finalizar el recorrido girá levemente los pulgares hacia afuera para buscar la contracción final del pectoral esternal.","Bajá de forma controlada permitiendo que las mancuernas queden ligeramente más abajo que el nivel del banco.","Mantené los codos a un ángulo de 45°-60° del torso durante todo el movimiento.","Espirá al empujar; inspirá al bajar."]'::jsonb,
  execution_steps_en = '["Lie on a flat bench with the dumbbells at chest level and palms facing your feet.","Press the dumbbells upward extending your arms; at the end of the range slightly rotate your thumbs outward to seek the final contraction of the sternal pectoral.","Lower in a controlled manner allowing the dumbbells to go slightly below bench level.","Keep elbows at a 45-60° angle from the torso throughout the movement.","Exhale on the press; inhale on the descent."]'::jsonb,
  common_errors_es = '["Forzar el giro del antebrazo en la parte superior más allá del rango cómodo.","Abrir los codos a 90°, aumentando el riesgo en el hombro anterior.","No bajar las mancuernas lo suficiente, acortando el estiramiento del pectoral.","Chocar las mancuernas en la parte superior, perdiendo la tensión muscular."]'::jsonb,
  common_errors_en = '["Forcing the forearm rotation at the top beyond a comfortable range.","Flaring the elbows to 90°, increasing risk on the anterior shoulder.","Not lowering the dumbbells enough, shortening the pectoral stretch.","Clashing the dumbbells at the top, losing muscular tension."]'::jsonb,
  pro_tip_es = 'El giro supino al final del movimiento busca una mayor contracción esternal, pero no lo fuerces; si sentís molestia en la muñeca, realizá el press con agarre neutro.',
  pro_tip_en = 'The supination twist at the end aims for greater sternal contraction, but do not force it; if you feel wrist discomfort, perform the press with a neutral grip.',
  tertiary_muscles = ARRAY['Subscapularis','Serratus Anterior','Core']::text[]
WHERE slug = 'dumbbell-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte transversalmente sobre el banco con los hombros apoyados y las caderas ligeramente abajo.","Sujetá una mancuerna con ambas manos (palmas contra la parte interna del disco superior) sobre el pecho.","Bajá la mancuerna en arco por encima de la cabeza inspirando profundamente hasta que el brazo quede paralelo al suelo o levemente más abajo.","Volvé en arco hacia el pecho espirando y contrayendo el pectoral y el dorsal.","Mantené los codos ligeramente flexionados y la zona lumbar controlada durante todo el movimiento."]'::jsonb,
  execution_steps_en = '["Lie transversely across the bench with your shoulders supported and hips slightly lower.","Hold a single dumbbell with both hands (palms against the inner upper plate) above the chest.","Lower the dumbbell in an arc overhead, inhaling deeply, until the arm is parallel to the floor or slightly below.","Return in an arc toward the chest, exhaling and contracting the pectoral and lats.","Keep elbows slightly bent and lower back controlled throughout."]'::jsonb,
  common_errors_es = '["Doblar los codos durante el movimiento, convirtiendo el ejercicio en un press de tríceps.","Bajar la mancuerna más allá del rango seguro, sobreestirando el hombro.","Permitir que las caderas se eleven al bajar el peso, perdiendo la posición.","Sostener la mancuerna de forma insegura con agarre débil."]'::jsonb,
  common_errors_en = '["Bending the elbows during movement, turning it into a triceps press.","Lowering the dumbbell past a safe range, overstretching the shoulder.","Allowing the hips to rise as the weight descends, losing position.","Holding the dumbbell insecurely with a weak grip."]'::jsonb,
  pro_tip_es = 'El pullover es uno de los pocos ejercicios que trabaja pectoral y dorsal en el mismo arco; expandí el tórax conscientemente al bajar el peso para maximizar el estiramiento.',
  pro_tip_en = 'The pullover is one of the few exercises that works pectorals and lats in the same arc; consciously expand the ribcage as you lower the weight to maximize the stretch.',
  tertiary_muscles = ARRAY['Teres Major','Rhomboids','Core']::text[]
WHERE slug = 'dumbbell-pullover';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte transversalmente en el banco con los hombros apoyados y sujetá la barra corta con agarre en pronación (palmas hacia los pies).","Bajá la barra en arco por encima de la cabeza inspirando hasta que los brazos queden paralelos al suelo.","Volvé en arco hacia el pecho espirando y contrayendo el pectoral y el dorsal.","Mantené los codos semiflexionados durante todo el recorrido.","Prestá especial atención al equilibrio del implemento durante todo el movimiento."]'::jsonb,
  execution_steps_en = '["Lie transversely on the bench with shoulders supported and grip the short bar in pronation (palms facing feet).","Lower the bar in an arc overhead, inhaling, until arms are parallel to the floor.","Return in an arc toward the chest, exhaling and contracting the pectoral and lats.","Keep elbows slightly bent throughout the full range.","Pay special attention to implement balance throughout the movement."]'::jsonb,
  common_errors_es = '["No controlar el equilibrio de la barra corta, generando un movimiento desequilibrado.","Estirar completamente los codos, aumentando el estrés articular.","Bajar la barra más allá del rango seguro para el hombro.","Subir demasiado rápido y perder el control del implemento."]'::jsonb,
  common_errors_en = '["Not controlling the balance of the short bar, creating an unbalanced movement.","Fully extending the elbows, increasing joint stress.","Lowering the bar past the safe range for the shoulder.","Rising too fast and losing control of the implement."]'::jsonb,
  pro_tip_es = 'Esta variante con barra es más desafiante que con mancuerna por el riesgo de desequilibrio; dominá primero la versión con mancuerna antes de probarla.',
  pro_tip_en = 'This barbell variation is more challenging than with a dumbbell due to the balance risk; master the dumbbell version first before attempting this one.',
  tertiary_muscles = ARRAY['Teres Major','Rhomboids','Coracobrachialis']::text[]
WHERE slug = 'dumbbell-pullover-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el suelo con las rodillas dobladas y las mancuernas orientadas hacia adelante.","Extendé los brazos sobre el pecho con las mancuernas alineadas y las palmas enfrentadas.","Dejá rodar las mancuernas hacia adelante por encima de la cabeza acercando el tronco al suelo e inspirando.","Mantené la apnea en el punto más bajo y volvé lentamente a la posición inicial espirando.","Controlá el movimiento evitando que las muñecas colapsen hacia atrás."]'::jsonb,
  execution_steps_en = '["Lie on the floor with knees bent and dumbbells oriented forward.","Extend arms above the chest with dumbbells aligned and palms facing each other.","Allow the dumbbells to roll overhead toward the floor while lowering the trunk and inhaling.","Hold at the bottom and slowly return to the starting position, exhaling.","Control the movement and prevent the wrists from collapsing backward."]'::jsonb,
  common_errors_es = '["No controlar el rodado de las mancuernas, generando riesgo de golpe en el suelo.","Levantar las caderas durante el movimiento, perdiendo la base estable.","Usar demasiado peso, lo que impide el rango de movimiento completo.","No mantener la apnea en el punto más bajo, perdiendo la estabilidad del core."]'::jsonb,
  common_errors_en = '["Not controlling the rolling of the dumbbells, creating a risk of floor impact.","Lifting the hips during the movement, losing the stable base.","Using too much weight, preventing full range of motion.","Not holding the breath at the bottom, losing core stability."]'::jsonb,
  pro_tip_es = 'El suelo actúa como tope natural de seguridad para el rango de movimiento del hombro; esta variante es más segura que el pullover en banco para principiantes.',
  pro_tip_en = 'The floor acts as a natural safety stop for the shoulder range of motion; this variation is safer than the bench pullover for beginners.',
  tertiary_muscles = ARRAY['Teres Major','Rhomboids','Serratus Anterior','Core']::text[]
WHERE slug = 'floor-dumbbell-pullover';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco entre 30° y 45° y agarrá las mancuernas desde las rodillas al recostarte.","Posicioná las mancuernas a la altura del pecho superior con los codos a 45°-60° del torso.","Empujá hacia arriba y levemente al centro hasta extender los brazos.","Bajá de forma controlada permitiendo que las mancuernas queden al nivel del pecho o levemente más abajo.","Espirá al empujar; inspirá al bajar."]'::jsonb,
  execution_steps_en = '["Set the bench to 30-45° and pick up the dumbbells from your knees as you lie back.","Position the dumbbells at upper chest height with elbows at 45-60° from the torso.","Press upward and slightly inward until arms are extended.","Lower in a controlled manner allowing the dumbbells to reach chest level or slightly below.","Exhale on the press; inhale on the descent."]'::jsonb,
  common_errors_es = '["Usar un ángulo de banco mayor de 45°, desplazando el trabajo hacia los deltoides.","Abrir los codos a 90°, cargando el hombro anterior en exceso.","No controlar la bajada, dejando caer las mancuernas por la gravedad.","Levantar los glúteos del banco para generar impulso."]'::jsonb,
  common_errors_en = '["Using a bench angle above 45°, shifting work to the deltoids.","Flaring the elbows to 90°, overloading the anterior shoulder.","Not controlling the descent, letting the dumbbells drop due to gravity.","Lifting the glutes off the bench to generate momentum."]'::jsonb,
  pro_tip_es = 'Un ángulo de 30° es generalmente más efectivo para el pectoral superior que 45°; ajustá el banco al rango bajo y priorizá la conexión mente-músculo.',
  pro_tip_en = 'A 30° angle is generally more effective for the upper pectoral than 45°; set the bench to the lower range and prioritize the mind-muscle connection.',
  tertiary_muscles = ARRAY['Deltoid (Middle Head)','Coracobrachialis','Subscapularis','Core']::text[]
WHERE slug = 'incline-bench-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el asiento de la máquina para que las manijas queden a la altura del pecho superior.","Sentáte con la espalda completamente apoyada en el respaldo inclinado y los pies en el suelo.","Agarrá las manijas con los codos a unos 45°-60° del torso.","Empujá las manijas hacia adelante y arriba hasta extender los brazos.","Volvé de forma controlada sin apoyar los pesos entre repeticiones."]'::jsonb,
  execution_steps_en = '["Adjust the machine seat so the handles are at upper chest height.","Sit with your back fully against the inclined pad and feet flat on the floor.","Grip the handles with elbows at 45-60° from the torso.","Push the handles forward and upward until arms are fully extended.","Return in a controlled manner without letting the weight stack rest between reps."]'::jsonb,
  common_errors_es = '["No ajustar la altura del asiento, desplazando el trabajo hacia los hombros.","Abrir los codos a 90°, generando estrés innecesario en el hombro.","Empujar asimétricamente, compensando con un brazo más fuerte.","Apostar el peso entre repeticiones, perdiendo la tensión muscular."]'::jsonb,
  common_errors_en = '["Not adjusting the seat height, shifting work to the shoulders.","Flaring the elbows to 90°, creating unnecessary shoulder stress.","Pushing asymmetrically, compensating with the stronger arm.","Letting the weight stack rest between reps, losing muscular tension."]'::jsonb,
  pro_tip_es = 'La máquina de press inclinado es ideal para principiantes porque elimina el desafío del equilibrio; una vez dominada, trasladáte a las mancuernas para mayor activación.',
  pro_tip_en = 'The incline chest press machine is ideal for beginners because it eliminates the balance challenge; once mastered, move to dumbbells for greater activation.',
  tertiary_muscles = ARRAY['Core','Subscapularis']::text[]
WHERE slug = 'incline-chest-press-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el banco inclinado con las mancuernas sobre el pecho superior, palmas enfrentadas y codos ligeramente flexionados.","Abrí los brazos en arco hacia los costados manteniendo la flexión fija en los codos.","Al llegar a la horizontal del banco abrí los brazos en cruz en aducción, luego volvé elevando en antepulsión hacia la posición inicial.","Espirá al cerrar; inspirá al abrir.","Mantené el torso apoyado en el banco durante todo el movimiento."]'::jsonb,
  execution_steps_en = '["Lie on the incline bench with dumbbells over the upper chest, palms facing each other and elbows slightly bent.","Open your arms in an arc to the sides maintaining the fixed elbow bend.","At bench horizontal, open arms outward in adduction, then return by elevating with shoulder flexion back to start.","Exhale on the close; inhale on the open.","Keep the torso supported on the bench throughout the movement."]'::jsonb,
  common_errors_es = '["Doblar los codos progresivamente durante el movimiento, quitando el trabajo al pectoral.","Bajar los brazos más allá de la horizontal del banco, sobreestirando el hombro.","Usar un peso excesivo que impide el movimiento fluido en arco.","Levantar los glúteos del banco para ayudarse en la fase de cierre."]'::jsonb,
  common_errors_en = '["Progressively bending the elbows during the movement, removing work from the pectoral.","Lowering the arms past bench horizontal, overstretching the shoulder.","Using excessive weight that prevents the smooth arc movement.","Lifting the glutes off the bench to assist on the closing phase."]'::jsonb,
  pro_tip_es = 'Este ejercicio combina un pullover con una apertura en una sola trayectoria continua; ejecutálo lentamente para aprovechar el rango completo de movimiento.',
  pro_tip_en = 'This exercise combines a pullover with a fly in one continuous trajectory; perform it slowly to take advantage of the full range of motion.',
  tertiary_muscles = ARRAY['Coracobrachialis','Biceps Brachii','Core']::text[]
WHERE slug = 'incline-dumbbell-fly';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá las poleas en la posición baja y posicionáte en el centro con un pie adelantado para estabilizarte.","Agarrá las manijas con los brazos extendidos hacia abajo y atrás.","Subí los brazos en arco hacia arriba y al centro hasta que las manos se encuentren a la altura del pecho.","Mantené una leve flexión en los codos durante todo el movimiento.","Volvé de forma controlada resistiendo la tensión de las poleas."]'::jsonb,
  execution_steps_en = '["Set pulleys to the low position and stand in the center with one foot forward for stability.","Grip the handles with arms extended downward and back.","Raise your arms in an upward arc toward center until hands meet at chest height.","Keep a slight bend in the elbows throughout the movement.","Return in a controlled manner, resisting pulley tension."]'::jsonb,
  common_errors_es = '["Estirar los codos por completo, desviando el trabajo al bíceps.","Levantar los hombros durante el movimiento, quitando el foco al pectoral.","Usar demasiado peso y perder el arco fluido del movimiento.","No controlar el retorno, dejando que la polea jale bruscamente."]'::jsonb,
  common_errors_en = '["Fully extending the elbows, shifting work to the biceps.","Shrugging the shoulders during the movement, losing pectoral focus.","Using too much weight and losing the smooth arc.","Not controlling the return, letting the cable pull abruptly."]'::jsonb,
  pro_tip_es = 'La polea baja es excelente para la zona superior del pectoral que es difícil de congestionar con peso libre; incluila después del press inclinado para un trabajo completo.',
  pro_tip_en = 'The low pulley is excellent for the upper chest area that is hard to pump with free weights; include it after the incline press for complete work.',
  tertiary_muscles = ARRAY['Coracobrachialis','Subscapularis','Core']::text[]
WHERE slug = 'low-cable-chest-fly';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el asiento para que las manijas queden alineadas con el pecho.","Sentáte con la espalda completamente apoyada en el respaldo y los pies en el suelo.","Agarrá las manijas con los codos a unos 45°-60° del torso.","Empujá las manijas hacia adelante hasta extender los brazos.","Volvé de forma controlada sin soltar la tensión entre repeticiones."]'::jsonb,
  execution_steps_en = '["Adjust the seat so the handles are aligned with your chest.","Sit with your back fully supported against the pad and feet flat on the floor.","Grip the handles with elbows at 45-60° from the torso.","Push the handles forward until arms are extended.","Return in a controlled manner without releasing tension between reps."]'::jsonb,
  common_errors_es = '["Sentarse muy bajo, haciendo que el trabajo se desplace a los hombros.","Abrir los codos a 90°, generando estrés excesivo en el hombro anterior.","No controlar la vuelta, dejando que los pesos impacten al stack.","Empujar con los brazos de forma asimétrica."]'::jsonb,
  common_errors_en = '["Sitting too low, causing work to shift to the shoulders.","Flaring the elbows to 90°, generating excessive anterior shoulder stress.","Not controlling the return, letting the weight plates slam the stack.","Pressing asymmetrically with both arms."]'::jsonb,
  pro_tip_es = 'La inclinación o diseño de la máquina guiada ya fija el ángulo de trabajo; ajustá solo la altura del asiento para asegurarte de que la manija quede exactamente a la altura del pecho.',
  pro_tip_en = 'The guided machine''s angle is fixed; only adjust seat height to ensure the handle is exactly at chest level.',
  tertiary_muscles = ARRAY['Serratus Anterior','Subscapularis','Core']::text[]
WHERE slug = 'machine-chest-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el asiento para que los codos queden a la altura de los hombros sobre los almohadillados.","Sentáte con la espalda completamente apoyada y los pies en el suelo.","Apretá los almohadillados hacia el centro en arco hasta que queden frente al pecho.","Mantenés la contracción del pectoral por un segundo en el punto de cierre.","Volvé de forma controlada sin dejar que los pesos impacten al stack."]'::jsonb,
  execution_steps_en = '["Adjust the seat so your elbows are at shoulder height on the pads.","Sit with your back fully supported and feet flat on the floor.","Press the pads toward center in an arc until they are in front of your chest.","Hold the pectoral contraction for one second at the closed position.","Return in a controlled manner without letting the weight stack slam."]'::jsonb,
  common_errors_es = '["Situar los codos por encima de los hombros, cargando el hombro en posición vulnerable.","No ajustar el asiento, lo que impide el rango completo de movimiento.","Usar momentum para cerrar los brazos en vez de contraer el pectoral.","Abrir los brazos más allá del rango cómodo en la fase de retorno."]'::jsonb,
  common_errors_en = '["Placing the elbows above shoulder height, loading the shoulder in a vulnerable position.","Not adjusting the seat, preventing full range of motion.","Using momentum to close the arms instead of contracting the pectoral.","Opening arms beyond comfortable range on the return phase."]'::jsonb,
  pro_tip_es = 'La Pec Deck es ideal para el trabajo de aislamiento al final de la sesión; la trayectoria guiada elimina la necesidad de estabilización y permite concentrarte solo en la contracción.',
  pro_tip_en = 'The Pec Deck is ideal for isolation work at the end of the session; the guided path eliminates the stabilization demand, letting you focus solely on contraction.',
  tertiary_muscles = ARRAY['Coracobrachialis','Core']::text[]
WHERE slug = 'pec-deck-butterfly-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el asiento y las almohadillas del contractor para que al abrir, los brazos queden a la altura de los hombros.","Sentáte con la espalda apoyada y sujetá las manijas o apoyá los antebrazos en las almohadillas.","Cerrá los brazos hacia el centro simulando un abrazo, contrayendo el pectoral durante todo el recorrido.","Mantenés la contracción en el cierre por un segundo antes de volver.","Abrís de forma controlada permitiendo el estiramiento del pectoral."]'::jsonb,
  execution_steps_en = '["Adjust the seat and contractor pads so that when open, your arms are at shoulder height.","Sit with your back supported and grip the handles or rest forearms on the pads.","Close your arms toward center in a hugging motion, contracting the pectoral throughout.","Hold the contraction at the closed position for one second before returning.","Open in a controlled manner allowing the pectoral to stretch."]'::jsonb,
  common_errors_es = '["No ajustar las almohadillas, generando trabajo asimétrico.","Usar momentum del torso para ayudar en el cierre.","Abrir más allá del rango seguro en la fase de retorno.","No mantener la espalda apoyada durante todo el movimiento."]'::jsonb,
  common_errors_en = '["Not adjusting the pads, creating asymmetric work.","Using torso momentum to assist on the close.","Opening past the safe range on the return phase.","Not keeping the back supported throughout the movement."]'::jsonb,
  pro_tip_es = 'A diferencia de las aperturas con mancuernas, el contractor mantiene tensión constante en toda la trayectoria incluyendo el punto de cierre; aprovechá eso haciendo repeticiones lentas.',
  pro_tip_en = 'Unlike dumbbell flys, the contractor maintains constant tension throughout including the closed position; take advantage of that by doing slow reps.',
  tertiary_muscles = ARRAY['Coracobrachialis','Subscapularis','Biceps Brachii (Short Head)']::text[]
WHERE slug = 'pec-deck-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Posicionáte en plancha alta con las manos un poco más anchas que los hombros y el cuerpo en línea recta de cabeza a talones.","Bajá el pecho hacia el suelo doblando los codos a unos 45°-60° del torso.","Tocá o casi tocás el suelo con el pecho manteniendo los glúteos y el core activos.","Empujá el suelo para extender los brazos volviendo a la posición inicial.","Espirá al subir; inspirá al bajar."]'::jsonb,
  execution_steps_en = '["Set up in a high plank with hands slightly wider than shoulder-width and body in a straight line from head to heels.","Lower your chest toward the floor, bending the elbows at 45-60° from the torso.","Touch or nearly touch the floor with your chest while keeping glutes and core engaged.","Push the floor away to extend the arms and return to the start position.","Exhale on the way up; inhale on the way down."]'::jsonb,
  common_errors_es = '["Dejar que las caderas se caigan o se eleven, perdiendo la alineación del cuerpo.","Abrir los codos a 90°, generando estrés excesivo en el hombro.","No bajar hasta el rango completo, reduciendo la activación del pectoral.","Girar la cabeza hacia un lado al bajar, desalineando la columna."]'::jsonb,
  common_errors_en = '["Letting the hips sag or rise, losing body alignment.","Flaring the elbows to 90°, generating excessive shoulder stress.","Not descending to full range, reducing pectoral activation.","Turning the head to one side on the way down, misaligning the spine."]'::jsonb,
  pro_tip_es = 'Podés ajustar la dificultad inclinando el torso: manos sobre un escalón activa más el pectoral inferior; pies sobre el escalón activa más el pectoral superior.',
  pro_tip_en = 'You can adjust difficulty by changing the torso angle: hands on a step activates the lower pectoral more; feet on a step activates the upper pectoral more.',
  tertiary_muscles = ARRAY['Core','Subscapularis','Serratus Anterior']::text[]
WHERE slug = 'push-ups';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco plano debajo de la barra Smith y colocáte con los ojos debajo de la barra.","Agarrá la barra con un agarre ligeramente más ancho que los hombros y desenganché los ganchos de seguridad.","Bajá la barra de forma controlada hasta el pecho medio con los codos a unos 45°-60° del torso.","Empujá hacia arriba hasta extender los brazos y volvé a enganchar los ganchos al finalizar.","Espirá al empujar; inspirá al bajar."]'::jsonb,
  execution_steps_en = '["Position the flat bench under the Smith bar and lie with your eyes under the bar.","Grip the bar slightly wider than shoulder-width and disengage the safety hooks.","Lower the bar in a controlled manner to the mid-chest with elbows at 45-60° from the torso.","Press upward until arms are extended and re-engage the hooks when finished.","Exhale on the press; inhale on the descent."]'::jsonb,
  common_errors_es = '["No desenganchar correctamente los ganchos de seguridad antes de comenzar.","Colocar el banco demasiado adelante o atrás respecto a la barra.","Abrir los codos a 90°, aumentando el estrés en el hombro anterior.","Usar el path fijo de la Smith para mover pesos que superan la técnica."]'::jsonb,
  common_errors_en = '["Not properly disengaging the safety hooks before starting.","Positioning the bench too far forward or back relative to the bar.","Flaring the elbows to 90°, increasing anterior shoulder stress.","Using the Smith''s fixed path to move weights that exceed proper technique."]'::jsonb,
  pro_tip_es = 'La barra Smith elimina la necesidad de equilibrar el peso, lo que la hace ideal para entrenamiento sin asistente; aprovechá los ganchos de seguridad en cada pausa.',
  pro_tip_en = 'The Smith bar eliminates the need to balance the weight, making it ideal for solo training; make use of the safety hooks on each rest.',
  tertiary_muscles = ARRAY['Core','Subscapularis','Serratus Anterior']::text[]
WHERE slug = 'smith-machine-bench-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá el banco con el ángulo deseado (inclinado 30°-45° o declinado ~30°) debajo de la barra Smith.","Agarrá la barra con un agarre al ancho de los hombros o ligeramente más ancho y desenganché los ganchos.","Bajá la barra hacia el área del pecho correspondiente al ángulo del banco de forma controlada.","Empujá la barra hacia arriba hasta extender los brazos.","Volvé a enganchar los ganchos al finalizar la serie."]'::jsonb,
  execution_steps_en = '["Position the bench at the desired angle (30-45° incline or ~30° decline) under the Smith bar.","Grip the bar shoulder-width or slightly wider and disengage the hooks.","Lower the bar toward the chest area corresponding to the bench angle in a controlled manner.","Press the bar upward until arms are extended.","Re-engage the hooks when the set is finished."]'::jsonb,
  common_errors_es = '["No ajustar la posición del banco respecto a la barra según el ángulo elegido.","Abrir los codos en exceso, generando estrés en el hombro.","No controlar la bajada de la barra en la posición declinada.","Superar el peso adecuado confiando excesivamente en la guía de la máquina."]'::jsonb,
  common_errors_en = '["Not adjusting the bench position relative to the bar for the chosen angle.","Flaring the elbows excessively, generating shoulder stress.","Not controlling the bar descent in the decline position.","Exceeding appropriate weight by over-relying on the machine''s guided path."]'::jsonb,
  pro_tip_es = 'En la versión declinada en Smith, el trabajo se concentra en las fibras inferiores del pectoral; aseguráte de que los pies estén bien fijados en todo momento.',
  pro_tip_en = 'In the Smith decline variation, work concentrates on the lower pectoral fibers; make sure your feet are securely anchored at all times.',
  tertiary_muscles = ARRAY['Core','Subscapularis','Serratus Anterior']::text[]
WHERE slug = 'smith-machine-bench-press-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco inclinado (30°-45°) debajo de la barra Smith y posicionáte con el pecho superior bajo la barra.","Agarrá la barra con un agarre al ancho de los hombros o ligeramente más ancho y desenganché los ganchos.","Bajá la barra hacia el pecho superior de forma controlada con los codos a 45°-60° del torso.","Empujá hacia arriba hasta extender los brazos sin bloquear los codos.","Volvé a enganchar los ganchos al finalizar la serie."]'::jsonb,
  execution_steps_en = '["Set the incline bench (30-45°) under the Smith bar and position yourself with the upper chest under the bar.","Grip the bar shoulder-width or slightly wider and disengage the hooks.","Lower the bar toward the upper chest in a controlled manner with elbows at 45-60° from the torso.","Press upward until arms are extended without locking the elbows.","Re-engage the hooks at the end of the set."]'::jsonb,
  common_errors_es = '["No ajustar el banco al ángulo correcto, desplazando el trabajo hacia los hombros.","Situar el banco demasiado atrás, haciendo que la barra quede sobre el cuello.","Abrir los codos a 90°, generando estrés innecesario en el hombro.","Usar el path fijo para levantar más peso del que la técnica permite."]'::jsonb,
  common_errors_en = '["Not setting the bench to the correct angle, shifting work to the shoulders.","Positioning the bench too far back, causing the bar to end up over the neck.","Flaring the elbows to 90°, generating unnecessary shoulder stress.","Using the fixed path to lift more weight than technique allows."]'::jsonb,
  pro_tip_es = 'La Smith inclinada combina la seguridad del path guiado con el foco en el pectoral superior; usala para series pesadas de entrenamiento cuando no tenés asistente.',
  pro_tip_en = 'The incline Smith combines the safety of the guided path with upper pectoral focus; use it for heavy training sets when you do not have a spotter.',
  tertiary_muscles = ARRAY['Core','Subscapularis','Serratus Anterior']::text[]
WHERE slug = 'smith-machine-incline-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el asiento para que el eje de rotación de la máquina quede a la altura de tus costillas flotantes.","Sentáte con la espalda en el respaldo, agarrá las asas laterales y apoyá los antebrazos en los soportes.","Espirá y contraé el abdomen llevando el esternón hacia la pelvis en un arco corto y controlado.","Pausá un segundo en el punto de máxima contracción antes de volver lentamente a la posición inicial.","Inspirá durante el retorno; no dejés que el peso quede sin tensión entre repeticiones."]'::jsonb,
  execution_steps_en = '["Adjust the seat so the machine''s pivot axis aligns with your floating ribs.","Sit with your back against the pad, grip the side handles, and rest your forearms on the supports.","Exhale and contract your abs, bringing the sternum toward the pelvis through a short, controlled arc.","Pause one second at peak contraction before slowly returning to the start position.","Inhale on the return; do not let the weight stack go slack between reps."]'::jsonb,
  common_errors_es = '["Usar el impulso de los hombros hacia adelante en lugar de contraer el abdomen.","Seleccionar tanto peso que el rango de movimiento se acorta a unos pocos grados.","Mantener el cuello tenso y la vista al frente; los ojos deben seguir el movimiento del tronco.","No ajustar el asiento, lo que desplaza el trabajo hacia los flexores de cadera."]'::jsonb,
  common_errors_en = '["Using shoulder momentum instead of abdominal contraction.","Selecting so much weight that range of motion is reduced to just a few degrees.","Keeping the neck tense with eyes fixed forward; gaze should follow the trunk movement.","Not adjusting the seat, shifting work to the hip flexors."]'::jsonb,
  pro_tip_es = 'Imaginá que querés doblar el cuerpo en dos desde el centro; ese cue mental mejora la activación del recto abdominal respecto de pensar en ''bajar los hombros''.',
  pro_tip_en = 'Imagine folding your body in half from the center; this mental cue improves rectus abdominis activation compared to thinking about ''pulling the shoulders down''.',
  tertiary_muscles = ARRAY['Hip Flexors','Tensor Fasciae Latae']::text[]
WHERE slug = 'ab-crunch-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina con la pelvis bloqueada contra el soporte y los pies bien apoyados en las plataformas.","Agarrá las asas o apoyá los muslos bajo el rodillo según el diseño del equipo.","Inspirá y, al espirar, empujá con los pies o muslos hacia arriba generando un encogimiento abdominal.","Concentrá la contracción en acercar la pelvis hacia las costillas, no en solo mover las piernas.","Bajá el soporte de forma controlada sin dejar que el peso golpee la pila al final de la repetición."]'::jsonb,
  execution_steps_en = '["Sit in the machine with the pelvis locked against the support and feet firmly on the platforms.","Grip the handles or place thighs under the roller depending on the machine design.","Inhale and, on the exhale, push with feet or thighs upward to produce an abdominal crunch.","Focus the contraction on bringing the pelvis toward the ribs, not just moving the legs.","Lower the pad under control without letting the weight stack drop at the end of each rep."]'::jsonb,
  common_errors_es = '["Dejar que los flexores de cadera (psoas) dominen el movimiento sin activar el abdomen.","Soltár el control en la fase excéntrica, perdiendo el beneficio del retorno.","Arquear la espalda baja en el inicio en lugar de mantener una postura neutra.","No ajustar la carga para el nivel de entrenamiento, eligiendo tanto peso que solo actúan las caderas."]'::jsonb,
  common_errors_en = '["Letting the hip flexors (psoas) dominate without engaging the abs.","Releasing control on the eccentric phase, losing the benefit of the return.","Arching the lower back at the start instead of maintaining a neutral posture.","Not matching load to training level, choosing so much weight that only the hips work."]'::jsonb,
  pro_tip_es = 'Antes de empujar, exhalá el 30 % del aire y creá presión intraabdominal; eso pre-activa el transverso y protege la zona lumbar durante el movimiento.',
  pro_tip_en = 'Before pushing, exhale about 30% of your air and build intra-abdominal pressure; this pre-activates the transversus abdominis and protects the lower back during the movement.',
  tertiary_muscles = ARRAY['Rectus Femoris','Iliopsoas','Pyramidalis']::text[]
WHERE slug = 'ab-crunch-machine-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco roman a 45° y apoyá las caderas en el soporte con los talones bien afianzados.","Cruzá los brazos sobre el pecho sosteniendo el lastre o extendiélos a los lados; la espalda parte neutra.","Dejá caer el tronco hacia adelante hasta unos 90° de flexión de cadera, manteniendo la espalda recta.","Espirá y extiende el tronco hasta alinear el cuerpo en una línea recta; no hiperextiendas la columna.","Pausá un segundo arriba antes de bajar de forma controlada al punto de partida."]'::jsonb,
  execution_steps_en = '["Set the roman chair to 45° and position your hips on the pad with heels firmly secured.","Cross arms over the chest holding the weight plate, or extend them to the sides; start with a neutral spine.","Lower the torso forward to about 90° of hip flexion, keeping the back straight.","Exhale and extend the torso until the body forms a straight line; do not hyperextend the lumbar spine.","Pause one second at the top before lowering in a controlled manner back to the start."]'::jsonb,
  common_errors_es = '["Hiperextender la columna lumbar al llegar arriba, comprimiendo los discos vertebrales.","Agregar rotación al movimiento, lo que aumenta el riesgo de lesión discal.","Usar un lastre demasiado pesado antes de dominar la técnica con peso corporal.","Descender más allá de los 90° de flexión de cadera cuando el hamstring limita el recorrido."]'::jsonb,
  common_errors_en = '["Hyperextending the lumbar spine at the top, compressing the intervertebral discs.","Adding rotation to the movement, which increases risk of disc injury.","Using a load that is too heavy before mastering the bodyweight technique.","Descending past 90° of hip flexion when hamstring tightness limits the range."]'::jsonb,
  pro_tip_es = 'Si usás lastre, colocálo en el pecho cruzado (no en la nuca) para mantener la columna cervical en posición neutra y reducir el momento de fuerza sobre las vértebras.',
  pro_tip_en = 'If using extra weight, hold it at the crossed chest (not behind the neck) to keep the cervical spine neutral and reduce the force moment on the vertebrae.',
  tertiary_muscles = ARRAY['Gluteus Medius','Piriformis','Adductor Magnus']::text[]
WHERE slug = 'back-extension-incline-bench';
UPDATE public.exercise_library SET
  execution_steps_es = '["Párate con los pies al ancho de hombros y apoyá la barra en la parte alta de la espalda (posición de sentadilla).","Manteniendo la pelvis fija y las rodillas ligeramente flexionadas, inclinàte lateralmente hacia un lado.","Bajá de forma controlada hasta sentir el estiramiento en el oblicuo del lado opuesto.","Volvé a la posición vertical usando los oblicuos y el cuadrado lumbar; no uses rebote.","Completá todas las repeticiones de un lado antes de cambiar al otro."]'::jsonb,
  execution_steps_en = '["Stand with feet shoulder-width apart and rest the bar across the upper back (squat position).","Keeping the pelvis fixed and knees slightly bent, bend laterally to one side.","Lower in a controlled manner until you feel the stretch in the opposite oblique.","Return to vertical using the obliques and quadratus lumborum; do not use momentum.","Complete all reps on one side before switching to the other."]'::jsonb,
  common_errors_es = '["Inclinar la pelvis en lugar de la columna, reduciendo el trabajo sobre los oblicuos.","Usar un rango de movimiento excesivo que estresa la columna lumbar en flexión lateral extrema.","Añadir rotación al movimiento lateral, lo que aumenta la carga en los discos.","Mantener la carga con dos manos, anulando el efecto asimétrico deseado."]'::jsonb,
  common_errors_en = '["Tilting the pelvis instead of the spine, reducing oblique engagement.","Using an excessive range of motion that stresses the lumbar spine in extreme lateral flexion.","Adding rotation to the lateral movement, increasing disc load.","Holding the load with two hands, canceling out the desired asymmetric effect."]'::jsonb,
  pro_tip_es = 'Un movimiento lento y corto (30–40° de recorrido) es más efectivo que un rango exagerado; priorizá la sensación en el oblicuo por sobre la amplitud.',
  pro_tip_en = 'A slow, short movement (30–40° range) is more effective than an exaggerated range; prioritize the oblique sensation over amplitude.',
  tertiary_muscles = ARRAY['Rectus Abdominis','Iliopsoas','Multifidus']::text[]
WHERE slug = 'barbell-side-bend';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte en un banco inclinado con el tronco levemente reclinado hacia atrás, sosteniendo la barra en la zona del pecho.","Activá el abdomen para mantener el tronco estable antes de iniciar cualquier rotación.","Girá el tronco hacia un lado de forma controlada llevando la barra en el mismo sentido.","Volvé al centro y repetí hacia el otro lado en un movimiento suave, sin impulso.","Mantenè el ritmo lento; si sentís dolor lumbar, interrumpí el ejercicio de inmediato."]'::jsonb,
  execution_steps_en = '["Position yourself on an inclined bench with the torso slightly reclined back, holding the bar at chest level.","Activate the abs to stabilize the torso before starting any rotation.","Rotate the torso to one side in a controlled manner, moving the bar in the same direction.","Return to center and repeat to the other side in a smooth, momentum-free movement.","Keep the pace slow; if you feel lower back pain, stop the exercise immediately."]'::jsonb,
  common_errors_es = '["Girar solo los brazos moviendo la barra sin rotar realmente el tronco.","Usar impulso o velocidad excesiva, aumentando el riesgo de lesión discal.","Reclinarse demasiado hacia atrás, convirtiendo el ejercicio en un crunch con rotación.","Ignorar el dolor lumbar o la sensación de pinchazos en la zona baja de la espalda."]'::jsonb,
  common_errors_en = '["Only moving the arms with the bar without actually rotating the torso.","Using excessive momentum or speed, increasing the risk of disc injury.","Reclining too far back, turning the exercise into a crunch with rotation.","Ignoring lower back pain or a pinching sensation in the lumbar region."]'::jsonb,
  pro_tip_es = 'Este ejercicio tiene potencial lesivo para los discos intervertebrales; si no tenés experiencia sólida en rotación de core, priorizá el cable wood chop o el Pallof press como alternativas más seguras.',
  pro_tip_en = 'This exercise carries injury risk for the intervertebral discs; if you lack solid core rotation experience, prioritize the cable wood chop or Pallof press as safer alternatives.',
  tertiary_muscles = ARRAY['Transversus Abdominis','Multifidus','Hip Flexors']::text[]
WHERE slug = 'barbell-twists-russian-twist-with-bar';
UPDATE public.exercise_library SET
  execution_steps_es = '["Enganchá una cuerda de tríceps a la polea alta y arrodilláte de frente a la máquina, a unos 50 cm de la columna.","Agarrá los extremos de la cuerda a ambos lados de la cabeza; los codos apuntan hacia adelante.","Espirá y llevá los codos hacia las rodillas curvando la columna; la cadera NO se flexiona.","Pausá un segundo en el punto de máxima contracción del recto abdominal.","Volvé lentamente a la posición inicial controlando el peso durante todo el trayecto."]'::jsonb,
  execution_steps_en = '["Attach a rope handle to the high pulley and kneel facing the machine, about 50 cm from the column.","Grip the rope ends on either side of your head with elbows pointing forward.","Exhale and bring the elbows toward the knees by curling the spine; the hips do NOT flex.","Pause one second at peak rectus abdominis contraction.","Return slowly to the start position, controlling the weight throughout."]'::jsonb,
  common_errors_es = '["Flexionar las caderas en lugar de curvar la columna, convirtiendo el ejercicio en un jalón de cadera.","Tirar de la cuerda con los brazos en vez de contraer el abdomen.","Arrodillarse demasiado lejos de la máquina, reduciendo el ángulo de tensión efectiva.","No controlar la fase excéntrica, dejando que el peso suba sin resistencia."]'::jsonb,
  common_errors_en = '["Flexing the hips instead of curling the spine, turning the exercise into a hip pull-down.","Pulling the rope with the arms instead of contracting the abs.","Kneeling too far from the machine, reducing the effective tension angle.","Not controlling the eccentric phase, allowing the weight to rise without resistance."]'::jsonb,
  pro_tip_es = 'Fijá los glúteos sobre los talones durante toda la serie; si los glúteos se elevan, estás usando caderas en vez de abdominales.',
  pro_tip_en = 'Keep your glutes resting on your heels throughout the set; if the glutes rise, you are using hips instead of abs.',
  tertiary_muscles = ARRAY['Hip Flexors','Serratus Anterior','Tensor Fasciae Latae']::text[]
WHERE slug = 'cable-crunch';
UPDATE public.exercise_library SET
  execution_steps_es = '["Enganchá una barra recta o cuerda a la polea alta y arrodilláte de frente a ella.","Agarrá el agarre con ambas manos frente a la frente, codos apuntando hacia adelante.","Espirá y curvá la columna llevando el esternón hacia las rodillas manteniendo la cadera fija.","Mantené el cuerpo bloqueado de cintura hacia abajo; solo el tronco superior se mueve.","Volvé de forma controlada a la posición inicial sin dejar que el peso descanse entre repeticiones."]'::jsonb,
  execution_steps_en = '["Attach a straight bar or rope to the high pulley and kneel facing it.","Grip the handle with both hands in front of your forehead, elbows pointing forward.","Exhale and curl the spine, bringing the sternum toward the knees while keeping the hips fixed.","Keep the body locked from the waist down; only the upper trunk moves.","Return in a controlled manner to the start without letting the weight rest between reps."]'::jsonb,
  common_errors_es = '["Permitir que las caderas bajen durante el crunch, generando un movimiento de bisagra en vez de curvatura espinal.","Separar las manos del agarre o flexionar los codos en exceso, transfiriendo trabajo a los brazos.","Realizar el movimiento demasiado rápido, perdiendo el tiempo bajo tensión.","No ajustar el peso al nivel de entrenamiento, lo que fuerza compensaciones con otros músculos."]'::jsonb,
  common_errors_en = '["Letting the hips drop during the crunch, creating a hinge movement instead of spinal flexion.","Releasing the handle grip or excessively bending the elbows, transferring work to the arms.","Performing the movement too fast, losing time under tension.","Not matching the weight to training level, forcing compensations with other muscles."]'::jsonb,
  pro_tip_es = 'Esta variante ''de rezo'' permite una carga mayor que el crunch convencional con cuerda; progresá el peso en incrementos pequeños y verificá que el rango no se reduzca al agregar carga.',
  pro_tip_en = 'This ''prayer'' variant allows heavier loading than the conventional rope crunch; increase weight in small increments and verify that range of motion does not decrease as load goes up.',
  tertiary_muscles = ARRAY['Transversus Abdominis','Iliopsoas','Pyramidalis']::text[]
WHERE slug = 'cable-crunch-kneeling';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá la polea a la altura del pecho y agarrá el agarre con ambas manos, parado de lado a la máquina.","Alejáte hasta que el cable esté tenso, con los pies al ancho de hombros y las rodillas levemente flexionadas.","Sostené el agarre frente al esternón, activá el core y el glúteo, y empujá las manos hacia adelante.","Extendé los brazos completamente sin dejar que el cable rote el torso; mantenélos extendidos 2 segundos.","Volvé las manos al esternón de forma controlada y repetí; el torso permanece perfectamente perpendicular al cable."]'::jsonb,
  execution_steps_en = '["Set the pulley at chest height and grip the handle with both hands, standing sideways to the machine.","Step away until the cable is taut, feet shoulder-width apart, knees slightly bent.","Hold the handle at the sternum, activate the core and glutes, and press hands straight out.","Fully extend the arms without letting the cable rotate the torso; hold extended for 2 seconds.","Return hands to the sternum under control and repeat; the torso remains perfectly perpendicular to the cable."]'::jsonb,
  common_errors_es = '["Permitir que el cable arrastre el torso en rotación, perdiendo el estímulo antirotacional.","Pararse demasiado cerca de la máquina, reduciendo la tensión real sobre el core.","Bloquear la respiración durante el press, aumentando innecesariamente la presión sanguínea.","Flexionar las rodillas de forma excesiva o cambiar la base de apoyo durante la serie."]'::jsonb,
  common_errors_en = '["Letting the cable pull the torso into rotation, losing the anti-rotation stimulus.","Standing too close to the machine, reducing actual tension on the core.","Holding the breath throughout the press, unnecessarily elevating blood pressure.","Excessively bending the knees or shifting the base of support during the set."]'::jsonb,
  pro_tip_es = 'El Pallof press es un ejercicio de estabilidad, no de movimiento; el objetivo es resistir la rotación, no generarla. Es ideal para rehabilitación y como activación de core antes de levantamientos pesados.',
  pro_tip_en = 'The Pallof press is a stability exercise, not a movement exercise; the goal is to resist rotation, not produce it. It is ideal for rehabilitation and as a core activation drill before heavy lifts.',
  tertiary_muscles = ARRAY['Gluteus Medius','Multifidus','Hip Abductors']::text[]
WHERE slug = 'cable-pallof-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá la polea en posición alta y agarrá el agarre con ambas manos, parado de lado a la máquina.","Con los brazos extendidos y el core activo, jalá el cable diagonalmente hacia abajo y al frente, rotando el tronco.","Guiá el movimiento desde la rotación torácica; las caderas acompañan levemente pero no lideran.","Llegá al punto final (manos frente a la cadera contraria) sin perder la tensión abdominal.","Volvé al punto de inicio de forma controlada, resistiendo la rotación de vuelta."]'::jsonb,
  execution_steps_en = '["Set the pulley in the high position and grip the handle with both hands, standing sideways to the machine.","With arms extended and core engaged, pull the cable diagonally down and forward, rotating the torso.","Drive the movement from thoracic rotation; the hips accompany slightly but do not lead.","Reach the end point (hands in front of the opposite hip) without losing abdominal tension.","Return to the start in a controlled manner, resisting the reverse rotation."]'::jsonb,
  common_errors_es = '["Rotar desde las caderas y no desde el tronco, reduciendo el trabajo de oblicuos.","Doblar los codos durante el jalón, convirtiendo el movimiento en un jalón de brazos.","Usar demasiado peso, lo que obliga a usar momentum y elimina el control.","Realizar el movimiento en un plano puramente horizontal, que no es el patrón funcional del ejercicio."]'::jsonb,
  common_errors_en = '["Rotating from the hips rather than the torso, reducing oblique engagement.","Bending the elbows during the pull, turning it into an arm pulldown.","Using too much weight, which forces momentum and eliminates control.","Performing the movement in a purely horizontal plane, which is not the functional pattern of the exercise."]'::jsonb,
  pro_tip_es = 'También podés hacerlo en variante ''low to high'' (de abajo hacia arriba) para cambiar el ángulo de reclutamiento de los oblicuos; combiná ambas variantes en el mismo bloque de entrenamiento.',
  pro_tip_en = 'You can also perform it in the ''low to high'' variant to change the oblique recruitment angle; combine both variants within the same training block.',
  tertiary_muscles = ARRAY['Anterior Deltoid','Gluteus Medius','Hip Rotators']::text[]
WHERE slug = 'cable-wood-chop';
UPDATE public.exercise_library SET
  execution_steps_es = '["Subíte a la silla del capitán y apoyá los antebrazos en las almohadillas; la espalda queda contra el respaldo.","Dejá las piernas colgando y activá el core antes de iniciar el movimiento.","Espirá y elevá las rodillas hacia el pecho (variante principiante) o las piernas extendidas hasta la horizontal (variante avanzada).","Mantené la pelvis en retroversión (cola hacia abajo) durante la subida para maximizar el trabajo del recto abdominal.","Bajá las piernas de forma lenta y controlada sin balancear el cuerpo."]'::jsonb,
  execution_steps_en = '["Mount the captain''s chair and rest your forearms on the pads; the back rests against the backrest.","Let the legs hang and activate the core before starting the movement.","Exhale and raise the knees toward the chest (beginner) or straight legs to horizontal (advanced).","Keep the pelvis in posterior tilt (tailbone down) during the raise to maximize rectus abdominis work.","Lower the legs slowly and in a controlled manner without swinging the body."]'::jsonb,
  common_errors_es = '["Balancear las piernas para tomar impulso en lugar de usar la fuerza abdominal.","Dejar que la pelvis quede en anteversión (espalda baja arqueada), transfiriendo trabajo a los flexores de cadera.","Subir las piernas solo a 45° y creer que es un rango completo de movimiento.","Bajar las piernas de golpe, perdiendo el beneficio de la fase excéntrica."]'::jsonb,
  common_errors_en = '["Swinging the legs to generate momentum instead of using abdominal strength.","Letting the pelvis go into anterior tilt (arched lower back), transferring work to hip flexors.","Raising the legs only to 45° and believing it is a full range of motion.","Dropping the legs suddenly, losing the benefit of the eccentric phase."]'::jsonb,
  pro_tip_es = 'Antes de subir las piernas, incliná levemente la pelvis hacia atrás (retroversión); ese pequeño ajuste activa el recto abdominal desde el inicio y reduce la participación del psoas.',
  pro_tip_en = 'Before raising the legs, slightly tilt the pelvis backward (posterior tilt); that small adjustment activates the rectus abdominis from the start and reduces psoas involvement.',
  tertiary_muscles = ARRAY['Iliopsoas','Tensor Fasciae Latae','Hip Flexors']::text[]
WHERE slug = 'captains-chair-leg-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el suelo con las rodillas flexionadas a 90°, pies apoyados y manos detrás de la cabeza (sin entrelazar).","Activá el core antes del movimiento y aplastá la zona lumbar contra el suelo.","Espirá y elevá el esternón hacia las rodillas curvando la parte alta de la espalda; la zona lumbar permanece en contacto con el suelo.","Alcanzá el punto de máxima curvatura, pausá un segundo y bajá de forma controlada.","No jalés la cabeza con las manos; los codos permanecen abiertos durante todo el movimiento."]'::jsonb,
  execution_steps_en = '["Lie on the floor with knees bent to 90°, feet flat and hands behind the head (not interlocked).","Activate the core before the movement and press the lower back into the floor.","Exhale and lift the sternum toward the knees by curling the upper back; the lower back stays in contact with the floor.","Reach maximum curvature, pause one second, then lower in a controlled manner.","Do not pull the head with your hands; elbows stay open throughout the movement."]'::jsonb,
  common_errors_es = '["Jalar la cabeza con las manos, generando tensión cervical y reduciendo el trabajo abdominal.","Intentar sentar el tronco completo, convirtiendo el crunch en un sit-up con carga lumbar.","Subir y bajar demasiado rápido, reduciendo el tiempo bajo tensión.","Despegar los pies del suelo durante la contracción, alterando la mecánica del ejercicio."]'::jsonb,
  common_errors_en = '["Pulling the head with the hands, creating cervical tension and reducing abdominal work.","Trying to fully sit up, turning the crunch into a sit-up with lumbar load.","Moving up and down too fast, reducing time under tension.","Lifting the feet off the floor during the contraction, altering exercise mechanics."]'::jsonb,
  pro_tip_es = 'Exhalá completamente al subir y forzá la espiración al máximo en el punto de contracción; esa maniobra aumenta la activación del recto abdominal y el transverso sin agregar carga externa.',
  pro_tip_en = 'Fully exhale as you rise and force maximum exhalation at the peak contraction; this technique increases rectus abdominis and transversus activation without adding external load.',
  tertiary_muscles = ARRAY['Transversus Abdominis','Iliopsoas','Pyramidalis']::text[]
WHERE slug = 'crunch-floor';
UPDATE public.exercise_library SET
  execution_steps_es = '["Acomodate en el banco decline con las rodillas flexionadas y los tobillos fijos bajo el soporte.","Cruzá los brazos sobre el pecho o apoyá las manos en las sienes; nunca detrás de la nuca.","Espirá y elevá el tronco curvando la espalda desde la zona lumbar hacia arriba hasta quedar casi erguido.","Mantené la contracción abdominal durante todo el ascenso y no usés el rebote para bajar.","Bajá de forma lenta y controlada hasta que la espalda quede en contacto con el banco."]'::jsonb,
  execution_steps_en = '["Position yourself on the decline bench with knees bent and ankles secured under the pad.","Cross arms over the chest or rest hands at the temples; never behind the neck.","Exhale and raise the torso by curling the spine from the lower back upward until nearly upright.","Maintain abdominal contraction throughout the ascent and do not use a bounce to descend.","Lower slowly and in a controlled manner until the back contacts the bench."]'::jsonb,
  common_errors_es = '["Rebotar el tronco al llegar al punto más alto para bajar con impulso.","Usar las manos detrás de la nuca jalando la cabeza, aumentando el riesgo de lesión cervical.","Inclinar el banco demasiado, generando una carga lumbar excesiva en personas sin base de entrenamiento.","Dejar los pies completamente extendidos, transfiriendo la carga a los flexores de cadera."]'::jsonb,
  common_errors_en = '["Bouncing the torso at the top to generate momentum for the descent.","Using hands behind the neck to pull the head, increasing cervical injury risk.","Inclining the bench too steeply, creating excessive lumbar load for untrained individuals.","Keeping the feet fully extended, shifting the load to hip flexors."]'::jsonb,
  pro_tip_es = 'A mayor inclinación del banco, mayor participación de los flexores de cadera (psoas); para aislar mejor el abdomen usá un ángulo moderado (20–30°) y concentráte en la curvatura espinal.',
  pro_tip_en = 'The steeper the bench angle, the more hip flexors (psoas) contribute; for better abdominal isolation use a moderate angle (20–30°) and focus on spinal flexion.',
  tertiary_muscles = ARRAY['Iliopsoas','Rectus Femoris','Hip Flexors']::text[]
WHERE slug = 'decline-sit-up';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en el suelo con las rodillas flexionadas a 90° y los pies apoyados (o levemente levantados para mayor dificultad).","Incliná el tronco hacia atrás unos 45°, manteniéndo la espalda recta sin redondear.","Sostené la mancuerna con ambas manos frente al pecho con los brazos ligeramente flexionados.","Espirá y rotá el tronco hacia un lado llevando la mancuerna cerca del suelo a ese lado.","Volvé al centro y repetí hacia el otro lado en un movimiento continuo y controlado."]'::jsonb,
  execution_steps_en = '["Sit on the floor with knees bent to 90° and feet flat (or slightly raised for more difficulty).","Lean the torso back about 45°, keeping the back straight without rounding.","Hold the dumbbell with both hands in front of the chest with arms slightly bent.","Exhale and rotate the torso to one side, bringing the dumbbell close to the floor on that side.","Return to center and repeat to the other side in a continuous, controlled movement."]'::jsonb,
  common_errors_es = '["Rotar solo los brazos moviendo la mancuerna sin girar realmente el tronco.","Redondear la espalda baja en lugar de mantenerla recta durante la inclinación.","Hacer el movimiento muy rápido, usando impulso en vez de fuerza abdominal.","Mantener los pies pegados al suelo cuando el nivel del ejercicio ya lo permite, reduciendo la demanda sobre el core."]'::jsonb,
  common_errors_en = '["Only moving the arms with the dumbbell without actually rotating the torso.","Rounding the lower back instead of keeping it straight during the lean.","Moving too fast, using momentum instead of abdominal strength.","Keeping feet flat when your level allows raising them, reducing the core demand."]'::jsonb,
  pro_tip_es = 'Mantené la mirada al frente en lugar de seguir la mancuerna con los ojos; esto facilita que la rotación provenga del tronco y no solo del cuello.',
  pro_tip_en = 'Keep your gaze forward rather than following the dumbbell with your eyes; this helps ensure the rotation comes from the torso rather than just the neck.',
  tertiary_muscles = ARRAY['Hip Flexors','Transversus Abdominis','Latissimus Dorsi']::text[]
WHERE slug = 'dumbbell-russian-twist';
UPDATE public.exercise_library SET
  execution_steps_es = '["Párate con los pies al ancho de hombros y sostenè una mancuerna en una mano con agarre neutro.","La mano libre puede descansar en la cintura o extenderse levemente al costado para equilibrio.","Manteniéndo la pelvis fija, inclinàte lateralmente hacia el lado de la mancuerna de forma controlada.","Sentí el estiramiento en el oblicuo del lado contrario y volvé a la posición vertical contrayendo ese oblicuo.","Completá todas las repeticiones de un lado antes de cambiar la mancuerna al otro."]'::jsonb,
  execution_steps_en = '["Stand with feet shoulder-width apart and hold a dumbbell in one hand with a neutral grip.","The free hand can rest on the hip or extend slightly to the side for balance.","With the pelvis fixed, bend laterally toward the dumbbell side in a controlled manner.","Feel the stretch in the opposite oblique and return to vertical by contracting that oblique.","Complete all reps on one side before switching the dumbbell to the other hand."]'::jsonb,
  common_errors_es = '["Usar ambas manos con mancuernas (una por lado), ya que los momentos de fuerza se anulan.","Desplazar la pelvis hacia el lado contrario en vez de inclinar la columna.","Elegir un peso demasiado pesado que obliga a usar rebote o compensaciones.","Inclinar el tronco hacia adelante durante la flexión lateral, mezclando planos de movimiento."]'::jsonb,
  common_errors_en = '["Using both hands with dumbbells (one per side), as the force moments cancel each other out.","Shifting the pelvis to the opposite side instead of bending the spine.","Choosing a weight so heavy it forces momentum or compensation.","Leaning the torso forward during the lateral bend, mixing planes of movement."]'::jsonb,
  pro_tip_es = 'El cuadrado lumbar del lado opuesto trabaja significativamente en este ejercicio; si buscás aislar los oblicuos, enfocáte en la sensación de acortamiento lateral y no solo en llegar tan abajo como sea posible.',
  pro_tip_en = 'The quadratus lumborum on the opposite side works significantly in this exercise; if you aim to isolate the obliques, focus on the lateral shortening sensation rather than just reaching as far down as possible.',
  tertiary_muscles = ARRAY['Quadratus Lumborum','Multifidus','Iliocostalis']::text[]
WHERE slug = 'dumbbell-side-bend';
UPDATE public.exercise_library SET
  execution_steps_es = '["Párate con los pies al ancho de hombros y sostené una mancuerna con ambas manos (agarre diamante).","Llevá la mancuerna hacia un lado y arriba (posición inicial alta) con el tronco levemente rotado.","Jalá la mancuerna en diagonal hacia abajo y al lado contrario, rotando el tronco y acompañando con las caderas.","Llegá al punto bajo (mancuerna frente a la cadera contraria) con los brazos casi extendidos.","Volvé al punto inicial de forma controlada resistiendo la rotación de vuelta."]'::jsonb,
  execution_steps_en = '["Stand with feet shoulder-width apart and hold a dumbbell with both hands (diamond grip).","Bring the dumbbell to one side and up (high start position) with the torso slightly rotated.","Pull the dumbbell diagonally downward and to the opposite side, rotating the torso and following with the hips.","Reach the low point (dumbbell in front of the opposite hip) with arms nearly extended.","Return to the start in a controlled manner, resisting the reverse rotation."]'::jsonb,
  common_errors_es = '["Mover solo los brazos sin rotar el tronco, reduciendo el trabajo de oblicuos.","Bloquear completamente las caderas, perdiendo el patrón de movimiento funcional.","Usar demasiado peso, obligando a acelerar el movimiento y perder control.","No controlar el retorno, dejando que el peso arrastre el tronco hacia el punto inicial."]'::jsonb,
  common_errors_en = '["Moving only the arms without rotating the torso, reducing oblique engagement.","Completely locking out the hips, losing the functional movement pattern.","Using too much weight, forcing acceleration and loss of control.","Not controlling the return, letting the weight drag the torso back to the start."]'::jsonb,
  pro_tip_es = 'La mancuerna es una alternativa práctica al cable; el cable ofrece tensión constante durante todo el arco, mientras que la mancuerna tiene mayor carga en los extremos del movimiento. Combiná ambos para mayor variedad.',
  pro_tip_en = 'The dumbbell is a practical alternative to the cable; the cable provides constant tension throughout the arc, while the dumbbell loads more at the movement extremes. Combine both for greater variety.',
  tertiary_muscles = ARRAY['Anterior Deltoid','Gluteus Medius','Iliopsoas']::text[]
WHERE slug = 'dumbbell-wood-chop';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en el suelo boca arriba con los brazos extendidos al frente o cruzados en el pecho.","Activá el core aplastando la zona lumbar contra el suelo antes de iniciar el movimiento.","Elevá las piernas y el tronco simultáneamente hacia el centro (variante tijera, uve o carpa) según el ejercicio elegido.","Mantené la contracción abdominal en el punto de máximo acercamiento entre tronco y piernas.","Bajá de forma controlada sin apoyar completamente ni pies ni espalda entre repeticiones."]'::jsonb,
  execution_steps_en = '["Lie face up on the floor with arms extended forward or crossed at the chest.","Activate the core by pressing the lower back into the floor before starting the movement.","Raise the legs and torso simultaneously toward each other (scissors, V-up, or jackknife variant) depending on the chosen exercise.","Hold the abdominal contraction at the point of maximum torso-to-leg approximation.","Lower in a controlled manner without fully resting feet or back between reps."]'::jsonb,
  common_errors_es = '["Apoyar la espalda baja completamente entre repeticiones, perdiendo la tensión constante.","Usar impulso de brazos o piernas para generar el movimiento en lugar de la fuerza abdominal.","Mantener las piernas completamente rectas si la cadena posterior es corta, aumentando la tensión lumbar.","Ignorar el dolor o tirón en la zona lumbar, que indica exceso de demanda sobre la columna."]'::jsonb,
  common_errors_en = '["Fully resting the lower back between reps, losing constant tension.","Using arm or leg momentum to generate the movement instead of abdominal strength.","Keeping the legs fully straight if posterior chain flexibility is limited, increasing lumbar tension.","Ignoring lower back pain or pulling sensation, which signals excessive spinal demand."]'::jsonb,
  pro_tip_es = 'Las variantes de suelo de este tipo (uve, tijera, carpa) tienen alta demanda sobre los flexores de cadera; si el objetivo principal es el abdomen, el crunch o el cable crunch son opciones con mejor aislamiento.',
  pro_tip_en = 'Floor variations of this type (V-up, scissors, jackknife) place high demand on the hip flexors; if the primary goal is abdominal development, the crunch or cable crunch offer better isolation.',
  tertiary_muscles = ARRAY['Iliopsoas','Rectus Femoris','Transversus Abdominis']::text[]
WHERE slug = 'floor-ab-variations';
UPDATE public.exercise_library SET
  execution_steps_es = '["Apoyá los antebrazos en los soportes del banco vertical o usá las agarraderas laterales para estabilizarte.","Dejá las piernas colgando y activá el core antes de iniciar el movimiento.","Espirá y flexioná las caderas llevando las rodillas hacia el pecho o las piernas extendidas hacia arriba.","Realizá una retroversión pélvica (cola hacia abajo) en el punto más alto para maximizar el trabajo del recto abdominal.","Bajá de forma lenta y controlada sin balancear el cuerpo."]'::jsonb,
  execution_steps_en = '["Rest your forearms on the vertical bench supports or use the side handles to stabilize.","Let the legs hang and activate the core before starting the movement.","Exhale and flex the hips, bringing knees toward the chest or raising straight legs upward.","Perform a posterior pelvic tilt (tailbone down) at the top to maximize rectus abdominis work.","Lower slowly and in a controlled manner without swinging the body."]'::jsonb,
  common_errors_es = '["Balancear el cuerpo para ganar impulso en vez de usar la fuerza del abdomen.","No realizar la retroversión pélvica en el punto más alto, lo que transfiere el trabajo a los flexores de cadera.","Bajar las piernas demasiado rápido, perdiendo el control y la fase excéntrica.","Mantener los brazos completamente rígidos en los soportes, generando tensión innecesaria en los hombros."]'::jsonb,
  common_errors_en = '["Swinging the body to gain momentum instead of using abdominal strength.","Not performing the posterior pelvic tilt at the top, shifting work to hip flexors.","Lowering the legs too fast, losing control and the eccentric phase.","Keeping the arms completely rigid on the supports, generating unnecessary shoulder tension."]'::jsonb,
  pro_tip_es = 'Si no podés elevar las piernas rectas, empezá con rodillas flexionadas; a medida que mejore la fuerza del core y la flexibilidad del psoas, extendé gradualmente las rodillas.',
  pro_tip_en = 'If you cannot raise straight legs, start with bent knees; as core strength and psoas flexibility improve, gradually extend the knees.',
  tertiary_muscles = ARRAY['Hip Flexors','Iliopsoas','Tensor Fasciae Latae']::text[]
WHERE slug = 'hanging-leg-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colgáte de la barra fija con agarre en pronación y las manos separadas al ancho de hombros.","Activá el core y estabilizá el cuerpo antes de iniciar el movimiento.","Espirá y elevá las piernas (flexionadas para principiantes, extendidas para avanzados) hasta la horizontal o más.","Realizá retroversión pélvica en el punto más alto para activar el recto abdominal y reducir la participación del psoas.","Bajá de forma controlada resistiendo el descenso; no soltés el control para que el cuerpo no balancee."]'::jsonb,
  execution_steps_en = '["Hang from the fixed bar with a pronated grip, hands shoulder-width apart.","Activate the core and stabilize the body before starting the movement.","Exhale and raise the legs (bent for beginners, straight for advanced) to horizontal or above.","Perform a posterior pelvic tilt at the top to activate the rectus abdominis and reduce psoas involvement.","Lower in a controlled manner, resisting the descent; do not release control to avoid body swinging."]'::jsonb,
  common_errors_es = '["Balancear el cuerpo hacia adelante con impulso para subir las piernas.","No controlar el descenso, dejando que las piernas caigan libremente.","Aferrarse a la barra con tanta fuerza que se genera tensión en cuello y hombros.","Subir las piernas solo hasta 45° y considerar eso como una repetición completa."]'::jsonb,
  common_errors_en = '["Swinging the body forward to use momentum to raise the legs.","Not controlling the descent, letting the legs fall freely.","Gripping the bar so tightly that tension builds in the neck and shoulders.","Raising the legs only to 45° and counting that as a complete rep."]'::jsonb,
  pro_tip_es = 'Usá correas (straps) de muñeca si la fuerza de agarre cede antes que el abdomen; así podés extender el tiempo bajo tensión sin que la fatiga del antebrazo limite la serie.',
  pro_tip_en = 'Use wrist straps if grip strength gives out before the abs; this lets you extend time under tension without forearm fatigue limiting the set.',
  tertiary_muscles = ARRAY['Hip Flexors','Iliopsoas','Forearm Flexors']::text[]
WHERE slug = 'hanging-leg-raise-bar';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte boca arriba en el suelo o en un banco plano con las manos bajo los glúteos o agarrando un soporte por encima de la cabeza.","Mantené las piernas juntas con las rodillas levemente flexionadas y activá el core.","Espirá y elevá las piernas hasta la vertical (90°) sin arquear la espalda baja.","En el punto más alto, realizá una pequeña retroversión pélvica para incorporar el recto abdominal inferior.","Bajá las piernas de forma controlada sin dejar que toquen el suelo entre repeticiones."]'::jsonb,
  execution_steps_en = '["Lie face up on the floor or flat bench with hands under the glutes or gripping a support overhead.","Keep legs together with knees slightly bent and activate the core.","Exhale and raise legs to vertical (90°) without arching the lower back.","At the top, perform a small posterior pelvic tilt to engage the lower rectus abdominis.","Lower the legs in a controlled manner without letting them touch the floor between reps."]'::jsonb,
  common_errors_es = '["Arquear excesivamente la zona lumbar durante el descenso de las piernas.","Bajar las piernas hasta el suelo perdiendo la tensión abdominal entre repeticiones.","Rebotar las piernas al llegar al punto más bajo para subir con impulso.","Mantener la zona lumbar despegada del suelo durante todo el ejercicio."]'::jsonb,
  common_errors_en = '["Excessively arching the lower back during the leg descent.","Lowering the legs to the floor and losing abdominal tension between reps.","Bouncing the legs at the bottom to use momentum going up.","Keeping the lower back off the floor throughout the exercise."]'::jsonb,
  pro_tip_es = 'Si sentís que la zona lumbar se arquea durante el descenso, limitá el recorrido a donde puedas mantener la espalda baja pegada al suelo; ese es tu rango de movimiento seguro y efectivo.',
  pro_tip_en = 'If you feel your lower back arching during the descent, limit the range to where you can keep the lower back pressed to the floor; that is your safe and effective range of motion.',
  tertiary_muscles = ARRAY['Hip Flexors','Iliopsoas','Tensor Fasciae Latae']::text[]
WHERE slug = 'lying-leg-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina con la espalda recta y bloqueá el cuerpo de la cintura hacia abajo contra los soportes.","Agarrá las asas y colocá los brazos en la posición indicada por el diseño de la máquina.","Espirá y rotá el tronco hacia un lado de forma controlada hasta el punto de máxima rotación sin dolor.","Pausá un segundo en el punto de mayor contracción del oblicuo y volvé al centro.","Completá la serie hacia un lado antes de reposicionarte para trabajar el otro."]'::jsonb,
  execution_steps_en = '["Sit in the machine with a straight back and lock the body from the waist down against the supports.","Grip the handles and position the arms as indicated by the machine design.","Exhale and rotate the torso to one side in a controlled manner up to the point of maximum rotation without pain.","Pause one second at peak oblique contraction and return to center.","Complete the set on one side before repositioning to work the other."]'::jsonb,
  common_errors_es = '["No bloquear la pelvis contra los soportes, girando las caderas en vez del tronco.","Rotar más allá del rango de movimiento confortable, aumentando el riesgo de lesión lumbar.","Usar impulso para acelerar la rotación, reduciendo el trabajo muscular efectivo.","Seleccionar demasiado peso, lo que obliga a compensar con otros grupos musculares."]'::jsonb,
  common_errors_en = '["Not locking the pelvis against the supports, rotating the hips instead of the torso.","Rotating beyond the comfortable range of motion, increasing lumbar injury risk.","Using momentum to accelerate the rotation, reducing effective muscle work.","Selecting too much weight, forcing compensations with other muscle groups."]'::jsonb,
  pro_tip_es = 'Esta máquina aísla los oblicuos de forma más específica que el disco o la barra; priorizala si el objetivo es el desarrollo estético o la prevención de lesiones de espalda.',
  pro_tip_en = 'This machine isolates the obliques more specifically than a plate or bar; prioritize it if the goal is aesthetic development or back injury prevention.',
  tertiary_muscles = ARRAY['Transversus Abdominis','Multifidus','Quadratus Lumborum']::text[]
WHERE slug = 'rotary-torso-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina de giros con el lastre seleccionado y ajustá los bloques de cadera para inmovilizar la pelvis.","Agarrá los soportes laterales y posicioná el tronco en posición neutra antes de iniciar.","Espirá y girá el tronco hacia el lado establecido de forma lenta (2 segundos de subida).","Pausá en el punto de máxima rotación y volvé al centro con igual velocidad (2 segundos de vuelta).","Alternáте entre un lado y el otro según el protocolo del ejercicio, evitando acumular fatiga asimétrica."]'::jsonb,
  execution_steps_en = '["Sit in the rotary torso machine with the selected weight and adjust the hip blocks to immobilize the pelvis.","Grip the side supports and position the torso in a neutral stance before starting.","Exhale and rotate the torso to the designated side slowly (2 seconds up).","Pause at the point of maximum rotation and return to center at the same speed (2 seconds back).","Alternate sides according to the exercise protocol, avoiding asymmetric fatigue accumulation."]'::jsonb,
  common_errors_es = '["Girar también las caderas al rotar el tronco, anulando el aislamiento de los oblicuos.","Realizar el movimiento de forma rápida e impulsiva, reduciendo la activación muscular.","Seleccionar tanto peso que solo se logran unos pocos grados de rotación.","Ignorar el trabajo bilateral, dejando un lado significativamente más fuerte que el otro."]'::jsonb,
  common_errors_en = '["Also rotating the hips when turning the torso, canceling oblique isolation.","Performing the movement rapidly and impulsively, reducing muscle activation.","Selecting so much weight that only a few degrees of rotation are achieved.","Neglecting bilateral work, leaving one side significantly stronger than the other."]'::jsonb,
  pro_tip_es = 'Comparado con el disco abdominal, esta máquina ofrece mayor especificidad y seguridad para los oblicuos; es especialmente útil en personas con historial de dolor lumbar bajo supervisión profesional.',
  pro_tip_en = 'Compared to the abdominal disc, this machine offers greater specificity and safety for the obliques; it is especially useful for individuals with a history of lower back pain under professional supervision.',
  tertiary_muscles = ARRAY['Rectus Abdominis','Transversus Abdominis','Quadratus Lumborum']::text[]
WHERE slug = 'rotary-torso-machine-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina con la parte superior de la espalda apoyada contra el soporte acolchado.","Agarrá los apoyabrazos laterales y aseguráte de que los pies estén bien apoyados en la plataforma.","Inspirá y, al espirar, extiende el tronco empujando el soporte hacia atrás hasta llegar a la horizontal.","Pausá un segundo en el punto de máxima extensión sin hiperextender la columna lumbar.","Volvé a la posición inicial de forma controlada resistiendo el regreso."]'::jsonb,
  execution_steps_en = '["Sit in the machine with the upper back resting against the padded support.","Grip the side armrests and ensure feet are firmly on the platform.","Inhale and, on the exhale, extend the torso by pushing the support backward until reaching horizontal.","Pause one second at peak extension without hyperextending the lumbar spine.","Return to the start position in a controlled manner, resisting the return."]'::jsonb,
  common_errors_es = '["Hiperextender la columna lumbar al llegar al punto más alto, aumentando la compresión discal.","No mantener los pies apoyados, reduciendo la base de soporte y la estabilidad.","Usar impulso para empujar el soporte en lugar de una contracción muscular controlada.","Seleccionar tanto peso que el rango de movimiento queda limitado a 20–30°."]'::jsonb,
  common_errors_en = '["Hyperextending the lumbar spine at the peak, increasing disc compression.","Not keeping feet firmly on the platform, reducing the base of support and stability.","Using momentum to push the support instead of controlled muscle contraction.","Selecting so much weight that range of motion is limited to 20–30°."]'::jsonb,
  pro_tip_es = 'Esta máquina trabaja principalmente los extensores lumbares inferiores; si el objetivo es trabajar los erectores de la zona media y alta, complementá con hiperextensiones en banco roman.',
  pro_tip_en = 'This machine primarily works the lower lumbar extensors; if the goal is to target the mid and upper erector spinae, complement with hyperextensions on a roman chair.',
  tertiary_muscles = ARRAY['Gluteus Maximus','Biceps Femoris','Adductor Magnus']::text[]
WHERE slug = 'seated-back-extension-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte de lado en el suelo con el cuerpo alineado: cabeza, hombros, caderas y tobillos en la misma línea.","Colocá el brazo inferior extendido o flexionado bajo la cabeza y el brazo superior apoyado en el tronco.","Espirá y elevá el tronco superior lateralmente acercando el codo al ilion del mismo lado.","Pausá en el punto de máxima contracción del oblicuo y bajá de forma controlada.","Realizá todas las repeticiones del mismo lado antes de voltear y trabajar el otro."]'::jsonb,
  execution_steps_en = '["Lie on your side on the floor with the body aligned: head, shoulders, hips, and ankles in the same line.","Place the lower arm extended or bent under the head and the upper arm resting on the torso.","Exhale and raise the upper torso laterally, bringing the elbow toward the ilium on the same side.","Pause at peak oblique contraction and lower in a controlled manner.","Complete all reps on the same side before rolling over to work the other."]'::jsonb,
  common_errors_es = '["Rotar el tronco hacia adelante o hacia atrás durante el crunch lateral, mezclando planos de movimiento.","Elevar también las piernas en lugar de aislar el movimiento al tronco superior.","Subir con impulso jalando la cabeza con el brazo superior.","No mantener los hombros perpendiculares al suelo durante el movimiento."]'::jsonb,
  common_errors_en = '["Rotating the torso forward or backward during the lateral crunch, mixing planes of movement.","Also raising the legs instead of isolating the movement to the upper torso.","Moving up with momentum by pulling the head with the upper arm.","Not keeping the shoulders perpendicular to the floor during the movement."]'::jsonb,
  pro_tip_es = 'Para aumentar la dificultad sin agregar peso, extendé el brazo superior por encima de la cabeza; el mayor brazo de palanca incrementa la demanda sobre el oblicuo sin requerir equipamiento adicional.',
  pro_tip_en = 'To increase difficulty without adding weight, extend the upper arm overhead; the longer lever arm increases the demand on the oblique without requiring additional equipment.',
  tertiary_muscles = ARRAY['Quadratus Lumborum','Rectus Abdominis','Serratus Anterior']::text[]
WHERE slug = 'side-lying-oblique-crunch';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en el suelo de frente a la polea con el agarre que viene desde atrás; las manos sostienen el agarre a la altura del pecho.","Activá el abdomen antes de iniciar y mantené la espalda baja en posición neutra.","Espirá y elevá el tronco mediante una contracción abdominal clara, acortando el espacio entre pelvis y esternón.","Realizá movimientos cortos y controlados; no bajés más allá del punto en que podás mantener la espalda baja estable.","Volvé de forma controlada a la posición inicial inhalando."]'::jsonb,
  execution_steps_en = '["Sit on the floor facing the cable machine with the handle coming from behind; hands hold the grip at chest height.","Activate the abs before starting and keep the lower back in a neutral position.","Exhale and raise the torso through a clear abdominal contraction, shortening the space between pelvis and sternum.","Perform short, controlled movements; do not lower beyond the point where you can maintain lower back stability.","Return in a controlled manner to the start position while inhaling."]'::jsonb,
  common_errors_es = '["Bajar el tronco demasiado, forzando la zona lumbar más allá de su rango estable.","Usar los flexores de cadera para elevar el tronco en vez del recto abdominal.","Realizar movimientos largos y rápidos, perdiendo el control y el tiempo bajo tensión.","No ajustar la carga de la polea al nivel de entrenamiento, eligiendo tanto peso que obliga a compensar."]'::jsonb,
  common_errors_en = '["Lowering the torso too far, forcing the lumbar spine beyond its stable range.","Using the hip flexors to raise the torso instead of the rectus abdominis.","Performing long, fast movements, losing control and time under tension.","Not adjusting the cable load to training level, choosing so much weight that compensations are forced."]'::jsonb,
  pro_tip_es = 'Esta variante en polea mantiene tensión constante durante todo el arco, a diferencia del crunch de suelo que pierde tensión en el punto más alto; aprovechá esa ventaja haciendo pausas cortas en el punto de máxima contracción.',
  pro_tip_en = 'This cable variant maintains constant tension throughout the arc, unlike the floor crunch which loses tension at the top; take advantage of that by adding short pauses at peak contraction.',
  tertiary_muscles = ARRAY['Hip Flexors','Iliopsoas','Transversus Abdominis']::text[]
WHERE slug = 'standing-cable-ab-rollout';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte la tobillera en el tobillo y paráte frente a la polea baja, sujetándote con ambas manos al soporte.","Inclináte levemente hacia adelante desde las caderas para mantener la espalda neutral.","Extendé la pierna hacia atrás en línea recta apretando el glúteo en el punto máximo de extensión.","Mantené la contracción un segundo y volvé la pierna de forma controlada sin apoyar el pie entre repeticiones.","Completá todas las repeticiones de un lado antes de cambiar."]'::jsonb,
  execution_steps_en = '["Attach the ankle strap and stand facing the low pulley, holding the support with both hands.","Lean slightly forward from the hips to keep a neutral spine.","Extend the leg straight back, squeezing the glute at maximum extension.","Hold the contraction for one second, then return the leg under control without resting the foot between reps.","Complete all reps on one side before switching."]'::jsonb,
  common_errors_es = '["Rotar la cadera para llevar la pierna más atrás, quitando el trabajo del glúteo.","Usar impulso del tronco en lugar de la extensión de cadera.","Cargar demasiado peso y acortar el recorrido.","No contraer el glúteo al final del movimiento."]'::jsonb,
  common_errors_en = '["Rotating the hip to swing the leg higher, removing glute engagement.","Using trunk momentum instead of a controlled hip extension.","Loading too much weight and shortening the range of motion.","Not squeezing the glute at the end of the movement."]'::jsonb,
  pro_tip_es = 'Imaginá que empujás el talón hacia la pared de atrás en línea recta; eso evita la rotación de cadera y concentra el esfuerzo en el glúteo mayor.',
  pro_tip_en = 'Imagine pushing your heel straight back toward the wall; this prevents hip rotation and keeps the focus on the gluteus maximus.',
  tertiary_muscles = ARRAY['Core','Erector Spinae','Hip Flexors (antagonist)']::text[]
WHERE slug = 'cable-glute-kickback';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte frente a la polea baja con la tobillera en el tobillo y el cuerpo levemente inclinado hacia adelante, sujetándote al aparato.","Desde la posición neutra, extendé el muslo hacia atrás siguiendo los mismos principios biomecánicos que la extensión en máquina.","Apretá el glúteo en el punto más alto del recorrido y sostené un instante.","Devolvé la pierna de manera controlada sin dejar que el peso jale bruscamente.","Mantenélos lumbares estables en todo momento; no arquees la espalda para compensar amplitud."]'::jsonb,
  execution_steps_en = '["Stand facing the low cable with the ankle strap attached, body slightly leaning forward while holding the machine.","From a neutral position, extend the thigh rearward following the same biomechanical principles as the machine version.","Squeeze the glute at the top of the range and briefly hold.","Return the leg under control without letting the weight jerk back.","Keep the lumbar spine stable throughout; do not hyperextend to gain extra range."]'::jsonb,
  common_errors_es = '["Hiperlordosis lumbar para lograr mayor amplitud.","Dejar que el pie arrastre en lugar de extender activamente la cadera.","No mantener el core activado durante la serie.","Balancear el tronco para generar impulso."]'::jsonb,
  common_errors_en = '["Hyperlordosis of the lumbar spine to gain extra range.","Letting the foot drag instead of actively extending the hip.","Failing to keep the core braced throughout the set.","Swinging the trunk to create momentum."]'::jsonb,
  pro_tip_es = 'Con polea libre la amplitud suele ser menor que en máquina; priorizá la calidad de contracción del glúteo por encima de la cantidad de recorrido.',
  pro_tip_en = 'Range of motion is usually shorter on the cable than on a machine; prioritize glute contraction quality over maximum range.',
  tertiary_muscles = ARRAY['Core','Erector Spinae','Hip Flexors (antagonist)']::text[]
WHERE slug = 'cable-glute-kickback-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte en decúbito prono sobre el banco con los pies orientados hacia la polea baja y sujetáte para estabilizarte.","Comenzá desde casi la extensión completa de rodilla y flexionálas de forma controlada hasta aproximadamente 120°.","Mantenélos lumbares neutros en todo momento; no hiperextendas la zona lumbar al bajar.","Volvé a la extensión de manera controlada sin bloquear la rodilla con brusquedad.","Respirá de forma natural en cargas ligeras; inspirá antes del descenso y espirá al subir en cargas moderadas."]'::jsonb,
  execution_steps_en = '["Lie prone on a bench with feet pointing toward the low pulley and hold on for stability.","Start from near full knee extension and flex the knees under control to approximately 120°.","Keep the lumbar spine neutral throughout; do not hyperextend the lower back during the descent.","Return to extension in a controlled manner without snapping the knee straight.","Breathe naturally at light loads; inhale before the descent and exhale on the way up at moderate loads."]'::jsonb,
  common_errors_es = '["Hiperlordosis lumbar al extender las rodillas.","Bajar más de 120° forzando el recorrido más allá del rango cómodo.","Usar impulso para completar las repeticiones en lugar de contracción activa.","No estabilizar el banco correctamente antes de iniciar."]'::jsonb,
  common_errors_en = '["Hyperlordosis of the lumbar spine when extending the knees.","Flexing beyond 120°, forcing the range past a comfortable position.","Using momentum to complete reps instead of active contraction.","Not securing the bench properly before starting."]'::jsonb,
  pro_tip_es = 'Este ejercicio es especialmente útil para trabajar el bíceps femoral corto, que no cruza la cadera; mantené la velocidad baja en la fase excéntrica para maximizar la tensión.',
  pro_tip_en = 'This exercise is especially useful for targeting the short head of the biceps femoris, which does not cross the hip; keep the eccentric phase slow to maximize tension.',
  tertiary_muscles = ARRAY['Popliteus','Sartorius','Plantaris']::text[]
WHERE slug = 'cable-hack-squat';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte la tobillera en el tobillo externo y paráte lateral a la polea baja, sujetándote con la mano del mismo lado.","Con la pierna ligeramente separada del suelo, llevála hacia afuera en abducción sin flexionar la cadera.","Llegá al máximo recorrido cómodo sin inclinarte lateralmente con el tronco.","Retorná de manera controlada y repetí sin inercia."]'::jsonb,
  execution_steps_en = '["Attach the ankle strap to the outer ankle and stand sideways to the low pulley, holding the support.","With the leg slightly off the ground, swing it outward in abduction without flexing at the hip.","Reach maximum comfortable range without lateral trunk lean.","Return under control and repeat without momentum."]'::jsonb,
  common_errors_es = '["Inclinar el tronco lateralmente para ganar amplitud.","Flexionar la cadera convirtiendo el movimiento en una elevación frontal.","Usar demasiado peso y reducir el control del movimiento.","No activar el glúteo medio durante la abducción."]'::jsonb,
  common_errors_en = '["Leaning the trunk sideways to gain extra range.","Flexing at the hip, turning the movement into a front raise.","Using too much weight and losing movement control.","Failing to consciously activate the gluteus medius during abduction."]'::jsonb,
  pro_tip_es = 'Mantené el tronco completamente vertical y el pie en posición neutra; eso garantiza que el trabajo recaiga sobre el glúteo medio y no sobre el tensor de la fascia lata.',
  pro_tip_en = 'Keep the trunk fully upright and the foot in a neutral position; this ensures the work falls on the gluteus medius rather than the tensor fascia latae.',
  tertiary_muscles = ARRAY['Core','Gluteus Minimus','Piriformis']::text[]
WHERE slug = 'cable-hip-abduction';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte la tobillera en el tobillo interno y paráte lateral a la polea baja con la pierna trabajadora alejada de ella.","Cruzá la pierna hacia adentro por delante de la pierna de apoyo en un movimiento de aducción controlado.","Llegá al cruce máximo sin rotar la cadera ni la columna.","Devolvé la pierna de forma controlada a la posición inicial."]'::jsonb,
  execution_steps_en = '["Attach the ankle strap to the inner ankle and stand sideways to the low pulley with the working leg away from it.","Cross the working leg inward in front of the support leg in a controlled adduction movement.","Reach maximum crossing point without rotating the hip or spine.","Return the leg under control to the starting position."]'::jsonb,
  common_errors_es = '["Rotar el tronco o la pelvis para ganar más amplitud.","No controlar el retorno y dejar que el peso jale bruscamente.","Flexionar la rodilla trabajadora durante el movimiento.","Inclinar el tronco lateralmente."]'::jsonb,
  common_errors_en = '["Rotating the trunk or pelvis to gain extra range.","Not controlling the return and letting the weight snap back.","Bending the working knee during the movement.","Leaning the trunk sideways."]'::jsonb,
  pro_tip_es = 'Realizá el movimiento en forma lenta y deliberada; los aductores son un grupo que responde bien al tiempo bajo tensión.',
  pro_tip_en = 'Perform the movement slowly and deliberately; the adductors respond well to time under tension.',
  tertiary_muscles = ARRAY['Core','Pectineus','Obturator Externus']::text[]
WHERE slug = 'cable-hip-adduction';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte lateralmente a la polea con la cuerda sujeta a la punta del pie más alejado.","Realizá una rotación lateral de la rodilla en movimiento lento y estricto, máximo 40°.","Dejá el talón apoyado y movéte solo con la punta del pie.","Volvé a la posición inicial de forma controlada.","Respirá de forma natural durante todo el ejercicio."]'::jsonb,
  execution_steps_en = '["Sit sideways to the cable with the rope attached to the far foot.","Perform a lateral knee rotation in a slow, strict movement, maximum 40°.","Keep the heel grounded and move only with the toe.","Return to the starting position under control.","Breathe naturally throughout the exercise."]'::jsonb,
  common_errors_es = '["Superar los 40° de rotación forzando el rango articular.","Usar el tronco o la cadera para generar el movimiento.","Ejecutar el movimiento a velocidad alta perdiendo el control.","No mantener el talón apoyado en el suelo."]'::jsonb,
  common_errors_en = '["Exceeding 40° of rotation and forcing the joint range.","Using the trunk or hip to generate the movement.","Executing the movement too fast and losing control.","Failing to keep the heel grounded."]'::jsonb,
  pro_tip_es = 'Priorizá la sensación muscular sobre la cantidad de recorrido; este ejercicio trabaja el bíceps femoral en un rango muy específico.',
  pro_tip_en = 'Prioritize the muscle feel over range of motion; this exercise targets the biceps femoris in a very specific range.',
  tertiary_muscles = ARRAY['Tensor Fascia Latae','Gluteus Minimus','Hip External Rotators']::text[]
WHERE slug = 'cable-hip-extension';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte de espaldas a la polea baja con la tobillera en la pierna trabajadora.","Desde la posición erguida, flexioná la cadera llevando la rodilla hacia adelante y arriba hasta aproximadamente 45-65° de la vertical.","Mantené la rodilla casi extendida durante el movimiento.","Retorná a la posición inicial de forma controlada sin dejar que el peso jale.","Completá todas las repeticiones de un lado antes de cambiar."]'::jsonb,
  execution_steps_en = '["Stand facing away from the low cable with the ankle strap on the working leg.","From an upright position, flex the hip by bringing the knee forward and upward to approximately 45–65° from vertical.","Keep the knee nearly extended throughout the movement.","Return to the starting position under control without letting the weight pull you back.","Complete all reps on one side before switching."]'::jsonb,
  common_errors_es = '["Flexionar la rodilla excesivamente en lugar de priorizar la flexión de cadera.","Inclinar el tronco hacia atrás para compensar la resistencia.","Usar impulso en lugar de activar el psoas-iliaco.","Superar el rango recomendado sin control lumbar adecuado."]'::jsonb,
  common_errors_en = '["Flexing the knee excessively instead of prioritizing hip flexion.","Leaning the trunk backward to compensate for the resistance.","Using momentum instead of actively engaging the iliopsoas.","Exceeding the recommended range without adequate lumbar control."]'::jsonb,
  pro_tip_es = 'Mantené el tronco estable y erguido durante todo el movimiento; si necesitás reclinarte, el peso es excesivo para ese rango.',
  pro_tip_en = 'Keep the trunk stable and upright throughout; if you need to lean back, the weight is too heavy for that range.',
  tertiary_muscles = ARRAY['Rectus Abdominis','Core','Pectineus']::text[]
WHERE slug = 'cable-hip-flexion';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte de espaldas a la polea baja y pasá la cuerda entre las piernas sujetándola con ambas manos.","Con los pies al ancho de los hombros, inclinéate hacia adelante desde las caderas manteniendo la espalda recta hasta que el torso quede casi paralelo al suelo.","Empujá las caderas hacia adelante de forma explosiva y controlada hasta la extensión completa, apretando los glúteos.","Controlá el retorno hacia atrás sin redondear la espalda.","Mantené el peso en los talones durante todo el movimiento."]'::jsonb,
  execution_steps_en = '["Stand facing away from the low cable and pass the rope between your legs, gripping it with both hands.","With feet shoulder-width apart, hinge forward at the hips with a flat back until the torso is nearly parallel to the floor.","Drive the hips forward explosively and under control to full extension, squeezing the glutes.","Control the return without rounding the back.","Keep weight through the heels throughout the movement."]'::jsonb,
  common_errors_es = '["Redondear la espalda al inclinar el tronco hacia adelante.","Doblar las rodillas convirtiendo el movimiento en una sentadilla.","No extender completamente las caderas al final del movimiento.","Dejar que los brazos tiren en lugar de que las caderas generen la fuerza."]'::jsonb,
  common_errors_en = '["Rounding the back when hinging the torso forward.","Bending the knees and turning it into a squat.","Not fully extending the hips at the end of the movement.","Letting the arms pull instead of driving from the hips."]'::jsonb,
  pro_tip_es = 'Pensá en este movimiento exactamente como en un swing de kettlebell: la fuerza viene de la extensión de cadera, no de los brazos ni de la espalda.',
  pro_tip_en = 'Think of this movement exactly like a kettlebell swing: the power comes from the hip extension, not the arms or back.',
  tertiary_muscles = ARRAY['Core','Erector Spinae','Adductors']::text[]
WHERE slug = 'cable-pull-through';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte en la prensa horizontal con solo la parte delantera del pie apoyada en el borde de la plataforma.","Desde la dorsiflexión máxima (talón bajo), empujá la plataforma en flexión plantar hasta la extensión completa del tobillo.","Sostenélo un instante en la cima y descendé de forma lenta y controlada hasta el punto de máximo estiramiento.","Mantenélas rodillas ligeramente flexionadas y fijas durante todo el movimiento.","Realizá el movimiento sin rebotar en la parte baja."]'::jsonb,
  execution_steps_en = '["Position yourself on the horizontal press with only the forefoot resting on the edge of the platform.","From maximum dorsiflexion (heel down), push the platform into plantar flexion until full ankle extension.","Hold briefly at the top, then lower slowly and under control to maximum stretch.","Keep the knees slightly bent and fixed throughout.","Do not bounce at the bottom position."]'::jsonb,
  common_errors_es = '["Rebotar en la posición de máximo estiramiento, aumentando el riesgo de lesión del tendón de Aquiles.","Usar las rodillas para ayudar al movimiento en lugar de aislar el tobillo.","No completar el rango completo de movimiento en ninguno de los dos extremos.","Cargar demasiado peso y perder el control de la velocidad."]'::jsonb,
  common_errors_en = '["Bouncing at the maximum stretch position, increasing Achilles tendon injury risk.","Using the knees to assist instead of isolating the ankle.","Not completing the full range of motion at either extreme.","Loading too much weight and losing speed control."]'::jsonb,
  pro_tip_es = 'Las series lentas (3 segundos de bajada, 1 de subida) en gemelos producen mejor hipertrofia que las rápidas; usá un tempo deliberado.',
  pro_tip_en = 'Slow sets (3-second descent, 1-second ascent) produce better calf hypertrophy than fast ones; use a deliberate tempo.',
  tertiary_muscles = ARRAY['Tibialis Posterior','Flexor Digitorum Longus','Peroneals']::text[]
WHERE slug = 'calf-press-on-leg-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá el pie trasero sobre un banco o superficie elevada y paráte con el pie adelantado a una distancia que permita que la rodilla delantera quede sobre el tobillo al bajar.","Sujetá una mancuerna en cada mano con los brazos extendidos a los costados.","Bajá el cuerpo de forma controlada hasta que la rodilla trasera esté cerca del suelo, manteniendo el tronco erguido.","Empujá desde el talón delantero para volver a la posición inicial.","Completá todas las repeticiones de un lado antes de cambiar."]'::jsonb,
  execution_steps_en = '["Place the rear foot on a bench or elevated surface and stand with the front foot far enough forward that the front knee stays over the ankle at the bottom.","Hold a dumbbell in each hand with arms extended at your sides.","Lower your body under control until the rear knee is close to the floor, keeping the torso upright.","Drive through the front heel to return to the starting position.","Complete all reps on one side before switching."]'::jsonb,
  common_errors_es = '["Dejar que la rodilla delantera caiga hacia adentro (valgo de rodilla).","Inclinarse excesivamente hacia adelante con el tronco.","Colocar el pie trasero demasiado cerca, lo que limita el descenso.","Rebotar en la posición baja en lugar de bajar de forma controlada."]'::jsonb,
  common_errors_en = '["Letting the front knee cave inward (knee valgus).","Leaning excessively forward with the torso.","Placing the rear foot too close, limiting the descent.","Bouncing at the bottom instead of lowering under control."]'::jsonb,
  pro_tip_es = 'Cuanto más adelantado esté el pie, mayor será la activación del glúteo; cuanto más vertical el torso, mayor será la del cuádriceps. Ajustá la posición según tu objetivo.',
  pro_tip_en = 'The further forward the front foot, the greater the glute activation; the more upright the torso, the more quad-dominant. Adjust foot position according to your goal.',
  tertiary_muscles = ARRAY['Core','Adductors','Tibialis Anterior']::text[]
WHERE slug = 'dumbbell-bulgarian-split-squat';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sujetá una mancuerna verticalmente a la altura del pecho con ambas manos, con los pies al ancho de los hombros o levemente más abiertos.","Bajá en sentadilla manteniendo el torso erguido y los talones apoyados en el suelo.","Llevá las rodillas hacia afuera en la línea de los pies durante todo el descenso.","Bajá hasta donde puedas mantener la espalda recta, idealmente con los muslos paralelos al suelo o más.","Empujá desde los talones para volver a la posición inicial."]'::jsonb,
  execution_steps_en = '["Hold a dumbbell vertically at chest height with both hands, feet shoulder-width apart or slightly wider.","Lower into a squat while keeping the torso upright and heels on the ground.","Track the knees outward in line with the feet throughout the descent.","Lower as deep as you can while maintaining a flat back, ideally thighs parallel to the floor or below.","Drive through the heels to return to the starting position."]'::jsonb,
  common_errors_es = '["Dejar que las rodillas colapsen hacia adentro.","Inclinarse hacia adelante y perder la postura erguida del tronco.","Levantar los talones del suelo.","Redondear la espalda baja al llegar a la profundidad máxima."]'::jsonb,
  common_errors_en = '["Letting the knees cave inward.","Leaning forward and losing the upright torso position.","Lifting the heels off the ground.","Rounding the lower back at maximum depth."]'::jsonb,
  pro_tip_es = 'El peso frente al cuerpo actúa como contrapeso y facilita una sentadilla profunda con el torso más vertical; es ideal para aprender la mecánica correcta de la sentadilla.',
  pro_tip_en = 'The weight in front acts as a counterbalance and makes it easier to squat deep with a more vertical torso; it is ideal for learning proper squat mechanics.',
  tertiary_muscles = ARRAY['Core','Erector Spinae','Tibialis Anterior']::text[]
WHERE slug = 'dumbbell-goblet-squat';
UPDATE public.exercise_library SET
  execution_steps_es = '["Apoyá los hombros sobre un banco y colocá una mancuerna sobre las caderas, sosteniéndola con ambas manos.","Con los pies apoyados en el suelo al ancho de las caderas, dejá bajar las caderas hacia el suelo de forma controlada.","Empujá las caderas hacia arriba hasta la extensión completa apretando los glúteos en el punto más alto.","Sostenélo un segundo en la cima y volvé a bajar de forma controlada.","Mantené la barbilla ligeramente hacia el pecho para no arquear el cuello."]'::jsonb,
  execution_steps_en = '["Rest the upper back on a bench and place a dumbbell on the hips, holding it with both hands.","With feet flat on the floor at hip width, lower your hips toward the ground under control.","Drive the hips upward to full extension, squeezing the glutes at the top.","Hold for one second at the top, then lower under control.","Keep the chin slightly tucked to avoid hyperextending the neck."]'::jsonb,
  common_errors_es = '["Arquear la espalda lumbar en exceso al llegar arriba en lugar de extender desde la cadera.","No llegar a la extensión completa de cadera en el punto más alto.","Dejar que las rodillas caigan hacia adentro.","Usar el cuello o los brazos para compensar en lugar de los glúteos."]'::jsonb,
  common_errors_en = '["Hyperextending the lower back at the top instead of extending from the hip.","Not reaching full hip extension at the top.","Letting the knees fall inward.","Using the neck or arms to compensate instead of the glutes."]'::jsonb,
  pro_tip_es = 'Girá levemente las puntas de los pies hacia afuera (10-20°); esto facilita la activación del glúteo mayor al final del movimiento.',
  pro_tip_en = 'Slightly externally rotate the feet (10–20°); this facilitates gluteus maximus activation at the end of the movement.',
  tertiary_muscles = ARRAY['Core','Adductors','Tibialis Anterior']::text[]
WHERE slug = 'dumbbell-hip-thrust';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte erguido con una mancuerna en cada mano y los pies juntos.","Dá un paso adelante con una pierna hasta que ambas rodillas queden a 90°.","Mantenélas rodillas alineadas con los pies y la rodilla delantera sin sobrepasar el tobillo.","Empujá desde el talón delantero para volver a la posición inicial.","Alternálos lados o completálos de un solo lado según el protocolo."]'::jsonb,
  execution_steps_en = '["Stand upright holding a dumbbell in each hand with feet together.","Step forward with one leg until both knees are at 90°.","Keep knees aligned with the feet and the front knee not past the toe.","Drive through the front heel to return to the starting position.","Alternate sides or complete all reps on one side as per the protocol."]'::jsonb,
  common_errors_es = '["Dejar que la rodilla delantera pase por delante del pie.","Inclinar el tronco excesivamente hacia adelante.","Valgo de rodilla (rodilla hacia adentro) en el descenso.","Dar pasos demasiado cortos que no permiten los 90° en ambas rodillas."]'::jsonb,
  common_errors_en = '["Letting the front knee travel past the toes.","Leaning the trunk excessively forward.","Knee valgus (knee caving inward) during the descent.","Taking steps too short to allow 90° at both knees."]'::jsonb,
  pro_tip_es = 'El largo del paso determina dónde recae el trabajo: un paso más largo activa más el glúteo, uno más corto activa más el cuádriceps.',
  pro_tip_en = 'Step length determines where the work falls: a longer step activates more glute, a shorter step activates more quad.',
  tertiary_muscles = ARRAY['Core','Tibialis Anterior','Peroneals']::text[]
WHERE slug = 'dumbbell-lunge';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte erguido con una mancuerna en cada mano y los pies juntos.","Dá un paso hacia atrás con una pierna y bajá la rodilla trasera hacia el suelo de forma controlada.","Mantené el tronco erguido y la rodilla delantera alineada con el tobillo.","Empujá desde el talón de la pierna delantera para volver a la posición inicial.","Completálos por el lado indicado antes de cambiar."]'::jsonb,
  execution_steps_en = '["Stand upright holding a dumbbell in each hand with feet together.","Step backward with one leg and lower the rear knee toward the floor under control.","Keep the torso upright and the front knee aligned over the front ankle.","Drive through the front heel to return to the starting position.","Complete all reps on the indicated side before switching."]'::jsonb,
  common_errors_es = '["Inclinar el tronco hacia adelante al descender.","Dejar caer bruscamente la rodilla trasera al suelo.","Valgo de rodilla en la pierna delantera.","Usar demasiado impulso al volver a la posición inicial."]'::jsonb,
  common_errors_en = '["Leaning the torso forward during the descent.","Dropping the rear knee to the floor abruptly.","Knee valgus in the front leg.","Using excessive momentum when returning to the starting position."]'::jsonb,
  pro_tip_es = 'La estocada inversa reduce el estrés en la rodilla delantera comparada con la estocada hacia adelante; es ideal para quienes tienen molestias en la articulación.',
  pro_tip_en = 'The reverse lunge reduces stress on the front knee compared to the forward lunge; it is ideal for those with knee discomfort.',
  tertiary_muscles = ARRAY['Core','Hip Flexors','Tibialis Anterior']::text[]
WHERE slug = 'dumbbell-reverse-lunge';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte erguido con una mancuerna en cada mano frente a los muslos, pies al ancho de las caderas.","Con una leve flexión fija en las rodillas, incliná el tronco hacia adelante empujando las caderas hacia atrás.","Bajá las mancuernas a lo largo de las piernas manteniendo la espalda completamente recta.","Sentí el estiramiento en los isquiotibiales y detené el descenso cuando la espalda no pueda mantenerse neutral.","Empujá las caderas hacia adelante para volver a la posición inicial."]'::jsonb,
  execution_steps_en = '["Stand upright holding a dumbbell in each hand in front of the thighs, feet hip-width apart.","With a slight fixed bend in the knees, hinge the torso forward by pushing the hips back.","Lower the dumbbells along the legs while keeping the back completely flat.","Feel the hamstring stretch and stop the descent when the back can no longer remain neutral.","Drive the hips forward to return to the starting position."]'::jsonb,
  common_errors_es = '["Redondear la espalda al bajar.","Doblar excesivamente las rodillas, convirtiendo el ejercicio en una sentadilla.","Dejar que las mancuernas se alejen del cuerpo.","Bloquear las rodillas completamente en la posición inicial."]'::jsonb,
  common_errors_en = '["Rounding the back during the descent.","Bending the knees excessively, turning it into a squat.","Letting the dumbbells drift away from the body.","Fully locking the knees at the starting position."]'::jsonb,
  pro_tip_es = 'Pensá en empujar las caderas hacia la pared de atrás en lugar de bajar las pesas; eso mantiene la carga en los isquiotibiales y glúteos en lugar de en la espalda.',
  pro_tip_en = 'Think of pushing the hips back toward the wall rather than lowering the weights; this keeps the load on the hamstrings and glutes rather than the back.',
  tertiary_muscles = ARRAY['Erector Spinae','Adductors','Core']::text[]
WHERE slug = 'dumbbell-romanian-deadlift';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con los pies al ancho de los hombros sosteniendo una mancuerna en cada mano a los costados del cuerpo.","Bajá en sentadilla manteniendo el pecho levantado, los talones en el suelo y las rodillas siguiendo la dirección de los pies.","Descendé hasta que los muslos estén paralelos al suelo o más abajo si la movilidad lo permite.","Empujá desde los talones para volver a la posición inicial.","Espirá durante el ascenso; inspirá durante el descenso."]'::jsonb,
  execution_steps_en = '["Stand with feet shoulder-width apart holding a dumbbell in each hand at your sides.","Lower into a squat keeping the chest up, heels on the ground and knees tracking over the toes.","Descend until thighs are parallel to the floor or lower if mobility allows.","Drive through the heels to return to the starting position.","Exhale during the ascent; inhale during the descent."]'::jsonb,
  common_errors_es = '["Dejar que las rodillas caigan hacia adentro.","Levantar los talones del suelo.","Inclinar el tronco excesivamente hacia adelante.","No alcanzar la profundidad paralela con las rodillas."]'::jsonb,
  common_errors_en = '["Letting the knees cave inward.","Lifting the heels off the ground.","Leaning the torso excessively forward.","Not reaching parallel depth with the thighs."]'::jsonb,
  pro_tip_es = 'Si las mancuernas a los costados limitan la profundidad, probálas a la altura de los hombros o en posición goblet para facilitar un torso más vertical.',
  pro_tip_en = 'If dumbbells at your sides limit depth, try holding them at shoulder height or in a goblet position to encourage a more vertical torso.',
  tertiary_muscles = ARRAY['Core','Erector Spinae','Tibialis Anterior']::text[]
WHERE slug = 'dumbbell-squat';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sujetá una mancuerna en cada mano y paráte con las puntas de los pies en el borde de un escalón o superficie elevada.","Bajá los talones por debajo del nivel del escalón para obtener el estiramiento máximo.","Empujá sobre los dedos del pie hasta la extensión completa del tobillo.","Sostenélo un segundo en la cima y bajá de forma lenta y controlada.","Realizá el movimiento en rango completo sin rebotar en la parte baja."]'::jsonb,
  execution_steps_en = '["Hold a dumbbell in each hand and stand with the balls of the feet on the edge of a step or elevated surface.","Lower the heels below the step level for maximum stretch.","Rise up on the toes to full ankle extension.","Hold briefly at the top and lower slowly and under control.","Perform the full range of motion without bouncing at the bottom."]'::jsonb,
  common_errors_es = '["Rebotar en la posición de máximo estiramiento.","No bajar los talones por debajo del nivel del escalón.","No llegar a la extensión completa del tobillo en la parte alta.","Doblar las rodillas para ayudar al movimiento."]'::jsonb,
  common_errors_en = '["Bouncing at the maximum stretch position.","Not lowering the heels below the step level.","Not reaching full ankle extension at the top.","Bending the knees to assist the movement."]'::jsonb,
  pro_tip_es = 'Para mayor activación del sóleo (músculo profundo de la pantorrilla) realizá el ejercicio con las rodillas levemente flexionadas.',
  pro_tip_en = 'For greater soleus activation (deep calf muscle) perform the exercise with the knees slightly bent.',
  tertiary_muscles = ARRAY['Tibialis Anterior','Peroneals','Flexor Hallucis Longus']::text[]
WHERE slug = 'dumbbell-standing-calf-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte frente a un banco o caja con una mancuerna en cada mano.","Colocá un pie completamente sobre la superficie y empujá desde ese talón para subir el cuerpo.","Llevá la pierna trasera arriba hasta que quede a 90° de cadera o la rodilla quede a nivel de la cadera.","Bajá de forma controlada volviendo el pie trasero al suelo primero.","Completá todas las repeticiones de un lado antes de cambiar."]'::jsonb,
  execution_steps_en = '["Stand in front of a bench or box holding a dumbbell in each hand.","Place one foot fully on the surface and drive through that heel to raise the body.","Bring the trailing leg up until the hip is at 90° or the knee is at hip level.","Lower under control, returning the trailing foot to the floor first.","Complete all reps on one side before switching."]'::jsonb,
  common_errors_es = '["Empujar con la pierna del suelo en lugar de la pierna elevada.","Dejar que la rodilla delantera caiga hacia adentro.","Bajar demasiado rápido sin controlar el excéntrico.","No colocar el pie completamente sobre la superficie."]'::jsonb,
  common_errors_en = '["Pushing off with the grounded leg instead of the elevated leg.","Letting the front knee cave inward.","Descending too fast without controlling the eccentric.","Not placing the full foot on the surface."]'::jsonb,
  pro_tip_es = 'Cuanto más alta la caja, mayor la activación del glúteo; usá una altura donde el muslo delantero esté paralelo o levemente por encima del suelo.',
  pro_tip_en = 'The higher the box, the greater the glute activation; use a height where the front thigh is parallel to or slightly above the floor.',
  tertiary_muscles = ARRAY['Core','Tibialis Anterior','Peroneals']::text[]
WHERE slug = 'dumbbell-step-up';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con los pies más anchos que los hombros y las puntas de los pies apuntando hacia afuera a unos 45°.","Sujetá una mancuerna con ambas manos colgando entre las piernas.","Bajá en sentadilla manteniendo el torso erguido y las rodillas siguiendo la dirección de los pies.","Descendé hasta que los muslos estén paralelos al suelo o más abajo si la movilidad lo permite.","Empujá desde los talones para volver a la posición inicial."]'::jsonb,
  execution_steps_en = '["Stand with feet wider than shoulder-width and toes pointing outward at approximately 45°.","Hold a single dumbbell with both hands hanging between the legs.","Lower into a squat keeping the torso upright and knees tracking over the toes.","Descend until thighs are parallel to the floor or lower if mobility allows.","Drive through the heels to return to the starting position."]'::jsonb,
  common_errors_es = '["Inclinar el tronco hacia adelante perdiendo la postura erguida.","Dejar que las rodillas caigan hacia adentro.","No aprovechar el rango completo del movimiento.","Llevar el peso demasiado adelante en lugar de dejarlo colgar."]'::jsonb,
  common_errors_en = '["Leaning the torso forward and losing the upright position.","Letting the knees cave inward.","Not using the full range of motion.","Letting the weight drift forward instead of hanging straight down."]'::jsonb,
  pro_tip_es = 'La posición amplia activa los aductores y el glúteo en un rango diferente al de la sentadilla convencional; combiná ambas en tu entrenamiento para cobertura completa.',
  pro_tip_en = 'The wide stance activates the adductors and glutes through a different range than a conventional squat; combine both in your training for complete coverage.',
  tertiary_muscles = ARRAY['Core','Erector Spinae','Hip External Rotators']::text[]
WHERE slug = 'dumbbell-sumo-squat';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte erguido con una mancuerna en cada mano y los pies juntos.","Dá un paso adelante con una pierna y bajá el cuerpo hasta que ambas rodillas queden a 90°.","Sin detener el movimiento, empujá desde el talón delantero y avanzá llevando la pierna trasera al frente para el siguiente paso.","Mantené el tronco erguido y los hombros sobre las caderas durante toda la trayectoria.","Continuálos pasos alternados hasta completar las repeticiones indicadas."]'::jsonb,
  execution_steps_en = '["Stand upright holding a dumbbell in each hand with feet together.","Step forward with one leg and lower the body until both knees are at 90°.","Without stopping, drive through the front heel and bring the rear leg forward for the next step.","Keep the torso upright and shoulders over the hips throughout.","Continue alternating steps until all indicated reps are complete."]'::jsonb,
  common_errors_es = '["Inclinarse hacia adelante con el tronco al dar el paso.","Valgo de rodilla en la pierna delantera.","Dar pasos demasiado cortos y no alcanzar los 90° de rodilla.","Perder el equilibrio al traspasar el peso entre piernas."]'::jsonb,
  common_errors_en = '["Leaning the torso forward when stepping.","Knee valgus in the front leg.","Taking short steps and failing to reach 90° knee flexion.","Losing balance when transferring weight between legs."]'::jsonb,
  pro_tip_es = 'Si te cuesta mantener el equilibrio al inicio, practicá primero estocadas estáticas; la versión caminando agrega demanda propioceptiva y cardiovascular.',
  pro_tip_en = 'If balance is a challenge at first, practice stationary lunges first; the walking version adds proprioceptive and cardiovascular demand.',
  tertiary_muscles = ARRAY['Core','Tibialis Anterior','Peroneals']::text[]
WHERE slug = 'dumbbell-walking-lunge';
UPDATE public.exercise_library SET
  execution_steps_es = '["Arrodilláte en la almohadilla del GHD con los pies bien anclados en los soportes.","Desde la posición erguida, bajá el torso hacia el suelo de forma excéntrica usando los isquiotibiales para frenar el movimiento.","Llegá al punto más bajo que el control muscular permita sin caer.","Contraé los isquiotibiales y los glúteos para volver a la posición inicial.","Mantené la espalda neutral en todo momento; no redondes la zona lumbar."]'::jsonb,
  execution_steps_en = '["Kneel on the GHD pad with the feet firmly anchored in the supports.","From the upright position, lower the torso toward the floor eccentrically using the hamstrings to brake the movement.","Reach the lowest point that muscular control allows without falling.","Contract the hamstrings and glutes to return to the starting position.","Keep the back neutral throughout; do not round the lumbar spine."]'::jsonb,
  common_errors_es = '["Usar la cadera en flexión-extensión para ayudar al movimiento en lugar de los isquiotibiales.","Bajar más rápido de lo que los músculos pueden controlar.","Redondear la espalda en la posición más baja.","Intentar el ejercicio sin una base de fuerza isquiotibial adecuada."]'::jsonb,
  common_errors_en = '["Using hip flexion-extension to assist the movement instead of the hamstrings.","Lowering faster than the muscles can control.","Rounding the back at the lowest position.","Attempting the exercise without an adequate hamstring strength base."]'::jsonb,
  pro_tip_es = 'Este es uno de los ejercicios más exigentes para los isquiotibiales; comenzá solo con la fase excéntrica (bajada con asistencia de los brazos) hasta tener la fuerza suficiente.',
  pro_tip_en = 'This is one of the most demanding hamstring exercises; start with only the eccentric phase (lowering with arm assistance) until you have sufficient strength.',
  tertiary_muscles = ARRAY['Erector Spinae','Gastrocnemius','Core']::text[]
WHERE slug = 'glute-ham-developer-ghd';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte en decúbito prono sobre un banco, abrazáte a él y dejá las piernas completamente fuera con las rodillas dobladas.","Elevá ambas piernas a la vez hasta la vertical contrayendo activamente los glúteos y los lumbares.","Sostenélo un instante en la posición alta y descendélas de forma controlada.","Mantené los lumbares contraídos isométricamente durante toda la serie para estabilizar la pelvis.","No uses impulso; el movimiento debe ser lento y deliberado."]'::jsonb,
  execution_steps_en = '["Lie prone on a bench, wrap your arms around it, and let both legs hang off the end with knees bent.","Raise both legs simultaneously toward vertical, actively contracting the glutes and lower back.","Hold briefly at the top position and lower under control.","Keep the lower back muscles contracted isometrically throughout to stabilize the pelvis.","Do not use momentum; the movement should be slow and deliberate."]'::jsonb,
  common_errors_es = '["Usar impulso para subir las piernas en lugar de contracción activa.","No llegar a la extensión completa de cadera.","Relajar los lumbares durante el movimiento.","Elevar solo una pierna alternativamente cuando el ejercicio requiere las dos."]'::jsonb,
  common_errors_en = '["Using momentum to raise the legs instead of active contraction.","Not reaching full hip extension.","Relaxing the lower back during the movement.","Alternating one leg at a time when the exercise requires both."]'::jsonb,
  pro_tip_es = 'La contracción isométrica de los lumbares es muy intensa en esta variante; si sentís molestia lumbar, reducí el rango o realizá el ejercicio de pie con soporte.',
  pro_tip_en = 'The isometric lower back contraction is very intense in this variation; if you feel lumbar discomfort, reduce the range or perform the exercise standing with support.',
  tertiary_muscles = ARRAY['Erector Spinae','Core','Piriformis']::text[]
WHERE slug = 'glute-kickback';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte con la espalda apoyada en el respaldo inclinado y los pies en la plataforma al ancho de los hombros.","Soltá los seguros y bajá de forma controlada flexionando las rodillas hasta que los muslos estén paralelos a la plataforma.","Empujá desde los talones y los medios pies para volver a la posición inicial sin bloquear las rodillas con brusquedad.","Mantené la espalda baja apoyada en el respaldo durante todo el movimiento.","Espirá durante el empuje; inspirá durante el descenso."]'::jsonb,
  execution_steps_en = '["Position yourself with the back against the angled pad and feet on the platform at shoulder width.","Release the safety handles and lower under control, bending the knees until the thighs are parallel to the platform.","Drive through the heels and mid-foot to return to the starting position without snapping the knees.","Keep the lower back in contact with the pad throughout the movement.","Exhale during the push; inhale during the descent."]'::jsonb,
  common_errors_es = '["Levantar los talones de la plataforma durante el descenso.","Dejar que las rodillas caigan hacia adentro.","No mantener la espalda en contacto con el respaldo.","Usar un rango de movimiento incompleto para manejar más peso."]'::jsonb,
  common_errors_en = '["Lifting the heels off the platform during the descent.","Letting the knees cave inward.","Losing back contact with the pad.","Using an incomplete range of motion to handle more weight."]'::jsonb,
  pro_tip_es = 'Colocar los pies más arriba en la plataforma activa más los glúteos e isquiotibiales; más abajo activa más el cuádriceps.',
  pro_tip_en = 'Placing the feet higher on the platform activates more glutes and hamstrings; lower placement emphasizes the quadriceps.',
  tertiary_muscles = ARRAY['Core','Tibialis Anterior','Adductors']::text[]
WHERE slug = 'hack-squat-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina con la espalda bien apoyada y colocá las almohadillas en el exterior de las rodillas.","Abrí las piernas empujando contra las almohadillas hasta llegar al máximo recorrido cómodo.","Sostenélas un instante en la posición abierta apretando el glúteo medio.","Volvélas a la posición inicial de forma controlada sin dejar que el peso las jale.","Mantené el tronco estable; no te inclinés para ganar amplitud."]'::jsonb,
  execution_steps_en = '["Sit in the machine with back fully supported and pads on the outside of the knees.","Open the legs by pushing outward against the pads to the maximum comfortable range.","Hold briefly at the open position, squeezing the gluteus medius.","Return to the starting position under control without letting the weight pull the legs.","Keep the trunk stable; do not lean to gain extra range."]'::jsonb,
  common_errors_es = '["Inclinarse hacia adelante con el tronco para ayudar al movimiento.","Usar peso excesivo y reducir el rango de movimiento.","No mantener la contracción muscular en el punto de máxima apertura.","Dejar que el peso controle el retorno en lugar de frenarlo activamente."]'::jsonb,
  common_errors_en = '["Leaning the torso forward to assist the movement.","Using excessive weight and reducing the range of motion.","Not maintaining muscle contraction at maximum opening.","Letting the weight control the return instead of actively braking."]'::jsonb,
  pro_tip_es = 'Este ejercicio complementa la sentadilla y el peso muerto para la salud de la cadera; priorizá la calidad del movimiento por encima de la carga.',
  pro_tip_en = 'This exercise complements squats and deadlifts for hip health; prioritize movement quality over load.',
  tertiary_muscles = ARRAY['Gluteus Minimus','Piriformis','Core']::text[]
WHERE slug = 'hip-abductor-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte lateral a la polea baja con la tobillera en la pierna alejada de la máquina y sujetáte al aparato.","Permanecé lo suficientemente separado de la polea para permitir un recorrido significativo.","Llevá la pierna en abducción en todo el rango posible sin llegar al choque articular de la cadera.","No flexionés apenas la cadera; mantené el cuerpo lateral a la polea para que el movimiento sea abducción pura.","Retorná de forma controlada y repetí."]'::jsonb,
  execution_steps_en = '["Stand sideways to the low pulley with the ankle strap on the far leg and hold the machine for support.","Stand far enough from the pulley to allow a significant range of motion.","Lift the leg in abduction through the full available range without forcing the hip joint.","Minimize hip flexion; keep the body sideways to the pulley so the movement is pure abduction.","Return under control and repeat."]'::jsonb,
  common_errors_es = '["Flexionar la cadera en lugar de realizar una abducción lateral pura.","Estar demasiado cerca de la polea y no tener recorrido útil.","Inclinar lateralmente el tronco para compensar la falta de movilidad.","Superar el rango seguro y forzar el choque articular."]'::jsonb,
  common_errors_en = '["Flexing the hip instead of performing pure lateral abduction.","Standing too close to the pulley with no useful range of motion.","Leaning the trunk laterally to compensate for limited mobility.","Exceeding the safe range and forcing a hip impingement."]'::jsonb,
  pro_tip_es = 'Mantené el pie en posición neutra (ni rotado hacia adentro ni hacia afuera) para asegurarte de que el glúteo medio sea el músculo principal.',
  pro_tip_en = 'Keep the foot in a neutral position (not rotated in or out) to ensure the gluteus medius is the primary muscle.',
  tertiary_muscles = ARRAY['Gluteus Minimus','Sartorius','Core']::text[]
WHERE slug = 'hip-abductor-machine-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina con la espalda apoyada y colocá las almohadillas en el interior de las rodillas.","Abrí las piernas hasta la posición inicial de estiramiento cómodo.","Cerrá las piernas empujando contra las almohadillas hacia adentro de forma controlada.","Sostenélas un instante en la posición cerrada y volvé al punto inicial de forma controlada.","Mantené el tronco estable y no uses el torso para generar fuerza."]'::jsonb,
  execution_steps_en = '["Sit in the machine with back supported and pads on the inside of the knees.","Open the legs to a comfortable initial stretch position.","Close the legs by pressing the pads inward in a controlled manner.","Hold briefly at the closed position and return to the start under control.","Keep the trunk stable and do not use the torso to generate force."]'::jsonb,
  common_errors_es = '["Usar el tronco o inclinarse para ayudar al cierre de las piernas.","Abrir las piernas en exceso y generar estiramiento doloroso.","Cerrar las piernas de forma explosiva sin control.","No completar el rango de movimiento en el cierre."]'::jsonb,
  common_errors_en = '["Using the trunk or leaning to help close the legs.","Opening the legs too wide and causing a painful stretch.","Closing the legs explosively without control.","Not completing the full range of motion at the close."]'::jsonb,
  pro_tip_es = 'Los aductores se trabajan muy poco con sentadillas convencionales; incluir esta máquina complementa el entrenamiento de piernas de forma eficiente.',
  pro_tip_en = 'The adductors are underworked in conventional squats; including this machine efficiently complements leg training.',
  tertiary_muscles = ARRAY['Pectineus','Obturator Externus','Core']::text[]
WHERE slug = 'hip-adductor-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la versión de la máquina con el respaldo más inclinado hacia atrás y colocá las almohadillas en el interior de las rodillas.","Abrí las piernas hasta la posición de estiramiento inicial cómodo.","Cerrá las piernas de forma controlada empujando las almohadillas hacia adentro.","Sostenélas en la posición cerrada un instante antes de volver al inicio.","La mayor inclinación del respaldo añade trabajo a los músculos posteriores de la pierna; mantenélos activados durante la serie."]'::jsonb,
  execution_steps_en = '["Sit in the version of the machine with the back pad more reclined and place the pads on the inside of the knees.","Open the legs to a comfortable initial stretch.","Close the legs under control by pressing the pads inward.","Hold briefly at the closed position before returning to the start.","The increased back recline adds work to the posterior leg muscles; keep them engaged throughout the set."]'::jsonb,
  common_errors_es = '["Usar impulso del tronco en lugar de los aductores.","No controlar el retorno a la posición abierta.","Abrir demasiado las piernas forzando el estiramiento.","Ignorar la activación adicional de la musculatura posterior que ofrece esta variante."]'::jsonb,
  common_errors_en = '["Using trunk momentum instead of the adductors.","Not controlling the return to the open position.","Opening the legs too wide, forcing the stretch.","Ignoring the additional posterior muscle activation this variant offers."]'::jsonb,
  pro_tip_es = 'Esta variante con respaldo reclinado recluta más el aductor mayor en su porción posterior; es complementaria a la variante sedente estándar.',
  pro_tip_en = 'This reclined back variant recruits more of the posterior portion of the adductor magnus; it complements the standard seated version.',
  tertiary_muscles = ARRAY['Adductor Magnus (posterior)','Gluteus Maximus (deep)','Core']::text[]
WHERE slug = 'hip-adductor-machine-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina con la espalda apoyada y la almohadilla justo sobre el tobillo.","Extendé las rodillas hasta la posición recta de forma controlada, apretando el cuádriceps en la cima.","Sostenélo un instante y bajá de forma lenta controlando el descenso.","No bloqueés las rodillas con brusquedad en la extensión completa.","Mantenélos pies en posición neutra durante todo el movimiento."]'::jsonb,
  execution_steps_en = '["Sit in the machine with back supported and the pad just above the ankle.","Extend the knees to straight under control, squeezing the quad at the top.","Hold briefly, then lower slowly with a controlled descent.","Do not snap the knees into full extension.","Keep the feet in a neutral position throughout."]'::jsonb,
  common_errors_es = '["Usar impulso balanceando el tronco para completar las repeticiones.","Extender de forma explosiva y bloquear la rodilla bruscamente.","No bajar de forma controlada en la fase excéntrica.","Colocar la almohadilla muy alta sobre la tibia generando presión excesiva."]'::jsonb,
  common_errors_en = '["Using trunk swinging momentum to complete reps.","Extending explosively and snapping the knee.","Not lowering under control during the eccentric phase.","Placing the pad too high on the shin, creating excessive pressure."]'::jsonb,
  pro_tip_es = 'El movimiento de extensión de rodilla aislado es útil para la hipertrofia del cuádriceps; combinalo con ejercicios compuestos para resultados óptimos.',
  pro_tip_en = 'The isolated knee extension is useful for quadriceps hypertrophy; combine it with compound exercises for optimal results.',
  tertiary_muscles = ARRAY['Tensor Fascia Latae','Sartorius','Core']::text[]
WHERE slug = 'leg-extension-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte con las puntas de los pies levemente giradas hacia adentro y apoyá el lateral del muslo en el banco.","Extendé la rodilla de forma controlada hasta aproximadamente 90° sin llegar a la extensión completa.","Apretá el vasto externo en el punto de mayor tensión y descendé de forma lenta.","Usá cargas ligeras en esta variante; es específica para rehabilitación o corrección de desequilibrios.","Solo realizá esta variante por indicación específica; la extensión completa no se recomienda en esta posición."]'::jsonb,
  execution_steps_en = '["Sit with the toes slightly turned inward and rest the lateral thigh against the bench.","Extend the knee under control to approximately 90° without reaching full extension.","Squeeze the vastus lateralis at the peak tension point and lower slowly.","Use light loads for this variation; it is specific to rehabilitation or imbalance correction.","Only perform this variation on specific indication; full extension is not recommended in this position."]'::jsonb,
  common_errors_es = '["Llegar a la extensión completa en esta variante.","Usar demasiado peso para una variante de corrección muscular.","No mantener la rotación interna durante todo el recorrido.","Realizar esta variante sin una indicación técnica o terapéutica específica."]'::jsonb,
  common_errors_en = '["Reaching full extension in this variation.","Using too much weight for a muscle-correction variant.","Not maintaining the internal rotation throughout the range.","Performing this variant without a specific technical or therapeutic indication."]'::jsonb,
  pro_tip_es = 'Esta variante está orientada a la rehabilitación de desequilibrios en el cuádriceps; no la uses como ejercicio principal de masa.',
  pro_tip_en = 'This variation targets quadriceps imbalance rehabilitation; do not use it as a primary mass-building exercise.',
  tertiary_muscles = ARRAY['Tensor Fascia Latae','Sartorius','Rectus Femoris']::text[]
WHERE slug = 'leg-extension-machine-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la prensa con la espalda y la pelvis bien apoyadas en el respaldo.","Colocá los pies al ancho de los hombros en la plataforma y soltá los seguros.","Bajá la plataforma de forma controlada hasta que las rodillas lleguen aproximadamente a 90°.","Empujá desde los talones y el centro del pie para volver a la posición inicial sin bloquear las rodillas.","Mantenélos lumbares en contacto con el respaldo durante todo el movimiento."]'::jsonb,
  execution_steps_en = '["Sit in the press with the back and pelvis fully supported against the pad.","Place feet shoulder-width apart on the platform and release the safety handles.","Lower the platform under control until the knees reach approximately 90°.","Drive through the heels and mid-foot to return to the starting position without locking the knees.","Keep the lower back in contact with the pad throughout the movement."]'::jsonb,
  common_errors_es = '["Dejar que la espalda baja se despegue del respaldo al bajar.","Doblar las rodillas más allá de 90° sin el rango de movilidad adecuado.","Bloqueár las rodillas de forma brusca al final del empuje.","Colocar los pies demasiado juntos, aumentando el stress en la rodilla."]'::jsonb,
  common_errors_en = '["Letting the lower back peel off the pad during the descent.","Bending the knees past 90° without adequate mobility.","Snapping the knees at the end of the push.","Placing feet too close together, increasing knee stress."]'::jsonb,
  pro_tip_es = 'Colocar los pies en la parte alta de la plataforma aumenta la activación de glúteos e isquiotibiales; más abajo activa más el cuádriceps.',
  pro_tip_en = 'Placing feet higher on the platform increases glute and hamstring activation; lower foot placement emphasizes the quadriceps.',
  tertiary_muscles = ARRAY['Calves','Core','Hip Flexors (eccentric)']::text[]
WHERE slug = 'leg-press-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en la plataforma inclinada a 45° con la espalda completamente apoyada.","Colocá los pies al ancho de los hombros en la plataforma y soltá los seguros.","Bajá la plataforma de forma controlada flexionando las rodillas sin despegar los lumbares.","Empujá desde los talones hasta casi la extensión completa sin bloquear las rodillas.","Respirá: inspirá en el descenso, espirá en el empuje."]'::jsonb,
  execution_steps_en = '["Recline on the 45° angled platform with the back fully supported.","Place feet shoulder-width apart on the platform and release the safety handles.","Lower the platform under control by bending the knees without letting the lower back peel off.","Drive through the heels to near full extension without locking the knees.","Breathe: inhale on the descent, exhale on the push."]'::jsonb,
  common_errors_es = '["Dejar que los lumbares se curven al bajar la plataforma demasiado.","Bloqueár las rodillas de golpe en la extensión.","Usar solo la punta del pie en lugar del talón y el centro del pie.","Soltar los seguros sin verificar que los pies estén bien posicionados."]'::jsonb,
  common_errors_en = '["Letting the lower back curl when lowering the platform too far.","Snapping the knees into extension.","Using only the toes instead of the heel and mid-foot.","Releasing the safety handles without verifying foot placement."]'::jsonb,
  pro_tip_es = 'La prensa a 45° permite cargar más peso que otras variantes con menos carga espinal; aprovechá esto para series de alto volumen de forma segura.',
  pro_tip_en = 'The 45° press allows heavier loading than other variants with less spinal compression; use this for high-volume sets safely.',
  tertiary_muscles = ARRAY['Calves','Adductors','Core']::text[]
WHERE slug = 'leg-press-machine-45';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la prensa horizontal con la espalda apoyada en el respaldo vertical.","Colocá los pies al ancho de los hombros en la plataforma y soltá los seguros.","Empujá la plataforma hacia adelante hasta casi la extensión completa de las rodillas.","Volvé la plataforma de forma controlada hasta que las rodillas lleguen a 90°.","Mantenélos pies planos en la plataforma y los lumbares en contacto con el respaldo."]'::jsonb,
  execution_steps_en = '["Sit in the horizontal press with the back against the vertical support.","Place feet shoulder-width apart on the platform and release the safety handles.","Push the platform forward to near full knee extension.","Return the platform under control until the knees reach 90°.","Keep the feet flat on the platform and the lower back in contact with the pad."]'::jsonb,
  common_errors_es = '["Bloqueár las rodillas de forma brusca en la extensión.","Dejar que las rodillas caigan hacia adentro durante el movimiento.","No controlar el retorno y dejar que el peso jale las piernas.","Despegar la espalda del respaldo al empujar."]'::jsonb,
  common_errors_en = '["Snapping the knees into extension.","Letting the knees cave inward during the movement.","Not controlling the return and letting the weight pull the legs.","Peeling the back off the pad during the push."]'::jsonb,
  pro_tip_es = 'La posición sentada de esta variante genera menor compresión en la columna que la prensa a 45°; es una buena alternativa para personas con molestias lumbares.',
  pro_tip_en = 'The seated position of this variant generates less spinal compression than the 45° press; it is a good alternative for those with lower back discomfort.',
  tertiary_muscles = ARRAY['Calves','Adductors','Core']::text[]
WHERE slug = 'leg-press-machine-horizontalseated';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte erguido con los pies juntos y las manos en las caderas o con peso adicional.","Dá un paso adelante con una pierna y bajá hasta que ambas rodillas estén a 90°.","La rodilla delantera no debe sobrepasar el tobillo; la trasera se acerca pero no toca el suelo.","Empujá desde el talón delantero para volver a la posición inicial.","Alternálos lados de forma controlada durante toda la serie."]'::jsonb,
  execution_steps_en = '["Stand upright with feet together and hands on hips or holding additional weight.","Step forward with one leg and lower until both knees are at 90°.","The front knee should not pass the ankle; the rear knee approaches but does not touch the floor.","Drive through the front heel to return to the starting position.","Alternate sides in a controlled manner throughout the set."]'::jsonb,
  common_errors_es = '["Dejar que la rodilla delantera pase por delante del tobillo.","Inclinar el tronco excesivamente hacia adelante.","Dar pasos demasiado cortos limitando la profundidad.","Valgo de rodilla en la pierna delantera."]'::jsonb,
  common_errors_en = '["Letting the front knee travel past the ankle.","Leaning the torso excessively forward.","Taking short steps that limit depth.","Knee valgus in the front leg."]'::jsonb,
  pro_tip_es = 'Mantené el tronco perfectamente vertical durante el descenso; imagináte que un hilo jala la parte superior de tu cabeza hacia el techo.',
  pro_tip_en = 'Keep the torso perfectly vertical during the descent; imagine a string pulling the top of your head toward the ceiling.',
  tertiary_muscles = ARRAY['Core','Tibialis Anterior','Peroneals']::text[]
WHERE slug = 'lunges';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte en decúbito prono con los talones bajo la almohadilla y las rodillas justo en el borde del banco.","Desde la extensión completa, flexioná las rodillas llevando los talones hacia los glúteos de forma controlada.","Apretá los isquiotibiales en el punto de máxima flexión.","Bajá de forma lenta y controlada sin dejar que el peso caiga.","Mantenélas caderas en contacto con el banco durante toda la serie."]'::jsonb,
  execution_steps_en = '["Lie prone with the heels under the pad and knees just at the bench edge.","From full extension, flex the knees bringing the heels toward the glutes under control.","Squeeze the hamstrings at maximum flexion.","Lower slowly and under control without letting the weight drop.","Keep the hips in contact with the bench throughout the set."]'::jsonb,
  common_errors_es = '["Levantar las caderas del banco para ayudar al movimiento.","No controlar el descenso y dejar que el peso jale hacia abajo.","Usar excesivo peso y acortar el rango de movimiento.","No llegar a la extensión completa entre repeticiones."]'::jsonb,
  common_errors_en = '["Lifting the hips off the bench to assist the movement.","Not controlling the descent and letting the weight pull down.","Using excessive weight and shortening the range of motion.","Not reaching full extension between reps."]'::jsonb,
  pro_tip_es = 'La versión acostada activa más el bíceps femoral (porción larga); combinala con la versión sentada para trabajar todos los isquiotibiales.',
  pro_tip_en = 'The prone version activates more of the biceps femoris (long head); combine it with the seated version to work all hamstring heads.',
  tertiary_muscles = ARRAY['Gastrocnemius','Popliteus','Sartorius']::text[]
WHERE slug = 'lying-leg-curl-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte en decúbito prono con los pies en rotación interna (puntas hacia adentro) y el lateral de la pierna apoyado.","Flexioná las rodillas de forma controlada llevando los talones hacia los glúteos.","Esta posición traslada mayor trabajo al semimembranoso y semitendinoso.","Bajá de forma lenta sin dejar que el peso jale.","Usá cargas moderadas dado el mayor estrés sobre los tendones en esta posición."]'::jsonb,
  execution_steps_en = '["Lie prone with feet internally rotated (toes inward) and the lateral leg resting against the bench.","Flex the knees under control, bringing the heels toward the glutes.","This position shifts more work to the semimembranosus and semitendinosus.","Lower slowly without letting the weight pull down.","Use moderate loads given the increased tendon stress in this position."]'::jsonb,
  common_errors_es = '["Usar demasiado peso en una posición que ya es más exigente para los tendones.","Perder la rotación interna durante el movimiento.","Levantar las caderas para completar las repeticiones.","Realizar esta variante sin una razón técnica específica."]'::jsonb,
  common_errors_en = '["Using too much weight in a position that is already more tendon-demanding.","Losing the internal rotation during the movement.","Raising the hips to complete reps.","Performing this variant without a specific technical reason."]'::jsonb,
  pro_tip_es = 'Esta variante permite dirigir el trabajo hacia la parte interna del muslo posterior; combinala con la versión estándar para desarrollo completo de isquiotibiales.',
  pro_tip_en = 'This variant directs work toward the inner posterior thigh; combine it with the standard version for complete hamstring development.',
  tertiary_muscles = ARRAY['Gracilis','Sartorius','Popliteus']::text[]
WHERE slug = 'lying-leg-curl-machine-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en un banco con las puntas de los pies sobre una superficie elevada y una barra o mancuernas sobre los muslos.","Desde la dorsiflexión máxima (talones bajos), elevá los talones en flexión plantar completa.","Sostenélos en la cima un segundo y bajá de forma lenta y controlada.","Mantenélas rodillas a 90° durante todo el movimiento para trabajar el sóleo.","No rebotés en la posición de máximo estiramiento."]'::jsonb,
  execution_steps_en = '["Sit on a bench with the balls of the feet on an elevated surface and a bar or dumbbells on the thighs.","From maximum dorsiflexion (heels low), raise the heels into full plantar flexion.","Hold at the top for one second and lower slowly under control.","Keep the knees at 90° throughout to target the soleus.","Do not bounce at the maximum stretch position."]'::jsonb,
  common_errors_es = '["Rebotar en la posición de estiramiento.","No mantener las rodillas a 90° durante el movimiento.","No llegar a la extensión completa del tobillo en la cima.","Usar demasiado peso y perder el control del movimiento."]'::jsonb,
  common_errors_en = '["Bouncing at the stretch position.","Not keeping the knees at 90° during the movement.","Not reaching full ankle extension at the top.","Using too much weight and losing movement control."]'::jsonb,
  pro_tip_es = 'Las rodillas dobladas a 90° relajan los gemelos y ponen el trabajo principalmente en el sóleo; esta variante es clave para desarrollar la pantorrilla completa.',
  pro_tip_en = 'Knees bent at 90° relax the gastrocnemius and place the work primarily on the soleus; this variant is key to developing the full calf.',
  tertiary_muscles = ARRAY['Tibialis Posterior','Peroneals','Flexor Digitorum Longus']::text[]
WHERE slug = 'seated-calf-raise-bar';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina con las almohadillas sobre los muslos y las puntas de los pies en la plataforma.","Desde la dorsiflexión máxima, elevá los talones hasta la extensión completa del tobillo.","Sostenélos en la cima un segundo y bajá de forma lenta y controlada.","Descargá el peso antes de retirarte de la máquina.","No rebotés en la posición de máximo estiramiento."]'::jsonb,
  execution_steps_en = '["Sit in the machine with pads on the thighs and balls of the feet on the platform.","From maximum dorsiflexion, raise the heels to full ankle extension.","Hold for one second at the top and lower slowly and under control.","Release the weight before getting off the machine.","Do not bounce at the maximum stretch position."]'::jsonb,
  common_errors_es = '["Rebotar en la posición baja para usar impulso.","No llegar a la extensión completa del tobillo.","Despegar los talones de la plataforma al inicio del movimiento.","Usar peso excesivo que impide el rango completo."]'::jsonb,
  common_errors_en = '["Bouncing at the bottom to use momentum.","Not reaching full ankle extension.","Lifting the heels off the platform at the start of the movement.","Using excessive weight that prevents full range."]'::jsonb,
  pro_tip_es = 'El sóleo responde especialmente bien a series largas (12-20 reps) con tempo lento; priorizá tiempo bajo tensión sobre carga máxima.',
  pro_tip_en = 'The soleus responds especially well to longer sets (12–20 reps) with a slow tempo; prioritize time under tension over maximum load.',
  tertiary_muscles = ARRAY['Tibialis Posterior','Peroneals','Flexor Hallucis Longus']::text[]
WHERE slug = 'seated-calf-raise-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina donde las puntas de los pies descienden en flexión plantar (diseño invertido).","Desde la posición inicial, elevá los talones empujando las puntas de los pies hacia abajo.","Llegá a la extensión máxima del tobillo y sostenélo un segundo.","Volvé de forma controlada al punto inicial sin rebotar.","Descargá el peso antes de salir de la máquina."]'::jsonb,
  execution_steps_en = '["Sit in the machine where the toes descend in plantar flexion (inverted design).","From the starting position, raise the heels by pushing the toes downward.","Reach maximum ankle extension and hold for one second.","Return under control to the starting point without bouncing.","Release the weight before getting off the machine."]'::jsonb,
  common_errors_es = '["No llegar al rango completo dado el diseño limitado de algunos aparatos.","Despegar los pies de la plataforma en lugar de mover solo el tobillo.","Usar carga excesiva en una máquina donde el rango es ya limitado.","No descargar el peso al terminar la serie."]'::jsonb,
  common_errors_en = '["Not achieving full range given the limited design of some machines.","Lifting the feet off the platform instead of moving only the ankle.","Using excessive load on a machine where range is already limited.","Not releasing the weight at the end of the set."]'::jsonb,
  pro_tip_es = 'Verificá el rango real de movimiento disponible en la máquina antes de cargar peso; algunos diseños tienen recorrido muy corto.',
  pro_tip_en = 'Check the actual available range of motion on the machine before loading weight; some designs have a very short stroke.',
  tertiary_muscles = ARRAY['Tibialis Posterior','Peroneals','Flexor Digitorum Longus']::text[]
WHERE slug = 'seated-calf-raise-machine-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte con la espalda apoyada en el respaldo y la almohadilla superior sobre los muslos.","Colocá los talones sobre la almohadilla inferior y aseguráte de que las rodillas queden alineadas con el eje de la máquina.","Flexioná las rodillas llevando los talones hacia abajo y hacia atrás en el rango completo.","Apretá los isquiotibiales en el punto de máxima flexión y volvé de forma controlada.","No uses el tronco para ayudar al movimiento."]'::jsonb,
  execution_steps_en = '["Sit with the back against the pad and the upper pad resting on the thighs.","Place the heels on the lower pad and ensure the knees align with the machine axis.","Flex the knees by bringing the heels down and back through the full range.","Squeeze the hamstrings at maximum flexion and return under control.","Do not use the trunk to assist the movement."]'::jsonb,
  common_errors_es = '["No alinear las rodillas con el eje de la máquina, generando estrés articular.","Usar el tronco hacia adelante para ayudar al movimiento.","No llegar al rango completo de flexión.","Relajar la tensión en la fase excéntrica."]'::jsonb,
  common_errors_en = '["Not aligning the knees with the machine axis, creating joint stress.","Using the trunk forward to assist the movement.","Not reaching the full range of flexion.","Releasing tension in the eccentric phase."]'::jsonb,
  pro_tip_es = 'La versión sentada estira los isquiotibiales desde la cadera y activa todos los cabezas del músculo de forma más equilibrada que la versión acostada.',
  pro_tip_en = 'The seated version stretches the hamstrings from the hip and activates all heads more evenly than the prone version.',
  tertiary_muscles = ARRAY['Gastrocnemius','Popliteus','Gracilis']::text[]
WHERE slug = 'seated-leg-curl-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte de lado en el suelo con el cuerpo en línea recta y la cabeza apoyada en el brazo extendido.","Desde la posición de piernas juntas, elevá la pierna superior en abducción sin doblar la cintura.","Llegá al máximo rango de abducción controlada sin rotar la cadera.","Bajá de forma controlada sin apoyar la pierna entre repeticiones para mantener la tensión.","Completá todas las repeticiones de un lado antes de girar."]'::jsonb,
  execution_steps_en = '["Lie on your side with the body in a straight line and the head resting on the extended arm.","From the legs-together position, raise the top leg in abduction without bending at the waist.","Reach maximum controlled abduction range without hip rotation.","Lower under control without resting the leg between reps to maintain tension.","Complete all reps on one side before rolling over."]'::jsonb,
  common_errors_es = '["Doblar la cintura hacia adelante en lugar de realizar una abducción pura.","Rotar la cadera y llevar la pierna hacia adelante.","No controlar el descenso y dejar que la pierna caiga.","Elevar la pierna demasiado alto forzando la articulación de la cadera."]'::jsonb,
  common_errors_en = '["Bending at the waist instead of performing pure abduction.","Rotating the hip and bringing the leg forward.","Not controlling the descent and letting the leg fall.","Lifting the leg too high and forcing the hip joint."]'::jsonb,
  pro_tip_es = 'Colocá una tobillera lastrada para aumentar la resistencia progresivamente; el peso corporal solo puede volverse insuficiente con el tiempo.',
  pro_tip_en = 'Use an ankle weight to progressively increase resistance; bodyweight alone may become insufficient over time.',
  tertiary_muscles = ARRAY['Gluteus Minimus','Piriformis','Core']::text[]
WHERE slug = 'side-leg-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá la barra de la máquina Smith sobre los hombros y paráte con las puntas de los pies en el borde de una plataforma.","Desde la dorsiflexión máxima, elevá los talones hasta la extensión completa del tobillo.","Sostenélos en la cima un segundo y bajá de forma lenta y controlada.","Mantenélas rodillas levemente flexionadas y fijas durante todo el movimiento.","No rebotés en la posición de máximo estiramiento."]'::jsonb,
  execution_steps_en = '["Place the Smith machine bar on the shoulders and stand with the balls of the feet on the edge of a platform.","From maximum dorsiflexion, raise the heels to full ankle extension.","Hold for one second at the top and lower slowly under control.","Keep the knees slightly bent and fixed throughout.","Do not bounce at the maximum stretch position."]'::jsonb,
  common_errors_es = '["Rebotar en la posición de estiramiento.","No llegar a la extensión completa del tobillo.","Doblar las rodillas para ayudar al movimiento.","Usar demasiado peso comprometiendo el rango de movimiento."]'::jsonb,
  common_errors_en = '["Bouncing at the stretch position.","Not reaching full ankle extension.","Bending the knees to assist the movement.","Using too much weight and compromising range of motion."]'::jsonb,
  pro_tip_es = 'La guía de la máquina Smith permite concentrarse en el tobillo sin preocuparse por el equilibrio, lo que facilita series de alto volumen y carga.',
  pro_tip_en = 'The Smith machine guide allows full focus on the ankle without balance concerns, making it easier to perform high-volume, heavy sets.',
  tertiary_muscles = ARRAY['Tibialis Anterior','Peroneals','Soleus']::text[]
WHERE slug = 'smith-machine-calf-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Apoyá los hombros en un banco y colocá la barra de la Smith sobre las caderas protegidas con una almohadilla.","Con los pies apoyados en el suelo al ancho de las caderas, bajá las caderas hacia el suelo de forma controlada.","Empujá las caderas hacia arriba hasta la extensión completa apretando los glúteos.","Sostenélos en la cima un segundo y volvé de forma controlada.","Ajustá la altura de la barra antes de comenzar la serie."]'::jsonb,
  execution_steps_en = '["Rest the upper back on a bench and place the Smith bar across the hips protected by a pad.","With feet flat on the floor at hip width, lower the hips toward the floor under control.","Drive the hips upward to full extension, squeezing the glutes.","Hold for one second at the top and return under control.","Adjust the bar height before starting the set."]'::jsonb,
  common_errors_es = '["Arquear la espalda lumbar en exceso en lugar de extender desde la cadera.","No usar almohadilla protectora en la barra.","No llegar a la extensión completa de cadera.","Dejar que las rodillas caigan hacia adentro."]'::jsonb,
  common_errors_en = '["Hyperextending the lower back instead of extending from the hip.","Not using a protective pad on the bar.","Not reaching full hip extension.","Letting the knees fall inward."]'::jsonb,
  pro_tip_es = 'La máquina Smith permite cargas más altas de forma segura al no requerir equilibrio; usá esto a tu favor para sobrecargar progresivamente los glúteos.',
  pro_tip_en = 'The Smith machine allows heavier safe loading by removing the balance requirement; use this advantage for progressive glute overload.',
  tertiary_muscles = ARRAY['Core','Adductors','Tibialis Anterior']::text[]
WHERE slug = 'smith-machine-hip-thrust';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá la barra de la Smith sobre los hombros y paráte erguido dentro de la máquina.","Dá un paso adelante con una pierna y bajá hasta que ambas rodillas queden a 90°.","Mantené el tronco erguido y la rodilla delantera alineada con el tobillo.","Empujá desde el talón delantero para volver a la posición inicial.","Completá todas las repeticiones de un lado antes de cambiar el paso."]'::jsonb,
  execution_steps_en = '["Place the Smith bar on the shoulders and stand upright inside the machine.","Step forward with one leg and lower until both knees are at 90°.","Keep the torso upright and the front knee aligned over the front ankle.","Drive through the front heel to return to the starting position.","Complete all reps on one side before changing the step."]'::jsonb,
  common_errors_es = '["Dejar que la rodilla delantera pase por delante del tobillo.","Inclinarse hacia adelante con el tronco al descender.","Valgo de rodilla en la pierna delantera.","Bloquear los seguros sin haber completado la repetición."]'::jsonb,
  common_errors_en = '["Letting the front knee travel past the ankle.","Leaning the torso forward during the descent.","Knee valgus in the front leg.","Engaging the safety handles before completing the rep."]'::jsonb,
  pro_tip_es = 'La guía de la Smith elimina la demanda de equilibrio, permitiéndote enfocarte en la profundidad y la activación muscular.',
  pro_tip_en = 'The Smith guide removes the balance demand, allowing you to focus entirely on depth and muscle activation.',
  tertiary_muscles = ARRAY['Core','Tibialis Anterior','Hip Flexors']::text[]
WHERE slug = 'smith-machine-lunge';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá la barra de la Smith a la altura de los hombros y colocátela sobre la parte alta de la espalda.","Colocá los pies ligeramente adelantados respecto a la vertical de la barra al ancho de los hombros.","Bajá en sentadilla de forma controlada hasta que los muslos estén paralelos al suelo.","Empujá desde los talones para volver a la posición inicial.","Espirá en el ascenso; inspirá en el descenso."]'::jsonb,
  execution_steps_en = '["Set the Smith bar at shoulder height and position it on the upper back.","Place feet slightly forward of the bar''s vertical line, shoulder-width apart.","Lower into a squat under control until the thighs are parallel to the floor.","Drive through the heels to return to the starting position.","Exhale on the ascent; inhale on the descent."]'::jsonb,
  common_errors_es = '["Colocar los pies directamente debajo de la barra en lugar de ligeramente adelantados.","Dejar que las rodillas caigan hacia adentro.","No alcanzar la profundidad paralela.","Bloqueár las rodillas de forma brusca al terminar."]'::jsonb,
  common_errors_en = '["Placing feet directly under the bar instead of slightly forward.","Letting the knees cave inward.","Not reaching parallel depth.","Snapping the knees at the end of the movement."]'::jsonb,
  pro_tip_es = 'La guía de la Smith limita el movimiento natural de la barra; colocálos pies ligeramente adelantados compensa esta restricción y reduce el stress lumbar.',
  pro_tip_en = 'The Smith guide limits the bar''s natural path; placing feet slightly forward compensates for this restriction and reduces lumbar stress.',
  tertiary_muscles = ARRAY['Core','Erector Spinae','Tibialis Anterior']::text[]
WHERE slug = 'smith-machine-squat';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá la barra en la posición de sentadilla convencional sobre la espalda alta dentro del multipower.","Posicionálos pies más adelantados que en una sentadilla libre; no hay riesgo de caer hacia atrás.","Bajá de forma controlada hasta la profundidad deseada manteniendo la espalda recta.","Empujá desde los talones para volver a la posición inicial.","El glúteo trabajará de forma más intensa con esta posición de pies adelantados."]'::jsonb,
  execution_steps_en = '["Place the bar in the conventional squat position on the upper back inside the Smith machine.","Position the feet further forward than in a free-weight squat; there is no risk of falling backward.","Lower under control to the desired depth while keeping the back straight.","Drive through the heels to return to the starting position.","The glutes will work more intensely with this forward foot position."]'::jsonb,
  common_errors_es = '["Colocar los pies demasiado juntos aumentando el estrés en la rodilla.","Dejar que las rodillas caigan hacia adentro.","No aprovechar la posición de pies adelantados para trabajar más el glúteo.","Usar el equilibrio del Smith para compensar una técnica deficiente."]'::jsonb,
  common_errors_en = '["Placing feet too close together, increasing knee stress.","Letting the knees cave inward.","Not taking advantage of the forward foot position to increase glute work.","Using the Smith balance to compensate for poor technique."]'::jsonb,
  pro_tip_es = 'Con los pies adelantados en el Smith, la tensión en la rótula se reduce y el glúteo trabaja de forma más intensa; es una ventaja táctica de esta variante.',
  pro_tip_en = 'With feet forward on the Smith, patellar stress is reduced and the glute works more intensely; this is a tactical advantage of this variant.',
  tertiary_muscles = ARRAY['Core','Erector Spinae','Adductors']::text[]
WHERE slug = 'smith-machine-squat-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte con las rodillas flexionadas 90° y los talones sobre un escalón bajo.","Colocá un disco o lastre sobre el empeine del pie.","Elevá el pie hasta el máximo recorrido posible, aproximadamente 30°, de forma controlada.","Sostenélo un instante en la parte alta y descendélo de nuevo.","Respirá de forma natural durante todo el ejercicio."]'::jsonb,
  execution_steps_en = '["Sit with knees bent at 90° and heels on a low step.","Place a weight plate or similar load on the top of the foot.","Raise the foot to the maximum available range, approximately 30°, in a controlled manner.","Hold briefly at the top and lower back down.","Breathe naturally throughout the exercise."]'::jsonb,
  common_errors_es = '["Superar los 30° de elevación forzando el rango articular del tobillo.","Usar demasiado peso y perder el control del movimiento.","No mantener las rodillas a 90° durante la serie.","Ejecutar el movimiento de forma rápida sin tiempo bajo tensión."]'::jsonb,
  common_errors_en = '["Exceeding 30° of elevation and forcing the ankle joint range.","Using too much weight and losing movement control.","Not keeping the knees at 90° during the set.","Executing the movement quickly without time under tension."]'::jsonb,
  pro_tip_es = 'Este es un ejercicio complementario para el tibial anterior y los extensores de los dedos; usálo en volúmenes moderados como parte de un trabajo de tobillo equilibrado.',
  pro_tip_en = 'This is a complementary exercise for the tibialis anterior and toe extensors; use it in moderate volumes as part of balanced ankle work.',
  tertiary_muscles = ARRAY['Extensor Hallucis Longus','Peroneus Tertius','Core']::text[]
WHERE slug = 'standing-cable-glute-extension';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte la tobillera y paráte de espaldas a la polea baja.","Desde la posición erguida, flexioná la rodilla llevando el talón hacia el glúteo de forma controlada.","Apretá los isquiotibiales en el punto de máxima flexión.","Bajá de forma controlada hasta casi la extensión completa sin apoyar el pie.","Completá todas las repeticiones de un lado antes de cambiar."]'::jsonb,
  execution_steps_en = '["Attach the ankle strap and stand facing away from the low cable.","From an upright position, flex the knee bringing the heel toward the glute under control.","Squeeze the hamstrings at maximum flexion.","Lower under control to near full extension without resting the foot.","Complete all reps on one side before switching."]'::jsonb,
  common_errors_es = '["Inclinar el tronco hacia adelante para compensar la resistencia.","Usar impulso del tronco en lugar de la flexión activa de rodilla.","No llegar a la extensión completa entre repeticiones.","Usar demasiado peso y acortar el rango de movimiento."]'::jsonb,
  common_errors_en = '["Leaning the torso forward to compensate for the resistance.","Using trunk momentum instead of active knee flexion.","Not reaching full extension between reps.","Using too much weight and shortening the range of motion."]'::jsonb,
  pro_tip_es = 'Sujetáte a un soporte con la mano para mantener el tronco estable; el objetivo es aislar los isquiotibiales, no trabajar el equilibrio.',
  pro_tip_en = 'Hold a support with one hand to keep the trunk stable; the goal is to isolate the hamstrings, not challenge balance.',
  tertiary_muscles = ARRAY['Gluteus Maximus','Sartorius','Core']::text[]
WHERE slug = 'standing-cable-hamstring-curl';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con las puntas de los pies en el borde de un escalón o superficie elevada.","Desde la dorsiflexión máxima, elevá los talones hasta la extensión completa del tobillo.","Sostenélos en la cima un segundo y bajá de forma lenta y controlada.","Realizá el movimiento en rango completo sin rebotar en la parte baja.","Para la versión con compañero: flexioná el tronco 90° y sujetáte a un soporte mientras el compañero se sienta en las caderas (no en la espalda)."]'::jsonb,
  execution_steps_en = '["Stand with the balls of the feet on the edge of a step or elevated surface.","From maximum dorsiflexion, raise the heels to full ankle extension.","Hold for one second at the top and lower slowly under control.","Perform the full range without bouncing at the bottom.","For the partner version: flex the torso 90° and hold a support while the partner sits on the hips (not the back)."]'::jsonb,
  common_errors_es = '["Rebotar en la posición de máximo estiramiento.","No bajar los talones por debajo del nivel del escalón.","No llegar a la extensión completa del tobillo en la cima.","Doblar las rodillas para ayudar al movimiento."]'::jsonb,
  common_errors_en = '["Bouncing at the maximum stretch position.","Not lowering the heels below the step level.","Not reaching full ankle extension at the top.","Bending the knees to assist the movement."]'::jsonb,
  pro_tip_es = 'Los gemelos (gastrocnemios) se trabajan mejor con la rodilla extendida; para el sóleo, flexioná levemente la rodilla.',
  pro_tip_en = 'The gastrocnemius is best targeted with the knee extended; for the soleus, add a slight knee bend.',
  tertiary_muscles = ARRAY['Tibialis Posterior','Peroneals','Flexor Digitorum Longus']::text[]
WHERE slug = 'standing-calf-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte bajo las almohadillas de la máquina con las puntas de los pies en el borde de la plataforma.","Desde la dorsiflexión máxima, elevá los talones empujando las almohadillas hacia arriba.","Llegá a la extensión completa del tobillo y sostenéla un segundo.","Descendé de forma lenta y controlada hasta el punto de máximo estiramiento.","No rebotés en la posición de máximo estiramiento."]'::jsonb,
  execution_steps_en = '["Position yourself under the machine pads with the balls of the feet on the platform edge.","From maximum dorsiflexion, raise the heels by pushing the pads upward.","Reach full ankle extension and hold for one second.","Lower slowly and under control to maximum stretch.","Do not bounce at the maximum stretch position."]'::jsonb,
  common_errors_es = '["Rebotar en la posición de estiramiento.","No completar el rango de movimiento en ninguno de los dos extremos.","Doblar las rodillas para ayudar al movimiento.","Usar demasiado peso y perder el control del movimiento."]'::jsonb,
  common_errors_en = '["Bouncing at the stretch position.","Not completing the range of motion at either extreme.","Bending the knees to assist the movement.","Using too much weight and losing movement control."]'::jsonb,
  pro_tip_es = 'Variá la posición de los pies (neutros, punta adentro, punta afuera) en diferentes series para estimular distintas porciones de los gastrocnemios.',
  pro_tip_en = 'Vary foot position (neutral, toes in, toes out) across sets to stimulate different portions of the gastrocnemius.',
  tertiary_muscles = ARRAY['Soleus','Tibialis Anterior','Peroneals']::text[]
WHERE slug = 'standing-calf-raise-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte en la máquina de gemelos de pie y ajustá las almohadillas sobre los hombros.","Para trabajar el gastrocnemio lateral: rotá levemente la pierna hacia adentro (rotación medial) con muy poco peso.","Para trabajar el gastrocnemio interno: rotá levemente la pierna hacia afuera (rotación lateral) con muy poco peso.","Realizá el rango completo de movimiento de dorsiflexión a flexión plantar.","Usá estas variantes solo para corregir descompensaciones musculares específicas, no como ejercicio principal."]'::jsonb,
  execution_steps_en = '["Position yourself in the standing calf machine and adjust the pads on the shoulders.","To target the lateral gastrocnemius: slightly internally rotate the leg with light weight.","To target the medial gastrocnemius: slightly externally rotate the leg with light weight.","Perform the full range of motion from dorsiflexion to plantar flexion.","Use these variations only to correct specific muscle imbalances, not as the primary exercise."]'::jsonb,
  common_errors_es = '["Usar estas variantes con cargas altas; son para corrección, no para carga máxima.","Exagerar la rotación, lo que puede generar estrés articular.","Usar estas variantes sin una razón técnica o de desequilibrio identificada.","No controlar el rango completo en cada variante."]'::jsonb,
  common_errors_en = '["Using these variations with heavy loads; they are for correction, not maximum loading.","Exaggerating the rotation, which can cause joint stress.","Using these variations without an identified technical or imbalance reason.","Not controlling the full range in each variant."]'::jsonb,
  pro_tip_es = 'Las rotaciones de pierna para diferenciar las porciones del gemelo son válidas solo con cargas muy ligeras; priorizá el ejercicio estándar para la masa.',
  pro_tip_en = 'Leg rotations to differentiate gastrocnemius portions are only valid with very light loads; prioritize the standard exercise for mass.',
  tertiary_muscles = ARRAY['Soleus','Tibialis Posterior','Peroneals']::text[]
WHERE slug = 'standing-calf-raise-machine-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte lateral a un soporte o colocáte en decúbito lateral en el suelo.","Para la versión de suelo: apoyá la pierna superior con la planta del pie y dejá levemente flexionada la cadera; elevá la pierna inferior en aducción.","Elevá la pierna de forma controlada sin rotar la pelvis.","Bajá de forma controlada sin dejar que la pierna toque el suelo entre repeticiones.","Completá todas las repeticiones de un lado antes de cambiar."]'::jsonb,
  execution_steps_en = '["Stand sideways to a support or lie on your side on the floor.","For the floor version: rest the top leg with its foot planted and allow a slight hip bend; raise the bottom leg in adduction.","Raise the leg under control without rotating the pelvis.","Lower under control without letting the leg touch the floor between reps.","Complete all reps on one side before switching."]'::jsonb,
  common_errors_es = '["Rotar la pelvis para compensar la falta de movilidad en aducción.","Usar impulso en lugar de contracción activa de los aductores.","No controlar el descenso.","Confundir aducción con flexión de cadera."]'::jsonb,
  common_errors_en = '["Rotating the pelvis to compensate for limited adduction mobility.","Using momentum instead of active adductor contraction.","Not controlling the descent.","Confusing adduction with hip flexion."]'::jsonb,
  pro_tip_es = 'La ventaja del suelo frente a la versión de pie es que los aductores trabajan contra la gravedad en todo el rango; aprovechá esto en el excéntrico.',
  pro_tip_en = 'The advantage of the floor version over the standing one is that the adductors work against gravity throughout the full range; take advantage of this in the eccentric.',
  tertiary_muscles = ARRAY['Psoas-Iliacus','Pectineus','Core']::text[]
WHERE slug = 'standing-hip-adduction';
UPDATE public.exercise_library SET
  execution_steps_es = '["Pará de pie con la barra tomada en agarre prono, manos separadas unos 30-40 cm, brazos extendidos frente a los muslos.","Inspirá y tirá la barra hacia arriba pegada al cuerpo, elevando los codos por encima de los hombros.","Al llegar a la altura del mentón, hacé una pausa breve con los codos apuntando al techo.","Espirá y bajá la barra de forma controlada hasta la posición inicial.","Mantené el torso recto y evitá inclinar el tronco para generar impulso."]'::jsonb,
  execution_steps_en = '["Stand with the barbell in an overhand grip, hands 30-40 cm apart, arms extended in front of your thighs.","Inhale and pull the bar straight up close to your body, driving elbows above shoulder level.","Hold briefly at chin height with elbows pointing toward the ceiling.","Exhale and lower the bar under control to the starting position.","Keep the torso upright and avoid leaning back to generate momentum."]'::jsonb,
  common_errors_es = '["Usar un agarre demasiado cerrado, lo que fuerza la rotación interna del hombro en la parte alta.","Dejar que la barra se separe del cuerpo durante el recorrido, reduciendo la activación del deltoides medio.","Elevar el mentón o el torso para alcanzar mayor altura en lugar de elevar los codos.","Bajar el peso con caída libre, perdiendo el control excéntrico."]'::jsonb,
  common_errors_en = '["Using too narrow a grip, which forces internal shoulder rotation at the top.","Letting the bar drift away from the body during the lift, reducing medial delt activation.","Raising the chin or torso to reach more height instead of driving the elbows.","Dropping the weight without eccentric control."]'::jsonb,
  pro_tip_es = 'Usá un agarre más ancho que el de los hombros para reducir la rotación interna y el riesgo de pinzamiento subacromial; los codos deben guiar el movimiento, no las manos.',
  pro_tip_en = 'Use a grip slightly wider than shoulder-width to reduce internal rotation and impingement risk; let the elbows lead the movement, not the hands.',
  tertiary_muscles = ARRAY['Serratus Anterior','Wrist Flexors','Core']::text[]
WHERE slug = 'barbell-upright-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Posicionáte de pie con las rodillas ligeramente flexionadas y el torso inclinado hasta casi paralelo al suelo.","Tomá las mancuernas con agarre neutro, dejándolas colgar bajo el pecho con codos ligeramente flexionados.","Inspirá y elevá ambos brazos hacia los costados con un arco controlado hasta la altura de los hombros.","Apretá los deltoides posteriores y los romboides en el punto más alto durante un instante.","Espirá y bajá las mancuernas de forma lenta y controlada a la posición inicial."]'::jsonb,
  execution_steps_en = '["Stand with knees slightly bent and hinge forward until your torso is nearly parallel to the floor.","Hold the dumbbells with a neutral grip, letting them hang below your chest with elbows slightly bent.","Inhale and raise both arms out to the sides in a controlled arc to shoulder height.","Squeeze the rear delts and rhomboids at the top for a brief moment.","Exhale and slowly lower the dumbbells back to the starting position."]'::jsonb,
  common_errors_es = '["Encorvar la espalda baja al inclinar el tronco, generando tensión lumbar innecesaria.","Doblar en exceso los codos, convirtiendo el movimiento en un jalón de remo.","Usar momentum con el torso para balancear las mancuernas hacia arriba.","No llegar a la altura de los hombros, reduciendo el rango de trabajo del deltoides posterior."]'::jsonb,
  common_errors_en = '["Rounding the lower back when hinging forward, creating unnecessary lumbar stress.","Bending the elbows too much, turning the movement into a rowing pull.","Using torso momentum to swing the dumbbells upward.","Not reaching shoulder height, reducing the rear delt range of motion."]'::jsonb,
  pro_tip_es = 'Imaginá que querés mostrar el dorso de las manos al techo al subir; esto mantiene la rotación externa del hombro y centra el trabajo en el deltoides posterior.',
  pro_tip_en = 'Imagine showing the backs of your hands to the ceiling as you lift; this maintains external shoulder rotation and keeps the work on the rear deltoid.',
  tertiary_muscles = ARRAY['Infraspinatus','Teres Minor','Erector Spinae']::text[]
WHERE slug = 'bent-over-rear-delt-fly';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá la cuerda en la polea a la altura de los ojos y agarrá cada extremo con agarre neutro.","Alejáte un paso de la polea para poner tensión en el cable y posicionáte con los pies separados al ancho de los hombros.","Inspirá y tirá la cuerda hacia tu cara separando las manos, llevando los codos hacia atrás y afuera a la altura de los hombros.","Al llegar al punto final, las manos deben quedar junto a las orejas con los pulgares apuntando atrás.","Espirá y extendé los brazos de regreso con control, sin dejar que el peso caiga."]'::jsonb,
  execution_steps_en = '["Attach the rope to a pulley at eye level and grip each end with a neutral grip.","Step back to create cable tension and stand with feet shoulder-width apart.","Inhale and pull the rope toward your face, separating the hands and driving elbows back and out at shoulder height.","At the end point, hands should be beside your ears with thumbs pointing backward.","Exhale and extend your arms back under control without letting the weight drop."]'::jsonb,
  common_errors_es = '["Tirar la cuerda hacia abajo o hacia el mentón en lugar de hacia la cara, reduciendo la activación del manguito.","Permitir que los codos caigan por debajo de la línea de los hombros durante el tirón.","Usar demasiado peso y recurrir al balanceo del tronco.","No separar los extremos de la cuerda al final, perdiendo la rotación externa del hombro."]'::jsonb,
  common_errors_en = '["Pulling the rope downward or toward the chin instead of the face, reducing rotator cuff activation.","Letting the elbows drop below shoulder level during the pull.","Using too much weight and relying on trunk swinging.","Not pulling the rope ends apart at the finish, losing external shoulder rotation."]'::jsonb,
  pro_tip_es = 'Este ejercicio es clave para la salud del manguito rotador y la postura; priorizá la calidad del movimiento sobre el peso, y realizalo con pesos moderados en series de 15-20 reps.',
  pro_tip_en = 'This exercise is key for rotator cuff health and posture; prioritize movement quality over weight, and perform it with moderate loads for 15-20 reps.',
  tertiary_muscles = ARRAY['Infraspinatus','Teres Minor','Subscapularis']::text[]
WHERE slug = 'cable-face-pull';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá una manija o barra corta a la polea baja y paráte de espaldas a la máquina.","Sujetá el agarre con una o ambas manos con agarre prono, brazos extendidos a los costados del cuerpo.","Inspirá y elevá el brazo hacia el frente de forma controlada hasta la altura del hombro.","Hacé una pequeña pausa al llegar a 90° para maximizar la contracción del deltoides anterior.","Espirá y bajá el brazo lentamente resistiendo la tensión del cable."]'::jsonb,
  execution_steps_en = '["Attach a handle or short bar to the low pulley and stand facing away from the machine.","Grip the handle with one or both hands in an overhand grip, arms extended by your sides.","Inhale and raise your arm forward in a controlled arc to shoulder height.","Pause briefly at 90° to maximize anterior deltoid contraction.","Exhale and lower your arm slowly, resisting the cable tension on the way down."]'::jsonb,
  common_errors_es = '["Inclinar el torso hacia atrás para ganar impulso en la fase concéntrica.","Superar la horizontal con el brazo de manera habitual, involucrando excesivamente el trapecio.","Doblar el codo durante el ascenso, reduciendo el trabajo del deltoides anterior.","Bajar el peso rápidamente sin resistencia excéntrica."]'::jsonb,
  common_errors_en = '["Leaning the torso back to generate momentum during the concentric phase.","Consistently going above horizontal, excessively recruiting the trapezius.","Bending the elbow during the ascent, reducing anterior delt engagement.","Lowering the weight quickly without eccentric resistance."]'::jsonb,
  pro_tip_es = 'La polea baja genera tensión constante en todo el rango, a diferencia de la mancuerna que tiene punto muerto al inicio; aprovechá esto bajando el peso muy despacio para maximizar el estímulo.',
  pro_tip_en = 'The low pulley provides constant tension throughout the range, unlike the dumbbell which has a dead spot at the bottom; take advantage by lowering very slowly to maximize stimulus.',
  tertiary_muscles = ARRAY['Serratus Anterior','Core','Wrist Extensors']::text[]
WHERE slug = 'cable-front-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá la cuerda o barra a la polea baja y pasala entre tus piernas, de espaldas a la máquina.","Tomá ambos extremos con agarre neutro o en semipronación, brazos extendidos hacia abajo.","Inspirá y elevá ambos brazos simultáneamente hacia el frente hasta la altura de los hombros.","Pausá brevemente al llegar a 90° y apretá el deltoides anterior.","Espirá y bajá los brazos lentamente manteniendo la tensión del cable."]'::jsonb,
  execution_steps_en = '["Attach the rope or bar to the low pulley and thread it between your legs, standing with your back to the machine.","Grip both ends with a neutral or semi-pronated grip, arms extended downward.","Inhale and raise both arms simultaneously forward to shoulder height.","Pause briefly at 90° and squeeze the anterior deltoid.","Exhale and lower your arms slowly, maintaining cable tension."]'::jsonb,
  common_errors_es = '["Inclinar la espalda baja hacia atrás para generar impulso, especialmente en series pesadas.","Permitir que el cable golpee las piernas durante el movimiento por mala colocación.","No mantener la simetría entre ambos brazos al subir simultáneamente.","Subir los hombros hacia las orejas en lugar de mantenerlos deprimidos."]'::jsonb,
  common_errors_en = '["Leaning the lower back backward to generate momentum, especially on heavier sets.","Allowing the cable to hit the legs due to poor positioning.","Failing to maintain symmetry between both arms when lifting simultaneously.","Shrugging the shoulders toward the ears instead of keeping them depressed."]'::jsonb,
  pro_tip_es = 'Usá un agarre en semipronación (pulgares hacia arriba) para concentrar el trabajo en el deltoides anterior y reducir la participación del pectoral superior.',
  pro_tip_en = 'Use a semi-pronated grip (thumbs up) to concentrate work on the anterior deltoid and reduce upper pectoralis involvement.',
  tertiary_muscles = ARRAY['Serratus Anterior','Upper Pectoralis','Core']::text[]
WHERE slug = 'cable-front-raise-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá la polea a la altura del codo y paráte de lado a la máquina con el brazo que trabaja más cercano.","Tomá el agarre con la mano interna, codo flexionado a 90° y pegado al costado del cuerpo.","Con el antebrazo paralelo al suelo (partiendo del lateral), rotá el hombro hacia adentro llevando la mano hacia el abdomen.","Llegá hasta donde el rango de movimiento sea cómodo, sin separar el codo del costado.","Volvé lentamente a la posición inicial controlando la resistencia del cable."]'::jsonb,
  execution_steps_en = '["Set the pulley to elbow height and stand sideways to the machine with the working arm closest.","Grip the handle with your inner hand, elbow bent 90° and tucked close to your side.","With your forearm parallel to the floor (starting from the side), internally rotate the shoulder by bringing your hand toward your abdomen.","Move as far as is comfortable without letting the elbow drift away from your side.","Slowly return to the starting position, controlling cable resistance."]'::jsonb,
  common_errors_es = '["Separar el codo del costado durante la rotación, cambiando el plano del movimiento.","Usar demasiado peso y completar el movimiento con la muñeca en lugar del hombro.","Realizar el recorrido demasiado rápido, perdiendo el control neuromuscular del manguito.","Inclinar el tronco para compensar la falta de rango articular."]'::jsonb,
  common_errors_en = '["Letting the elbow drift away from your side during rotation, altering the movement plane.","Using too much weight and completing the motion with the wrist instead of the shoulder.","Moving too quickly, losing neuromuscular control of the rotator cuff.","Tilting the torso to compensate for limited joint range."]'::jsonb,
  pro_tip_es = 'Este movimiento es de rehabilitación y prevención; usá cargas muy bajas (1-5 kg) y enfocáte en sentir el manguito rotador trabajar, no en mover mucho peso.',
  pro_tip_en = 'This is a rehabilitation and prevention movement; use very light loads (1-5 kg) and focus on feeling the rotator cuff work, not on moving heavy weight.',
  tertiary_muscles = ARRAY['Subscapularis','Pectoralis Major','Biceps Brachii']::text[]
WHERE slug = 'cable-internal-rotation';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá una manija a la polea baja y paráte de lado a la máquina, sujetando el agarre con la mano más alejada.","Tomá el soporte de la máquina con la mano libre para estabilizarte y colocá los pies al ancho de los hombros.","Inspirá y elevá el brazo lateralmente de forma controlada hasta la altura del hombro.","Hacé una pausa breve con el brazo a 90°, manteniendo el hombro deprimido.","Espirá y bajá el brazo lentamente resistiendo la tensión constante del cable."]'::jsonb,
  execution_steps_en = '["Attach a D-handle to the low pulley and stand sideways to the machine, gripping the handle with your far hand.","Hold the machine frame with your free hand for stability and stand with feet shoulder-width apart.","Inhale and raise your arm laterally in a controlled arc to shoulder height.","Pause briefly at 90° with your shoulder depressed.","Exhale and lower your arm slowly, resisting the constant cable tension."]'::jsonb,
  common_errors_es = '["Elevar el hombro hacia la oreja durante el ascenso, activando el trapecio en lugar del deltoides medio.","Inclinar el torso hacia el lado contrario para generar impulso.","No controlar la bajada, perdiendo el trabajo excéntrico del deltoides.","Posicionar el cable demasiado adelante o atrás respecto al cuerpo, alterando el plano de movimiento."]'::jsonb,
  common_errors_en = '["Shrugging the shoulder toward the ear during the ascent, activating the trapezius instead of the medial delt.","Tilting the torso to the opposite side to generate momentum.","Not controlling the descent, losing eccentric deltoid work.","Positioning the cable too far forward or backward relative to the body, altering the movement plane."]'::jsonb,
  pro_tip_es = 'La polea baja genera tensión desde el inicio del movimiento, a diferencia de la mancuerna; aprovechá el punto muerto inferior para trabajar la parte inicial del rango con mayor estímulo.',
  pro_tip_en = 'The low pulley creates tension from the very start of the movement, unlike a dumbbell; use the bottom dead-spot to challenge the initial range with greater stimulus.',
  tertiary_muscles = ARRAY['Serratus Anterior','Core','Subscapularis']::text[]
WHERE slug = 'cable-lateral-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá la polea baja y tomá el agarre con la mano del lado que trabaja, pasando el cable por detrás de tu cuerpo.","Paráte erguido con el lado trabajador alejado de la máquina y sujetáte al soporte con la mano libre.","Inspirá y elevá el brazo lateralmente hasta la altura del hombro, manteniendo el codo ligeramente flexionado.","El cable detrás del cuerpo limita la posibilidad de adelantar la mano; esto fuerza un plano de elevación lateral más puro.","Espirá y bajá el brazo de manera controlada hasta la posición inicial."]'::jsonb,
  execution_steps_en = '["Set the low pulley and grip the handle with the working hand, running the cable behind your body.","Stand upright with the working side away from the machine and hold the frame with your free hand.","Inhale and raise your arm laterally to shoulder height, keeping the elbow slightly bent.","The cable behind your body prevents the hand from drifting forward, enforcing a purer lateral raise plane.","Exhale and lower your arm in a controlled manner to the starting position."]'::jsonb,
  common_errors_es = '["No fijar correctamente el tronco, permitiendo rotaciones de columna durante el movimiento.","Llevar el brazo hacia el frente en lugar de mantener el plano lateral puro.","Elevar el hombro ipsilateral hacia la oreja durante la fase concéntrica.","No aprovechar la variante y realizar el mismo patrón que la elevación lateral convencional."]'::jsonb,
  common_errors_en = '["Failing to brace the trunk, allowing spinal rotation during the movement.","Moving the arm forward instead of maintaining a pure lateral plane.","Shrugging the ipsilateral shoulder toward the ear during the concentric phase.","Not taking advantage of the variant and replicating the same pattern as the standard lateral raise."]'::jsonb,
  pro_tip_es = 'Esta variante con el cable pasado por detrás forza la contracción terminal del deltoides lateral y el acromial; es una buena opción para trabajar la porción lateral en el punto de máxima tensión.',
  pro_tip_en = 'This behind-the-body cable variant forces terminal contraction of the lateral and acromial deltoid; it is a good option for loading the lateral portion at maximum tension.',
  tertiary_muscles = ARRAY['Supraspinatus','Serratus Anterior','Core']::text[]
WHERE slug = 'cable-lateral-raise-single';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocá ambas poleas a la altura de los hombros o cruza los cables (mano derecha toma polea izquierda y viceversa).","Paráte en el centro con los brazos cruzados o extendidos al frente y tomá las manijas con agarre neutro.","Inspirá y abrí los brazos horizontalmente hacia atrás, manteniendo los codos ligeramente flexionados.","Llegá hasta la extensión horizontal completa apretando los deltoides posteriores y romboides.","Espirá y volvé los brazos al centro de manera controlada sin dejar caer el peso."]'::jsonb,
  execution_steps_en = '["Set both pulleys at shoulder height or cross the cables (right hand takes left pulley and vice versa).","Stand in the center with arms crossed or extended forward, gripping handles with a neutral grip.","Inhale and open your arms horizontally backward, keeping elbows slightly bent.","Reach full horizontal extension, squeezing the rear delts and rhomboids.","Exhale and return your arms to center under control without dropping the weight."]'::jsonb,
  common_errors_es = '["Flexionar en exceso los codos convirtiendo el ejercicio en un remo.","Bajar los brazos por debajo de la horizontal, activando más el dorsal que el deltoides posterior.","Inclinar el torso hacia adelante para ayudarse con el movimiento.","Usar demasiado peso y completar el recorrido con rotaciones de tronco."]'::jsonb,
  common_errors_en = '["Bending the elbows too much, turning the exercise into a row.","Dropping the arms below the horizontal, activating the lats more than the rear delt.","Leaning the torso forward to assist the movement.","Using excessive weight and completing the range with trunk rotation."]'::jsonb,
  pro_tip_es = 'Mantené los brazos a la altura exacta de los hombros durante todo el movimiento; si el peso te obliga a bajarlos, es demasiado pesado para aislar el deltoides posterior.',
  pro_tip_en = 'Keep your arms exactly at shoulder height throughout the movement; if the weight forces you to drop them, it is too heavy to isolate the rear deltoid.',
  tertiary_muscles = ARRAY['Infraspinatus','Teres Minor','Middle Trapezius']::text[]
WHERE slug = 'cable-rear-delt-fly';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá la polea a la altura del hombro y paráte de frente a la máquina, tomando el agarre con la mano contraria al lado de la polea.","Atrasá la pierna del lado trabajador para ganar estabilidad y mirá hacia la polea.","Con el brazo casi extendido, tirá en extensión/retropulsión horizontal hasta que el brazo quede detrás de la línea del cuerpo.","Apretá el deltoides posterior y el dorsal al llegar al rango final.","Volvé de forma lenta y controlada a la posición inicial."]'::jsonb,
  execution_steps_en = '["Set the pulley at shoulder height and stand facing the machine, gripping the handle with the hand opposite to the pulley side.","Step back the foot on the working side for stability and look toward the pulley.","With your arm nearly extended, pull in horizontal extension/retropulsion until your arm is behind the body line.","Squeeze the rear deltoid and lat at the end of the range.","Return slowly and under control to the starting position."]'::jsonb,
  common_errors_es = '["Rotar el tronco para completar el recorrido en lugar de mover solo el hombro.","Flexionar en exceso el codo, convirtiendo el movimiento en un remo.","No estabilizar la cadera y los glúteos durante la ejecución unilateral.","Usar momentum del tronco en lugar de controlar el movimiento desde el deltoides."]'::jsonb,
  common_errors_en = '["Rotating the trunk to complete the range instead of moving only the shoulder.","Bending the elbow too much, turning the movement into a row.","Failing to stabilize the hips and glutes during unilateral execution.","Using trunk momentum instead of controlling the movement from the deltoid."]'::jsonb,
  pro_tip_es = 'Al trabajar un brazo a la vez podés concentrarte en la contracción y corregir desequilibrios entre el hombro dominante y el no dominante.',
  pro_tip_en = 'Working one arm at a time lets you focus on the contraction and correct imbalances between the dominant and non-dominant shoulder.',
  tertiary_muscles = ARRAY['Latissimus Dorsi','Teres Major','Rhomboids']::text[]
WHERE slug = 'cable-rear-delt-fly-single';
UPDATE public.exercise_library SET
  execution_steps_es = '["Conectá una barra corta o cuerda a la polea baja y paráte frente a la máquina con los pies al ancho de los hombros.","Sujetá la barra con agarre prono, manos separadas al ancho de los hombros, brazos extendidos hacia abajo.","Inspirá y tirá la barra hacia el mentón elevando los codos por encima de la línea de los hombros.","Pausá en la parte alta y apretá el deltoides medio y el trapecio.","Espirá y bajá la barra de forma controlada aprovechando la tensión constante del cable."]'::jsonb,
  execution_steps_en = '["Attach a short bar or rope to the low pulley and stand facing the machine with feet shoulder-width apart.","Grip the bar overhand with hands shoulder-width apart, arms extended downward.","Inhale and pull the bar to chin height, driving the elbows above shoulder level.","Pause at the top and squeeze the medial delt and trapezius.","Exhale and lower the bar under control, taking advantage of constant cable tension."]'::jsonb,
  common_errors_es = '["Usar un agarre demasiado cerrado que fuerza la rotación interna del hombro en la parte alta.","Inclinar el torso hacia atrás para completar el recorrido.","No controlar la fase excéntrica, perdiendo el beneficio de la tensión constante del cable.","Elevar solo hasta la altura del pecho, reduciendo el trabajo del deltoides medio."]'::jsonb,
  common_errors_en = '["Using a grip too narrow, forcing internal shoulder rotation at the top.","Leaning the torso back to complete the range.","Not controlling the eccentric phase, losing the benefit of constant cable tension.","Only raising to chest height, reducing medial delt engagement."]'::jsonb,
  pro_tip_es = 'La polea garantiza tensión desde el inicio, donde la mancuerna tiene punto muerto; esto hace que la fase baja del remo sea más estimulante que con barra libre.',
  pro_tip_en = 'The cable ensures tension from the start, where a barbell has a dead spot; this makes the bottom phase of the upright row more stimulating than with free weights.',
  tertiary_muscles = ARRAY['Serratus Anterior','Wrist Flexors','Core']::text[]
WHERE slug = 'cable-upright-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá la máquina de remo y conectá una barra corta a la polea baja; recostáte en el asiento con el torso apoyado.","Tomá la barra con agarre prono, manos al ancho de los hombros, brazos extendidos al frente.","Inspirá y jalá la barra hacia el mentón elevando los codos por encima de los hombros.","Pausá en la posición alta y apretá el deltoides medio y el trapecio.","Espirá y extendé los brazos de forma lenta y controlada hasta la posición de partida."]'::jsonb,
  execution_steps_en = '["Set up the rowing machine and attach a short bar to the low pulley; recline in the seat with your torso supported.","Grip the bar overhand with hands shoulder-width apart, arms extended forward.","Inhale and pull the bar to chin height, raising elbows above shoulder level.","Pause at the top and squeeze the medial delt and trapezius.","Exhale and slowly extend the arms back to the starting position."]'::jsonb,
  common_errors_es = '["No apoyar correctamente el torso, permitiendo que la zona lumbar tome carga.","Usar demasiado peso aprovechando la posición sentada para generar impulso.","No elevar los codos lo suficiente, limitando la activación del deltoides medio.","Subir los hombros hacia las orejas en lugar de elevar los codos."]'::jsonb,
  common_errors_en = '["Failing to properly support the torso, letting the lower back take load.","Using too much weight and exploiting the seated position to generate momentum.","Not raising the elbows high enough, limiting medial delt activation.","Shrugging the shoulders to the ears instead of driving the elbows up."]'::jsonb,
  pro_tip_es = 'La posición recostada elimina el balanceo de tronco y permite concentrarse puramente en la mecánica del hombro; es una excelente variante para quienes tienen problemas de espalda baja.',
  pro_tip_en = 'The reclined position eliminates trunk swinging and allows you to focus purely on shoulder mechanics; it is an excellent variant for those with lower back issues.',
  tertiary_muscles = ARRAY['Serratus Anterior','Core','Wrist Flexors']::text[]
WHERE slug = 'cable-upright-row-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en un banco con respaldo vertical y tomá las mancuernas con agarre supino (palmas hacia vos) a la altura del mentón.","Inspirá y comenzá el press rotando las palmas hacia el frente al mismo tiempo que empujás las mancuernas hacia arriba.","Al finalizar la rotación, las palmas deben mirar hacia afuera y los brazos deben estar casi extendidos.","Pausá brevemente arriba y espirá al completar la extensión.","Bajá las mancuernas invirtiendo la rotación, volviendo a la posición con palmas hacia vos."]'::jsonb,
  execution_steps_en = '["Sit on a bench with a vertical backrest and hold dumbbells in a supinated grip (palms facing you) at chin height.","Inhale and begin pressing while rotating the palms to face forward simultaneously.","At the end of the rotation, palms should face outward and arms should be nearly extended.","Pause briefly at the top and exhale as you complete the extension.","Lower the dumbbells by reversing the rotation, returning to the palms-facing-you position."]'::jsonb,
  common_errors_es = '["Realizar la rotación antes de iniciar el press, en lugar de ejecutar ambos movimientos simultáneamente.","Arquear excesivamente la espalda baja durante el press para alcanzar más altura.","No completar el rango de rotación, reduciendo la activación del deltoides anterior y medio.","Usar demasiado peso que impide la rotación suave y controlada."]'::jsonb,
  common_errors_en = '["Rotating before starting the press, instead of performing both movements simultaneously.","Excessively arching the lower back during the press to reach more height.","Not completing the full rotation range, reducing anterior and medial delt activation.","Using too much weight that prevents smooth, controlled rotation."]'::jsonb,
  pro_tip_es = 'El Arnold press activa las tres cabezas del deltoides gracias a la rotación; es más demandante que un press estándar, así que reducí el peso respecto a tu press de hombros convencional.',
  pro_tip_en = 'The Arnold press activates all three deltoid heads thanks to the rotation; it is more demanding than a standard press, so reduce the weight compared to your conventional shoulder press.',
  tertiary_muscles = ARRAY['Serratus Anterior','Upper Pectoralis','Core']::text[]
WHERE slug = 'dumbbell-arnold-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recliná el banco a unos 45°-60° y sentáte con la espalda apoyada, sujetando las mancuernas con agarre supino a la altura del mentón.","Rotá las palmas hacia el frente mientras empujás las mancuernas en diagonal hacia arriba y al frente.","El trayecto es oblicuo, no completamente vertical; apuntá a un punto frente a vos y algo por encima.","Extendé los brazos sin bloquear los codos y pausá un instante en el punto más alto.","Bajá invirtiendo el movimiento, con la palma volviendo a mirar hacia vos."]'::jsonb,
  execution_steps_en = '["Recline the bench to 45-60° and sit with your back supported, holding dumbbells in a supinated grip at chin height.","Rotate your palms to face forward while pressing the dumbbells diagonally upward and forward.","The trajectory is oblique, not fully vertical; aim toward a point in front of you and slightly above.","Extend your arms without locking the elbows and pause briefly at the top.","Lower by reversing the movement, with the palm returning to face you."]'::jsonb,
  common_errors_es = '["Empujar verticalmente como en un press estándar, perdiendo el énfasis en el deltoides anterior.","Perder el contacto de la espalda con el respaldo del banco al llegar al punto alto.","No sincronizar la rotación de la palma con el empuje.","Descender el peso sin control, perdiendo la fase excéntrica."]'::jsonb,
  common_errors_en = '["Pressing vertically like a standard press, losing the anterior delt emphasis.","Losing back contact with the bench backrest at the top of the press.","Failing to synchronize palm rotation with the press.","Lowering the weight without control, losing the eccentric phase."]'::jsonb,
  pro_tip_es = 'El banco inclinado reduce el trabajo del tríceps y dirige más el estímulo al deltoides anterior y pectoral superior; útil para series de mayor volumen con carga media.',
  pro_tip_en = 'The inclined bench reduces triceps involvement and directs more stimulus to the anterior delt and upper pectoralis; useful for higher-volume sets with moderate load.',
  tertiary_muscles = ARRAY['Upper Pectoralis','Triceps Long Head','Serratus Anterior']::text[]
WHERE slug = 'dumbbell-arnold-press-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Apoyáte en un banco horizontal con la mano y rodilla del mismo lado, como en el remo con mancuerna.","Tomá la mancuerna con la mano libre en posición neutra, con el codo a 90° y el antebrazo paralelo al suelo.","Inspirá y rotá externamente el hombro hasta llevar el antebrazo paralelo al suelo en el plano frontal.","Llegá hasta aproximadamente 80° de rotación sin modificar la flexión del codo.","Espirá y volvé lentamente a la posición inicial resistiendo la gravedad."]'::jsonb,
  execution_steps_en = '["Support yourself on a flat bench with the same-side hand and knee, as in a dumbbell row.","Hold the dumbbell with your free hand in a neutral grip, elbow at 90° and forearm parallel to the floor.","Inhale and externally rotate the shoulder until the forearm is parallel to the floor in the frontal plane.","Reach approximately 80° of rotation without changing elbow flexion.","Exhale and slowly return to the starting position, resisting gravity."]'::jsonb,
  common_errors_es = '["Modificar el ángulo del codo durante la rotación, cambiando el patrón del ejercicio.","Usar un peso excesivo que impide el rango de rotación completo.","Rotar el tronco en lugar de rotar solo el hombro.","Realizar el movimiento demasiado rápido, perdiendo el control del manguito rotador."]'::jsonb,
  common_errors_en = '["Changing the elbow angle during the rotation, altering the exercise pattern.","Using excessive weight that prevents full rotation range.","Rotating the trunk instead of only rotating the shoulder.","Moving too quickly, losing rotator cuff control."]'::jsonb,
  pro_tip_es = 'Este ejercicio trabaja el infraespinoso y el redondo menor; es fundamental para la salud del manguito rotador y se ejecuta con cargas muy bajas (1-5 kg), priorizando el control del movimiento.',
  pro_tip_en = 'This exercise targets the infraspinatus and teres minor; it is essential for rotator cuff health and is performed with very light loads (1-5 kg), prioritizing movement control.',
  tertiary_muscles = ARRAY['Posterior Deltoid','Rhomboids','Lower Trapezius']::text[]
WHERE slug = 'dumbbell-external-rotation';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con las mancuernas frente a los muslos, agarre prono (palmas abajo) o neutro, brazos ligeramente flexionados.","Inspirá y elevá uno o ambos brazos hacia el frente de forma controlada hasta la altura de los hombros.","Pausá un instante al llegar a 90° con el brazo paralelo al suelo.","Espirá y bajá el brazo de manera lenta y controlada resistiendo la gravedad.","Mantené el torso estable y los hombros deprimidos durante todo el movimiento."]'::jsonb,
  execution_steps_en = '["Stand with dumbbells in front of your thighs, overhand (palms down) or neutral grip, arms slightly bent.","Inhale and raise one or both arms forward in a controlled arc to shoulder height.","Pause briefly at 90° with your arm parallel to the floor.","Exhale and lower the arm slowly and in a controlled manner, resisting gravity.","Keep your torso stable and shoulders depressed throughout the movement."]'::jsonb,
  common_errors_es = '["Balancear el torso hacia atrás para generar impulso en la fase concéntrica.","Elevar los brazos por encima de la horizontal de forma habitual, aumentando el riesgo de pinzamiento.","Subir los hombros hacia las orejas durante la elevación.","Bajar el peso con caída libre, perdiendo el trabajo excéntrico del deltoides anterior."]'::jsonb,
  common_errors_en = '["Swinging the torso backward to generate momentum during the concentric phase.","Habitually raising the arms above horizontal, increasing impingement risk.","Shrugging the shoulders to the ears during the raise.","Dropping the weight without control, losing eccentric anterior delt work."]'::jsonb,
  pro_tip_es = 'La elevación frontal aísla el deltoides anterior; usala como ejercicio complementario, no como movimiento principal, dado que el press de hombros ya lo trabaja intensamente.',
  pro_tip_en = 'The front raise isolates the anterior deltoid; use it as an accessory movement, not a main one, since the shoulder press already trains it heavily.',
  tertiary_muscles = ARRAY['Upper Pectoralis','Serratus Anterior','Wrist Extensors']::text[]
WHERE slug = 'dumbbell-front-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en un banco inclinado a 45° con el pecho apoyado, sujetando las mancuernas con agarre neutro a los costados.","Inspirá y elevá los brazos hacia el frente de forma alterna o simultánea, manteniendo los codos sin extensión completa.","Subí hasta que los brazos queden paralelos o ligeramente por encima del suelo (según el diseño del banco).","Pausá en el punto alto y apretá el deltoides anterior.","Espirá y bajá de forma controlada sin soltar la tensión al llegar a la posición inicial."]'::jsonb,
  execution_steps_en = '["Sit on a 45° incline bench with your chest supported, holding dumbbells in a neutral grip at your sides.","Inhale and raise your arms forward alternately or simultaneously, keeping elbows without full extension.","Raise until your arms are parallel to or slightly above the floor (depending on bench design).","Pause at the top and squeeze the anterior deltoid.","Exhale and lower under control without releasing tension at the starting position."]'::jsonb,
  common_errors_es = '["Extender completamente el antebrazo, lo que puede generar tensión en el codo.","Usar un banco con demasiada inclinación que impide el rango correcto de movimiento.","Balancear el torso para generar impulso incluso estando apoyado en el banco.","No mantener los hombros deprimidos, activando excesivamente el trapecio."]'::jsonb,
  common_errors_en = '["Fully extending the forearm, which can create elbow stress.","Using a bench with too much incline that prevents the correct range of motion.","Swinging the torso to generate momentum even with chest support.","Not keeping the shoulders depressed, excessively activating the trapezius."]'::jsonb,
  pro_tip_es = 'El banco inclinado elimina el balanceo y pone mayor tensión en el deltoides anterior desde el inicio del movimiento; una alternativa útil cuando necesitás mayor estricción que la elevación de pie.',
  pro_tip_en = 'The incline bench eliminates swinging and places greater tension on the anterior deltoid from the very start of the movement; a useful alternative when you need more strictness than the standing raise.',
  tertiary_muscles = ARRAY['Biceps Brachii','Serratus Anterior','Core']::text[]
WHERE slug = 'dumbbell-front-raise-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con las mancuernas a los costados del cuerpo, codos ligeramente flexionados, palmas mirando hacia adentro.","Inspirá y elevá ambos brazos lateralmente de forma controlada hasta la altura de los hombros.","Mantené los hombros deprimidos y los codos ligeramente adelante del plano del cuerpo.","Pausá un instante con los brazos a 90° y apretá el deltoides medio.","Espirá y bajá las mancuernas de forma lenta y controlada resistiendo la gravedad."]'::jsonb,
  execution_steps_en = '["Stand with dumbbells at your sides, elbows slightly bent, palms facing inward.","Inhale and raise both arms laterally in a controlled arc to shoulder height.","Keep shoulders depressed and elbows slightly in front of the body plane.","Pause briefly with arms at 90° and squeeze the medial deltoid.","Exhale and lower the dumbbells slowly and under control, resisting gravity."]'::jsonb,
  common_errors_es = '["Elevar los hombros hacia las orejas (encogerse) durante el ascenso, activando el trapecio.","Balancear el torso para generar impulso en lugar de trabajar el deltoides medio.","Extender los codos completamente, lo que puede estresar el codo y el manguito.","Bajar las mancuernas rápidamente sin control excéntrico."]'::jsonb,
  common_errors_en = '["Shrugging the shoulders toward the ears during the ascent, activating the trapezius.","Swinging the torso to generate momentum instead of working the medial deltoid.","Fully extending the elbows, which can stress the elbow and rotator cuff.","Lowering the dumbbells quickly without eccentric control."]'::jsonb,
  pro_tip_es = 'Incliná levemente el torso hacia adelante (~10°) para alinear mejor el deltoides medio con el plano de elevación y reducir la participación del supraespinoso en la parte alta del recorrido.',
  pro_tip_en = 'Tilt the torso slightly forward (~10°) to better align the medial deltoid with the elevation plane and reduce supraspinatus involvement at the top of the range.',
  tertiary_muscles = ARRAY['Supraspinatus','Serratus Anterior','Core']::text[]
WHERE slug = 'dumbbell-lateral-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con las mancuernas a los costados, eligiendo el agarre: pulgares arriba (rotación externa) o pulgares abajo (rotación interna).","Inspirá y elevá los brazos lateralmente hasta la altura de los hombros.","Si usás pulgares hacia abajo, sentirás más activación del deltoides medio y posterior.","Si usás pulgares hacia arriba, el deltoides anterior y el bíceps toman más participación.","Espirá y bajá de forma controlada en ambas variantes."]'::jsonb,
  execution_steps_en = '["Stand with dumbbells at your sides, choosing your grip: thumbs up (external rotation) or thumbs down (internal rotation).","Inhale and raise your arms laterally to shoulder height.","With thumbs pointing down, you will feel more medial and posterior delt activation.","With thumbs pointing up, the anterior delt and biceps take more involvement.","Exhale and lower in a controlled manner for both grip variants."]'::jsonb,
  common_errors_es = '["No elegir conscientemente la variante de agarre y mezclar posiciones en la misma serie.","Elevar los hombros hacia las orejas independientemente del agarre utilizado.","Sobrepasar la horizontal con los brazos de forma habitual, aumentando el riesgo de pinzamiento.","Usar peso excesivo que impide el control de la rotación durante el movimiento."]'::jsonb,
  common_errors_en = '["Not consciously choosing a grip variant and mixing positions within the same set.","Shrugging the shoulders to the ears regardless of the grip used.","Habitually going above horizontal, increasing impingement risk.","Using excessive weight that prevents grip rotation control during the movement."]'::jsonb,
  pro_tip_es = 'La variante con pulgares abajo (rotación interna) puede reducir la protección del bíceps sobre la articulación glenohumeral; evitá usarla con cargas elevadas si tenés historial de lesión en el hombro.',
  pro_tip_en = 'The thumbs-down variant (internal rotation) may reduce the protective role of the biceps on the glenohumeral joint; avoid using it with heavy loads if you have a shoulder injury history.',
  tertiary_muscles = ARRAY['Supraspinatus','Biceps Brachii','Upper Trapezius']::text[]
WHERE slug = 'dumbbell-lateral-raise-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en un banco con respaldo vertical o paráte con los pies al ancho de los hombros, sujetando las mancuernas a la altura de los hombros con agarre prono.","Inspirá, activá el core y empujá las mancuernas hacia arriba y ligeramente hacia adentro hasta casi extender los brazos.","Juntá levemente las mancuernas en el punto más alto sin chocarlas.","Pausá un instante arriba y espirá al completar el empuje.","Bajá las mancuernas de forma controlada hasta la posición de inicio en los hombros."]'::jsonb,
  execution_steps_en = '["Sit on a bench with a vertical backrest or stand with feet shoulder-width apart, holding dumbbells at shoulder height with an overhand grip.","Inhale, brace your core, and press the dumbbells upward and slightly inward until arms are almost fully extended.","Bring the dumbbells slightly together at the top without clashing them.","Pause briefly at the top and exhale as you complete the press.","Lower the dumbbells under control back to the starting shoulder-height position."]'::jsonb,
  common_errors_es = '["Arquear la espalda baja de forma exagerada durante el press, generando carga en la columna lumbar.","Bajar las mancuernas por debajo de la línea de los hombros, reduciendo el trabajo del deltoides.","No activar el core antes del press, inestabilizando la columna.","Realizar el movimiento en un plano completamente frontal, sin convergencia de las mancuernas al subir."]'::jsonb,
  common_errors_en = '["Excessively arching the lower back during the press, loading the lumbar spine.","Lowering the dumbbells below shoulder level, reducing deltoid engagement.","Not bracing the core before the press, destabilizing the spine.","Pressing in a completely frontal plane without bringing the dumbbells together at the top."]'::jsonb,
  pro_tip_es = 'Las mancuernas permiten mayor libertad de movimiento que la barra; aprovechá esto para encontrar el plano de press más cómodo para tus hombros (ligeramente en diagonal).',
  pro_tip_en = 'Dumbbells allow greater freedom of movement than a barbell; use this to find the most comfortable pressing plane for your shoulders (slightly diagonal).',
  tertiary_muscles = ARRAY['Serratus Anterior','Upper Pectoralis','Core']::text[]
WHERE slug = 'dumbbell-overhead-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte o sentáte con las mancuernas a la altura de los hombros en agarre prono, con el tronco activo.","Empujá las mancuernas de forma alterna, extendiendo un brazo mientras el otro permanece en posición inicial.","Mantené el tronco firme y evitá las inclinaciones laterales de columna al alternar brazos.","Completá el rango de cada brazo antes de iniciar el empuje del otro.","Controlá la bajada de cada mancuerna de forma independiente."]'::jsonb,
  execution_steps_en = '["Stand or sit with dumbbells at shoulder height in an overhand grip, with an active core.","Press the dumbbells alternately, extending one arm while the other stays in the starting position.","Keep the trunk firm and avoid lateral spinal tilting when alternating arms.","Complete the full range of each arm before starting the next press.","Control the descent of each dumbbell independently."]'::jsonb,
  common_errors_es = '["Inclinar el tronco hacia el lado del brazo que baja para ayudarse con el peso.","No completar la extensión de un brazo antes de iniciar el empuje del otro.","Usar un peso excesivo que fuerza a compensar con rotaciones de columna.","Perder la posición neutra de la columna al hacer el empuje alterno."]'::jsonb,
  common_errors_en = '["Tilting the trunk toward the lowering arm to help with the weight.","Not completing the extension of one arm before starting the press of the other.","Using excessive weight that forces spinal rotation compensation.","Losing neutral spine position during alternating presses."]'::jsonb,
  pro_tip_es = 'El press alterno aumenta el tiempo bajo tensión de cada deltoides y exige mayor estabilización del core que el press bilateral; reducí el peso respecto al press simultáneo.',
  pro_tip_en = 'Alternating presses increase time under tension for each deltoid and demand more core stabilization than bilateral presses; reduce weight compared to simultaneous pressing.',
  tertiary_muscles = ARRAY['Serratus Anterior','Core','Upper Trapezius']::text[]
WHERE slug = 'dumbbell-press-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Incliná el torso hasta quedar casi paralelo al suelo con las rodillas ligeramente flexionadas.","Dejá colgar las mancuernas con agarre neutro bajo el pecho, codos con una leve flexión fija.","Inspirá y elevá ambos brazos hacia los costados en un arco controlado hasta la altura de los hombros.","Apretá los deltoides posteriores y los romboides en el punto más alto.","Espirá y bajá las mancuernas de forma lenta y controlada sin relajar el core."]'::jsonb,
  execution_steps_en = '["Hinge your torso until nearly parallel to the floor with knees slightly bent.","Let the dumbbells hang with a neutral grip below your chest, elbows with a slight fixed bend.","Inhale and raise both arms out to the sides in a controlled arc to shoulder height.","Squeeze the rear delts and rhomboids at the top.","Exhale and lower the dumbbells slowly and under control without releasing core tension."]'::jsonb,
  common_errors_es = '["Encorvar la espalda baja al inclinar el torso.","Doblar los codos progresivamente durante el movimiento, convirtiendo el ejercicio en un remo.","Usar el balanceo del torso para ayudarse en la subida.","No llegar a la altura de los hombros, reduciendo el estímulo del deltoides posterior."]'::jsonb,
  common_errors_en = '["Rounding the lower back when hinging the torso.","Progressively bending the elbows during the movement, turning it into a row.","Using torso momentum to assist the lift.","Not reaching shoulder height, reducing posterior delt stimulus."]'::jsonb,
  pro_tip_es = 'Realizálo sentado en el borde de un banco con el pecho apoyado en los muslos para eliminar completamente el balanceo y reducir la tensión lumbar.',
  pro_tip_en = 'Perform it seated at the edge of a bench with your chest resting on your thighs to completely eliminate swinging and reduce lumbar stress.',
  tertiary_muscles = ARRAY['Infraspinatus','Teres Minor','Erector Spinae']::text[]
WHERE slug = 'dumbbell-rear-delt-fly';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en un banco inclinado a 45°-60° con el respaldo elevado, sujetando las mancuernas en posición neutra a los costados.","Elevá las mancuernas frontalmente de forma alterna o simultánea sin modificar la flexión de los codos.","Subí hasta una altura algo superior a la cabeza controlando el movimiento.","Inspirá al iniciar el movimiento ascendente y espirá al bajar.","Bajá de forma controlada sin relajar la tensión del deltoides."]'::jsonb,
  execution_steps_en = '["Sit on a bench inclined at 45-60° with the backrest raised, holding dumbbells in a neutral grip at your sides.","Raise the dumbbells forward alternately or simultaneously without changing elbow flexion.","Raise to slightly above head height, controlling the movement.","Inhale as you begin the ascending movement and exhale as you lower.","Lower in a controlled manner without releasing deltoid tension."]'::jsonb,
  common_errors_es = '["Modificar el ángulo del codo durante el movimiento, cambiando el patrón del ejercicio.","Usar impulso del tronco para completar series pesadas.","No mantener la espalda apoyada en el respaldo durante todo el recorrido.","Bajar las mancuernas con caída libre, perdiendo el trabajo excéntrico."]'::jsonb,
  common_errors_en = '["Changing the elbow angle during the movement, altering the exercise pattern.","Using trunk momentum to complete heavier sets.","Failing to keep the back pressed against the backrest throughout the range.","Dropping the dumbbells without control, losing eccentric work."]'::jsonb,
  pro_tip_es = 'El banco inclinado fija el tronco y elimina el balanceo; el movimiento debe originarse completamente desde el hombro, no desde el codo ni la muñeca.',
  pro_tip_en = 'The incline bench fixes the trunk and eliminates swinging; the movement should originate entirely from the shoulder, not the elbow or wrist.',
  tertiary_muscles = ARRAY['Biceps Brachii','Serratus Anterior','Upper Trapezius']::text[]
WHERE slug = 'dumbbell-shrug-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte con las mancuernas frente a los muslos en agarre prono, manos al ancho de los hombros.","Inspirá y jalá las mancuernas hacia el mentón elevando los codos hacia arriba y afuera.","Al llegar a la altura del mentón, los codos deben estar por encima de las muñecas y de los hombros.","Pausá brevemente en el punto alto y apretá el deltoides medio y el trapecio.","Espirá y bajá las mancuernas de forma controlada hasta la posición inicial."]'::jsonb,
  execution_steps_en = '["Stand with dumbbells in front of your thighs in an overhand grip, hands shoulder-width apart.","Inhale and pull the dumbbells toward your chin, driving elbows upward and outward.","At chin height, elbows should be above the wrists and the shoulders.","Pause briefly at the top and squeeze the medial delt and trapezius.","Exhale and lower the dumbbells under control to the starting position."]'::jsonb,
  common_errors_es = '["Usar un agarre demasiado cerrado que fuerza la rotación interna del hombro en la parte alta.","No elevar los codos lo suficiente, limitando la activación del deltoides medio.","Inclinar el torso hacia atrás para ayudarse con el peso.","Bajar las mancuernas de forma brusca sin control excéntrico."]'::jsonb,
  common_errors_en = '["Using too narrow a grip, forcing internal shoulder rotation at the top.","Not raising the elbows high enough, limiting medial delt activation.","Leaning the torso back to help with the weight.","Dropping the dumbbells abruptly without eccentric control."]'::jsonb,
  pro_tip_es = 'Las mancuernas permiten mayor libertad de movimiento que la barra en el remo al mentón; los codos pueden abrirse más naturalmente, reduciendo el riesgo de pinzamiento subacromial.',
  pro_tip_en = 'Dumbbells allow greater freedom of movement than a barbell in the upright row; elbows can flare more naturally, reducing subacromial impingement risk.',
  tertiary_muscles = ARRAY['Serratus Anterior','Wrist Flexors','Core']::text[]
WHERE slug = 'dumbbell-upright-row';
UPDATE public.exercise_library SET
  execution_steps_es = '["Paráte de lado a un soporte firme y sujetáte con la mano libre para estabilizarte.","Tomá la mancuerna con la mano exterior y apoyá el cuerpo levemente inclinado hacia el soporte.","Inspirá y elevá el brazo lateralmente de forma controlada hasta la altura del hombro.","Apretá el deltoides medio en el punto más alto y pausá un instante.","Espirá y bajá la mancuerna de manera lenta y controlada resistiendo la gravedad."]'::jsonb,
  execution_steps_en = '["Stand sideways to a sturdy support and hold it with your free hand for stability.","Hold the dumbbell with your outer hand and lean the body slightly toward the support.","Inhale and raise your arm laterally in a controlled arc to shoulder height.","Squeeze the medial deltoid at the top and hold briefly.","Exhale and lower the dumbbell slowly and under control, resisting gravity."]'::jsonb,
  common_errors_es = '["No sujetarse firmemente al soporte, lo que genera inestabilidad durante el movimiento.","Elevar el hombro hacia la oreja durante el ascenso.","Inclinarse excesivamente hacia el soporte para ganar impulso.","No controlar la bajada, perdiendo el trabajo excéntrico del deltoides."]'::jsonb,
  common_errors_en = '["Not gripping the support firmly, causing instability during the movement.","Shrugging the shoulder toward the ear during the ascent.","Leaning excessively toward the support to generate momentum.","Not controlling the descent, losing eccentric deltoid work."]'::jsonb,
  pro_tip_es = 'Sujetarte al soporte y apoyarte levemente elimina el punto muerto inferior de la elevación lateral; podés generar una gran contracción final si ejecutás de forma estricta.',
  pro_tip_en = 'Holding the support and leaning slightly eliminates the bottom dead-spot of the lateral raise; you can generate a strong terminal contraction if you execute strictly.',
  tertiary_muscles = ARRAY['Supraspinatus','Serratus Anterior','Core']::text[]
WHERE slug = 'elevaciones-laterales-a-una-mano';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte en decúbito prono sobre un banco plano con el pecho apoyado en el borde y la cabeza fuera del banco.","Abrazá el banco con los brazos a los costados para mantener el equilibrio.","Realizá el gesto de mirar al frente elevando la cabeza de forma natural.","Luego dejá caer la cabeza suavemente hasta mirar más allá del suelo, sin forzar el rango.","Respirá de forma natural durante todo el movimiento sin contener el aliento."]'::jsonb,
  execution_steps_en = '["Lie prone on a flat bench with your chest at the edge and your head hanging off.","Hug the bench with your arms at your sides to maintain balance.","Perform the gesture of looking forward by lifting your head naturally.","Then gently lower your head until you are looking past the floor, without forcing the range.","Breathe naturally throughout the movement without holding your breath."]'::jsonb,
  common_errors_es = '["Forzar el rango de movimiento más allá del límite confortable, generando tensión cervical.","Sostener la respiración durante el ejercicio, aumentando la tensión muscular innecesariamente.","Realizar el movimiento de forma brusca en lugar de lenta y controlada.","No apoyar correctamente el pecho en el banco, generando inestabilidad."]'::jsonb,
  common_errors_en = '["Forcing the range of motion beyond the comfortable limit, causing cervical strain.","Holding breath during the exercise, unnecessarily increasing muscle tension.","Performing the movement abruptly instead of slowly and controlled.","Not properly supporting the chest on the bench, creating instability."]'::jsonb,
  pro_tip_es = 'Este es un ejercicio de movilidad cervical y no de fuerza; el objetivo es la movilización suave de la columna cervical, no generar carga. Realizálo con total control y sin dolor.',
  pro_tip_en = 'This is a cervical mobility exercise, not a strength exercise; the goal is gentle cervical spine mobilization, not load generation. Perform it with full control and without pain.',
  tertiary_muscles = ARRAY['Cervical Erectors','Splenius Capitis','Levator Scapulae']::text[]
WHERE slug = 'floor-shoulder-rotation';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina de elevaciones laterales y ajustá el asiento para que los codos queden alineados con el pivote de la máquina.","Apoyá los brazos en las almohadillas con los codos ligeramente flexionados.","Inspirá y empujá las almohadillas hacia arriba y afuera hasta que los brazos lleguen a la horizontal.","Pausá brevemente en el punto alto y apretá el deltoides medio.","Espirá y bajá las almohadillas de forma lenta y controlada."]'::jsonb,
  execution_steps_en = '["Sit in the lateral raise machine and adjust the seat so your elbows align with the machine pivot.","Rest your arms on the pads with elbows slightly bent.","Inhale and push the pads upward and outward until your arms reach horizontal.","Pause briefly at the top and squeeze the medial deltoid.","Exhale and lower the pads slowly and under control."]'::jsonb,
  common_errors_es = '["No ajustar la altura del asiento, lo que desalinea el pivote del codo con el eje de la máquina.","Elevar los hombros hacia las orejas durante el movimiento.","No llegar a la horizontal, reduciendo el rango efectivo del deltoides medio.","Bajar el peso bruscamente sin control excéntrico."]'::jsonb,
  common_errors_en = '["Not adjusting seat height, misaligning the elbow pivot with the machine axis.","Shrugging the shoulders toward the ears during the movement.","Not reaching horizontal, reducing the effective medial delt range.","Dropping the weight abruptly without eccentric control."]'::jsonb,
  pro_tip_es = 'La máquina guiada es ideal para principiantes porque elimina la necesidad de equilibrio; ajustá el pivote con precisión para que el movimiento sea eficiente y sin compensaciones.',
  pro_tip_en = 'The guided machine is ideal for beginners because it eliminates the need for balance; adjust the pivot precisely so the movement is efficient and without compensation.',
  tertiary_muscles = ARRAY['Supraspinatus','Upper Trapezius','Serratus Anterior']::text[]
WHERE slug = 'lateral-raise-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el asiento de la máquina para que el pivote quede alineado con el hombro y colocá los brazos en las almohadillas.","Tomá el agarre o apoyá los antebrazos según el diseño de la máquina.","Inspirá y empujá las palancas hacia arriba y afuera hasta llegar a la horizontal.","Pausá en el punto más alto y apretá el deltoides lateral.","Espirá y bajá de forma controlada hasta la posición de partida."]'::jsonb,
  execution_steps_en = '["Adjust the machine seat so the pivot aligns with your shoulder and place your arms on the pads.","Grip the handle or rest your forearms according to the machine design.","Inhale and push the levers upward and outward until you reach horizontal.","Pause at the top and squeeze the lateral deltoid.","Exhale and lower under control to the starting position."]'::jsonb,
  common_errors_es = '["No ajustar el asiento correctamente, lo que fuerza compensaciones en el rango de movimiento.","Elevar los hombros durante la ejecución en lugar de mantenerlos deprimidos.","Usar el diseño de la máquina para hacer trampa inclinando el torso.","Realizar el movimiento solo con un brazo sin ajustar el contrapeso si la máquina es bilateral."]'::jsonb,
  common_errors_en = '["Not correctly adjusting the seat, forcing compensations in range of motion.","Raising the shoulders during the movement instead of keeping them depressed.","Using the machine design to cheat by tilting the torso.","Performing the movement with only one arm without adjusting the counterweight on bilateral machines."]'::jsonb,
  pro_tip_es = 'En las máquinas de elevación lateral con almohadillas para antebrazos podés usar más carga que con mancuernas porque el antebrazo actúa como punto de apoyo; controlá igualmente la bajada.',
  pro_tip_en = 'On lateral raise machines with forearm pads you can use more load than with dumbbells because the forearm acts as a lever point; still control the lowering phase.',
  tertiary_muscles = ARRAY['Supraspinatus','Serratus Anterior','Core']::text[]
WHERE slug = 'machine-lateral-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el asiento para que las manijas queden a la altura de los hombros y apoyá la espalda en el respaldo.","Tomá las manijas con agarre prono y los codos ligeramente hacia adentro.","Inspirá, activá el core y empujá las manijas hacia arriba hasta casi extender los brazos.","Pausá un instante en el punto alto sin bloquear los codos.","Espirá y bajá las manijas de forma controlada hasta la posición inicial."]'::jsonb,
  execution_steps_en = '["Adjust the seat so the handles are at shoulder height and press your back against the backrest.","Grip the handles with an overhand grip and elbows slightly inward.","Inhale, brace your core, and push the handles upward until arms are nearly extended.","Pause briefly at the top without locking the elbows.","Exhale and lower the handles under control to the starting position."]'::jsonb,
  common_errors_es = '["No ajustar la altura del asiento, presionando desde una posición que carga el cuello o el trapecio.","Levantar los glúteos del asiento al empujar.","Bloquear los codos en el punto alto, trasladando toda la carga a los tendones.","Bajar el peso de forma brusca sin control excéntrico."]'::jsonb,
  common_errors_en = '["Not adjusting the seat height, pressing from a position that loads the neck or trapezius.","Lifting the glutes off the seat during the press.","Locking the elbows at the top, transferring all load to the tendons.","Lowering the weight abruptly without eccentric control."]'::jsonb,
  pro_tip_es = 'La máquina guiada fija el plano de movimiento y reduce la demanda de estabilización; es una buena opción para añadir volumen de press sin fatigar los estabilizadores del hombro.',
  pro_tip_en = 'The guided machine fixes the movement plane and reduces stabilization demand; it is a good option to add pressing volume without fatiguing shoulder stabilizers.',
  tertiary_muscles = ARRAY['Serratus Anterior','Core','Biceps Long Head']::text[]
WHERE slug = 'machine-shoulder-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Posicioná la barra en el rack a la altura de los hombros y tomala con agarre prono, manos algo más anchas que los hombros.","Sacá la barra del rack, paráte con los pies al ancho de los hombros y sostené la barra frente a la clavícula.","Inspirá, activá el core y empujá la barra verticalmente hacia arriba pasando por delante de la cara.","Extendé los brazos por encima de la cabeza y metés la cabeza hacia adelante al finalizar para quedar con la barra sobre la línea media del cuerpo.","Espirá y bajá la barra de forma controlada hasta la posición inicial frente a la clavícula."]'::jsonb,
  execution_steps_en = '["Position the bar in the rack at shoulder height and grip it overhand with hands slightly wider than shoulders.","Unrack the bar, stand with feet shoulder-width apart, and hold it in front of your collarbone.","Inhale, brace your core, and press the bar vertically upward, passing in front of your face.","Extend your arms overhead and push your head forward at the end so the bar is over your body''s midline.","Exhale and lower the bar under control to the starting position in front of the collarbone."]'::jsonb,
  common_errors_es = '["No meter la cabeza hacia adelante al final del press, dejando la barra delante del cuerpo en lugar de sobre él.","Arquear excesivamente la espalda baja durante el press para alcanzar más altura.","No activar el core antes del empuje, desestabilizando la columna lumbar.","Bajar la barra detrás de la cabeza como variante sin indicación específica, lo que aumenta el riesgo de lesión cervical."]'::jsonb,
  common_errors_en = '["Not tucking the head forward at the top of the press, leaving the bar in front of the body instead of directly overhead.","Excessively arching the lower back during the press to reach more height.","Not bracing the core before the press, destabilizing the lumbar spine.","Lowering the bar behind the head as a variant without specific instruction, increasing cervical injury risk."]'::jsonb,
  pro_tip_es = 'El press militar es el ejercicio base de hombros con barra; dominá primero la técnica antes de aumentar la carga, especialmente la mecánica de meter la cabeza al finalizar cada rep.',
  pro_tip_en = 'The military press is the foundational barbell shoulder exercise; master technique before increasing load, especially the mechanics of pushing the head through at the end of each rep.',
  tertiary_muscles = ARRAY['Serratus Anterior','Core','Upper Pectoralis']::text[]
WHERE slug = 'military-press-barbell';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en la máquina de pectoral (pec deck) al revés, con el pecho apoyado en el respaldo y los brazos en abducción de 90°.","Ajustá la posición para que los codos o antebrazos queden apoyados en las almohadillas.","Inspirá y abrí los brazos hacia atrás en el arco que permite la máquina.","Llegá al rango máximo que permite el diseño de la máquina apretando el deltoides posterior.","Espirá y volvé a la posición inicial de forma controlada."]'::jsonb,
  execution_steps_en = '["Sit in the pec deck machine in reverse, with your chest against the backrest and arms in 90° abduction.","Adjust the position so your elbows or forearms rest on the pads.","Inhale and open your arms rearward through the arc the machine allows.","Reach the maximum range the machine design permits, squeezing the rear deltoid.","Exhale and return to the starting position under control."]'::jsonb,
  common_errors_es = '["No invertir correctamente la posición en la máquina, terminando en la posición de pectoral en lugar de la de deltoides posterior.","Usar un recorrido parcial porque el diseño de la máquina no es óptimo para este ejercicio.","Elevar los hombros durante el movimiento en lugar de mantenerlos deprimidos.","Usar demasiado peso que impide el rango controlado de apertura posterior."]'::jsonb,
  common_errors_en = '["Not correctly reversing the position in the machine, ending up in the pec-deck position instead of rear-delt position.","Using a partial range because the machine design is not optimal for this exercise.","Shrugging the shoulders during the movement instead of keeping them depressed.","Using too much weight that prevents the controlled rear-opening range."]'::jsonb,
  pro_tip_es = 'Si el gimnasio tiene una máquina específica para deltoides posterior, es preferible usarla; si usás el pec deck al revés, verificá que el diseño permita un rango real de apertura posterior.',
  pro_tip_en = 'If the gym has a specific rear delt machine, it is preferable to use it; if using the pec deck in reverse, verify that the design allows a real rear-opening range.',
  tertiary_muscles = ARRAY['Infraspinatus','Teres Minor','Rhomboids']::text[]
WHERE slug = 'rear-delt-machine-fly';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte frente al respaldo acolchado de la máquina de deltoides posterior y apoyá el pecho en él.","Tomá las manijas con agarre neutro y los brazos extendidos hacia el frente.","Inspirá y abrí los brazos hacia atrás en el plano horizontal apretando los deltoides posteriores.","Llegá al rango máximo de la máquina y pausá un instante en el punto de máxima contracción.","Espirá y volvé las manijas al frente de forma controlada."]'::jsonb,
  execution_steps_en = '["Sit facing the padded backrest of the rear delt machine and press your chest against it.","Grip the handles with a neutral grip and arms extended forward.","Inhale and open your arms rearward in the horizontal plane, squeezing the rear deltoids.","Reach the machine''s maximum range and pause briefly at peak contraction.","Exhale and return the handles forward under control."]'::jsonb,
  common_errors_es = '["No ajustar el asiento para que los brazos queden en el plano horizontal correcto.","Doblar los codos durante el movimiento, convirtiendo el ejercicio en un remo.","No apoyar firmemente el pecho en el respaldo, permitiendo que el torso se balancea.","Bajar el peso sin control al final del recorrido."]'::jsonb,
  common_errors_en = '["Not adjusting the seat so the arms are in the correct horizontal plane.","Bending the elbows during the movement, turning the exercise into a row.","Not firmly pressing the chest against the backrest, allowing the torso to sway.","Dropping the weight without control at the end of the range."]'::jsonb,
  pro_tip_es = 'La máquina específica de deltoides posterior permite aislar el hombro trasero sin tensión lumbar; es la opción más segura para quienes tienen limitaciones en la espalda baja.',
  pro_tip_en = 'The dedicated rear delt machine allows isolation of the posterior shoulder without lumbar stress; it is the safest option for those with lower back limitations.',
  tertiary_muscles = ARRAY['Infraspinatus','Teres Minor','Lower Trapezius']::text[]
WHERE slug = 'rear-delt-reverse-fly-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Pisá la banda elástica con el pie del mismo lado del brazo que trabaja y sujetá el extremo superior con la mano.","Paráte erguido con el brazo extendido a un costado del cuerpo.","Inspirá y elevá el brazo lateralmente de forma controlada hasta la altura del hombro.","Pausá brevemente en el punto alto y apretá el deltoides medio.","Espirá y bajá el brazo de forma lenta controlando la resistencia de la banda."]'::jsonb,
  execution_steps_en = '["Step on the resistance band with the foot on the same side as the working arm and grip the top end with your hand.","Stand upright with your arm extended at your side.","Inhale and raise your arm laterally in a controlled arc to shoulder height.","Pause briefly at the top and squeeze the medial deltoid.","Exhale and lower your arm slowly, controlling the band''s resistance."]'::jsonb,
  common_errors_es = '["Usar una banda de resistencia excesiva que impide el rango completo de movimiento.","No fijar la banda bajo el pie de forma segura, generando riesgo de que se suelte.","Inclinar el torso al lado contrario para completar el rango.","Elevar el hombro hacia la oreja durante el ascenso."]'::jsonb,
  common_errors_en = '["Using a resistance band that is too heavy, preventing full range of motion.","Not securing the band under the foot safely, risking it coming loose.","Tilting the torso to the opposite side to complete the range.","Shrugging the shoulder toward the ear during the ascent."]'::jsonb,
  pro_tip_es = 'La banda elástica aumenta la resistencia progresivamente a medida que se estira; esto genera mayor tensión al final del rango donde el deltoides medio está más activo.',
  pro_tip_en = 'The resistance band increases resistance progressively as it stretches; this creates greater tension at the end of the range where the medial deltoid is most active.',
  tertiary_muscles = ARRAY['Supraspinatus','Serratus Anterior','Core']::text[]
WHERE slug = 'resistance-band-lateral-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el asiento de la máquina de press de hombros para que las manijas queden a la altura de los hombros.","Apoyá firmemente la espalda en el respaldo y tomá las manijas con agarre prono.","Inspirá, activá el core y empujá las manijas verticalmente hacia arriba hasta casi extender los brazos.","Pausá un instante sin bloquear los codos y apretá el deltoides.","Espirá y bajá las manijas de forma controlada hasta la posición inicial."]'::jsonb,
  execution_steps_en = '["Adjust the shoulder press machine seat so the handles are at shoulder height.","Firmly press your back against the backrest and grip the handles with an overhand grip.","Inhale, brace your core, and press the handles vertically upward until arms are nearly extended.","Pause briefly without locking the elbows and squeeze the deltoid.","Exhale and lower the handles under control to the starting position."]'::jsonb,
  common_errors_es = '["No ajustar la altura del asiento, haciendo que las manijas estén demasiado arriba o abajo.","Separar la espalda del respaldo durante el press.","Bloquear los codos en el punto más alto.","Bajar el peso de forma brusca sin control excéntrico."]'::jsonb,
  common_errors_en = '["Not adjusting seat height, leaving the handles too high or too low.","Separating the back from the backrest during the press.","Locking the elbows at the top of the movement.","Dropping the weight abruptly without eccentric control."]'::jsonb,
  pro_tip_es = 'La máquina de press de hombros fija el plano de movimiento; es una excelente herramienta para principiantes y para añadir volumen sin requerir estabilización adicional.',
  pro_tip_en = 'The shoulder press machine fixes the movement plane; it is an excellent tool for beginners and for adding volume without requiring additional stabilization.',
  tertiary_muscles = ARRAY['Serratus Anterior','Core','Upper Trapezius']::text[]
WHERE slug = 'shoulder-press-machine';
UPDATE public.exercise_library SET
  execution_steps_es = '["Colocáte en el Smith Machine con la barra frente al cuerpo a la altura de los muslos y agarrala con agarre prono al ancho de los hombros.","Paráte erguido con los brazos extendidos y los hombros en posición neutra.","Inspirá y elevá los hombros directamente hacia las orejas sin doblar los codos ni rotar.","Llegá al rango máximo de elevación y pausá un instante apretando el trapecio superior.","Espirá y bajá los hombros de forma controlada a la posición inicial."]'::jsonb,
  execution_steps_en = '["Position yourself in the Smith Machine with the bar in front of your body at thigh height, gripping it overhand at shoulder width.","Stand upright with arms extended and shoulders in a neutral position.","Inhale and shrug your shoulders straight up toward your ears without bending the elbows or rotating.","Reach the maximum shrug height and pause briefly, squeezing the upper trapezius.","Exhale and lower your shoulders under control to the starting position."]'::jsonb,
  common_errors_es = '["Rotar los hombros durante el encogimiento (hacia adelante o hacia atrás), lo que no añade trabajo al trapecio y puede generar tensión articular.","Doblar los codos durante el movimiento, convirtiéndolo en un jalón parcial.","Inclinar el cuello hacia adelante al elevar los hombros.","Bajar los hombros con caída libre, perdiendo el trabajo excéntrico del trapecio."]'::jsonb,
  common_errors_en = '["Rotating the shoulders during the shrug (forward or backward), which adds no work to the trapezius and may create joint stress.","Bending the elbows during the movement, turning it into a partial pull.","Leaning the neck forward when shrugging the shoulders.","Dropping the shoulders without control, losing eccentric trapezius work."]'::jsonb,
  pro_tip_es = 'El Smith Machine garantiza la verticalidad del movimiento; pensá en elevar las orejas hacia los hombros (no al revés) para maximizar el reclutamiento del trapecio superior.',
  pro_tip_en = 'The Smith Machine ensures vertical movement; think of bringing your ears toward your shoulders (not the other way around) to maximize upper trapezius recruitment.',
  tertiary_muscles = ARRAY['Rhomboids','Deltoid (Medial)','Supraspinatus']::text[]
WHERE slug = 'shoulder-shrug';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá la barra en el Smith Machine a la altura de los muslos y agarrala con agarre prono.","Comenzá como en un remo al mentón: elevá los codos hacia arriba hasta llegar a la altura máxima.","Desde esa posición alta, extendé los brazos hacia el frente en horizontal, manteniendo el control.","Bajá el peso con los codos casi extendidos implicando más el deltoides anterior.","Controlá todo el recorrido descendente antes de volver a la posición inicial."]'::jsonb,
  execution_steps_en = '["Set the bar in the Smith Machine at thigh height and grip it overhand.","Begin as in an upright row: drive the elbows upward to maximum height.","From that high position, extend the arms forward horizontally, maintaining control.","Lower the weight with elbows nearly extended, involving the anterior deltoid more.","Control the entire descent before returning to the starting position."]'::jsonb,
  common_errors_es = '["No completar el remo inicial antes de extender los brazos al frente.","Soltar el control en la transición entre el remo y la extensión frontal.","Usar demasiado peso que impide el control en la extensión y el descenso.","Inclinar el torso hacia atrás durante la extensión frontal."]'::jsonb,
  common_errors_en = '["Not completing the upright row before extending the arms forward.","Losing control during the transition between the row and the frontal extension.","Using too much weight that prevents control during extension and descent.","Leaning the torso back during the frontal extension."]'::jsonb,
  pro_tip_es = 'Esta variante combina el encogimiento con un movimiento de extensión frontal; demanda coordinación y control, así que aprendé bien cada fase por separado antes de combinarlas.',
  pro_tip_en = 'This variant combines the shrug with a frontal extension movement; it demands coordination and control, so learn each phase separately before combining them.',
  tertiary_muscles = ARRAY['Deltoid (Anterior)','Serratus Anterior','Wrist Flexors']::text[]
WHERE slug = 'shoulder-shrug-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Recostáte de costado sobre un banco o colchoneta con el cuerpo alineado.","Sujetá la mancuerna con la mano de arriba en agarre neutro, con el brazo extendido a lo largo del cuerpo.","Inspirá y elevá el brazo hacia arriba y ligeramente hacia atrás en el plano del cuerpo hasta la vertical.","Apretá el deltoides posterior en el punto más alto.","Espirá y bajá la mancuerna de forma lenta y controlada resistiendo la gravedad."]'::jsonb,
  execution_steps_en = '["Lie on your side on a bench or mat with your body aligned.","Hold the dumbbell with your top hand in a neutral grip, arm extended along your body.","Inhale and raise your arm upward and slightly backward in the plane of your body to vertical.","Squeeze the rear deltoid at the top.","Exhale and lower the dumbbell slowly and under control, resisting gravity."]'::jsonb,
  common_errors_es = '["Rotar el tronco hacia atrás para alcanzar mayor rango, sacando el trabajo del deltoides posterior.","Llevar el codo demasiado cerca del cuerpo, convirtiendo el movimiento en una variante de dorsal.","No mantener el cuerpo alineado lateralmente durante todo el recorrido.","Usar demasiado peso y perder el control en la fase excéntrica."]'::jsonb,
  common_errors_en = '["Rotating the trunk backward to achieve greater range, taking the work away from the rear delt.","Bringing the elbow too close to the body, turning the movement into a lat variant.","Failing to maintain lateral body alignment throughout the range.","Using too much weight and losing control during the eccentric phase."]'::jsonb,
  pro_tip_es = 'La posición lateral elimina la compensación del trapecio que suele ocurrir en las elevaciones posteriores de pie; es una variante excelente para aislar el deltoides posterior sin mover la espalda.',
  pro_tip_en = 'The lateral position eliminates trapezius compensation that often occurs in standing rear delt raises; it is an excellent variant to isolate the posterior deltoid without moving the back.',
  tertiary_muscles = ARRAY['Infraspinatus','Teres Minor','Rhomboids']::text[]
WHERE slug = 'side-lying-rear-delt-raise';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco con respaldo vertical dentro del Smith Machine y posicioná la barra a la altura de la clavícula.","Sentáte con la espalda firmemente apoyada y tomá la barra con agarre prono, manos algo más anchas que los hombros.","Desbloqueá la barra y bajala de forma controlada hasta la clavícula.","Inspirá, activá el core y empujá la barra verticalmente hasta casi extender los brazos.","Espirá y volvé a bajar de forma controlada para la siguiente repetición."]'::jsonb,
  execution_steps_en = '["Set up a vertical backrest bench inside the Smith Machine and position the bar at collarbone height.","Sit with your back firmly pressed and grip the bar overhand with hands slightly wider than shoulders.","Unlock the bar and lower it under control to the collarbone.","Inhale, brace your core, and press the bar vertically until arms are nearly extended.","Exhale and lower under control for the next repetition."]'::jsonb,
  common_errors_es = '["Arquear la espalda baja de forma exagerada durante el press.","Dejar que la barra caiga sin control al bajar, perdiendo el trabajo excéntrico.","No desbloquear y bloquear correctamente la barra antes y después de la serie.","Usar la guía fija del Smith para forzar rangos de movimiento poco naturales para el hombro."]'::jsonb,
  common_errors_en = '["Excessively arching the lower back during the press.","Letting the bar drop without control on the way down, losing eccentric work.","Not correctly unlocking and locking the bar before and after the set.","Using the Smith guide to force unnatural ranges of motion for the shoulder."]'::jsonb,
  pro_tip_es = 'El Smith Machine elimina el balance lateral pero mantiene la guía vertical; es una opción útil para principiantes o para series con fatiga máxima donde el balance libre compromete la seguridad.',
  pro_tip_en = 'The Smith Machine eliminates lateral balance but maintains vertical guidance; it is a useful option for beginners or for high-fatigue sets where free-weight balance compromises safety.',
  tertiary_muscles = ARRAY['Serratus Anterior','Core','Upper Pectoralis']::text[]
WHERE slug = 'smith-machine-shoulder-press';
UPDATE public.exercise_library SET
  execution_steps_es = '["Ajustá el banco con respaldo completamente vertical dentro del Smith Machine y posicioná la barra detrás de la cabeza, a la altura de la nuca.","Flexioná ligeramente la cabeza hacia adelante y tomá la barra con agarre prono, manos más anchas que los hombros.","Bajá la barra de forma controlada hasta la altura de la nuca sin bajarla más allá.","Inspirá, activá el core y empujá la barra verticalmente hasta casi extender los brazos.","Espirá y volvé a bajar de forma controlada."]'::jsonb,
  execution_steps_en = '["Set up a fully vertical backrest bench inside the Smith Machine and position the bar behind your head at nape height.","Slightly flex your head forward and grip the bar overhand with hands wider than shoulders.","Lower the bar under control to nape height without going further down.","Inhale, brace your core, and press the bar vertically until arms are nearly extended.","Exhale and lower under control."]'::jsonb,
  common_errors_es = '["Bajar la barra demasiado, llevándola al nivel del cuello o la espalda media, aumentando el riesgo cervical.","No flexionar la cabeza hacia adelante, dejándola en la trayectoria de la barra.","Usar un agarre demasiado cerrado que aumenta la tensión en el manguito rotador.","Arquear la espalda baja de forma exagerada durante el press."]'::jsonb,
  common_errors_en = '["Lowering the bar too far, bringing it to neck or mid-back level, increasing cervical risk.","Not flexing the head forward, leaving it in the bar''s path.","Using too narrow a grip that increases rotator cuff stress.","Excessively arching the lower back during the press."]'::jsonb,
  pro_tip_es = 'El press trasnuca activa las tres cabezas del deltoides de forma intensa; sin embargo, requiere una buena movilidad de hombros y no es recomendable para quienes tienen antecedentes de pinzamiento subacromial.',
  pro_tip_en = 'The behind-the-neck press intensely activates all three deltoid heads; however, it requires good shoulder mobility and is not recommended for those with a history of subacromial impingement.',
  tertiary_muscles = ARRAY['Serratus Anterior','Upper Pectoralis','Core']::text[]
WHERE slug = 'smith-machine-shoulder-press-2';
UPDATE public.exercise_library SET
  execution_steps_es = '["Sentáte en un banco con respaldo vertical o paráte con el core activado, con una mancuerna a la altura del hombro en agarre prono.","Inspirá y empujá la mancuerna hacia arriba hasta casi extender el brazo, manteniendo el tronco recto.","Evitá inclinar el torso hacia el lado contrario del brazo que trabaja.","Pausá un instante en el punto alto y espirá al completar la extensión.","Bajá la mancuerna de forma controlada hasta la posición de inicio en el hombro."]'::jsonb,
  execution_steps_en = '["Sit on a bench with a vertical backrest or stand with your core braced, holding one dumbbell at shoulder height in an overhand grip.","Inhale and press the dumbbell upward until the arm is nearly extended, keeping the torso upright.","Avoid tilting the torso toward the opposite side of the working arm.","Pause briefly at the top and exhale as you complete the extension.","Lower the dumbbell under control to the starting shoulder-height position."]'::jsonb,
  common_errors_es = '["Inclinar el tronco hacia el lado contrario para compensar la asimetría del peso.","No activar el core, lo que genera inestabilidad lateral de la columna.","Usar una carga excesiva que fuerza compensaciones posturales.","Bajar la mancuerna sin control, perdiendo el trabajo excéntrico del deltoides."]'::jsonb,
  common_errors_en = '["Tilting the trunk to the opposite side to compensate for the weight asymmetry.","Not bracing the core, causing lateral spinal instability.","Using excessive load that forces postural compensations.","Lowering the dumbbell without control, losing eccentric deltoid work."]'::jsonb,
